function getApiErrorMessage(body, fallback = "Erro inesperado") {
    if (!body) {
        return fallback;
    }

    const detail = body.detail ?? body.message ?? body.error ?? body;
    if (typeof detail === "string") {
        return detail;
    }

    if (Array.isArray(detail)) {
        const messages = detail.map((item) => {
            if (typeof item === "string") {
                return item;
            }
            if (item && typeof item === "object") {
                const location = Array.isArray(item.loc) ? `${item.loc.join(".")}: ` : "";
                return `${location}${item.msg || "Erro de validação"}`;
            }
            return String(item);
        });
        return messages.join(" | ");
    }

    if (detail && typeof detail === "object") {
        return detail.message || JSON.stringify(detail);
    }

    return fallback;
}

function getHeaders(extra = {}) {
    return {
        "Content-Type": "application/json",
        ...(token ? { Authorization: `Bearer ${token}` } : {}),
        ...extra,
    };
}

async function api(path, options = {}) {
    const response = await fetch(`${API}${path}`, {
        ...options,
        headers: getHeaders(options.headers || {}),
    });
    if (response.status === 401) {
        clearSession();
        showAuth("Sua sessao expirou. Entre novamente.");
        throw new Error("Unauthorized");
    }
    if (!response.ok) {
        const data = await response.json().catch(() => ({}));
        const error = new Error(getApiErrorMessage(data, response.statusText || "Erro inesperado"));
        error.apiData = data;
        error.status = response.status;
        throw error;
    }
    if (response.status === 204) {
        return null;
    }
    return response.json();
}

async function apiForm(path, formData, options = {}) {
    let response = null;
    let lastError = null;
    for (let attempt = 0; attempt < 2; attempt++) {
        try {
            response = await fetch(`${API}${path}`, {
                method: options.method || "POST",
                ...options,
                body: formData,
                headers: {
                    ...(token ? { Authorization: `Bearer ${token}` } : {}),
                    ...(options.headers || {}),
                },
            });
            break;
        } catch (error) {
            lastError = error;
            const isNetworkError = error && /failed to fetch|networkerror|load failed/i.test(String(error.message || error));
            if (!isNetworkError || attempt === 1) {
                throw new Error("Falha de conexão ao enviar arquivos. Verifique a internet e tente novamente.");
            }
            await new Promise((resolve) => setTimeout(resolve, 800));
        }
    }
    if (!response) {
        throw new Error(lastError?.message || "Falha ao enviar requisição.");
    }
    if (response.status === 401) {
        clearSession();
        showAuth("Sua sessao expirou. Entre novamente.");
        throw new Error("Unauthorized");
    }
    if (!response.ok) {
        const data = await response.json().catch(() => ({}));
        const error = new Error(getApiErrorMessage(data, response.statusText || "Erro inesperado"));
        error.apiData = data;
        error.status = response.status;
        throw error;
    }
    if (response.status === 204) {
        return null;
    }
    return response.json();
}

function apiFormWithProgress(path, formData, options = {}) {
    return new Promise((resolve, reject) => {
        const xhr = new XMLHttpRequest();
        xhr.open(options.method || "POST", `${API}${path}`, true);

        const headers = {
            ...(token ? { Authorization: `Bearer ${token}` } : {}),
            ...(options.headers || {}),
        };
        Object.entries(headers).forEach(([key, value]) => {
            if (value == null) {
                return;
            }
            xhr.setRequestHeader(key, String(value));
        });

        if (typeof options.onUploadProgress === "function") {
            xhr.upload.addEventListener("progress", (event) => {
                const loaded = Number(event.loaded || 0);
                const total = Number(event.total || 0);
                const progress = event.lengthComputable && total > 0 ? loaded / total : 0;
                options.onUploadProgress({
                    loaded,
                    total,
                    lengthComputable: !!event.lengthComputable,
                    progress,
                });
            });
            xhr.upload.addEventListener("load", () => {
                if (typeof options.onUploadProcessing === "function") {
                    options.onUploadProcessing();
                }
            });
        }

        xhr.onerror = () => {
            reject(new Error("Falha de conexão ao enviar arquivos. Verifique a internet e tente novamente."));
        };

        xhr.onload = () => {
            if (xhr.status === 401) {
                clearSession();
                showAuth("Sua sessao expirou. Entre novamente.");
                reject(new Error("Unauthorized"));
                return;
            }

            let data = null;
            try {
                data = xhr.responseText ? JSON.parse(xhr.responseText) : null;
            } catch {
                data = null;
            }

            if (xhr.status < 200 || xhr.status >= 300) {
                const error = new Error(getApiErrorMessage(data || {}, xhr.statusText || "Erro inesperado"));
                error.apiData = data || {};
                error.status = xhr.status;
                reject(error);
                return;
            }

            resolve(data);
        };

        xhr.send(formData);
    });
}

function setSession(accessToken, user) {
    token = accessToken;
    currentUser = user;
    _currentCreditPlan = "free";
    _currentCreditPlanExpiresAt = "";
    localStorage.setItem(APP_TOKEN_KEY, accessToken);
    _resetTevoxiRuntimeState();
    renderSession();
}

function clearSession() {
    token = "";
    currentUser = null;
    _currentCreditPlan = "free";
    _currentCreditPlanExpiresAt = "";
    _lastTrackedPage = "";
    localStorage.removeItem(APP_TOKEN_KEY);
    _closeProfileAdminPanel(true);
    _resetTevoxiRuntimeState();
}

function clearLevitaSession() {
    localStorage.removeItem(LEVITA_TOKEN_KEY);
    _resetTevoxiRuntimeState();
}

function _isProfileAdminUser() {
    if (!currentUser) return false;
    const role = String(currentUser.role || "").trim().toLowerCase();
    const email = String(currentUser.email || "").trim().toLowerCase();
    return role === "admin" || email === ADMIN_PANEL_EMAIL;
}

function _openProfileAdminPanel() {
    if (!_isProfileAdminUser()) {
        showToast("Acesso restrito ao perfil administrativo.", "error");
        return;
    }
    const host = document.getElementById("profile-admin-host");
    const iframe = document.getElementById("profile-admin-iframe");
    if (!host || !iframe) return;
    host.hidden = false;
    if (!_profileAdminIframeLoaded) {
        const src = iframe.dataset.src || "/video/static/admin-panel.html";
        iframe.src = src;
        _profileAdminIframeLoaded = true;
    }
}

function _closeProfileAdminPanel(forceReset = false) {
    const host = document.getElementById("profile-admin-host");
    const iframe = document.getElementById("profile-admin-iframe");
    if (host) host.hidden = true;
    if (forceReset && iframe) {
        iframe.src = "about:blank";
        _profileAdminIframeLoaded = false;
    }
}

function _syncProfileAdminControls() {
    const openBtn = document.getElementById("btn-profile-admin-open");
    if (!openBtn) return;
    const allowed = _isProfileAdminUser();
    openBtn.hidden = !allowed;
    if (!allowed) {
        _closeProfileAdminPanel(true);
    }
}

function _trackPageView(pageName) {
    const page = String(pageName || "").trim().toLowerCase();
    if (!page || !token || !currentUser) return;
    if (_lastTrackedPage === page) return;
    _lastTrackedPage = page;
    api("/admin/track-view", {
        method: "POST",
        body: JSON.stringify({ page }),
    }).catch(() => {});
}

function _normalizeSessionPlanCode(planCode = "") {
    const normalized = String(planCode || "free").trim().toLowerCase() || "free";
    const resolved = normalized === "pro" ? "professional" : normalized;
    return SESSION_PLAN_LABELS[resolved] ? resolved : "free";
}

function _getSessionPlanPresentation() {
    const planCode = _normalizeSessionPlanCode(currentUser?.plan || _currentCreditPlan || "free");
    const label = SESSION_PLAN_LABELS[planCode] || SESSION_PLAN_LABELS.free;
    const expiresText = planCode !== "free" && _currentCreditPlanExpiresAt
        ? ` até ${new Date(_currentCreditPlanExpiresAt).toLocaleDateString("pt-BR")}`
        : "";
    return {
        code: planCode,
        label,
        title: `${label}${expiresText}`,
    };
}

function renderSession() {
    if (!currentUser) {
        return;
    }
    const sessionName = document.getElementById("session-name");
    const sessionMeta = document.getElementById("session-meta");
    const sidebarProfileTrigger = document.getElementById("sidebar-profile-trigger");
    const sessionPlan = _getSessionPlanPresentation();
    if (sessionName) {
        sessionName.textContent = currentUser.name || "Cliente";
    }
    if (sessionMeta) {
        sessionMeta.textContent = sessionPlan.label;
        sessionMeta.className = `user-role plan-${sessionPlan.code}`;
        sessionMeta.title = sessionPlan.title;
    }
    if (sidebarProfileTrigger) {
        sidebarProfileTrigger.dataset.plan = sessionPlan.code;
        sidebarProfileTrigger.title = `${sessionPlan.title} · Abrir perfil`;
    }
    // Profile page
    const profileName = document.getElementById("profile-name");
    const profileEmail = document.getElementById("profile-email");
    const profileBadge = document.getElementById("profile-role-badge");
    if (profileName) profileName.textContent = currentUser.name || "Usuário";
    if (profileEmail) profileEmail.textContent = currentUser.email || "-";
    if (profileBadge) {
        const src = currentUser.source === "google" ? "Google" : "CriaVideo";
        profileBadge.textContent = _isProfileAdminUser() ? "Admin" : src;
    }
    _syncProfileAdminControls();
}

function showAuth(message = "") {
    document.getElementById("auth-shell").hidden = false;
    document.getElementById("app-shell").hidden = true;
    setAuthStatus(message);
}

function showApp() {
    document.getElementById("auth-shell").hidden = true;
    document.getElementById("app-shell").hidden = false;
    _syncDesktopSidebarForViewport();
    renderSession();
}

function _isDesktopSidebarMode() {
    return window.innerWidth > 768;
}

function _openDesktopSidebar() {
    const appShell = document.getElementById("app");
    if (!appShell || !_isDesktopSidebarMode()) {
        return;
    }
    appShell.classList.add("sidebar-collapsed", "sidebar-open");
}

function _collapseDesktopSidebar() {
    const appShell = document.getElementById("app");
    if (!appShell || !_isDesktopSidebarMode()) {
        return;
    }
    appShell.classList.add("sidebar-collapsed");
    appShell.classList.remove("sidebar-open");
}

function _syncDesktopSidebarForViewport() {
    const appShell = document.getElementById("app");
    if (!appShell) {
        return;
    }
    if (_isDesktopSidebarMode()) {
        appShell.classList.add("sidebar-collapsed");
        appShell.classList.remove("sidebar-open");
        return;
    }
    appShell.classList.remove("sidebar-open");
}

function setAuthStatus(message = "") {
    const status = document.getElementById("auth-status");
    if (!message) {
        status.hidden = true;
        status.textContent = "";
        return;
    }
    status.hidden = false;
    status.textContent = message;
}

function setAuthMode(mode) {
    authMode = mode;
    const isLogin = mode === "login";
    document.getElementById("login-form").hidden = !isLogin;
    document.getElementById("register-form").hidden = isLogin;
    document.getElementById("auth-title").textContent = isLogin ? "Entrar" : "Criar conta";
    const subtitle = document.getElementById("auth-subtitle");
    if (subtitle) subtitle.textContent = isLogin
        ? "Acesse seus projetos e publique em múltiplos canais."
        : "Crie sua conta para gerenciar seus vídeos diretamente no CriaVideo.";
    document.getElementById("auth-switch-copy").textContent = isLogin ? "Não tem conta?" : "Já tem conta?";
    document.getElementById("auth-switch-button").textContent = isLogin ? "Criar conta" : "Entrar";
    setAuthStatus("");
}

function cleanUrlTokenParam() {
    const url = new URL(window.location.href);
    url.searchParams.delete("token");
    window.history.replaceState({}, "", url.pathname + url.search + url.hash);
}

async function loadProviders() {
    try {
        providers = await fetch("/api/auth/providers").then((response) => response.json());
    } catch (_) {
        providers = { ...providers };
    }
    const hasGoogleProvider = !!(providers.google_enabled && providers.google_client_id);
    const authDivider = document.querySelector(".auth-divider");
    const providerStack = document.querySelector(".provider-stack");
    if (authDivider) authDivider.hidden = !hasGoogleProvider;
    if (providerStack) providerStack.hidden = !hasGoogleProvider;
    initGoogleLogin();
}

function initGoogleLogin(remainingAttempts = 20) {
    if (!providers.google_enabled || !providers.google_client_id) {
        return;
    }
    if (window.google?.accounts?.id) {
        document.getElementById("google-login").hidden = false;
        window.google.accounts.id.initialize({
            client_id: providers.google_client_id,
            callback: handleGoogleCredential,
        });
        window.google.accounts.id.renderButton(
            document.getElementById("google-login-button"),
            { type: "standard", theme: "outline", size: "large", text: "signin_with", shape: "pill", width: 300 },
        );
        return;
    }
    if (remainingAttempts > 0) {
        window.setTimeout(() => initGoogleLogin(remainingAttempts - 1), 300);
    }
}

async function handleGoogleCredential(response) {
    try {
        const data = await fetch("/api/auth/google", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ credential: response.credential }),
        }).then(async (resp) => {
            if (!resp.ok) {
                const err = await resp.json().catch(() => ({}));
                throw new Error(getApiErrorMessage(err, "Falha ao entrar com Google"));
            }
            return resp.json();
        });
        clearLevitaSession();
        setSession(data.access_token, data.user);
        cleanUrlTokenParam();
        showApp();
        initDashboard();
    } catch (error) {
        showAuth(error.message);
    }
}

async function hydrateSession() {
    if (!token) {
        return false;
    }
    try {
        const data = await api("/auth/me");
        currentUser = data.user;
        renderSession();
        return true;
    } catch (_) {
        return false;
    }
}

function bindAuthEvents() {
    document.getElementById("auth-switch-button").addEventListener("click", () => {
        setAuthMode(authMode === "login" ? "register" : "login");
    });
    document.getElementById("login-form").addEventListener("submit", async (event) => {
        event.preventDefault();
        setAuthStatus("");
        const email = document.getElementById("login-email").value;
        const password = document.getElementById("login-password").value;
        try {
            const data = await fetch("/api/auth/login", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ email, password }),
            }).then(async (resp) => {
                const body = await resp.json().catch(() => ({}));
                if (!resp.ok) {
                    throw new Error(getApiErrorMessage(body, "Falha ao entrar"));
                }
                return body;
            });
            clearLevitaSession();

            setSession(data.access_token, data.user);
            showApp();
            initDashboard();
        } catch (error) {
            setAuthStatus(error.message);
        }
    });
    document.getElementById("register-form").addEventListener("submit", async (event) => {
        event.preventDefault();
        setAuthStatus("");
        try {
            const data = await fetch("/api/auth/register", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    name: document.getElementById("register-name").value,
                    email: document.getElementById("register-email").value,
                    password: document.getElementById("register-password").value,
                }),
            }).then(async (resp) => {
                const body = await resp.json().catch(() => ({}));
                if (!resp.ok) {
                    throw new Error(getApiErrorMessage(body, "Falha ao criar conta"));
                }
                return body;
            });
            clearLevitaSession();
            setSession(data.access_token, data.user);
            showApp();
            initDashboard();
        } catch (error) {
            setAuthStatus(error.message);
        }
    });
    document.getElementById("btn-logout").addEventListener("click", () => {
        clearSession();
        clearLevitaSession();
        showAuth("Sessao encerrada.");
    });
}

function navigateTo(pageName) {
    const normalizedPage = (pageName === "accounts") ? "publish" : pageName;
    document.querySelectorAll(".page").forEach((p) => p.classList.remove("active"));
    const target = document.getElementById("page-" + normalizedPage);
    if (target) target.classList.add("active");
    // Update sidebar active
    document.querySelectorAll(".sidebar-nav .nav-item").forEach((item) => {
        item.classList.toggle("active", item.dataset.page === normalizedPage);
    });
    // Update mobile tabs active
    document.querySelectorAll(".mobile-nav-tab").forEach((tab) => {
        tab.classList.toggle("active", tab.dataset.mobilePage === normalizedPage);
    });
    if (normalizedPage !== "editor") {
        closeModal("modal-editor-drafts");
        _editorCloseSubtitleTextModal();
    }
    _collapseDesktopSidebar();
    loadPageData(pageName);
    _trackPageView(normalizedPage);
}

function bindNavigation() {
    const appShell = document.getElementById("app");
    const sidebar = document.getElementById("sidebar");
    const sidebarToggle = document.getElementById("sidebar-toggle");

    // Sidebar nav items
    document.querySelectorAll(".sidebar-nav .nav-item").forEach((link) => {
        link.addEventListener("click", (event) => {
            event.preventDefault();
            navigateTo(link.dataset.page);
        });
    });
    // Logo click toggles sidebar
    const logo = document.querySelector(".sidebar-header .logo");
    if (logo) {
        logo.addEventListener("click", () => {
            if (!_isDesktopSidebarMode()) {
                return;
            }
            appShell?.classList.toggle("sidebar-open");
        });
    }
    // Toggle button reopens sidebar
    if (sidebarToggle) {
        sidebarToggle.addEventListener("click", () => {
            _openDesktopSidebar();
        });
    }
    if (sidebar) {
        sidebar.addEventListener("mouseenter", () => {
            _openDesktopSidebar();
        });
        sidebar.addEventListener("mouseleave", () => {
            _collapseDesktopSidebar();
        });
        sidebar.addEventListener("focusin", () => {
            _openDesktopSidebar();
        });
    }
    document.addEventListener("click", (event) => {
        if (!_isDesktopSidebarMode() || !sidebar) {
            return;
        }
        if (sidebar.contains(event.target) || sidebarToggle?.contains(event.target)) {
            return;
        }
        _collapseDesktopSidebar();
    });
    window.addEventListener("resize", _syncDesktopSidebarForViewport);
    _syncDesktopSidebarForViewport();
    // Mobile bottom tabs
    document.querySelectorAll(".mobile-nav-tab").forEach((tab) => {
        tab.addEventListener("click", () => {
            navigateTo(tab.dataset.mobilePage);
        });
    });
    // Profile logout button
    const profileLogout = document.getElementById("btn-profile-logout");
    if (profileLogout) {
        profileLogout.addEventListener("click", () => {
            clearSession();
            clearLevitaSession();
            showAuth("Sessao encerrada.");
        });
    }
    const sidebarProfileTrigger = document.getElementById("sidebar-profile-trigger");
    if (sidebarProfileTrigger) {
        sidebarProfileTrigger.addEventListener("click", (event) => {
            if (event.target?.closest("#btn-logout")) {
                return;
            }
            navigateTo("profile");
            if (_isProfileAdminUser()) {
                _openProfileAdminPanel();
            }
        });
        sidebarProfileTrigger.addEventListener("keydown", (event) => {
            if (event.key !== "Enter" && event.key !== " ") {
                return;
            }
            event.preventDefault();
            navigateTo("profile");
            if (_isProfileAdminUser()) {
                _openProfileAdminPanel();
            }
        });
    }
    const profileAdminOpen = document.getElementById("btn-profile-admin-open");
    if (profileAdminOpen) {
        profileAdminOpen.addEventListener("click", () => {
            _openProfileAdminPanel();
        });
    }
    const profileAdminClose = document.getElementById("btn-profile-admin-close");
    if (profileAdminClose) {
        profileAdminClose.addEventListener("click", () => {
            _closeProfileAdminPanel(false);
        });
    }
    // Mobile profile avatar
    const mobileProfileBtn = document.getElementById("mobile-profile-btn");
    if (mobileProfileBtn) {
        mobileProfileBtn.addEventListener("click", () => {
            navigateTo("profile");
        });
    }
}

function ensurePublishDraftSelector() {
    const formArea = document.getElementById("publish-form-area");
    const renderSelect = document.getElementById("pub-render-select");
    if (!formArea || !renderSelect) {
        return;
    }

    if (document.getElementById("pub-draft-select")) {
        return;
    }

    const renderGroup = renderSelect.closest(".form-group");
    if (!renderGroup || !renderGroup.parentNode) {
        return;
    }

    let row = renderGroup.closest(".publish-select-row");
    if (!row) {
        row = document.createElement("div");
        row.className = "publish-select-row";
        renderGroup.parentNode.insertBefore(row, renderGroup);
        row.appendChild(renderGroup);
    }

    const draftGroup = document.createElement("div");
    draftGroup.className = "form-group publish-form-group";
    draftGroup.innerHTML = "<select id=\"pub-draft-select\" class=\"input\" aria-label=\"Selecionar rascunho salvo\"><option value=\"\">Meus rascunhos...</option></select>";
    row.appendChild(draftGroup);
}

function bindDashboardEvents() {
    ensurePublishDraftSelector();

    document.getElementById("btn-new-project").addEventListener("click", () => {
        resetCreateWizard();
        openModal("modal-new-project");
    });
    document.getElementById("btn-publish").addEventListener("click", submitPublishNow);
    document.getElementById("btn-save-draft").addEventListener("click", savePublishDraft);
    document.getElementById("btn-schedule-publish").addEventListener("click", openPublishScheduleModal);
    const publishProgressDismissBtn = document.getElementById("btn-publish-progress-dismiss");
    if (publishProgressDismissBtn) {
        publishProgressDismissBtn.addEventListener("click", dismissPublishProgressPanel);
    }
    document.getElementById("pub-links-toggle").addEventListener("click", togglePublishLinks);
    document.getElementById("btn-save-links").addEventListener("click", savePublishLinksForAccount);
    const renderPickerBtn = document.getElementById("pub-render-picker-btn");
    if (renderPickerBtn) {
        renderPickerBtn.addEventListener("click", () => {
            _publishOpenRenderSourceModal();
        });
    }
    const publishHeaderBtn = document.getElementById("btn-open-publish-source");
    if (publishHeaderBtn) {
        publishHeaderBtn.addEventListener("click", () => {
            _publishOpenRenderSourceModal();
        });
    }
    const renderSelect = document.getElementById("pub-render-select");
    if (renderSelect) {
        renderSelect.addEventListener("change", (e) => {
            const renderId = parseInt(e.target.value || "", 10);
            _publishSyncRenderPicker();
            if (renderId) {
                onRenderSelected(renderId);
                return;
            }

            _clearPublishMetadataFields();
            _publishLastThumbnailPrompt = "";
            clearPublishThumbnail();
            clearPublishThumbReference();
            _resetPublishAnalysisState({ keepRenderId: false });
        });
    }
    const draftSelect = document.getElementById("pub-draft-select");
    if (draftSelect) {
        draftSelect.addEventListener("change", async (event) => {
            const renderId = parseInt(event.target.value || "", 10);
            if (!renderId) {
                return;
            }
            await openPublishDraftFromList(renderId);
        });
    }
    const publishAnalyzeBtn = document.getElementById("btn-publish-analyze");
    if (publishAnalyzeBtn) {
        publishAnalyzeBtn.addEventListener("click", () => {
            publishStartAnalysis();
        });
    }
    const publishGenerateBtn = document.getElementById("btn-generate-publish-ai");
    if (publishGenerateBtn) {
        publishGenerateBtn.addEventListener("click", () => {
            generatePublishTitleDescription();
        });
    }
    const publishDetailsBtn = document.getElementById("btn-publish-analysis-details");
    if (publishDetailsBtn) {
        publishDetailsBtn.addEventListener("click", () => {
            togglePublishAnalysisDetails();
        });
    }
    const publishPreviewVideo = document.getElementById("pub-render-preview");
    if (publishPreviewVideo) {
        publishPreviewVideo.addEventListener("loadedmetadata", () => {
            schedulePublishAnalysisCreditEstimate();
        });
    }
    document.getElementById("btn-regenerate-thumb").addEventListener("click", () => {
        const renderId = document.getElementById("pub-render-select").value;
        if (renderId) {
            const currentTitle = document.getElementById("pub-title").value;
            const currentDescription = document.getElementById("pub-description").value;
            generatePublishThumbnail(
                parseInt(renderId, 10),
                currentTitle,
                currentDescription,
                _publishLastThumbnailPrompt,
            );
        }
    });
    const thumbRefBtn = document.getElementById("btn-upload-thumb-reference");
    const thumbRefInput = document.getElementById("pub-thumb-reference-input");
    const thumbRefRemoveBtn = document.getElementById("btn-remove-thumb-reference");
    if (thumbRefBtn && thumbRefInput) {
        thumbRefBtn.addEventListener("click", () => thumbRefInput.click());
    }
    if (thumbRefInput) {
        thumbRefInput.addEventListener("change", handlePublishThumbReferenceSelect);
    }
    if (thumbRefRemoveBtn) {
        thumbRefRemoveBtn.addEventListener("click", removePublishThumbReference);
    }
    document.getElementById("btn-new-schedule").addEventListener("click", async () => {
        await loadAccountsForSelect();
        openModal("modal-new-schedule");
    });
    document.getElementById("btn-new-automation").addEventListener("click", () => {
        openNewAutomationModal();
    });
    const autoPilotBtn = document.getElementById("btn-auto-pilot");
    if (autoPilotBtn) {
        autoPilotBtn.addEventListener("click", () => {
            openAutoPilotModal();
        });
    }
    document.querySelectorAll(".publish-top-tab").forEach((tabBtn) => {
        tabBtn.addEventListener("click", () => {
            setPublishTab(tabBtn.dataset.publishTab || "publish");
        });
    });
    const analyzeAccountSelect = document.getElementById("analyze-account-select");
    if (analyzeAccountSelect) {
        analyzeAccountSelect.addEventListener("change", () => {
            const selectedId = parseInt(analyzeAccountSelect.value || "0", 10) || 0;
            _analyzeSelectAccount(selectedId, false);
        });
    }
    const analyzeRunBtn = document.getElementById("btn-run-analysis");
    if (analyzeRunBtn) {
        analyzeRunBtn.addEventListener("click", () => {
            runAnalyzeChannel();
        });
    }
    const analyzeAddAccountBtn = document.getElementById("btn-add-analyze-account");
    if (analyzeAddAccountBtn) {
        analyzeAddAccountBtn.addEventListener("click", () => {
            connectPlatform("youtube");
        });
    }
    const analyzeHistoryBtn = document.getElementById("btn-analyze-history");
    if (analyzeHistoryBtn) {
        analyzeHistoryBtn.addEventListener("click", () => {
            openAnalyzeHistoryModal();
        });
    }
    const analyzeHistoryFilter = document.getElementById("analyze-history-account-filter");
    if (analyzeHistoryFilter) {
        analyzeHistoryFilter.addEventListener("change", () => {
            _analyzeState.historyFilterAccountId = Math.max(0, parseInt(analyzeHistoryFilter.value || "0", 10) || 0);
            loadAnalyzeHistoryList(true);
        });
    }
    document.addEventListener("keydown", (event) => {
        if (event.key !== "Escape") {
            return;
        }
        if (_publishRenderLibrary.open) {
            _publishCloseRenderLibrary();
            return;
        }
        const sourceModal = document.getElementById("modal-publish-render-source");
        if (sourceModal?.classList.contains("open")) {
            closeModal("modal-publish-render-source");
        }
    });
    _publishSyncRenderPicker();
    const analyzeHistoryRefreshBtn = document.getElementById("analyze-history-refresh-btn");
    if (analyzeHistoryRefreshBtn) {
        analyzeHistoryRefreshBtn.addEventListener("click", () => {
            loadAnalyzeHistoryList(true);
        });
    }
    document.querySelectorAll(".publish-platform-chip input").forEach((checkbox) => {
        checkbox.addEventListener("change", () => {
            renderPublishAccountSelectors();
        });
    });
    const schedulePlatformSelect = document.getElementById("ns-platform");
    if (schedulePlatformSelect) {
        schedulePlatformSelect.addEventListener("change", () => {
            refreshScheduleAccountOptions();
        });
    }
    document.addEventListener("change", (event) => {
        if (event.target.id !== "np-song-select") {
            return;
        }
        const value = event.target.value;
        const manualFields = document.getElementById("np-manual-fields");
        const details = document.getElementById("np-song-details");
        if (value === "manual") {
            manualFields.hidden = false;
            details.hidden = true;
            return;
        }
        const selectedSong = levitaSongs[parseInt(value, 10)];
        if (value !== "" && selectedSong) {
            manualFields.hidden = true;
            details.hidden = false;
            details.innerHTML = `
                <p><strong>${esc(selectedSong.title || "Sem título")}</strong></p>
                ${selectedSong.artist ? `<p>${esc(selectedSong.artist)}</p>` : ""}
                ${selectedSong.duration ? `<p>${Math.round(selectedSong.duration)}s</p>` : ""}
                ${selectedSong.lyrics ? `<p>${esc(selectedSong.lyrics).slice(0, 280)}...</p>` : ""}
            `;
            return;
        }
        manualFields.hidden = true;
        details.hidden = true;
    });

    // ── Creation Wizard Event Bindings ──
    initCreateWizard();
}

async function bootstrap() {
    setAuthMode("login");
    bindAuthEvents();
    bindNavigation();
    bindDashboardEvents();
    initSeriesWorkspace();
    await loadProviders();
    if (new URLSearchParams(window.location.search).has("token")) {
        cleanUrlTokenParam();
    }
    const authenticated = await hydrateSession();
    if (!authenticated) {
        showAuth();
        return;
    }
    showApp();
    initDashboard();
}

function handleSocialCallbackResult() {
    const params = new URLSearchParams(window.location.search);
    const connected = String(params.get("social_connected") || "").toLowerCase();
    const socialError = String(params.get("social_error") || "").toLowerCase();
    const socialReason = (params.get("social_reason") || "").trim();
    if (!connected && !socialError) return;

    const cleanUrl = `${window.location.pathname}${window.location.hash || ""}`;
    window.history.replaceState({}, "", cleanUrl);

    if (connected) {
        alert(`${socialPlatformName(connected)} conectada com sucesso.`);
        navigateTo("accounts");
        return;
    }

    const platformName = socialPlatformName(socialError || "social");
    const reasonText = socialReason ? `\n\nDetalhes: ${socialReason}` : "";
    alert(`Não foi possível conectar ${platformName}.${reasonText}`);
    navigateTo("accounts");
}

function initDashboard() {
    renderSession();
    updateCreditsDisplay();
    const renameInput = document.getElementById("edit-project-title");
    if (renameInput) {
        renameInput.addEventListener("keydown", (event) => {
            if (event.key === "Enter") {
                event.preventDefault();
                saveProjectEdit();
            }
        });
    }
    const connectLabelInput = document.getElementById("connect-account-label");
    if (connectLabelInput) {
        connectLabelInput.addEventListener("keydown", (event) => {
            if (event.key === "Enter") {
                event.preventDefault();
                confirmConnectPlatform();
            }
        });
    }
    const editAccountInput = document.getElementById("edit-account-label");
    if (editAccountInput) {
        editAccountInput.addEventListener("keydown", (event) => {
            if (event.key === "Enter") {
                event.preventDefault();
                saveSocialAccountLabel();
            }
        });
    }
    const publishScheduleInput = document.getElementById("pub-schedule-datetime");
    if (publishScheduleInput) {
        publishScheduleInput.addEventListener("keydown", (event) => {
            if (event.key === "Enter") {
                event.preventDefault();
                confirmSchedulePublish();
            }
        });
    }

    handleSocialCallbackResult();
    _refreshPersonaContext("wizard", "natureza");
    _refreshPersonaContext("script", "natureza");
    _refreshPersonaContext("ai", "natureza");
    _refreshPersonaContext("auto", "natureza");

    const hashValue = String(window.location.hash || "").toLowerCase();
    if (hashValue.includes("/social")) {
        navigateTo("accounts");
        return;
    }

    const params = new URLSearchParams(window.location.search);
    const audioUrl = params.get("audio_url");
    if (audioUrl) {
        const requestedAspect =
            params.get("aspect") ||
            params.get("aspect_ratio") ||
            params.get("video_format") ||
            params.get("format") ||
            "16:9";
        const aspectRatio = ["16:9", "9:16", "1:1"].includes(requestedAspect)
            ? requestedAspect
            : "16:9";
        window.history.replaceState({}, "", window.location.pathname);
        quickCreate({
            song_title: params.get("song_title") || "",
            song_artist: params.get("song_artist") || "",
            audio_url: audioUrl,
            lyrics: params.get("lyrics") || "",
            duration: parseFloat(params.get("duration")) || 180,
            aspect_ratio: aspectRatio,
        });
        _trackPageView("projects");
        return;
    }
    loadProjects();
    _trackPageView("projects");
}

function loadPageData(page) {
    if (page === "projects") {
        loadProjects();
        _closeProfileAdminPanel(false);
    } else if (page === "series-workspace") {
        void loadSeriesWorkspacePage();
        _closeProfileAdminPanel(false);
    } else if (page === "publish" || page === "accounts") {
        setPublishTab(page === "publish" ? "publish" : page);
        _closeProfileAdminPanel(false);
    } else if (page === "analyze") {
        loadAnalyzePage();
        _closeProfileAdminPanel(false);
    } else if (page === "automate") {
        loadAutoSchedules();
        _closeProfileAdminPanel(false);
    } else if (page === "editor") {
        _editorHandleEditorPageEntry();
        _closeProfileAdminPanel(false);
    } else if (page === "profile") {
        if (_isProfileAdminUser()) {
            _openProfileAdminPanel();
        } else {
            _closeProfileAdminPanel(false);
        }
    }
}

function setPublishTab(tabName) {
    const nextTab = ["publish", "accounts"].includes(tabName) ? tabName : "publish";
    document.querySelectorAll(".publish-top-tab").forEach((btn) => {
        btn.classList.toggle("active", btn.dataset.publishTab === nextTab);
    });
    document.querySelectorAll(".publish-tab-content").forEach((panel) => {
        panel.classList.toggle("active", panel.id === `publish-tab-${nextTab}`);
    });

    if (nextTab === "publish") {
        const preselectProjectId = _pendingPublishProjectId;
        _pendingPublishProjectId = 0;
        renderPublishDraftList();
        renderPublishAccountSelectors(true);
        loadRenders(preselectProjectId).then((preselected) => {
            if (preselected) {
                const renderId = document.getElementById("pub-render-select").value;
                if (renderId) {
                    onRenderSelected(parseInt(renderId, 10));
                }
            }
        });
        loadPublishJobs();
        loadSchedules();
    } else if (nextTab === "accounts") {
        loadAccounts();
    }
}

function _seriesKindLabel(kind) {
    const normalized = String(kind || "").trim().toLowerCase();
    if (normalized === "film") return "Filme";
    if (normalized === "drama") return "Drama";
    return "Série";
}

function _seriesNormalizeTab(tab) {
    const normalized = String(tab || "").trim().toLowerCase();
    if (normalized === "tela") return "projeto";
    if (["projeto", "roteiro", "personagens", "storyboard", "timeline"].includes(normalized)) {
        return normalized;
    }
    return "projeto";
}

function _seriesDefaultCreatePayload(kind) {
    const normalized = String(kind || "series").trim().toLowerCase();
    if (normalized === "film") {
        return {
            kind: "film",
            title: "Novo filme",
            description: "",
            aspect_ratio: "16:9",
            language: "pt-BR",
            target_duration_seconds: 1800,
            episode_count: 1,
            default_settings: { mode: "long_form", pacing: "cinematic" },
            workspace_state: { active_tab: "projeto" },
        };
    }
    if (normalized === "drama") {
        return {
            kind: "drama",
            title: "Novo drama",
            description: "",
            aspect_ratio: "16:9",
            language: "pt-BR",
            target_duration_seconds: 1200,
            episode_count: 8,
            default_settings: { mode: "dramatic", pacing: "episodic" },
            workspace_state: { active_tab: "projeto" },
        };
    }
    return {
        kind: "series",
        title: "Nova série",
        description: "",
        aspect_ratio: "16:9",
        language: "pt-BR",
        target_duration_seconds: 900,
        episode_count: 5,
        default_settings: { mode: "episodic", pacing: "continuous" },
        workspace_state: { active_tab: "projeto" },
    };
}

function _seriesClearPersistTimer() {
    if (_seriesWorkspaceState.persistTimer) {
        clearTimeout(_seriesWorkspaceState.persistTimer);
        _seriesWorkspaceState.persistTimer = null;
    }
}

function _seriesClearPlanningStatusTimer() {
    if (_seriesWorkspaceState.planningStatusTimer) {
        clearInterval(_seriesWorkspaceState.planningStatusTimer);
        _seriesWorkspaceState.planningStatusTimer = null;
    }
}

function _seriesResetWorkspaceState() {
    _seriesClearPersistTimer();
    _seriesClearPlanningStatusTimer();
    _seriesWorkspaceState.creating = false;
    _seriesWorkspaceState.loading = false;
    _seriesWorkspaceState.planning = false;
    _seriesWorkspaceState.planningStatusLabel = "";
    _seriesWorkspaceState.pendingUserMessage = "";
    _seriesWorkspaceState.activeSeriesId = 0;
    _seriesWorkspaceState.activeTab = "projeto";
    _seriesWorkspaceState.series = null;
    _seriesWorkspaceState.episodes = [];
    _seriesWorkspaceState.threads = [];
    _seriesWorkspaceState.activeThreadId = 0;
    _seriesWorkspaceState.messages = [];
}

function _seriesGetActiveThread() {
    return _seriesWorkspaceState.threads.find((thread) => Number(thread.id || 0) === Number(_seriesWorkspaceState.activeThreadId || 0)) || null;
}

function _seriesGetWorkspaceState() {
    if (!_seriesWorkspaceState.series) {
        return { active_tab: _seriesWorkspaceState.activeTab };
    }
    const current = _seriesWorkspaceState.series.workspace_state;
    if (!current || typeof current !== "object" || Array.isArray(current)) {
        _seriesWorkspaceState.series.workspace_state = { active_tab: _seriesWorkspaceState.activeTab };
    }
    return _seriesWorkspaceState.series.workspace_state;
}

function _seriesUpdateWorkspaceState(patch = {}) {
    if (!_seriesWorkspaceState.series) {
        return;
    }
    const current = _seriesGetWorkspaceState();
    const nextState = {
        ...current,
        ...patch,
    };
    _seriesWorkspaceState.series = {
        ..._seriesWorkspaceState.series,
        workspace_state: nextState,
    };
    _seriesWorkspaceState.activeTab = _seriesNormalizeTab(nextState.active_tab || _seriesWorkspaceState.activeTab);
}

function _seriesGetProjectPlan() {
    const projectPlan = _seriesGetWorkspaceState().project_plan;
    return {
        overview: String(projectPlan?.overview || _seriesWorkspaceState.series?.description || "").trim(),
        storyTreatment: String(projectPlan?.story_treatment || projectPlan?.overview || _seriesWorkspaceState.series?.description || "").trim(),
        requirements: Array.isArray(projectPlan?.requirements)
            ? projectPlan.requirements.map((item) => String(item || "").trim()).filter(Boolean)
            : [],
        lastGeneratedBrief: String(projectPlan?.last_generated_brief || "").trim(),
    };
}

function _seriesGetCharacters() {
    const characters = _seriesGetWorkspaceState().characters;
    return Array.isArray(characters) ? characters : [];
}

function _seriesGetStoryboardBank() {
    const storyboard = _seriesGetWorkspaceState().storyboard;
    const safeStoryboard = storyboard && typeof storyboard === "object" && !Array.isArray(storyboard) ? storyboard : {};
    return {
        scenes: Array.isArray(safeStoryboard.scenes) ? safeStoryboard.scenes : [],
        objects: Array.isArray(safeStoryboard.objects) ? safeStoryboard.objects : [],
    };
}

function _seriesFindPersonaProfile(profileId, personaType = "") {
    const pid = parseInt(profileId || "0", 10) || 0;
    if (!pid) return null;
    const direct = _getPersonaProfileById(pid, personaType || "personalizado");
    if (direct) return direct;
    for (const type of REALISTIC_PERSONA_TYPES) {
        const match = _getPersonaProfileById(pid, type);
        if (match) return match;
    }
    return null;
}

function _seriesMakeWorkspaceItemId(prefix) {
    return `${prefix}-${Date.now()}-${Math.random().toString(16).slice(2, 8)}`;
}

function _seriesFormatLongDuration(seconds) {
    const total = Math.max(0, parseInt(seconds || "0", 10) || 0);
    if (!total) return "--";
    const hours = Math.floor(total / 3600);
    const minutes = Math.floor((total % 3600) / 60);
    const secs = total % 60;
    if (hours > 0) {
        return `${hours}h ${String(minutes).padStart(2, "0")}m`;
    }
    if (minutes > 0) {
        return secs > 0 ? `${minutes}m ${String(secs).padStart(2, "0")}s` : `${minutes}m`;
    }
    return `${secs}s`;
}

function _seriesGetEpisodeDuration(episode) {
    return parseInt(episode?.timeline_data?.duration_seconds || "0", 10) || 0;
}

function _seriesCountEpisodeScenes() {
    return (_seriesWorkspaceState.episodes || []).reduce((total, episode) => {
        const scenes = Array.isArray(episode?.storyboard) ? episode.storyboard : [];
        return total + scenes.length;
    }, 0);
}

function _seriesRenderTextParagraphs(text, emptyCopy) {
    const trimmed = String(text || "").trim();
    if (!trimmed) {
        return `<p>${esc(emptyCopy)}</p>`;
    }
    return trimmed
        .split(/\n+/)
        .map((paragraph) => paragraph.trim())
        .filter(Boolean)
        .map((paragraph) => `<p>${esc(paragraph)}</p>`)
        .join("");
}

function _seriesStartPlanningFeedback() {
    _seriesClearPlanningStatusTimer();
    let currentIndex = 0;
    _seriesWorkspaceState.planningStatusLabel = SERIES_PLANNING_STATUS_STEPS[currentIndex];
    _seriesWorkspaceState.planningStatusTimer = setInterval(() => {
        if (!_seriesWorkspaceState.planning) {
            _seriesClearPlanningStatusTimer();
            return;
        }
        currentIndex = (currentIndex + 1) % SERIES_PLANNING_STATUS_STEPS.length;
        _seriesWorkspaceState.planningStatusLabel = SERIES_PLANNING_STATUS_STEPS[currentIndex];
        _seriesRenderChat();
    }, 1700);
}

function _seriesStopPlanningFeedback() {
    _seriesClearPlanningStatusTimer();
    _seriesWorkspaceState.planningStatusLabel = "";
    _seriesWorkspaceState.pendingUserMessage = "";
}

function _seriesBuildWelcomeMessage() {
    const kindLabel = _seriesKindLabel(_seriesWorkspaceState.series?.kind);
    return `Workspace de ${kindLabel.toLowerCase()} pronto. Descreva no chat o que voce quer criar e eu organizo automaticamente Projeto, Roteiro, Personagens, Storyboard e Linha do tempo dentro deste workspace.`;
}

function _seriesTabLabel(tab) {
    if (tab === "projeto") return "Projeto";
    if (tab === "roteiro") return "Roteiro";
    if (tab === "personagens") return "Personagens";
    if (tab === "storyboard") return "Storyboard";
    if (tab === "timeline") return "Linha do tempo";
    return "Projeto";
}

async function _seriesPersistWorkspaceState(options = {}) {
    if (!_seriesWorkspaceState.series || !_seriesWorkspaceState.activeSeriesId) {
        return;
    }
    try {
        const payload = await api(`/series/${_seriesWorkspaceState.activeSeriesId}`, {
            method: "PATCH",
            body: JSON.stringify({
                workspace_state: _seriesGetWorkspaceState(),
            }),
        });
        if (payload?.series) {
            _seriesWorkspaceState.series = {
                ..._seriesWorkspaceState.series,
                ...payload.series,
            };
            _seriesWorkspaceState.activeTab = _seriesNormalizeTab(payload.series?.workspace_state?.active_tab || _seriesWorkspaceState.activeTab);
        }
        if (!options.silent) {
            showToast("Projeto atualizado.", "success");
        }
    } catch (error) {
        if (!options.silent) {
            showToast(`Erro ao salvar o projeto: ${error.message}`, "error");
        }
    }
}

function _seriesQueueWorkspaceStatePersist(delay = 450) {
    _seriesClearPersistTimer();
    _seriesWorkspaceState.persistTimer = setTimeout(() => {
        _seriesWorkspaceState.persistTimer = null;
        void _seriesPersistWorkspaceState({ silent: true });
    }, delay);
}

function _seriesGuessPersonaTypeForCharacter(character) {
    const explicit = String(character?.persona_type || "").trim().toLowerCase();
    if (REALISTIC_PERSONA_TYPES.includes(explicit)) {
        return explicit;
    }
    const text = `${character?.role || ""} ${character?.summary || ""}`.toLowerCase();
    if (text.includes("crianca") || text.includes("infantil")) return "crianca";
    if (text.includes("mulher") || text.includes("feminina")) return "mulher";
    if (text.includes("homem") || text.includes("masculino")) return "homem";
    if (text.includes("familia")) return "familia";
    if (text.includes("animal") || text.includes("natureza")) return "natureza";
    if (text.includes("desenho") || text.includes("anime") || text.includes("cartoon")) return "desenho";
    return "personalizado";
}

function _seriesApplyPersonaToCharacter(index, profile, createdProfileId = 0) {
    const characters = [..._seriesGetCharacters()];
    const current = characters[index];
    if (!current) {
        return;
    }
    const resolvedProfile = profile || {};
    const profileId = parseInt(resolvedProfile.id || createdProfileId || current.persona_profile_id || "0", 10) || 0;
    characters[index] = {
        ...current,
        persona_profile_id: profileId,
        voice_profile_id: parseInt(resolvedProfile.voice_profile_id || current.voice_profile_id || "0", 10) || 0,
        persona_type: String(resolvedProfile.persona_type || current.persona_type || _seriesGuessPersonaTypeForCharacter(current) || "personalizado").trim(),
        name: String(current.name || resolvedProfile.name || `Personagem ${index + 1}`).trim(),
        summary: String(current.summary || current.role || resolvedProfile.prompt_text || "").trim(),
        image_url: String(resolvedProfile.image_url || current.image_url || "").trim(),
        image_path: String(resolvedProfile.image_path || current.image_path || "").trim(),
        prompt_text: String(resolvedProfile.prompt_text || current.prompt_text || "").trim(),
    };
    _seriesUpdateWorkspaceState({ characters });
    _seriesRenderWorkspace();
    _seriesQueueWorkspaceStatePersist(0);
}

window._seriesSyncCharacterVoiceFromPersona = function _seriesSyncCharacterVoiceFromPersona(profileId, voiceProfileId) {
    const pid = parseInt(profileId || "0", 10) || 0;
    const vid = parseInt(voiceProfileId || "0", 10) || 0;
    if (!pid || !vid) {
        return;
    }
    const characters = [..._seriesGetCharacters()];
    let changed = false;
    characters.forEach((character, index) => {
        if ((parseInt(character?.persona_profile_id || "0", 10) || 0) === pid) {
            characters[index] = {
                ...character,
                voice_profile_id: vid,
            };
            changed = true;
        }
    });
    if (!changed) {
        return;
    }
    _seriesUpdateWorkspaceState({ characters });
    _seriesRenderWorkspace();
    _seriesQueueWorkspaceStatePersist(0);
};

function _seriesAddCharacterCard() {
    const characters = [..._seriesGetCharacters()];
    characters.push({
        id: _seriesMakeWorkspaceItemId("character"),
        name: `Personagem ${characters.length + 1}`,
        role: "Funcao dramatica a definir.",
        summary: "Descreva a historia, o visual e a personalidade deste personagem.",
        persona_type: "personalizado",
        persona_profile_id: 0,
        voice_profile_id: 0,
    });
    _seriesUpdateWorkspaceState({ characters });
    _seriesRenderWorkspace();
    _seriesQueueWorkspaceStatePersist();
}

function _seriesRemoveCharacterCard(index) {
    const characters = [..._seriesGetCharacters()];
    if (!characters[index]) return;
    characters.splice(index, 1);
    _seriesUpdateWorkspaceState({ characters });
    _seriesRenderWorkspace();
    _seriesQueueWorkspaceStatePersist();
}

async function _seriesOpenCharacterPersonaBuilder(index) {
    const characters = _seriesGetCharacters();
    const character = characters[index];
    if (!character) {
        return;
    }
    _personaManagerContext = "script";
    _personaManagerMulti = false;
    _personaManagerType = _seriesGuessPersonaTypeForCharacter(character);
    _seriesPersonaCreateHook = async (createdId, createdProfile) => {
        _seriesApplyPersonaToCharacter(index, createdProfile, createdId);
        showToast("Persona vinculada ao personagem.", "success");
    };
    await openPersonaCreateModal();
    const nameInput = document.getElementById("persona-manager-name");
    if (nameInput && !String(nameInput.value || "").trim()) {
        nameInput.value = String(character.name || "").trim();
    }
    const customDesc = document.getElementById("persona-manager-custom-desc");
    if (customDesc && !String(customDesc.value || "").trim()) {
        customDesc.value = String(character.summary || character.role || "").trim();
    }
    const extraInput = document.getElementById("persona-manager-extra");
    if (extraInput && !String(extraInput.value || "").trim()) {
        extraInput.value = String(character.role || "").trim();
    }
}

async function _seriesOpenCharacterVoiceBuilder(index) {
    const character = _seriesGetCharacters()[index];
    const profileId = parseInt(character?.persona_profile_id || "0", 10) || 0;
    if (!profileId) {
        showToast("Crie uma persona para este personagem antes de gerar a voz.", "info");
        return;
    }
    const personaType = _seriesGuessPersonaTypeForCharacter(character);
    _personaManagerType = personaType;
    try {
        await _loadPersonaProfiles(personaType, false);
    } catch (error) {
        console.warn("Failed to load persona profiles for voice builder:", error);
    }
    openPersonaVoiceBuilder(profileId);
}

function _seriesAddStoryboardItem(kind) {
    const storyboard = _seriesGetStoryboardBank();
    const list = kind === "objects" ? [...storyboard.objects] : [...storyboard.scenes];
    const nextIndex = list.length + 1;
    list.push({
        id: _seriesMakeWorkspaceItemId(kind === "objects" ? "object" : "scene"),
        name: kind === "objects" ? `Objeto ${nextIndex}` : `Cena ${nextIndex}`,
        summary: kind === "objects"
            ? "Descreva o objeto, adereco ou elemento visual importante para a historia."
            : "Descreva a cena, o objetivo dramatica e o enquadramento visual.",
        image_prompt: kind === "objects"
            ? "Objeto cinematografico, fundo limpo, detalhes claros, iluminacao premium."
            : "Cena cinematografica, composicao forte, luz definida, atmosfera coerente com a historia.",
    });
    _seriesUpdateWorkspaceState({
        storyboard: {
            ...storyboard,
            [kind]: list,
        },
    });
    _seriesRenderWorkspace();
    _seriesQueueWorkspaceStatePersist();
}

function _seriesRemoveStoryboardItem(kind, index) {
    const storyboard = _seriesGetStoryboardBank();
    const key = kind === "objects" ? "objects" : "scenes";
    const list = [...storyboard[key]];
    if (!list[index]) return;
    list.splice(index, 1);
    _seriesUpdateWorkspaceState({
        storyboard: {
            ...storyboard,
            [key]: list,
        },
    });
    _seriesRenderWorkspace();
    _seriesQueueWorkspaceStatePersist();
}

function _seriesOpenStoryboardItemImageCreator(kind, index) {
    const storyboard = _seriesGetStoryboardBank();
    const key = kind === "objects" ? "objects" : "scenes";
    const item = storyboard[key][index];
    if (!item) {
        return;
    }
    resetScriptImageCreatorModalState();
    _scriptImageCreatorLaunchSource = "script";
    _scriptImageCreatorConsumer = async (generatedItem) => {
        const refreshedStoryboard = _seriesGetStoryboardBank();
        const nextList = [...refreshedStoryboard[key]];
        const current = nextList[index];
        if (!current) {
            return;
        }
        nextList[index] = {
            ...current,
            image_url: String(generatedItem.image_url || current.image_url || "").trim(),
            upload_id: String(generatedItem.upload_id || current.upload_id || "").trim(),
            image_prompt: String(current.image_prompt || item.image_prompt || "").trim(),
        };
        _seriesUpdateWorkspaceState({
            storyboard: {
                ...refreshedStoryboard,
                [key]: nextList,
            },
        });
        _seriesRenderWorkspace();
        _seriesQueueWorkspaceStatePersist(0);
    };
    _ensureScriptImageCreatorPromptCapacity(1);
    _scriptImageCreatorState.promptValues[0] = String(item.image_prompt || item.summary || item.name || "").trim();
    _scriptImageCreatorState.generatedImages = [];
    _scriptImageCreatorState.activeResultIndex = 0;
    _scriptImageCreatorState.referenceFiles = [];
    const aspectSelect = document.getElementById("script-image-generator-aspect");
    if (aspectSelect) {
        aspectSelect.value = String(_seriesWorkspaceState.series?.aspect_ratio || "16:9").trim() || "16:9";
    }
    syncScriptImageCreatorControls();
    renderScriptImageCreatorReferencePreview();
    renderScriptImageCreatorResults();
    scheduleScriptImageCreatorEstimate(0);
    openModal("modal-script-image-creator");
}

function _seriesUpdateCharacterField(index, field, value) {
    const characters = [..._seriesGetCharacters()];
    const current = characters[index];
    if (!current) {
        return;
    }
    characters[index] = {
        ...current,
        [field]: value,
    };
    _seriesUpdateWorkspaceState({ characters });
    _seriesQueueWorkspaceStatePersist();
}

function _seriesUpdateStoryboardField(kind, index, field, value) {
    const storyboard = _seriesGetStoryboardBank();
    const key = kind === "objects" ? "objects" : "scenes";
    const list = [...storyboard[key]];
    const current = list[index];
    if (!current) {
        return;
    }
    list[index] = {
        ...current,
        [field]: value,
    };
    _seriesUpdateWorkspaceState({
        storyboard: {
            ...storyboard,
            [key]: list,
        },
    });
    _seriesQueueWorkspaceStatePersist();
}

function _seriesRenderProjectTab() {
    const series = _seriesWorkspaceState.series;
    const episodes = _seriesWorkspaceState.episodes || [];
    const projectPlan = _seriesGetProjectPlan();
    const characters = _seriesGetCharacters();
    const storyboard = _seriesGetStoryboardBank();
    const longStoryMarkup = _seriesRenderTextParagraphs(
        projectPlan.storyTreatment,
        "Use o chat para descrever a historia completa. Aqui vai aparecer o texto-base longo do projeto, com o começo, o desenvolvimento, as viradas e o final que as outras abas vao seguir.",
    );
    const requirementChips = projectPlan.requirements.length
        ? `<div class="series-chip-list">${projectPlan.requirements.map((item) => `<span class="series-chip">${esc(item)}</span>`).join("")}</div>`
        : '<div class="series-inline-note">Descreva no chat o tema, a duracao, o tom, os personagens e o visual. O painel ajusta automaticamente.</div>';
    const totalVisualItems = storyboard.scenes.length + storyboard.objects.length;
    const scopeCopy = series.kind === "film"
        ? "bloco principal"
        : (series.kind === "drama" ? "capitulo(s)" : "episodio(s)");
    return `
        <div class="series-project-hero-layout">
            <article class="series-data-card series-project-story-card">
                <span class="series-card-label">Projeto</span>
                <h3>${esc(series.title || "Sem título")}</h3>
                <div class="series-project-story-copy">
                    ${longStoryMarkup}
                </div>
                ${requirementChips}
            </article>
            <div class="series-project-side-stack">
                <article class="series-data-card series-project-side-card">
                    <span class="series-card-label">Formato</span>
                    <strong>${esc(series.aspect_ratio || "16:9")}</strong>
                    <p>Idioma: ${esc(series.language || "pt-BR")}</p>
                </article>
                <article class="series-data-card series-project-side-card">
                    <span class="series-card-label">Duração-alvo</span>
                    <strong>${esc(_seriesFormatLongDuration(series.target_duration_seconds))}</strong>
                    <p>Tempo total do projeto. Hoje existem ${episodes.length} ${scopeCopy}, ${characters.length} personagem(ns) e ${totalVisualItems} item(ns) visuais planejados.</p>
                </article>
            </div>
        </div>
        <div class="series-project-summary-grid">
            <article class="series-mini-card">
                <span>Roteiro</span>
                <strong>${episodes.length ? `${episodes.length} bloco(s)` : "Aguardando briefing"}</strong>
            </article>
            <article class="series-mini-card">
                <span>Personagens</span>
                <strong>${characters.length || 0} card(s)</strong>
            </article>
            <article class="series-mini-card">
                <span>Storyboard</span>
                <strong>${_seriesCountEpisodeScenes()} cena(s) + ${storyboard.objects.length} objeto(s)</strong>
            </article>
        </div>
        <div class="series-episode-strip">
            ${episodes.map((episode) => `
                <article class="series-mini-card">
                    <span>${esc(series.kind === "film" ? "Bloco principal" : `T${episode.season_number} · E${episode.episode_number}`)}</span>
                    <strong>${esc(episode.title || `Episódio ${episode.episode_number}`)}</strong>
                    <small>${esc(_seriesFormatLongDuration(_seriesGetEpisodeDuration(episode)))}</small>
                </article>
            `).join("")}
        </div>
    `;
}

function _seriesRenderRoteiroTab() {
    const episodes = _seriesWorkspaceState.episodes || [];
    if (!episodes.length) {
        return `
            <div class="series-empty-card">
                <strong>Nenhum roteiro gerado ainda.</strong>
                <span>Escreva no chat o tema, a duração total, os episódios ou capítulos e o tipo de história. Eu monto a estrutura completa do projeto automaticamente.</span>
            </div>
        `;
    }
    return `
        <div class="series-list-stack">
            ${episodes.map((episode) => `
                <article class="series-story-card">
                    <div class="series-story-card-head">
                        <div>
                            <span class="series-card-label">${esc(`T${episode.season_number} · E${episode.episode_number}`)}</span>
                            <h3>${esc(episode.title || `Episódio ${episode.episode_number}`)}</h3>
                        </div>
                        <span class="series-status-pill">${esc(episode.status || "draft")}</span>
                    </div>
                    <p>${esc(episode.synopsis || "Sinopse ainda vazia. Use o chat ao lado para começar a estruturar o arco deste episódio.")}</p>
                    <div class="series-meta-inline">
                        <span>Duração: ${esc(_seriesFormatLongDuration(_seriesGetEpisodeDuration(episode)))}</span>
                        <span>${Array.isArray(episode.storyboard) ? episode.storyboard.length : 0} cena(s)</span>
                    </div>
                    <div class="series-scene-grid">
                        ${(Array.isArray(episode.storyboard) ? episode.storyboard : []).map((scene, sceneIndex) => `
                            <article class="series-scene-mini-card">
                                <span class="series-card-label">Cena ${esc(String(scene.scene_number || sceneIndex + 1))}</span>
                                <strong>${esc(scene.title || `Cena ${sceneIndex + 1}`)}</strong>
                                <p>${esc(scene.beat || "Beat ainda nao descrito.")}</p>
                                <div class="series-meta-inline">
                                    <span>${esc(scene.location || "Local a definir")}</span>
                                    <span>${esc(_seriesFormatLongDuration(scene.duration_seconds))}</span>
                                </div>
                                <div class="series-chip-list compact">
                                    ${(Array.isArray(scene.characters) ? scene.characters : []).slice(0, 4).map((item) => `<span class="series-chip">${esc(item)}</span>`).join("")}
                                    ${(Array.isArray(scene.objects) ? scene.objects : []).slice(0, 3).map((item) => `<span class="series-chip">${esc(item)}</span>`).join("")}
                                </div>
                            </article>
                        `).join("")}
                    </div>
                    <div class="series-code-block">${esc(episode.script_text || "Nenhum roteiro gerado ainda para este episódio.")}</div>
                </article>
            `).join("")}
        </div>
    `;
}

function _seriesRenderPersonagensTab() {
    const characters = _seriesGetCharacters();
    if (!characters.length) {
        return `
            <div class="series-empty-card series-empty-card-actionable">
                <strong>Nenhum personagem criado ainda.</strong>
                <span>Adicione personagens para definir persona, voz, visual e função dramatica dentro do projeto.</span>
                <button class="btn btn-primary btn-sm" type="button" data-series-add-character>Adicionar personagem</button>
            </div>
        `;
    }
    return `
        <div class="series-section-head">
            <div>
                <span class="series-card-label">Persona e voz</span>
                <h3>Personagens do projeto</h3>
            </div>
            <button class="btn btn-primary btn-sm" type="button" data-series-add-character>Adicionar personagem</button>
        </div>
        <div class="series-character-grid">
            ${characters.map((character, index) => {
                const profileId = parseInt(character.persona_profile_id || "0", 10) || 0;
                const personaType = _seriesGuessPersonaTypeForCharacter(character);
                const profile = _seriesFindPersonaProfile(profileId, personaType);
                const imageUrl = _editorResolveMediaUrl(character.image_url || character.image_path || profile?.image_url || profile?.image_path || "");
                const voiceProfileId = parseInt(character.voice_profile_id || profile?.voice_profile_id || "0", 10) || 0;
                return `
                <article class="series-character-card">
                    <div class="series-character-card-top">
                        <div class="series-character-avatar${imageUrl ? " has-image" : ""}">
                            ${imageUrl
                                ? `<img src="${esc(imageUrl)}" alt="${esc(character.name || `Personagem ${index + 1}`)}">`
                                : `<span>${esc(String(character.name || "?").trim().charAt(0) || "?")}</span>`}
                        </div>
                        <div>
                            <span class="series-card-label">Personagem</span>
                            <h3>${esc(character.name || `Personagem ${index + 1}`)}</h3>
                            <p>${esc(character.role || "Funcao dramatica a definir.")}</p>
                        </div>
                    </div>
                    <div class="series-field-grid">
                        <label class="series-field-label">
                            <span>Nome</span>
                            <input class="series-inline-input" type="text" value="${esc(character.name || "")}" data-series-character-index="${index}" data-series-character-field="name">
                        </label>
                        <label class="series-field-label">
                            <span>Tipo</span>
                            <select class="series-inline-select" data-series-character-index="${index}" data-series-character-field="persona_type">
                                ${REALISTIC_PERSONA_TYPES.map((type) => `<option value="${type}"${type === personaType ? " selected" : ""}>${esc(REALISTIC_PERSONA_LABELS[type] || type)}</option>`).join("")}
                            </select>
                        </label>
                    </div>
                    <label class="series-field-label">
                        <span>Papel na historia</span>
                        <input class="series-inline-input" type="text" value="${esc(character.role || "")}" data-series-character-index="${index}" data-series-character-field="role">
                    </label>
                    <label class="series-field-label">
                        <span>Resumo</span>
                        <textarea class="series-inline-textarea" data-series-character-index="${index}" data-series-character-field="summary">${esc(character.summary || "")}</textarea>
                    </label>
                    <div class="series-chip-list compact">
                        <span class="series-chip">${esc(profileId ? `Persona #${profileId}` : "Sem persona")}</span>
                        <span class="series-chip">${esc(voiceProfileId ? `Voz #${voiceProfileId}` : "Sem voz")}</span>
                    </div>
                    <div class="series-card-actions">
                        <button class="btn btn-primary btn-sm" type="button" data-series-character-persona="${index}">${profileId ? "Atualizar persona" : "Criar persona"}</button>
                        <button class="btn btn-secondary btn-sm" type="button" data-series-character-voice="${index}" ${profileId ? "" : "disabled"}>Voz</button>
                        <button class="btn btn-secondary btn-sm" type="button" data-series-remove-character="${index}">Remover</button>
                    </div>
                </article>
            `;
            }).join("")}
        </div>
    `;
}

function _seriesRenderStoryboardBank(kind, title, items, emptyText) {
    const bankKind = kind === "objects" ? "objects" : "scenes";
    const itemLabel = bankKind === "objects" ? "Objeto" : "Cena";
    return `
        <section class="series-storyboard-bank">
            <div class="series-section-head">
                <div>
                    <span class="series-card-label">${esc(itemLabel)}</span>
                    <h3>${esc(title)}</h3>
                </div>
                <button class="btn btn-secondary btn-sm" type="button" data-series-add-storyboard="${bankKind}">Adicionar ${esc(itemLabel.toLowerCase())}</button>
            </div>
            ${items.length ? `
                <div class="series-storyboard-grid">
                    ${items.map((item, index) => {
                        const imageUrl = _editorResolveMediaUrl(item.image_url || item.image_path || "");
                        return `
                            <article class="series-storyboard-card series-storyboard-editor-card">
                                <div class="series-storyboard-thumb${imageUrl ? " has-image" : ""}">
                                    ${imageUrl
                                        ? `<img src="${esc(imageUrl)}" alt="${esc(item.name || `${itemLabel} ${index + 1}`)}">`
                                        : `<span>${esc(item.name || `${itemLabel} ${index + 1}`)}</span>`}
                                </div>
                                <div class="series-storyboard-body">
                                    <label class="series-field-label">
                                        <span>Nome</span>
                                        <input class="series-inline-input" type="text" value="${esc(item.name || "")}" data-series-storyboard-kind="${bankKind}" data-series-storyboard-index="${index}" data-series-storyboard-field="name">
                                    </label>
                                    <label class="series-field-label">
                                        <span>Resumo</span>
                                        <textarea class="series-inline-textarea" data-series-storyboard-kind="${bankKind}" data-series-storyboard-index="${index}" data-series-storyboard-field="summary">${esc(item.summary || "")}</textarea>
                                    </label>
                                    <label class="series-field-label">
                                        <span>Prompt da imagem</span>
                                        <textarea class="series-inline-textarea short" data-series-storyboard-kind="${bankKind}" data-series-storyboard-index="${index}" data-series-storyboard-field="image_prompt">${esc(item.image_prompt || "")}</textarea>
                                    </label>
                                    <div class="series-card-actions">
                                        <button class="btn btn-primary btn-sm" type="button" data-series-storyboard-image="${bankKind}:${index}">${imageUrl ? "Gerar nova imagem" : "Criar imagem"}</button>
                                        <button class="btn btn-secondary btn-sm" type="button" data-series-remove-storyboard="${bankKind}:${index}">Remover</button>
                                    </div>
                                </div>
                            </article>
                        `;
                    }).join("")}
                </div>
            ` : `
                <div class="series-empty-card series-empty-card-actionable">
                    <strong>Nenhum ${esc(itemLabel.toLowerCase())} cadastrado.</strong>
                    <span>${esc(emptyText)}</span>
                    <button class="btn btn-secondary btn-sm" type="button" data-series-add-storyboard="${bankKind}">Adicionar ${esc(itemLabel.toLowerCase())}</button>
                </div>
            `}
        </section>
    `;
}

function _seriesRenderStoryboardTab() {
    const storyboard = _seriesGetStoryboardBank();
    return `
        <div class="series-list-stack">
            ${_seriesRenderStoryboardBank("scenes", "Cenas do projeto", storyboard.scenes, "Transforme as cenas principais em cards visuais e gere as imagens de cada uma usando o criador de imagens existente.")}
            ${_seriesRenderStoryboardBank("objects", "Objetos e elementos de cena", storyboard.objects, "Cadastre objetos, props e elementos recorrentes para manter consistencia visual ao longo da historia.")}
        </div>
    `;
}

function _seriesRenderTimelineTab() {
    const episodes = _seriesWorkspaceState.episodes || [];
    return `
        <div class="series-list-stack">
            ${episodes.map((episode) => `
                <article class="series-story-card series-timeline-card">
                    <div class="series-story-card-head">
                        <div>
                            <span class="series-card-label">${esc(`T${episode.season_number} · E${episode.episode_number}`)}</span>
                            <h3>${esc(episode.title || `Episódio ${episode.episode_number}`)}</h3>
                        </div>
                        <button class="btn btn-secondary btn-sm" data-series-open-episode="${episode.id}" type="button" ${episode.video_project_id ? "" : "disabled"}>Abrir no editor</button>
                    </div>
                    <p>${esc(episode.timeline_data && Object.keys(episode.timeline_data).length ? "Este episódio já possui dados iniciais de timeline salvos." : "A timeline detalhada vai continuar no editor atual assim que um VideoProject for vinculado a este episódio.")}</p>
                    <div class="series-meta-inline">
                        <span>Status: ${esc(episode.status || "draft")}</span>
                        <span>Projeto ligado: ${episode.video_project_id ? esc(String(episode.video_project_id)) : "não"}</span>
                    </div>
                </article>
            `).join("")}
        </div>
    `;
}

function _seriesRenderTabPanel() {
    if (!_seriesWorkspaceState.series) {
        return "";
    }
    if (_seriesWorkspaceState.activeTab === "roteiro") {
        return _seriesRenderRoteiroTab();
    }
    if (_seriesWorkspaceState.activeTab === "personagens") {
        return _seriesRenderPersonagensTab();
    }
    if (_seriesWorkspaceState.activeTab === "storyboard") {
        return _seriesRenderStoryboardTab();
    }
    if (_seriesWorkspaceState.activeTab === "timeline") {
        return _seriesRenderTimelineTab();
    }
    return _seriesRenderProjectTab();
}

function _seriesRenderChat() {
    const threadSelect = document.getElementById("series-thread-select");
    const messagesEl = document.getElementById("series-chat-messages");
    const emptyEl = document.getElementById("series-chat-empty");
    const inputEl = document.getElementById("series-chat-input");
    const sendBtn = document.getElementById("series-chat-send");
    const newChatBtn = document.getElementById("series-new-chat-btn");
    if (!threadSelect || !messagesEl || !emptyEl || !inputEl || !sendBtn || !newChatBtn) {
        return;
    }

    const hasSeries = Boolean(_seriesWorkspaceState.series);
    const threads = _seriesWorkspaceState.threads || [];
    threadSelect.disabled = !hasSeries || !threads.length || _seriesWorkspaceState.planning;
    inputEl.disabled = !hasSeries || !_seriesWorkspaceState.activeThreadId || _seriesWorkspaceState.planning;
    sendBtn.disabled = !hasSeries || !_seriesWorkspaceState.activeThreadId || _seriesWorkspaceState.planning;
    newChatBtn.disabled = !hasSeries || _seriesWorkspaceState.planning;
    sendBtn.textContent = _seriesWorkspaceState.planning ? "Pensando..." : "Enviar";
    inputEl.placeholder = hasSeries
        ? "Descreva o projeto, a duracao, os episodios, os personagens e o visual que voce quer montar..."
        : "Crie um workspace para começar";

    threadSelect.innerHTML = threads.length
        ? threads.map((thread) => `<option value="${thread.id}"${Number(thread.id) === Number(_seriesWorkspaceState.activeThreadId || 0) ? " selected" : ""}>${esc(thread.title || "Novo bate-papo")}</option>`).join("")
        : '<option value="">Novo bate-papo</option>';

    if (!hasSeries) {
        emptyEl.hidden = false;
        emptyEl.innerHTML = "<strong>Como posso ajudá-lo hoje?</strong><span>Crie um workspace para começar a usar este bate-papo com o projeto.</span>";
        messagesEl.querySelectorAll(".series-chat-bubble").forEach((node) => node.remove());
        return;
    }

    const messages = _seriesWorkspaceState.messages || [];
    const renderedMessages = [...messages];
    if (_seriesWorkspaceState.pendingUserMessage) {
        renderedMessages.push({
            role: "user",
            content: _seriesWorkspaceState.pendingUserMessage,
            local_pending: true,
        });
    }
    if (_seriesWorkspaceState.planning) {
        renderedMessages.push({
            role: "assistant",
            content: _seriesWorkspaceState.planningStatusLabel || "Pensando na resposta...",
            working: true,
        });
    }
    emptyEl.hidden = renderedMessages.length > 0;
    if (!renderedMessages.length) {
        emptyEl.innerHTML = `<strong>${esc(_seriesTabLabel(_seriesWorkspaceState.activeTab))}</strong><span>Esta conversa fica salva no workspace. Escreva o briefing e eu reorganizo o projeto automaticamente.</span>`;
    }
    messagesEl.querySelectorAll(".series-chat-bubble").forEach((node) => node.remove());
    if (renderedMessages.length) {
        messagesEl.insertAdjacentHTML("beforeend", renderedMessages.map((message) => `
            <article class="series-chat-bubble ${message.role === "user" ? "user" : "assistant"}${message.working ? " working" : ""}">
                <span class="series-chat-bubble-role">${esc(message.role === "user" ? "Você" : "Assistente")}</span>
                ${message.working ? `
                    <div class="series-chat-thinking" aria-live="polite">
                        <span class="series-chat-thinking-spinner" aria-hidden="true"></span>
                        <strong>${esc(message.content || "Pensando na resposta...")}</strong>
                    </div>
                ` : ""}
                <p>${message.working ? "Estou montando o projeto, ajustando formato, tempo, personagens e a historia-base completa." : esc(message.content || "")}</p>
            </article>
        `).join(""));
        messagesEl.scrollTop = messagesEl.scrollHeight;
    }
}

function _seriesRenderWorkspace() {
    const titleEl = document.getElementById("series-workspace-title");
    const kindPill = document.getElementById("series-kind-pill");
    const startPanel = document.getElementById("series-start-panel");
    const contentPanel = document.getElementById("series-content-panel");
    const tabPanel = document.getElementById("series-tab-panel");
    const tabs = document.querySelectorAll("#series-workspace-tabs [data-series-tab]");
    const hasSeries = Boolean(_seriesWorkspaceState.series);
    if (!titleEl || !kindPill || !startPanel || !contentPanel || !tabPanel) {
        return;
    }

    titleEl.textContent = hasSeries ? (_seriesWorkspaceState.series.title || "Séries") : "Séries";
    kindPill.hidden = !hasSeries;
    kindPill.textContent = hasSeries ? _seriesKindLabel(_seriesWorkspaceState.series.kind) : "";
    startPanel.hidden = hasSeries;
    contentPanel.hidden = !hasSeries;
    tabs.forEach((tab) => {
        const isActive = tab.dataset.seriesTab === _seriesWorkspaceState.activeTab;
        tab.disabled = !hasSeries;
        tab.classList.toggle("active", isActive);
    });
    tabPanel.innerHTML = hasSeries ? _seriesRenderTabPanel() : "";
    _seriesRenderChat();
}

async function _seriesEnsureWelcomeMessage() {
    if (!_seriesWorkspaceState.series || !_seriesWorkspaceState.activeThreadId) {
        return;
    }
    if ((_seriesWorkspaceState.messages || []).length > 0) {
        return;
    }
    await api(`/series/${_seriesWorkspaceState.activeSeriesId}/threads/${_seriesWorkspaceState.activeThreadId}/messages`, {
        method: "POST",
        body: JSON.stringify({
            role: "assistant",
            content: _seriesBuildWelcomeMessage(),
            actions: [{ type: "bootstrap_workspace", target_tab: _seriesWorkspaceState.activeTab }],
        }),
    });
    await _seriesLoadThreadMessages(_seriesWorkspaceState.activeThreadId, { silent: true });
}

async function _seriesLoadThreadMessages(threadId, options = {}) {
    if (!_seriesWorkspaceState.activeSeriesId || !threadId) {
        _seriesWorkspaceState.messages = [];
        _seriesRenderChat();
        return;
    }
    const payload = await api(`/series/${_seriesWorkspaceState.activeSeriesId}/threads/${threadId}/messages`);
    _seriesWorkspaceState.activeThreadId = Number(payload.thread?.id || threadId || 0);
    _seriesWorkspaceState.messages = Array.isArray(payload.messages) ? payload.messages : [];
    _seriesWorkspaceState.pendingUserMessage = "";
    _seriesRenderChat();
    if (!options.silent) {
        showToast("Bate-papo carregado.", "success");
    }
}

async function _seriesLoadWorkspace(seriesId, options = {}) {
    if (!seriesId) {
        _seriesRenderWorkspace();
        return;
    }
    _seriesWorkspaceState.loading = true;
    try {
        const payload = await api(`/series/${seriesId}`);
        _seriesWorkspaceState.activeSeriesId = Number(payload.series?.id || seriesId || 0);
        _seriesWorkspaceState.series = payload.series || null;
        _seriesWorkspaceState.episodes = Array.isArray(payload.episodes) ? payload.episodes : [];
        _seriesWorkspaceState.threads = Array.isArray(payload.threads) ? payload.threads : [];
        _seriesWorkspaceState.activeThreadId = Number(payload.active_thread?.id || _seriesWorkspaceState.threads[0]?.id || 0);
        _seriesWorkspaceState.messages = Array.isArray(payload.messages) ? payload.messages : [];
        _seriesWorkspaceState.pendingUserMessage = "";
        _seriesWorkspaceState.activeTab = _seriesNormalizeTab(_seriesWorkspaceState.series?.workspace_state?.active_tab || _seriesWorkspaceState.activeTab || "projeto");
        _seriesRenderWorkspace();
        await _seriesEnsureWelcomeMessage();
        if (!options.silent) {
            showToast(`${_seriesKindLabel(_seriesWorkspaceState.series?.kind)} carregado.`, "success");
        }
    } catch (error) {
        showToast(`Erro ao abrir workspace de séries: ${error.message}`, "error");
    } finally {
        _seriesWorkspaceState.loading = false;
    }
}

async function _seriesCreateWorkspace(kind) {
    if (_seriesWorkspaceState.creating) {
        return;
    }
    _seriesWorkspaceState.creating = true;
    try {
        const payload = await api("/series", {
            method: "POST",
            body: JSON.stringify(_seriesDefaultCreatePayload(kind)),
        });
        _seriesWorkspaceState.activeSeriesId = Number(payload.series?.id || 0);
        _seriesWorkspaceState.series = payload.series || null;
        _seriesWorkspaceState.episodes = Array.isArray(payload.episodes) ? payload.episodes : [];
        _seriesWorkspaceState.threads = payload.active_thread ? [payload.active_thread] : [];
        _seriesWorkspaceState.activeThreadId = Number(payload.active_thread?.id || 0);
        _seriesWorkspaceState.messages = [];
        _seriesWorkspaceState.activeTab = "projeto";
        _seriesRenderWorkspace();
        await _seriesEnsureWelcomeMessage();
        showToast(`${_seriesKindLabel(kind)} criado no novo workspace.`, "success");
    } catch (error) {
        showToast(`Erro ao criar workspace de séries: ${error.message}`, "error");
    } finally {
        _seriesWorkspaceState.creating = false;
    }
}

function openSeriesWorkspaceStart(options = {}) {
    if (options.fromCreateModal) {
        closeModal("modal-new-project");
        resetCreateWizard();
    }
    _seriesResetWorkspaceState();
    navigateTo("series-workspace");
    _seriesRenderWorkspace();
}

async function loadSeriesWorkspacePage() {
    if (_seriesWorkspaceState.activeSeriesId) {
        await _seriesLoadWorkspace(_seriesWorkspaceState.activeSeriesId, { silent: true });
        return;
    }
    _seriesRenderWorkspace();
}

async function _seriesCreateThread() {
    if (!_seriesWorkspaceState.activeSeriesId) {
        return;
    }
    try {
        const payload = await api(`/series/${_seriesWorkspaceState.activeSeriesId}/threads`, {
            method: "POST",
            body: JSON.stringify({ title: "Novo bate-papo" }),
        });
        if (payload.thread) {
            _seriesWorkspaceState.threads.unshift(payload.thread);
            _seriesWorkspaceState.activeThreadId = Number(payload.thread.id || 0);
            _seriesWorkspaceState.messages = [];
            _seriesRenderWorkspace();
            await _seriesEnsureWelcomeMessage();
        }
    } catch (error) {
        showToast(`Erro ao criar conversa: ${error.message}`, "error");
    }
}

async function _seriesSendMessage() {
    const inputEl = document.getElementById("series-chat-input");
    if (!inputEl || !_seriesWorkspaceState.activeSeriesId || !_seriesWorkspaceState.activeThreadId || _seriesWorkspaceState.planning) {
        return;
    }
    const content = String(inputEl.value || "").trim();
    if (!content) {
        showToast("Escreva uma mensagem antes de enviar.", "error");
        return;
    }
    try {
        _seriesWorkspaceState.planning = true;
        _seriesWorkspaceState.pendingUserMessage = content;
        _seriesStartPlanningFeedback();
        _seriesRenderChat();
        inputEl.value = "";
        await api(`/series/${_seriesWorkspaceState.activeSeriesId}/threads/${_seriesWorkspaceState.activeThreadId}/messages`, {
            method: "POST",
            body: JSON.stringify({
                role: "user",
                content,
                actions: [{ type: "note", target_tab: _seriesWorkspaceState.activeTab }],
            }),
        });
        const planPayload = await api(`/series/${_seriesWorkspaceState.activeSeriesId}/plan`, {
            method: "POST",
            body: JSON.stringify({
                message: content,
                tab: _seriesWorkspaceState.activeTab,
            }),
        });
        await api(`/series/${_seriesWorkspaceState.activeSeriesId}/threads/${_seriesWorkspaceState.activeThreadId}/messages`, {
            method: "POST",
            body: JSON.stringify({
                role: "assistant",
                content: String(planPayload?.assistant_message || "Projeto atualizado.").trim() || "Projeto atualizado.",
                actions: [{ type: "series_plan_generated", target_tab: _seriesWorkspaceState.activeTab }],
            }),
        });
        await _seriesLoadWorkspace(_seriesWorkspaceState.activeSeriesId, { silent: true });
    } catch (error) {
        showToast(`Erro ao enviar mensagem: ${error.message}`, "error");
        await _seriesLoadThreadMessages(_seriesWorkspaceState.activeThreadId, { silent: true });
    } finally {
        _seriesWorkspaceState.planning = false;
        _seriesStopPlanningFeedback();
        _seriesRenderChat();
    }
}

function _seriesOpenEpisodeLinkedProject(episodeId) {
    const episode = (_seriesWorkspaceState.episodes || []).find((item) => Number(item.id || 0) === Number(episodeId || 0));
    if (!episode || !episode.video_project_id) {
        showToast("Este episódio ainda não possui um projeto de vídeo vinculado.", "info");
        return;
    }
    navigateTo("editor");
    void openEditor(Number(episode.video_project_id), { restoreDraft: true });
}

function initSeriesWorkspace() {
    if (_seriesWorkspaceState.initialized) {
        return;
    }
    _seriesWorkspaceState.initialized = true;

    const page = document.getElementById("page-series-workspace");
    const backBtn = document.getElementById("series-back-btn");
    const newChatBtn = document.getElementById("series-new-chat-btn");
    const threadSelect = document.getElementById("series-thread-select");
    const sendBtn = document.getElementById("series-chat-send");
    const inputEl = document.getElementById("series-chat-input");

    if (backBtn) {
        backBtn.addEventListener("click", () => {
            navigateTo("projects");
        });
    }
    if (newChatBtn) {
        newChatBtn.addEventListener("click", () => {
            void _seriesCreateThread();
        });
    }
    if (threadSelect) {
        threadSelect.addEventListener("change", () => {
            const nextThreadId = Number(threadSelect.value || 0);
            if (nextThreadId > 0) {
                void _seriesLoadThreadMessages(nextThreadId, { silent: true });
            }
        });
    }
    if (sendBtn) {
        sendBtn.addEventListener("click", () => {
            void _seriesSendMessage();
        });
    }
    if (inputEl) {
        inputEl.addEventListener("keydown", (event) => {
            if ((event.ctrlKey || event.metaKey) && event.key === "Enter") {
                event.preventDefault();
                void _seriesSendMessage();
            }
        });
    }
    if (page) {
        page.addEventListener("click", (event) => {
            const createKindBtn = event.target.closest("[data-series-create-kind]");
            if (createKindBtn) {
                void _seriesCreateWorkspace(createKindBtn.dataset.seriesCreateKind || "series");
                return;
            }

            const tabBtn = event.target.closest("[data-series-tab]");
            if (tabBtn && _seriesWorkspaceState.series) {
                const nextTab = _seriesNormalizeTab(tabBtn.dataset.seriesTab || "projeto");
                _seriesUpdateWorkspaceState({ active_tab: nextTab });
                _seriesRenderWorkspace();
                _seriesQueueWorkspaceStatePersist(150);
                return;
            }

            const addCharacterBtn = event.target.closest("[data-series-add-character]");
            if (addCharacterBtn) {
                _seriesAddCharacterCard();
                return;
            }

            const characterPersonaBtn = event.target.closest("[data-series-character-persona]");
            if (characterPersonaBtn) {
                void _seriesOpenCharacterPersonaBuilder(parseInt(characterPersonaBtn.dataset.seriesCharacterPersona || "-1", 10));
                return;
            }

            const characterVoiceBtn = event.target.closest("[data-series-character-voice]");
            if (characterVoiceBtn) {
                void _seriesOpenCharacterVoiceBuilder(parseInt(characterVoiceBtn.dataset.seriesCharacterVoice || "-1", 10));
                return;
            }

            const removeCharacterBtn = event.target.closest("[data-series-remove-character]");
            if (removeCharacterBtn) {
                _seriesRemoveCharacterCard(parseInt(removeCharacterBtn.dataset.seriesRemoveCharacter || "-1", 10));
                return;
            }

            const addStoryboardBtn = event.target.closest("[data-series-add-storyboard]");
            if (addStoryboardBtn) {
                _seriesAddStoryboardItem(addStoryboardBtn.dataset.seriesAddStoryboard || "scenes");
                return;
            }

            const storyboardImageBtn = event.target.closest("[data-series-storyboard-image]");
            if (storyboardImageBtn) {
                const [kind, rawIndex] = String(storyboardImageBtn.dataset.seriesStoryboardImage || "").split(":");
                _seriesOpenStoryboardItemImageCreator(kind || "scenes", parseInt(rawIndex || "-1", 10));
                return;
            }

            const removeStoryboardBtn = event.target.closest("[data-series-remove-storyboard]");
            if (removeStoryboardBtn) {
                const [kind, rawIndex] = String(removeStoryboardBtn.dataset.seriesRemoveStoryboard || "").split(":");
                _seriesRemoveStoryboardItem(kind || "scenes", parseInt(rawIndex || "-1", 10));
                return;
            }

            const openEpisodeBtn = event.target.closest("[data-series-open-episode]");
            if (openEpisodeBtn) {
                _seriesOpenEpisodeLinkedProject(openEpisodeBtn.dataset.seriesOpenEpisode);
            }
        });

        page.addEventListener("input", (event) => {
            const characterField = event.target.closest("[data-series-character-field]");
            if (characterField) {
                const index = parseInt(characterField.dataset.seriesCharacterIndex || "-1", 10);
                const field = String(characterField.dataset.seriesCharacterField || "").trim();
                if (index >= 0 && field) {
                    _seriesUpdateCharacterField(index, field, characterField.value);
                }
                return;
            }

            const storyboardField = event.target.closest("[data-series-storyboard-field]");
            if (storyboardField) {
                const kind = storyboardField.dataset.seriesStoryboardKind || "scenes";
                const index = parseInt(storyboardField.dataset.seriesStoryboardIndex || "-1", 10);
                const field = String(storyboardField.dataset.seriesStoryboardField || "").trim();
                if (index >= 0 && field) {
                    _seriesUpdateStoryboardField(kind, index, field, storyboardField.value);
                }
            }
        });

        page.addEventListener("change", (event) => {
            const textCharacterField = event.target.closest("input[data-series-character-field], textarea[data-series-character-field]");
            if (textCharacterField) {
                const index = parseInt(textCharacterField.dataset.seriesCharacterIndex || "-1", 10);
                const field = String(textCharacterField.dataset.seriesCharacterField || "").trim();
                if (index >= 0 && field) {
                    _seriesUpdateCharacterField(index, field, textCharacterField.value);
                    _seriesRenderWorkspace();
                }
                return;
            }

            const characterField = event.target.closest("select[data-series-character-field]");
            if (characterField) {
                const index = parseInt(characterField.dataset.seriesCharacterIndex || "-1", 10);
                const field = String(characterField.dataset.seriesCharacterField || "").trim();
                if (index >= 0 && field) {
                    _seriesUpdateCharacterField(index, field, characterField.value);
                    _seriesRenderWorkspace();
                }
                return;
            }

            const storyboardField = event.target.closest("input[data-series-storyboard-field], textarea[data-series-storyboard-field]");
            if (storyboardField) {
                const kind = storyboardField.dataset.seriesStoryboardKind || "scenes";
                const index = parseInt(storyboardField.dataset.seriesStoryboardIndex || "-1", 10);
                const field = String(storyboardField.dataset.seriesStoryboardField || "").trim();
                if (index >= 0 && field) {
                    _seriesUpdateStoryboardField(kind, index, field, storyboardField.value);
                    _seriesRenderWorkspace();
                }
            }
        });
    }

    _seriesRenderWorkspace();
}

function _analyzeFormatNumber(value, compact = false) {
    const num = Number(value || 0);
    if (!Number.isFinite(num)) return "--";
    return new Intl.NumberFormat("pt-BR", compact
        ? { notation: "compact", maximumFractionDigits: 1 }
        : { maximumFractionDigits: 0 }).format(num);
}

function _analyzeFormatDuration(seconds) {
    const total = Math.max(0, parseInt(seconds || "0", 10) || 0);
    if (!total) return "--";
    const h = Math.floor(total / 3600);
    const m = Math.floor((total % 3600) / 60);
    const s = total % 60;
    if (h > 0) return `${h}:${String(m).padStart(2, "0")}:${String(s).padStart(2, "0")}`;
    return `${m}:${String(s).padStart(2, "0")}`;
}

function _analyzeFormatDate(value) {
    if (!value) return "";
    const dt = new Date(value);
    if (Number.isNaN(dt.getTime())) return "";
    return dt.toLocaleDateString("pt-BR", { day: "2-digit", month: "2-digit", year: "numeric" });
}

function _analyzeFormatDateTime(value) {
    if (!value) return "";
    const dt = new Date(value);
    if (Number.isNaN(dt.getTime())) return "";
    return dt.toLocaleString("pt-BR", {
        day: "2-digit",
        month: "2-digit",
        year: "numeric",
        hour: "2-digit",
        minute: "2-digit",
    });
}

function _analyzeShowLoading(message) {
    const loadingEl = document.getElementById("analyze-loading");
    if (loadingEl) {
        loadingEl.hidden = false;
        loadingEl.textContent = message || "Carregando analise...";
    }
    const resultsEl = document.getElementById("analyze-results");
    if (resultsEl) {
        resultsEl.hidden = true;
    }
}

function _analyzeShowResults(show) {
    const loadingEl = document.getElementById("analyze-loading");
    const resultsEl = document.getElementById("analyze-results");
    if (loadingEl) {
        loadingEl.hidden = !!show;
    }
    if (resultsEl) {
        resultsEl.hidden = !show;
    }
}

function _analyzeSetRunButtonState(running) {
    _analyzeState.running = !!running;
    const runBtn = document.getElementById("btn-run-analysis");
    if (!runBtn) return;
    runBtn.disabled = !!running;
    runBtn.textContent = running ? "Analisando..." : "Analisar agora";
}

function _analyzeRenderAccountSelect(accounts) {
    const select = document.getElementById("analyze-account-select");
    if (!select) return;

    const current = _analyzeState.selectedAccountId;
    const preferred = (accounts.find((a) => a.id === current)?.id)
        || (accounts.find((a) => a.platform === "youtube")?.id)
        || (accounts[0]?.id || 0);

    _analyzeState.selectedAccountId = preferred;
    select.innerHTML = accounts.map((account) => {
        const platformName = socialPlatformName(account.platform || "");
        const label = socialAccountDisplayName(account);
        return `<option value="${account.id}">${esc(platformName)} · ${esc(label)}</option>`;
    }).join("");

    if (preferred) {
        select.value = String(preferred);
    }
}

function _analyzeRenderConnectedAccounts(accounts) {
    const container = document.getElementById("analyze-connected-list");
    if (!container) return;

    if (!accounts.length) {
        container.innerHTML = "<p class='loading'>Nenhuma conta conectada ainda.</p>";
        return;
    }

    container.innerHTML = accounts.map((account) => {
        const platform = String(account.platform || "").toLowerCase();
        const accountName = socialAccountDisplayName(account);
        const username = (account.platform_username && account.platform_username !== accountName)
            ? account.platform_username
            : "";
        const selectedClass = account.id === _analyzeState.selectedAccountId ? " selected" : "";
        return `
            <button class="analyze-connected-card${selectedClass}" data-account-id="${account.id}" type="button">
                <span class="social-account-icon" aria-hidden="true">${socialPlatformIcon(platform)}</span>
                <span class="analyze-connected-meta">
                    <strong>${esc(accountName)}</strong>
                    <small>${esc(socialPlatformName(platform))}${username ? ` · ${esc(username)}` : ""}</small>
                </span>
                <span class="analyze-account-status">Conectada</span>
            </button>
        `;
    }).join("");

    container.querySelectorAll(".analyze-connected-card").forEach((card) => {
        card.addEventListener("click", () => {
            const accountId = parseInt(card.dataset.accountId || "0", 10) || 0;
            _analyzeSelectAccount(accountId, false);
        });
    });
}

function _analyzeSelectAccount(accountId, autoRun = false) {
    const selectedId = parseInt(accountId || "0", 10) || 0;
    _analyzeState.selectedAccountId = selectedId;

    const select = document.getElementById("analyze-account-select");
    if (select && selectedId) {
        select.value = String(selectedId);
    }

    document.querySelectorAll(".analyze-connected-card").forEach((card) => {
        const cardId = parseInt(card.dataset.accountId || "0", 10) || 0;
        card.classList.toggle("selected", cardId === selectedId);
    });

    if (!selectedId) {
        _analyzeShowLoading("Selecione uma conta para iniciar a analise.");
        return;
    }

    const cached = _analyzeState.payloadByAccount[selectedId];
    if (cached) {
        _analyzeRenderPayload(cached);
        return;
    }

    _analyzeShowLoading("Conta selecionada. Clique em Analisar agora para gerar diagnostico.");
    if (autoRun) {
        runAnalyzeChannel({ skipEmptyAlert: true, silentError: true });
    }
}

async function _loadLatestSavedAnalysis(accountId) {
    const selectedId = parseInt(accountId || "0", 10) || 0;
    if (!selectedId) return false;

    try {
        const rows = await api(`/analyze/history?social_account_id=${selectedId}&limit=1`);
        const items = Array.isArray(rows) ? rows : [];
        const latest = items[0];
        if (!latest?.id) return false;

        const payload = await api(`/analyze/history/${latest.id}`);
        if (!payload || typeof payload !== "object") return false;

        _analyzeState.payloadByAccount[selectedId] = payload;
        _analyzeRenderPayload(payload);
        return true;
    } catch (error) {
        console.warn("[analyze] failed to load saved analysis:", error);
        return false;
    }
}

function _analyzeRenderHistoryFilterOptions() {
    const select = document.getElementById("analyze-history-account-filter");
    if (!select) return;

    const optionsById = new Map();

    const connectedAccounts = Array.isArray(_analyzeState.accounts) ? _analyzeState.accounts : [];
    for (const account of connectedAccounts) {
        const id = parseInt(account?.id || "0", 10) || 0;
        if (!id) continue;
        const platformName = socialPlatformName(account.platform || "");
        const displayName = socialAccountDisplayName(account);
        optionsById.set(id, `${platformName} · ${displayName}`);
    }

    const historyItems = Array.isArray(_analyzeState.historyItems) ? _analyzeState.historyItems : [];
    for (const item of historyItems) {
        const id = parseInt(item?.social_account_id || "0", 10) || 0;
        if (!id || optionsById.has(id)) continue;
        const accountLabel = String(item?.account_label || item?.platform_username || item?.channel_title || `Canal ${id}`).trim();
        optionsById.set(id, accountLabel);
    }

    const sortedOptions = Array.from(optionsById.entries()).sort((a, b) => a[1].localeCompare(b[1], "pt-BR"));

    let selectedId = Math.max(0, parseInt(_analyzeState.historyFilterAccountId || "0", 10) || 0);
    if (selectedId && !optionsById.has(selectedId)) {
        selectedId = 0;
        _analyzeState.historyFilterAccountId = 0;
    }

    const html = ["<option value=\"0\">Todos os canais</option>"];
    for (const [id, label] of sortedOptions) {
        html.push(`<option value="${id}">${esc(label)}</option>`);
    }
    select.innerHTML = html.join("");
    select.value = String(selectedId || 0);
}

function _analyzeRenderHistoryList() {
    const container = document.getElementById("analyze-history-list");
    if (!container) return;

    _analyzeRenderHistoryFilterOptions();

    if (_analyzeState.historyLoading) {
        container.innerHTML = "<p class='loading'>Carregando historico...</p>";
        return;
    }

    const items = Array.isArray(_analyzeState.historyItems) ? _analyzeState.historyItems : [];
    if (!items.length) {
        container.innerHTML = "<p class='loading'>Nenhuma analise salva ainda. Clique em Analisar agora para criar a primeira.</p>";
        return;
    }

    container.innerHTML = items.map((item) => {
        const reportId = parseInt(item.id || "0", 10) || 0;
        const accountId = parseInt(item.social_account_id || "0", 10) || 0;
        const title = item.channel_title || item.account_label || item.platform_username || "Analise";
        const accountLabel = item.account_label || item.platform_username || "Conta conectada";
        const createdAt = _analyzeFormatDateTime(item.created_at) || "--";
        return `
            <button class="analyze-history-item" data-report-id="${reportId}" data-account-id="${accountId}" type="button">
                <span class="analyze-history-title">${esc(title)}</span>
                <span class="analyze-history-meta">${esc(accountLabel)}</span>
                <span class="analyze-history-date">${esc(createdAt)}</span>
            </button>
        `;
    }).join("");

    container.querySelectorAll(".analyze-history-item").forEach((node) => {
        node.addEventListener("click", () => {
            const reportId = parseInt(node.dataset.reportId || "0", 10) || 0;
            const accountId = parseInt(node.dataset.accountId || "0", 10) || 0;
            openSavedAnalysisReport(reportId, accountId);
        });
    });
}

async function loadAnalyzeHistoryList(forceReload = false) {
    if (_analyzeState.historyLoading && !forceReload) {
        return;
    }

    _analyzeState.historyLoading = true;
    _analyzeRenderHistoryList();

    try {
        const params = new URLSearchParams();
        params.set("limit", "60");
        const filterAccountId = Math.max(0, parseInt(_analyzeState.historyFilterAccountId || "0", 10) || 0);
        if (filterAccountId > 0) {
            params.set("social_account_id", String(filterAccountId));
        }

        const rows = await api(`/analyze/history?${params.toString()}`);
        _analyzeState.historyItems = Array.isArray(rows) ? rows : [];
    } catch (error) {
        const container = document.getElementById("analyze-history-list");
        if (container) {
            container.innerHTML = `<p class="loading">Erro ao carregar historico: ${esc(error.message)}</p>`;
        }
        _analyzeState.historyItems = [];
    } finally {
        _analyzeState.historyLoading = false;
        _analyzeRenderHistoryList();
    }
}

async function openAnalyzeHistoryModal() {
    if (!Array.isArray(_analyzeState.accounts) || !_analyzeState.accounts.length) {
        try {
            const accounts = await api("/social/accounts");
            _socialAccountsCache = Array.isArray(accounts) ? accounts : _socialAccountsCache;
            _analyzeState.accounts = _socialAccountsCache;
        } catch (error) {
            console.warn("[analyze] failed to refresh accounts for history filter:", error);
        }
    }

    openModal("modal-analyze-history");
    _analyzeRenderHistoryFilterOptions();
    await loadAnalyzeHistoryList(true);
}

async function openSavedAnalysisReport(reportId, socialAccountId = 0) {
    const id = parseInt(reportId || "0", 10) || 0;
    if (!id) return;

    try {
        const payload = await api(`/analyze/history/${id}`);
        const payloadAccountId = parseInt(payload?.account?.id || "0", 10) || 0;
        const accountId = payloadAccountId || (parseInt(socialAccountId || "0", 10) || 0);

        if (accountId) {
            _analyzeState.payloadByAccount[accountId] = payload;
            _analyzeSelectAccount(accountId, false);
        }

        _analyzeRenderPayload(payload);
        _analyzeRenderConnectedAccounts(_analyzeState.accounts);
        closeModal("modal-analyze-history");
    } catch (error) {
        alert(`Erro ao abrir analise salva: ${error.message}`);
    }
}

async function loadAnalyzePage(forceReload = false) {
    if (_analyzeState.loadingAccounts && !forceReload) {
        return;
    }

    _analyzeState.loadingAccounts = true;
    _analyzeShowLoading("Carregando contas conectadas...");

    try {
        const accounts = await api("/social/accounts");
        _socialAccountsCache = Array.isArray(accounts) ? accounts : [];
        _analyzeState.accounts = _socialAccountsCache;

        _analyzeRenderConnectedAccounts(_analyzeState.accounts);

        if (!_analyzeState.accounts.length) {
            const select = document.getElementById("analyze-account-select");
            if (select) {
                select.innerHTML = "<option value=''>Sem contas conectadas</option>";
            }
            _analyzeState.selectedAccountId = 0;
            _analyzeShowLoading("Conecte ao menos uma conta social para iniciar a analise.");
            return;
        }

        _analyzeRenderAccountSelect(_analyzeState.accounts);
        _analyzeSelectAccount(_analyzeState.selectedAccountId, false);

        const selectedId = _analyzeState.selectedAccountId;
        const hasCached = !!_analyzeState.payloadByAccount[selectedId];
        if (!hasCached && selectedId) {
            const loaded = await _loadLatestSavedAnalysis(selectedId);
            if (!loaded) {
                _analyzeShowLoading("Conta selecionada. Clique em Analisar agora para gerar diagnostico.");
            }
        }

        await loadAnalyzeHistoryList(forceReload);
    } catch (error) {
        _analyzeShowLoading(`Erro ao carregar contas: ${error.message}`);
    } finally {
        _analyzeState.loadingAccounts = false;
    }
}

function _analyzeRenderStringList(containerId, rawItems, emptyText) {
    const container = document.getElementById(containerId);
    if (!container) return;

    const items = Array.isArray(rawItems)
        ? rawItems.map((item) => String(item || "").trim()).filter(Boolean)
        : [];

    if (!items.length) {
        container.innerHTML = `<li class="analyze-empty">${esc(emptyText || "Sem dados disponiveis.")}</li>`;
        return;
    }

    container.innerHTML = items.map((item, idx) => (
        `<li><span class="analyze-list-index">${idx + 1}.</span><span>${esc(item)}</span></li>`
    )).join("");
}

function _analyzeRenderTopVideos(rawVideos) {
    const container = document.getElementById("analyze-top-videos");
    if (!container) return;

    const videos = Array.isArray(rawVideos) ? rawVideos : [];
    if (!videos.length) {
        container.innerHTML = "<p class='loading'>Ainda nao ha videos suficientes para ranking nesta conta.</p>";
        return;
    }

    container.innerHTML = videos.slice(0, 10).map((video, idx) => {
        const views = _analyzeFormatNumber(video.views || 0, true);
        const likes = _analyzeFormatNumber(video.likes || 0, true);
        const comments = _analyzeFormatNumber(video.comments || 0, true);
        const duration = _analyzeFormatDuration(video.duration_seconds || 0);
        const pubDate = _analyzeFormatDate(video.published_at);
        const watchBtn = video.url
            ? `<a class="btn btn-secondary btn-sm" href="${esc(video.url)}" target="_blank" rel="noopener noreferrer">Abrir</a>`
            : "";
        const thumb = video.thumbnail_url
            ? `<img src="${esc(video.thumbnail_url)}" alt="Thumbnail" class="analyze-video-thumb">`
            : `<div class="analyze-video-thumb analyze-video-thumb-placeholder">Sem thumb</div>`;

        return `
            <article class="analyze-video-card">
                <div class="analyze-video-rank">#${idx + 1}</div>
                ${thumb}
                <div class="analyze-video-body">
                    <h4>${esc(video.title || "Sem titulo")}</h4>
                    <div class="analyze-video-metrics">
                        <span><strong>${views}</strong> views</span>
                        <span><strong>${likes}</strong> likes</span>
                        <span><strong>${comments}</strong> comentarios</span>
                        <span><strong>${duration}</strong> duracao</span>
                    </div>
                    <div class="analyze-video-footer">
                        <span>${esc(pubDate || "")}</span>
                        ${watchBtn}
                    </div>
                </div>
            </article>
        `;
    }).join("");
}

function _analyzeRenderPersonaInsights(rawInsights) {
    const section = document.getElementById("analyze-persona-section");
    const summaryEl = document.getElementById("analyze-persona-summary");
    const combosEl = document.getElementById("analyze-persona-combinations");
    const elementsEl = document.getElementById("analyze-persona-elements");
    const actionsEl = document.getElementById("analyze-persona-actions");

    const insights = rawInsights && typeof rawInsights === "object" ? rawInsights : {};
    const tracked = parseInt(insights.tracked_published_videos || "0", 10) || 0;
    const hasSectionContent = !!insights.available || tracked > 0 || !!String(insights.summary || "").trim();

    if (section) {
        section.hidden = !hasSectionContent;
    }
    if (!hasSectionContent) {
        return;
    }

    if (summaryEl) {
        summaryEl.textContent = String(insights.summary || "").trim() || "A analise ainda nao cruzou personas suficientes nesta conta.";
    }

    const renderChips = (values) => (Array.isArray(values) ? values : []).map((value) => {
        const label = REALISTIC_PERSONA_LABELS[_normalizeRealisticPersonaType(value)] || String(value || "");
        return `<span class="analyze-persona-chip">${esc(label)}</span>`;
    }).join("");

    if (combosEl) {
        const combinations = Array.isArray(insights.top_combinations) ? insights.top_combinations : [];
        combosEl.innerHTML = combinations.length
            ? combinations.map((item) => `
                <article class="analyze-persona-card">
                    <div class="analyze-persona-card-head">
                        <h4>${esc(item.label || "Composicao")}</h4>
                        <span class="analyze-persona-badge">${esc(String(item.matched_top_videos || 0))} top videos</span>
                    </div>
                    <div class="analyze-persona-chip-row">${renderChips(item.persona_types)}</div>
                    <p class="analyze-persona-metrics">Media ${esc(_analyzeFormatNumber(item.avg_views || 0, true))} views · ${esc(_analyzeFormatNumber(item.avg_likes || 0, true))} likes · ${esc(String(item.published_count || 0))} publicados</p>
                    ${item.best_video_title ? `<p class="analyze-persona-best">Melhor caso: ${esc(item.best_video_title)} · ${esc(_analyzeFormatNumber(item.best_video_views || 0, true))} views</p>` : ""}
                </article>
            `).join("")
            : "<p class='analyze-empty-card'>Sem combinacoes vencedoras mapeadas ainda.</p>";
    }

    if (elementsEl) {
        const elements = Array.isArray(insights.top_elements) ? insights.top_elements : [];
        elementsEl.innerHTML = elements.length
            ? elements.map((item) => `
                <article class="analyze-persona-card analyze-persona-card-compact">
                    <div class="analyze-persona-card-head">
                        <h4>${esc(item.label || "Persona")}</h4>
                        <span class="analyze-persona-badge analyze-persona-badge-soft">${esc(String(item.matched_top_videos || 0))} top videos</span>
                    </div>
                    <p class="analyze-persona-metrics">Media ${esc(_analyzeFormatNumber(item.avg_views || 0, true))} views · ${esc(_analyzeFormatNumber(item.avg_likes || 0, true))} likes</p>
                    <p class="analyze-persona-best">${esc(String(item.published_count || 0))} videos internos com essa persona</p>
                </article>
            `).join("")
            : "<p class='analyze-empty-card'>Sem elementos de persona suficientes ainda.</p>";
    }

    _analyzeRenderStringList(
        "analyze-persona-actions",
        insights.recommendations,
        "Sem recomendacoes de persona disponiveis por enquanto.",
    );

    if (actionsEl) {
        actionsEl.classList.toggle("analyze-list-strong", Array.isArray(insights.recommendations) && insights.recommendations.length > 0);
    }
}

function _analyzeRenderKpis(channel, history, platformSupported) {
    const container = document.getElementById("analyze-kpi-grid");
    if (!container) return;

    const isSupported = !!platformSupported;
    const kpis = [
        {
            label: "Inscritos",
            value: isSupported ? _analyzeFormatNumber(channel.subscribers || 0, true) : "--",
            hint: "Canal conectado",
        },
        {
            label: "Views totais",
            value: isSupported ? _analyzeFormatNumber(channel.total_views || 0, true) : "--",
            hint: "Historico do canal",
        },
        {
            label: "Videos no canal",
            value: isSupported ? _analyzeFormatNumber(channel.total_videos || 0, false) : _analyzeFormatNumber(history.published_jobs || 0, false),
            hint: isSupported ? "Dados YouTube" : "Publicacoes internas",
        },
        {
            label: "Media views recentes",
            value: isSupported ? _analyzeFormatNumber(channel.avg_views_recent || 0, true) : "--",
            hint: "Ultimos uploads",
        },
        {
            label: "Uploads (30 dias)",
            value: _analyzeFormatNumber(
                isSupported ? (channel.uploads_last_30d || 0) : (history.last_30d_published || 0),
                false,
            ),
            hint: "Cadencia recente",
        },
        {
            label: "Janela de postagem",
            value: history.best_publish_window || "Sem padrao",
            hint: "Melhor hora do historico",
        },
    ];

    container.innerHTML = kpis.map((item) => `
        <article class="analyze-kpi-card">
            <span class="analyze-kpi-label">${esc(item.label)}</span>
            <strong class="analyze-kpi-value">${esc(String(item.value))}</strong>
            <small class="analyze-kpi-hint">${esc(item.hint)}</small>
        </article>
    `).join("");
}

function _analyzeRenderToolStudy(rawTools) {
    const container = document.getElementById("analyze-tools-study");
    if (!container) return;

    const tools = Array.isArray(rawTools) ? rawTools : [];
    if (!tools.length) {
        container.innerHTML = "<p class='loading'>Sem estudo de ferramentas disponivel.</p>";
        return;
    }

    container.innerHTML = tools.map((tool) => `
        <article class="analyze-tool-card">
            <div class="analyze-tool-head">
                <h4>${esc(tool.name || "Ferramenta")}</h4>
                <div class="analyze-tool-badges">
                    <span class="analyze-badge">${esc(tool.phase || "Fase")}</span>
                    <span class="analyze-badge analyze-badge-soft">${esc(tool.effort || "Esforco")}</span>
                </div>
            </div>
            <p>${esc(tool.focus || "")}</p>
            <p class="analyze-tool-why">${esc(tool.why || "")}</p>
        </article>
    `).join("");
}

function _analyzeRenderPayload(payload) {
    if (!payload || typeof payload !== "object") {
        _analyzeShowLoading("Nao foi possivel renderizar a analise.");
        return;
    }

    _analyzeShowResults(true);

    const channel = payload.channel || {};
    const history = payload.history || {};
    const rec = payload.recommendations || {};

    const accountLabel = payload.account?.account_label || payload.account?.platform_username || "Conta conectada";
    const channelTitle = channel.title || accountLabel;
    const platformName = socialPlatformName(payload.account?.platform || "");
    const handle = String(channel.handle || "").trim();
    const handleText = handle && handle.startsWith("@") ? handle : (handle ? `@${handle}` : "");
    const generatedAt = payload.source?.generated_at ? _analyzeFormatDate(payload.source.generated_at) : "";

    const headEl = document.getElementById("analyze-channel-head");
    if (headEl) {
        const avatar = channel.thumbnail_url
            ? `<img src="${esc(channel.thumbnail_url)}" alt="Canal" class="analyze-channel-avatar">`
            : `<div class="analyze-channel-avatar analyze-channel-avatar-fallback">${esc((channelTitle || "C").charAt(0).toUpperCase())}</div>`;

        headEl.innerHTML = `
            <div class="analyze-channel-main">
                ${avatar}
                <div class="analyze-channel-meta">
                    <h3>${esc(channelTitle)}</h3>
                    <p>${esc(platformName)}${handleText ? ` · ${esc(handleText)}` : ""}</p>
                </div>
            </div>
            <div class="analyze-channel-extra">
                ${generatedAt ? `<span class="analyze-generated-at">Atualizado em ${esc(generatedAt)}</span>` : ""}
            </div>
        `;
    }

    const noteEl = document.getElementById("analyze-platform-note");
    if (noteEl) {
        const note = String(rec.platform_note || "").trim();
        noteEl.hidden = !note;
        noteEl.textContent = note;
    }

    _analyzeRenderKpis(channel, history, !!payload.platform_supported);
    _analyzeRenderTopVideos(payload.top_videos || []);
    _analyzeRenderPersonaInsights(payload.persona_insights || {});
    _analyzeRenderStringList("analyze-title-ideas", rec.title_ideas, "Sem titulos sugeridos.");
    _analyzeRenderStringList("analyze-thumbnail-ideas", rec.thumbnail_ideas, "Sem direcoes de thumbnail.");
    _analyzeRenderStringList("analyze-growth-actions", rec.growth_actions, "Sem plano de crescimento.");
    _analyzeRenderStringList("analyze-content-gaps", rec.content_gaps, "Sem lacunas detectadas.");
    _analyzeRenderToolStudy(payload.tool_study || []);

    const descEl = document.getElementById("analyze-description-template");
    if (descEl) {
        descEl.value = String(rec.description_template || "").trim();
    }

    const hashtagsEl = document.getElementById("analyze-hashtags");
    if (hashtagsEl) {
        const tags = Array.isArray(rec.hashtags)
            ? rec.hashtags.map((tag) => String(tag || "").trim()).filter(Boolean)
            : [];
        hashtagsEl.innerHTML = tags.length
            ? tags.map((tag) => {
                const formatted = tag.startsWith("#") ? tag : `#${tag}`;
                return `<span class="analyze-hashtag">${esc(formatted)}</span>`;
            }).join("")
            : "<span class='analyze-hashtag-muted'>Sem hashtags sugeridas.</span>";
    }
}

async function runAnalyzeChannel(options = {}) {
    const select = document.getElementById("analyze-account-select");
    const selectedId = parseInt(select?.value || _analyzeState.selectedAccountId || "0", 10) || 0;
    _analyzeState.selectedAccountId = selectedId;

    if (!selectedId) {
        if (!options.skipEmptyAlert) {
            alert("Selecione uma conta para analisar.");
        }
        _analyzeShowLoading("Selecione uma conta para iniciar a analise.");
        return;
    }

    _analyzeSetRunButtonState(true);
    _analyzeShowLoading("Analisando canal e historico de publicacoes...");

    try {
        const payload = await api(`/analyze/channel?social_account_id=${selectedId}`);
        _analyzeState.payloadByAccount[selectedId] = payload;
        _analyzeRenderPayload(payload);
        _analyzeRenderConnectedAccounts(_analyzeState.accounts);
        await loadAnalyzeHistoryList(true);
    } catch (error) {
        _analyzeShowLoading(`Erro ao analisar: ${error.message}`);
        if (!options.silentError) {
            alert(`Erro ao analisar canal: ${error.message}`);
        }
    } finally {
        _analyzeSetRunButtonState(false);
    }
}

function openModal(id) {
    const modal = document.getElementById(id);
    if (!modal) {
        return;
    }
    // Move modal to <body> so it escapes any ancestor stacking context or flex container.
    document.body.appendChild(modal);
    modal.classList.add("open");
    modal.style.display = "flex";
}

function closeModal(id) {
    const modal = document.getElementById(id);
    if (!modal) {
        return;
    }
    modal.classList.remove("open");
    modal.style.display = "";
    if (id === "modal-persona-manager") {
        closeModal("modal-persona-manager-create");
    }
    if (id === "modal-new-project") {
        stopKaraokeProgressPolling();
        _stopSimilarPolling();
        closeScriptAudioVideoSourceModal();
        closeScriptAudioVideoUrlModal(true);
        closeModal("modal-script-image-creator");
        _setNewProjectModalWorkflowLayout(false);
    }
    if (id === "modal-script-image-creator") {
        closeScriptImageCreatorExpandedResult();
        resetScriptImageCreatorModalState();
        _scriptImageCreatorConsumer = null;
    }
    if (id === "modal-persona-manager-create") {
        _seriesPersonaCreateHook = null;
    }
    if (id === "modal-edit-project") {
        _renameProjectId = 0;
        const input = document.getElementById("edit-project-title");
        if (input) input.value = "";
    }
    if (id === "modal-connect-account") {
        _pendingConnectPlatform = "";
        const input = document.getElementById("connect-account-label");
        if (input) input.value = "";
        const keyInput = document.getElementById("connect-tiktok-client-key");
        const secretInput = document.getElementById("connect-tiktok-client-secret");
        if (keyInput) keyInput.value = "";
        if (secretInput) secretInput.value = "";
        const tiktokKeys = document.getElementById("connect-tiktok-keys");
        if (tiktokKeys) tiktokKeys.hidden = true;
    }
    if (id === "modal-tevoxi-about") {
        _tevoxiPendingToggleContext = "";
        const retryBtn = document.getElementById("tevoxi-about-retry-btn");
        if (retryBtn) {
            retryBtn.disabled = false;
            retryBtn.textContent = "Ja tenho conta / Ja conectei";
        }
    }
    if (id === "modal-edit-account") {
        _editingSocialAccountId = 0;
        const input = document.getElementById("edit-account-label");
        if (input) input.value = "";
    }
    if (id === "modal-publish-schedule") {
        const dtInput = document.getElementById("pub-schedule-datetime");
        if (dtInput) dtInput.value = "";
        const btn = document.getElementById("btn-confirm-schedule-publish");
        if (btn) {
            btn.disabled = false;
            btn.textContent = "Agendar";
        }
    }
    if (id === "modal-player") {
        const video = document.getElementById("player-video");
        if (video) {
            video.pause();
            video.src = "";
        }
    }
}

function _setGrokAnchorPreviewBusy(isBusy, message = "") {
    _grokAnchorPreviewState.busy = !!isBusy;
    const statusEl = document.getElementById("grok-anchor-preview-status");
    const regenBtn = document.getElementById("grok-anchor-preview-regenerate-btn");
    const approveBtn = document.getElementById("grok-anchor-preview-approve-btn");

    if (statusEl && message) {
        statusEl.textContent = message;
    }
    if (regenBtn) {
        regenBtn.disabled = !!isBusy;
    }
    if (approveBtn) {
        approveBtn.disabled = !!isBusy || !_grokAnchorPreviewState.uploadId;
    }
}

function _renderGrokAnchorPreview(result) {
    const imgEl = document.getElementById("grok-anchor-preview-img");
    const statusEl = document.getElementById("grok-anchor-preview-status");

    _grokAnchorPreviewState.uploadId = result.upload_id || "";
    _grokAnchorPreviewState.previewDataUrl = result.preview_data_url || "";
    _grokAnchorPreviewState.provider = result.provider || "";
    _grokAnchorPreviewState.retryCount = Number(result.retry_count || 0);

    if (imgEl) {
        imgEl.src = _grokAnchorPreviewState.previewDataUrl;
        imgEl.hidden = !_grokAnchorPreviewState.previewDataUrl;
    }

    if (statusEl) {
        const providerLabel = _grokAnchorPreviewState.provider || "desconhecido";
        const retryLabel = _grokAnchorPreviewState.retryCount > 0
            ? `, retry: ${_grokAnchorPreviewState.retryCount}`
            : "";
        statusEl.textContent = `Prévia gerada (provedor: ${providerLabel}${retryLabel}).`;
    }

    _setGrokAnchorPreviewBusy(false);
}

async function _fetchGrokAnchorPreview(payload) {
    return api("/video/preview-grok-anchor", {
        method: "POST",
        body: JSON.stringify(payload),
    });
}

async function regenerateGrokAnchorPreview() {
    if (_grokAnchorPreviewState.busy) {
        return;
    }
    if (!_grokAnchorPreviewState.payload) {
        alert("Não foi possível regenerar a prévia agora.");
        return;
    }

    _setGrokAnchorPreviewBusy(true, "Gerando outra imagem-base...");
    try {
        const result = await _fetchGrokAnchorPreview(_grokAnchorPreviewState.payload);
        _renderGrokAnchorPreview(result);
    } catch (error) {
        _setGrokAnchorPreviewBusy(false, "Falha ao gerar a prévia.");
        alert(`Erro ao gerar prévia: ${error.message}`);
    }
}

function cancelGrokAnchorPreview() {
    closeModal("modal-grok-anchor-preview");
    const resolve = _grokAnchorPreviewState.resolve;
    _grokAnchorPreviewState.resolve = null;
    _grokAnchorPreviewState.payload = null;
    _grokAnchorPreviewState.uploadId = "";
    _grokAnchorPreviewState.previewDataUrl = "";
    if (resolve) {
        resolve({ approved: false, upload_id: "" });
    }
}

function approveGrokAnchorPreview() {
    if (!_grokAnchorPreviewState.uploadId) {
        alert("A prévia ainda não está pronta.");
        return;
    }

    closeModal("modal-grok-anchor-preview");
    const resolve = _grokAnchorPreviewState.resolve;
    const uploadId = _grokAnchorPreviewState.uploadId;
    _grokAnchorPreviewState.resolve = null;
    _grokAnchorPreviewState.payload = null;
    _grokAnchorPreviewState.uploadId = "";
    _grokAnchorPreviewState.previewDataUrl = "";
    if (resolve) {
        resolve({ approved: true, upload_id: uploadId });
    }
}

async function requestGrokAnchorApproval(payload) {
    _grokAnchorPreviewState.payload = payload;
    _setGrokAnchorPreviewBusy(true, "Gerando imagem-base de personas...");

    const result = await _fetchGrokAnchorPreview(payload);
    _renderGrokAnchorPreview(result);

    return new Promise((resolve) => {
        _grokAnchorPreviewState.resolve = resolve;
        openModal("modal-grok-anchor-preview");
    });
}

async function loadLevitaSongs() {
    if (!token) {
        levitaSongs = [];
        return [];
    }
    try {
        const data = await api("/automation/tevoxi-songs");
        levitaSongs = Array.isArray(data) ? data : [];
        return levitaSongs;
    } catch (_) {
        levitaSongs = [];
        return [];
    }
}

async function populateSongSelector() {
    const select = document.getElementById("np-song-select");
    const details = document.getElementById("np-song-details");
    details.hidden = true;
    select.innerHTML = "<option value=''>Carregando...</option>";
    const songs = await loadLevitaSongs();
    const baseOptions = ["<option value=''>Selecione uma música</option>", "<option value='manual'>Inserir manualmente</option>"];
    if (!songs.length) {
        select.innerHTML = baseOptions.join("");
        document.getElementById("np-manual-fields").hidden = false;
        return;
    }
    document.getElementById("np-manual-fields").hidden = true;
    select.innerHTML = baseOptions.join("") + songs.map((song, index) => {
        const artist = song.artist ? ` - ${esc(song.artist)}` : "";
        return `<option value="${index}">${esc(song.title || "Sem título")}${artist}</option>`;
    }).join("");
}

let _projectsCache = [];
let _copyFormatSourceProjectId = 0;
let _pendingPublishProjectId = 0;
let _renameProjectId = 0;

function _isEditorProjectListItem(project) {
    return Boolean(project?.is_editor_project || String(project?.workflow_type || "").trim().toLowerCase() === "editor");
}

function _isProjectProcessingStatus(status) {
    const normalizedStatus = String(status || "").trim().toLowerCase();
    return normalizedStatus === "pending"
        || normalizedStatus.includes("generat")
        || normalizedStatus.includes("render");
}

function _projectVisibleInCreateList(project) {
    const normalizedStatus = String(project?.status || "").trim().toLowerCase();
    return !project?.hide_from_create_list
        && !_isEditorProjectListItem(project)
        && (
            _isProjectProcessingStatus(normalizedStatus)
            || normalizedStatus === "failed"
            || ((normalizedStatus === "completed" || normalizedStatus === "published") && !project?.video_expired)
        );
}

function _projectVisibleInEditorList(project) {
    return _isEditorProjectListItem(project)
        && String(project?.status || "").trim().toLowerCase() === "completed"
        && !project?.video_expired;
}

async function loadProjects() {
    const container = document.getElementById("projects-list");
    try {
        const data = await api("/video/projects");
        _projectsCache = data;
        const visibleData = data.filter(_projectVisibleInCreateList);
        const activeProjects = visibleData.filter((project) => _isProjectProcessingStatus(project.status));
        if (!activeProjects.length) {
            _stopProjectVisualProgress();
        } else {
            activeProjects.forEach(_seedProjectVisualProgress);
            _startProjectVisualProgress();
        }
        if (!visibleData.length) {
            container.innerHTML = "<p class='loading'>Nenhum vídeo criado ainda. Crie o primeiro.</p>";
            return;
        }
        container.innerHTML = visibleData.map((project) => {
            const normalizedStatus = String(project.status || "").trim().toLowerCase();
            const workflowType = String(project.workflow_type || "").trim().toLowerCase();
            const isSimilarProject = workflowType === "similar";
            const dateStr = _renderExpiryOrDate(project);
            const statusPt = _statusPt(project.status);
            const isExpired = project.video_expired || false;
            const canWatch = (normalizedStatus === "completed" || normalizedStatus === "published") && !isExpired;
            const isGenerating = _isProjectProcessingStatus(normalizedStatus);
            const thumbClick = canWatch
                ? `onclick="watchVideo(${project.id})" style="cursor:pointer"`
                : (isSimilarProject ? `onclick="openSimilarProject(${project.id})" style="cursor:pointer"` : "");
            const cardClasses = `card card--create-project${isGenerating ? " is-generating" : ""}`;
            const reopenSimilarButton = isSimilarProject
                ? `<button class="card-btn card-btn-similar" onclick="openSimilarProject(${project.id})" type="button" title="Abrir semelhante"><svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="m15 4 1.5 3L20 8.5 16.5 10 15 13l-1.5-3L10 8.5 13.5 7 15 4Z"/><path d="m4 20 7-7"/><path d="M9 20H4v-5"/></svg></button>`
                : "";
            const cardActions = `
                ${reopenSimilarButton}
                ${canWatch ? `<button class="card-btn card-btn-publish" onclick="openPublishForProject(${project.id})" type="button" title="Publicar"><svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M12 3v12"/><polyline points="8 7 12 3 16 7"/><rect x="4" y="15" width="16" height="6" rx="2"/></svg></button>` : ""}
                ${((project.status === "pending" || project.status === "failed") && !isSimilarProject) ? `<button class="card-btn card-btn-generate" onclick="generateVideo(${project.id})" type="button" title="Gerar vídeo"><svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polygon points="5 3 19 12 5 21 5 3"/></svg></button>` : ""}
                ${canWatch ? `<button class="card-btn card-btn-similar" onclick="openCopyChoiceModal(${project.id})" type="button" title="Criar copia"><svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="9" y="9" width="13" height="13" rx="2"/><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"/></svg></button>` : (project.lyrics_text ? `<button class="card-btn card-btn-similar" onclick="createSimilar(${project.id})" type="button" title="Criar Semelhante"><svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="9" y="9" width="13" height="13" rx="2"/><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"/></svg></button>` : "")}
                ${(canWatch && !isSimilarProject) ? `<button class="card-btn card-btn-edit" onclick="openProjectEditorFromCreate(${project.id})" type="button" title="Editar"><svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M12 20h9"/><path d="M16.5 3.5a2.12 2.12 0 1 1 3 3L7 19l-4 1 1-4 12.5-12.5z"/></svg></button>` : ""}
                <button class="card-btn card-btn-delete" onclick="deleteProject(${project.id})" type="button" title="Excluir"><svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"/><path d="M10 11v6"/><path d="M14 11v6"/><path d="M9 6V4a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v2"/></svg></button>
            `;
            const thumb = project.thumbnail_url
                ? `<img class="card-thumb${isGenerating ? " is-generating" : ""}" src="${project.thumbnail_url}" alt="" loading="lazy" onerror="handleProjectThumbError(this, ${project.id}, ${canWatch})" ${thumbClick}>`
                : `<div class="card-thumb card-thumb-placeholder${isGenerating ? " is-generating" : ""}" ${thumbClick}><svg width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><polygon points="5 3 19 12 5 21 5 3"/></svg></div>`;
            return `
                <div class="${cardClasses}" data-project-id="${project.id}">
                    <div class="card-media">
                        ${thumb}
                        <div class="card-media-actions">
                            ${cardActions}
                        </div>
                    </div>
                    <div class="card-body card-body--create-project">
                        <div class="card-title-row">
                            <h4 class="card-title">${esc(project.title)}</h4>
                            <span class="card-date">${dateStr}</span>
                        </div>
                        ${project.status !== "completed" ? `<span class="badge badge-${badgeClass(project.status)}">${esc(statusPt)}</span>` : ""}
                        ${isGenerating ? `<div class="progress-bar"><div class="progress-bar-fill" style="width:${_getProjectDisplayProgress(project) || 12}%"></div></div>` : ""}
                        ${project.error_message ? `<p class="card-error">${esc(project.error_message)}</p>` : ""}
                    </div>
                </div>
            `;
        }).join("");
        // Start polling for in-progress projects
        _pollInProgress(data);
        _startCountdownRefresh();
    } catch (error) {
        container.innerHTML = `<p class="loading">Erro: ${esc(error.message)}</p>`;
    }
}

async function openSimilarProject(projectId) {
    const parsedProjectId = Number(projectId || 0);
    if (!parsedProjectId) {
        return;
    }

    try {
        const project = await api(`/video/projects/${parsedProjectId}`);
        const tags = _safeSimilarTags(project?.tags);
        const workflowType = String(tags.type || project?.workflow_type || "").trim().toLowerCase();
        if (workflowType !== "similar") {
            throw new Error("Projeto semelhante não encontrado.");
        }

        _resetSimilarModeState();
        similarState.projectId = parsedProjectId;
        similarState.lastProjectSnapshot = project;

        const titleEl = document.getElementById("similar-title");
        if (titleEl) {
            titleEl.value = project.title || "";
        }

        const aspectEl = document.getElementById("similar-aspect");
        if (aspectEl) {
            aspectEl.value = _normalizeSimilarAspectRatio(project.aspect_ratio) || "16:9";
        }

        const sourceEl = document.getElementById("similar-source-url");
        if (sourceEl) {
            sourceEl.value = String(tags.similar_source_url || "").trim();
        }

        switchCreateMode("similar");
        await _refreshSimilarProject({ silent: true });
    } catch (error) {
        showToast(`Erro ao abrir semelhante: ${error.message}`, "error");
    }
}

function handleProjectThumbError(imgElement, projectId, canWatch) {
    const placeholder = document.createElement("div");
    placeholder.className = "card-thumb card-thumb-placeholder";
    if (imgElement.classList.contains("is-generating")) {
        placeholder.classList.add("is-generating");
    }
    if (canWatch) {
        placeholder.style.cursor = "pointer";
        placeholder.addEventListener("click", () => watchVideo(projectId));
    }
    placeholder.innerHTML = '<svg width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><polygon points="5 3 19 12 5 21 5 3"/></svg>';
    imgElement.replaceWith(placeholder);
}

const _projectVisualProgress = new Map();
let _projectVisualProgressTimer = null;

function _projectProgressCap(status) {
    const normalizedStatus = String(status || "").trim().toLowerCase();
    if (normalizedStatus === "generating_scenes") return 48;
    if (normalizedStatus === "generating_clips") return 78;
    if (normalizedStatus === "rendering") return 94;
    return 88;
}

function _seedProjectVisualProgress(project) {
    const normalizedStatus = String(project?.status || "").trim().toLowerCase();
    const isActive = normalizedStatus !== "completed" && normalizedStatus !== "failed" && normalizedStatus !== "pending";
    if (!isActive) {
        _projectVisualProgress.delete(project?.id);
        return;
    }
    const serverProgress = Number(project?.progress);
    const safeServerProgress = Number.isFinite(serverProgress) ? Math.max(6, Math.min(99, serverProgress)) : 0;
    const tracked = _projectVisualProgress.get(project.id);
    if (!tracked) {
        _projectVisualProgress.set(project.id, {
            value: safeServerProgress > 0 ? safeServerProgress : 12,
            status: normalizedStatus,
            updatedAt: Date.now(),
        });
        return;
    }
    tracked.status = normalizedStatus;
    tracked.updatedAt = Date.now();
    if (safeServerProgress > tracked.value) {
        tracked.value = safeServerProgress;
    }
}

function _getProjectDisplayProgress(project) {
    _seedProjectVisualProgress(project);
    const tracked = _projectVisualProgress.get(project?.id);
    if (!tracked) return null;
    return Math.round(Math.max(6, Math.min(99, tracked.value)));
}

function _refreshProjectProgressBars() {
    const container = document.getElementById("projects-list");
    if (!container) return;
    for (const project of _projectsCache) {
        const normalizedStatus = String(project?.status || "").trim().toLowerCase();
        const isActive = normalizedStatus !== "completed" && normalizedStatus !== "failed" && normalizedStatus !== "pending";
        if (!isActive) continue;
        const tracked = _projectVisualProgress.get(project.id);
        if (!tracked) continue;
        const cap = _projectProgressCap(tracked.status);
        if (tracked.value < cap) {
            const remaining = cap - tracked.value;
            const step = Math.max(0.35, remaining * 0.04);
            tracked.value = Math.min(cap, tracked.value + step);
        }
        const card = container.querySelector(`.card[data-project-id="${project.id}"]`);
        const fill = card?.querySelector(".progress-bar-fill");
        if (fill) {
            fill.style.width = `${Math.round(tracked.value)}%`;
        }
    }
}

function _startProjectVisualProgress() {
    if (_projectVisualProgressTimer) return;
    _projectVisualProgressTimer = setInterval(_refreshProjectProgressBars, 900);
}

function _stopProjectVisualProgress() {
    if (_projectVisualProgressTimer) {
        clearInterval(_projectVisualProgressTimer);
        _projectVisualProgressTimer = null;
    }
    _projectVisualProgress.clear();
}

function _statusPt(status) {
    const map = {
        "pending": "Pendente",
        "generating_scenes": "Gerando cenas...",
        "generating_clips": "Gerando clipes...",
        "rendering": "Gerando vídeo...",
        "completed": "Concluído",
        "failed": "Falhou",
        "published": "Publicado",
    };
    return map[status] || status;
}

const RENDER_EXPIRY_HOURS = 48;

function _renderExpiryOrDate(project) {
    // For completed projects with a render, show countdown to expiry
    if (project.status === "completed" && project.video_expired) {
        return '<span class="expiry-expired">Expirado</span>';
    }
    if (project.status === "completed" && project.render_created_at) {
        const renderDate = new Date(project.render_created_at);
        const expiresAt = new Date(renderDate.getTime() + RENDER_EXPIRY_HOURS * 3600000);
        const now = new Date();
        const remaining = expiresAt - now;
        if (remaining <= 0) {
            return '<span class="expiry-expired">Expirado</span>';
        }
        const hours = Math.floor(remaining / 3600000);
        const mins = Math.floor((remaining % 3600000) / 60000);
        if (hours < 6) {
            return `<span class="expiry-urgent">⏳ ${hours}h ${String(mins).padStart(2,"0")}m</span>`;
        }
        return `<span class="expiry-countdown">⏳ ${hours}h ${String(mins).padStart(2,"0")}m</span>`;
    }
    // For non-completed projects, show creation date
    const dt = project.created_at ? new Date(project.created_at) : null;
    return dt ? `${String(dt.getHours()).padStart(2,"0")}:${String(dt.getMinutes()).padStart(2,"0")} · ${dt.toLocaleDateString("pt-BR")}` : "-";
}

// Auto-refresh countdown timers every minute
let _countdownTimer = null;
function _startCountdownRefresh() {
    if (_countdownTimer) clearInterval(_countdownTimer);
    _countdownTimer = setInterval(() => {
        const container = document.getElementById("projects-list");
        if (!container) return;
        for (const project of _projectsCache) {
            if (project.status !== "completed" || !project.render_created_at) continue;
            const cards = container.querySelectorAll(".card");
            for (const card of cards) {
                const btn = card.querySelector("[onclick*='watchVideo(" + project.id + ")']") ||
                            card.querySelector("[onclick*='deleteProject(" + project.id + ")']");
                if (btn) {
                    const dateSpan = card.querySelector(".card-date");
                    if (dateSpan) dateSpan.innerHTML = _renderExpiryOrDate(project);
                    break;
                }
            }
        }
    }, 60000);
}

let _pollTimer = null;
let _prevActiveIds = new Set();
function _pollInProgress(projects) {
    if (_pollTimer) clearInterval(_pollTimer);
    const active = projects.filter(p =>
        p.status !== "completed" && p.status !== "failed" && p.status !== "pending"
    );
    if (!active.length) {
        _stopProjectVisualProgress();
        return;
    }
    active.forEach(_seedProjectVisualProgress);
    _startProjectVisualProgress();
    _prevActiveIds = new Set(active.map(p => p.id));
    _pollTimer = setInterval(async () => {
        try {
            const data = await api("/video/projects");
            _projectsCache = data;
            const stillActive = data.filter(p =>
                p.status !== "completed" && p.status !== "failed" && p.status !== "pending"
            );
            // Detect newly completed projects
            const newlyCompleted = data.filter(p =>
                p.status === "completed" && _prevActiveIds.has(p.id)
            );
            _prevActiveIds = new Set(stillActive.map(p => p.id));
            if (stillActive.length) {
                stillActive.forEach(_seedProjectVisualProgress);
            }
            // Update cards in-place instead of full re-render
            for (const p of data) {
                _updateCardInPlace(p);
            }
            if (!stillActive.length) {
                clearInterval(_pollTimer);
                _pollTimer = null;
                _stopProjectVisualProgress();
                loadProjects(); // Full refresh to get thumbnails
                // Show expiry warning and auto-download newly completed videos
                if (newlyCompleted.length) {
                    _showExpiryWarning();
                    _autoDownloadCompleted(newlyCompleted);
                }
            }
        } catch (_) {
            clearInterval(_pollTimer);
            _pollTimer = null;
            _stopProjectVisualProgress();
        }
    }, 3000);
}

function _showExpiryWarning() {
    const modal = document.getElementById("modal-expiry-warning");
    if (modal) {
        openModal("modal-expiry-warning");
    }
}

async function _autoDownloadCompleted(projects) {
    for (const p of projects) {
        try {
            const detail = await api(`/video/projects/${p.id}`);
            const render = _pickLatestAvailableRender(detail.renders || []);
            if (!render) continue;
            const a = document.createElement("a");
            a.href = render.video_url;
            a.download = `${p.title || "video"}.mp4`;
            a.style.display = "none";
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
        } catch (_) {}
    }
}

function _updateCardInPlace(project) {
    const container = document.getElementById("projects-list");
    const card = container.querySelector(`.card[data-project-id="${project.id}"]`);
    if (!card) {
        return;
    }
    const body = card.querySelector(".card-body");
    const thumb = card.querySelector(".card-thumb");
    const isActive = project.status !== "completed" && project.status !== "failed" && project.status !== "pending";
    const isGenerating = _isProjectProcessingStatus(project.status);
    card.classList.toggle("is-generating", isGenerating);
    if (thumb) {
        thumb.classList.toggle("is-generating", isGenerating);
    }
    let badge = card.querySelector(".badge");
    if (project.status !== "completed") {
        if (!badge) {
            badge = document.createElement("span");
            body.appendChild(badge);
        }
        badge.textContent = _statusPt(project.status);
        badge.className = `badge badge-${badgeClass(project.status)}`;
    } else if (badge) {
        badge.remove();
    }
    let barWrap = card.querySelector(".progress-bar");
    if (isActive) {
        if (!barWrap) {
            barWrap = document.createElement("div");
            barWrap.className = "progress-bar";
            barWrap.innerHTML = '<div class="progress-bar-fill"></div>';
            body.appendChild(barWrap);
        }
        const displayProgress = _getProjectDisplayProgress(project) || 12;
        barWrap.querySelector(".progress-bar-fill").style.width = displayProgress + "%";
    } else if (barWrap) {
        barWrap.remove();
        _projectVisualProgress.delete(project.id);
    }
}

