function workflowBuildPrompt() {
    const promptTexts = Array.from(document.querySelectorAll("#create-panel-workflow .workflow-node-prompt textarea"))
        .map((el) => String(el.value || "").trim())
        .filter(Boolean);
    const prompt = promptTexts.join("\n\n");
    const videoUrls = Array.from(document.querySelectorAll("#create-panel-workflow .workflow-video-url-input"))
        .map((el) => String(el.value || "").trim())
        .filter(Boolean)
        .join(" | ");
    const audioUrls = Array.from(document.querySelectorAll("#create-panel-workflow .workflow-audio-url-input"))
        .map((el) => String(el.value || "").trim())
        .filter(Boolean)
        .join(" | ");
    const extraVideoNotes = Array.from(document.querySelectorAll("#create-panel-workflow .workflow-video-notes-input"))
        .map((el) => String(el.value || "").trim())
        .filter(Boolean)
        .join(" | ");
    const extraAudioNotes = Array.from(document.querySelectorAll("#create-panel-workflow .workflow-audio-notes-input"))
        .map((el) => String(el.value || "").trim())
        .filter(Boolean)
        .join(" | ");
    const imageNotes = Array.from(document.querySelectorAll("#create-panel-workflow .workflow-node-images textarea"))
        .map((el) => String(el.value || "").trim())
        .filter(Boolean)
        .join(" | ");
    const nodeVideoNames = Array.from(document.querySelectorAll("#create-panel-workflow .workflow-node-video"))
        .map((node) => String(node.dataset.videoName || "").trim())
        .filter(Boolean)
        .join(", ");
    const nodeAudioNames = Array.from(document.querySelectorAll("#create-panel-workflow .workflow-node-audio"))
        .map((node) => String(node.dataset.audioName || "").trim())
        .filter(Boolean)
        .join(", ");
    const parts = [];
    if (prompt) parts.push(prompt);
    if (imageNotes) parts.push(`Referencia de imagens/geracao visual: ${imageNotes}`);
    if (workflowState.videos.length || nodeVideoNames) parts.push(`Videos enviados como referencia: ${workflowState.videos.map((file) => file.name || "video").concat(nodeVideoNames ? [nodeVideoNames] : []).join(", ")}`);
    if (videoUrls || extraVideoNotes) parts.push(`Referencia de video: ${[videoUrls, extraVideoNotes].filter(Boolean).join(" | ")}`);
    if (workflowState.audio || nodeAudioNames) parts.push(`Audio enviado como referencia: ${[workflowState.audio?.name || "", nodeAudioNames].filter(Boolean).join(", ")}`);
    if (audioUrls || extraAudioNotes) parts.push(`Referencia de audio/clima sonoro: ${[audioUrls, extraAudioNotes].filter(Boolean).join(" | ")}`);
    parts.push("Use as imagens de referencia como base visual quando fornecidas. Evite colagem; gere uma cena unica e coesa.");
    return parts.join("\n\n").trim();
}

async function workflowEnsureUploadedImages(templateKey = "") {
    workflowCollectGeneratedNodeImages();
    const existingIds = workflowState.images.map((item) => item.upload_id).filter(Boolean);
    if (workflowState.imageUploadIds.length === workflowState.images.length && workflowState.imageUploadIds.length > 0) {
        return workflowState.imageUploadIds.slice();
    }
    const uploadIds = existingIds.slice();
    for (let index = 0; index < workflowState.images.length; index += 1) {
        if (workflowState.images[index]?.upload_id) continue;
        workflowSetOutputProgress(8 + index, `Enviando imagem ${index + 1}/${workflowState.images.length}...`, templateKey);
        const uploaded = await uploadTempFileWithRetry(workflowState.images[index], "image", `imagem workflow ${index + 1}`, { showProgress: false });
        if (uploaded?.upload_id) {
            workflowState.images[index].upload_id = uploaded.upload_id;
            uploadIds.push(uploaded.upload_id);
        }
    }
    workflowState.imageUploadIds = uploadIds;
    return uploadIds;
}

async function workflowConnectedImageUploadIds(templateKey = "") {
    const connectedImagePorts = workflowState.connections
        .filter(([, to]) => to === "model-images-in")
        .map(([from]) => from);
    const allUploadIds = await workflowEnsureUploadedImages(templateKey);
    const selectedIds = [];
    if (connectedImagePorts.includes("images-out")) {
        workflowState.images.filter((item) => !workflowIsCollectedNodeImage(item)).forEach((item) => {
            if (item.upload_id) selectedIds.push(item.upload_id);
        });
    }
    connectedImagePorts.forEach((port) => {
        if (port === "images-out") return;
        const node = document.querySelector(`#create-panel-workflow .workflow-port[data-port="${CSS.escape(port)}"]`)?.closest(".workflow-node");
        const uploadId = node?.dataset?.uploadId || "";
        if (uploadId) selectedIds.push(uploadId);
    });
    for (const port of connectedImagePorts) {
        if (port === "images-out") continue;
        const node = document.querySelector(`#create-panel-workflow .workflow-port[data-port="${CSS.escape(port)}"]`)?.closest(".workflow-node");
        if (!node?._workflowImageFile || node.dataset.uploadId) continue;
        workflowSetOutputProgress(10, `Enviando imagem do card ${node.dataset.title || node.dataset.nodeId || "imagem"}...`, templateKey);
        const uploaded = await uploadTempFileWithRetry(node._workflowImageFile, "image", `imagem ${node.dataset.title || node.dataset.nodeId || "workflow"}`, { showProgress: false });
        if (uploaded?.upload_id) {
            node.dataset.uploadId = uploaded.upload_id;
            selectedIds.push(uploaded.upload_id);
        }
    }
    const uniqueIds = Array.from(new Set(selectedIds.filter(Boolean)));
    return uniqueIds.length ? uniqueIds : allUploadIds;
}

async function workflowEnsureUploadedVideos(templateKey = "") {
    const uploadIds = [];
    for (let index = 0; index < workflowState.videos.length; index += 1) {
        if (workflowState.videos[index]?.upload_id) {
            uploadIds.push(workflowState.videos[index].upload_id);
            continue;
        }
        workflowSetOutputProgress(12 + index, `Enviando vídeo ${index + 1}/${workflowState.videos.length}...`, templateKey);
        const uploaded = await uploadTempFileWithRetry(workflowState.videos[index], "video", `vídeo workflow ${index + 1}`, { showProgress: false });
        if (uploaded?.upload_id) {
            workflowState.videos[index].upload_id = uploaded.upload_id;
            uploadIds.push(uploaded.upload_id);
        }
    }
    workflowState.videoUploadIds = Array.from(new Set(uploadIds.filter(Boolean)));
    return workflowState.videoUploadIds.slice();
}

async function workflowEnsureUploadedAudio(templateKey = "") {
    if (!workflowState.audio) return "";
    if (workflowState.audioUploadId) return workflowState.audioUploadId;
    workflowSetOutputProgress(15, "Enviando áudio do workflow...", templateKey);
    const uploaded = await uploadTempFileWithRetry(workflowState.audio, "audio", "áudio workflow", { showProgress: false });
    workflowState.audioUploadId = uploaded?.upload_id || "";
    return workflowState.audioUploadId;
}

async function workflowRunSeedance() {
    const runTemplateKey = workflowCurrentRuntimeTemplateKey();
    if (workflowTemplateRunInProgress(runTemplateKey)) {
        alert("Este template já está gerando um vídeo. Aguarde finalizar ou use outro template.");
        return;
    }

    const prompt = workflowBuildPrompt();
    if (!prompt) {
        alert("Preencha o bloco Prompt antes de rodar o workflow.");
        workflowFocusNode("prompt");
        return;
    }
    const workflowEngine = document.getElementById("workflow-engine")?.value || "wan2";
    if (workflowEngine === "avatar31" && !workflowHasImageReference()) {
        alert("Avatar 3.1 Plus exige uma imagem no workflow.");
        workflowFocusNode("images");
        return;
    }

    const workflowEstimatePayload = _buildWorkflowEstimatePayload();
    const creditsNeeded = await _resolveCreditsNeededForAction(workflowEstimatePayload, "workflow");
    if (creditsNeeded > 0 && _userCredits < creditsNeeded) {
        showCreditsPurchaseModal();
        return;
    }

    const runBtn = document.getElementById("workflow-run");
    if (runBtn) runBtn.disabled = true;
    const progressEl = document.getElementById("create-progress");
    if (progressEl) progressEl.hidden = true;
    _stopSmoothProgress();
    workflowState.pendingRunSetupTemplateKey = runTemplateKey;
    workflowUpdateTemplateRunState(runTemplateKey, {
        status: "starting",
        isProcessing: true,
        progress: 8,
        message: "Preparando criação do vídeo...",
    });
    workflowSetOutputProgress(8, "Preparando criação do vídeo...", runTemplateKey);

    try {
        const imageUploadIds = await workflowConnectedImageUploadIds(runTemplateKey);
        await workflowEnsureUploadedVideos(runTemplateKey);
        const workflowAudioUploadId = await workflowEnsureUploadedAudio(runTemplateKey);
        if (workflowEngine === "avatar31" && !imageUploadIds.length) {
            throw new Error("Avatar 3.1 Plus exige uma imagem e um áudio no workflow.");
        }
        workflowSetOutputProgress(
            16,
            imageUploadIds.length
                ? "Enviando referências para o gerador..."
                : "Iniciando gerador sem referências visuais...",
            runTemplateKey,
        );

        workflowSyncEngineDurationOptions();
        const duration = parseInt(document.getElementById("workflow-duration")?.value || "10", 10) || 10;
        const aspect = document.getElementById("workflow-aspect")?.value || "16:9";
        const generateAudio = !!document.getElementById("workflow-generate-audio")?.checked;
        const resolution = document.getElementById("workflow-resolution")?.value || workflowPreferredResolutionForEngine(workflowEngine);
        const useLastImageAsFinalFrame = _isSeedanceFamilyEngine(workflowEngine)
            && !!document.getElementById("workflow-seedance-last-frame")?.checked;
        const workflowEngineLabel = workflowGetEngineLabel(workflowEngine);
        if (workflowEngine === "avatar31" && !workflowAudioUploadId) {
            throw new Error("Avatar 3.1 Plus exige uma imagem e um áudio no workflow.");
        }

        const resp = await api("/video/generate-realistic", {
            method: "POST",
            body: JSON.stringify({
                prompt,
                duration,
                aspect_ratio: aspect,
                generate_audio: generateAudio || workflowEngine === "avatar31",
                add_music: false,
                add_narration: false,
                title: "Workflow de vídeo",
                image_upload_id: imageUploadIds[0] || "",
                image_upload_ids: imageUploadIds,
                audio_upload_id: workflowAudioUploadId,
                engine: workflowEngine,
                use_last_image_as_final_frame: useLastImageAsFinalFrame,
                prompt_optimized: false,
                realistic_style: `workflow_visual_${resolution}`,
                interaction_persona: "nenhum",
                disable_persona_reference: true,
            }),
        });

        const projectId = resp.id;
        workflowUpdateTemplateRunState(runTemplateKey, {
            projectId,
            engineLabel: workflowEngineLabel,
            status: "generating_scenes",
            isProcessing: true,
            progress: 25,
            message: `${workflowEngineLabel} está criando seu vídeo...`,
        });
        workflowSetOutputProgress(25, `${workflowEngineLabel} está criando seu vídeo...`, runTemplateKey);
        workflowStartTemplateRunTracking(projectId, workflowEngineLabel, runTemplateKey);
        await updateCreditsDisplay();
        showToast("Geração iniciada. Você pode continuar editando outros templates.", "success");
        loadProjects();
    } catch (error) {
        const message = error?.message || "Erro ao executar workflow.";
        workflowUpdateTemplateRunState(runTemplateKey, {
            status: "failed",
            isProcessing: false,
            message,
        });
        workflowSetOutputError(message, runTemplateKey);
    } finally {
        if (workflowRuntimeTemplateKey(workflowState.pendingRunSetupTemplateKey) === runTemplateKey) {
            workflowState.pendingRunSetupTemplateKey = "";
        }
        if (runBtn) runBtn.disabled = false;
    }
}

function workflowSetOutputProgress(percent, message, templateKey = "") {
    if (!workflowCanRenderOutputForTemplate(templateKey)) return;
    const outputBox = document.getElementById("workflow-output-box");
    if (!outputBox) return;
    const safePercent = Math.max(0, Math.min(100, Number(percent || 0)));
    outputBox.innerHTML = `
        <div class="workflow-output-loader"></div>
        <strong>${workflowEscapeHtml(message || "Criando vídeo...")}</strong>
        <div class="workflow-output-progress"><span style="width:${safePercent}%"></span></div>
        <small>${safePercent}%</small>
    `;
}

function workflowSetOutputError(message, templateKey = "") {
    if (!workflowCanRenderOutputForTemplate(templateKey)) return;
    const outputBox = document.getElementById("workflow-output-box");
    if (!outputBox) return;
    outputBox.innerHTML = `<strong>Não foi possível criar o vídeo.</strong><span>${workflowEscapeHtml(message || "Erro desconhecido.")}</span>`;
}

async function workflowPollVideoProgress(projectId, engineLabel, templateKey = "") {
    const runKey = workflowRuntimeTemplateKey(templateKey || workflowState.templateKey);
    const maxWait = 12 * 60 * 1000;
    const pollInterval = 4000;
    const start = Date.now();
    while (Date.now() - start < maxWait) {
        await new Promise((resolve) => setTimeout(resolve, pollInterval));
        const resp = await fetch(`${API}/video/projects/${projectId}`, { headers: getHeaders() });
        if (!resp.ok) continue;
        const data = await resp.json();
        const progress = Number(data.progress || 0);
        const status = String(data.status || "").toLowerCase();
        const message = progress < 80
            ? `${engineLabel} está criando seu vídeo...`
            : progress < 95
                ? "Finalizando vídeo..."
                : "Preparando resultado...";
        workflowUpdateTemplateRunState(runKey, {
            projectId,
            engineLabel,
            status,
            isProcessing: ["pending", "generating_scenes", "generating_clips", "rendering"].includes(status),
            progress,
            message,
            errorMessage: data.error_message || "",
        });
        workflowSetOutputProgress(progress, message, runKey);
        if (status === "completed") return data;
        if (status === "failed") throw new Error(data.error_message || "Falha na geração do vídeo.");
    }
    throw new Error("Tempo limite excedido. O vídeo pode ainda estar sendo gerado na lista de projetos.");
}

async function workflowRenderCompletedVideo(projectId, templateKey = "") {
    const runKey = workflowRuntimeTemplateKey(templateKey || workflowState.templateKey);
    const completionMessage = "O resultado apareceu na lista de projetos.";
    const outputBox = document.getElementById("workflow-output-box");
    const detail = await api(`/video/projects/${projectId}`);
    const render = _pickLatestAvailableRender(detail.renders || []);
    const videoUrl = String(render?.video_url || "").trim();

    workflowUpdateTemplateRunState(runKey, {
        projectId,
        status: "completed",
        isProcessing: false,
        progress: 100,
        message: completionMessage,
        videoUrl,
    });

    if (!workflowCanRenderOutputForTemplate(runKey) || !outputBox) return;
    if (videoUrl) {
        outputBox.innerHTML = `<video class="workflow-output-video" src="${workflowEscapeHtml(videoUrl)}" controls playsinline></video><strong>Vídeo pronto.</strong>`;
    } else {
        outputBox.innerHTML = `<strong>Vídeo pronto.</strong><span>${completionMessage}</span>`;
    }
}

async function _refreshSimilarProject({ silent = false, preserveUnifiedTags = null } = {}) {
    const projectId = Number(similarState.projectId || 0);
    if (!projectId) return;

    try {
        const project = await api(`/video/projects/${projectId}`);
        if (preserveUnifiedTags) {
            project.tags = _mergeSimilarUnifiedPromptTags(project.tags, preserveUnifiedTags);
        }
        const tags = _safeSimilarTags(project.tags);
        const status = String(project.status || "").toLowerCase();
        const progress = Number(project.progress || 0);
        const isProcessing = ["generating_scenes", "generating_clips", "rendering"].includes(status);
        const rawStage = String(tags.similar_stage || "").trim();
        const stage = _resolveSimilarBusyStage(rawStage, status) || rawStage;
        const activeSceneGenerationIds = _reconcileSimilarPendingBusySceneIds(project, tags);
        const lockGlobalUi = isProcessing && !["generating_scene", "regenerating_scene", "generating_previews"].includes(stage);
        const suppressGlobalStatus = status !== "failed" && (
            (isProcessing && ["generating_scene", "regenerating_scene", "generating_previews"].includes(stage))
            || (!isProcessing && ["generating_scene", "regenerating_scene", "generating_previews"].includes(rawStage))
            || (!isProcessing && ["scene_edited", "scene_image_ready", "preview_ready"].includes(rawStage))
        );
        const stageLabel = stage === "downloading_reference" && String(tags.similar_source_type || "").trim().toLowerCase() === "upload"
            ? "Preparando vídeo de referência..."
            : SIMILAR_STAGE_LABELS[stage] || "Processando modo semelhante...";
        const detectedMode = _resolveSimilarDetectedMode(tags);
        const detectedModeLabel = SIMILAR_DETECTED_MODE_LABELS[detectedMode] || "";

        similarState.status = status;
        similarState.progress = progress;

        let kind = "running";
        if (status === "failed") {
            kind = "error";
        } else if (status === "completed") {
            kind = "success";
        }

        let message = stageLabel;
        if (status === "failed" && project.error_message) {
            message = project.error_message;
        } else if (status === "completed") {
            message = "Vídeo final pronto. Você pode assistir na lista de projetos.";
        } else if ((stage === "analysis_ready" || stage === "analysis_general_ready") && detectedModeLabel) {
            message = `${stageLabel} ${detectedModeLabel}`;
        }

        const showGlobalStatus = status === "failed" || isProcessing || activeSceneGenerationIds.length > 0;
        if (!isProcessing && !activeSceneGenerationIds.length) {
            _clearSimilarBusyIntent();
        }

        _setSimilarStatus(
            showGlobalStatus && !suppressGlobalStatus ? message : "",
            kind,
            showGlobalStatus && !suppressGlobalStatus && kind === "running"
                ? { progress: progress > 0 ? progress : 4, stage }
                : {},
        );
        similarState.lastProjectSnapshot = project;
        _syncSimilarSourcePreview(project);
        scheduleSimilarAnalysisCreditEstimates();
        _renderSimilarUnifiedPrompt(project);
        _renderSimilarScenes(project);
        _updateSimilarGenerationStep(project, tags);
        _updateSimilarBusyOverlay(project, tags, {
            stage,
            status,
            progress,
            sceneId: activeSceneGenerationIds[0] || Number(tags.similar_regenerating_scene_id || 0) || similarState.pendingBusySceneId,
        });
        _refreshSimilarButtonsDisabled(lockGlobalUi);

        if (!isProcessing && !activeSceneGenerationIds.length) {
            _stopSimilarPolling();
            _refreshSimilarButtonsDisabled(false);
        }

        if (status === "completed" || status === "failed") {
            _stopSimilarPolling();
            loadProjects();
            _refreshSimilarButtonsDisabled(false);
        }
    } catch (error) {
        if (!silent) {
            _setSimilarStatus(`Erro ao atualizar projeto semelhante: ${error.message}`, "error");
        }
        _stopSimilarPolling();
        _refreshSimilarButtonsDisabled(false);
        _clearSimilarBusyIntent();
        _hideSimilarBusyOverlay();
    }
}

function _startSimilarPolling() {
    _stopSimilarPolling();
    similarState.pollingTimer = setInterval(() => {
        _refreshSimilarProject({ silent: true });
    }, 4000);
}

