async function similarVerifySource() {
    const sourceEl = document.getElementById("similar-source-url");
    const sourceFile = similarState.sourceVideoFile;
    const sourceUrl = _normalizeSimilarSourceUrl(sourceEl?.value || "");
    const currentSourceKey = _getSimilarCurrentSourceKey();

    if (!sourceUrl && !sourceFile) {
        alert("Cole o link do vídeo de referência ou envie um vídeo antes de verificar.");
        return;
    }
    if (!currentSourceKey) {
        alert("Não foi possível identificar a origem do vídeo para verificar.");
        return;
    }

    similarState.sourceVerificationToken = Number(similarState.sourceVerificationToken || 0) + 1;
    const verificationToken = similarState.sourceVerificationToken;
    similarState.sourceVerificationStatus = "pending";
    similarState.sourceVerificationMessage = sourceFile
        ? "Lendo a duração do vídeo enviado..."
        : "Baixando o vídeo de referência e medindo a duração para calcular o custo...";
    similarState.verifiedSourceKey = "";
    similarState.verifiedSourceUploadId = "";
    similarState.verifiedSourcePreviewUrl = "";
    similarState.verifiedSourceUrl = "";
    similarState.verifiedSourceName = "";
    _hideSimilarAnalysisEstimateBadges();
    _refreshSimilarButtonsDisabled(true);
    _queueSimilarScroll({ preferStatus: true, preferSource: true });

    try {
        let durationSeconds = 0;

        if (sourceFile) {
            if (!similarState.sourceVideoObjectUrl) {
                try {
                    similarState.sourceVideoObjectUrl = URL.createObjectURL(sourceFile);
                } catch (_) {
                    similarState.sourceVideoObjectUrl = "";
                }
            }
            if (!similarState.sourceVideoObjectUrl) {
                throw new Error("Não foi possível preparar a prévia do vídeo enviado.");
            }

            _renderSimilarUploadedSourcePreview();
            durationSeconds = await _awaitSimilarSourceDuration();
            if (similarState.sourceVerificationToken !== verificationToken) return;

            similarState.verifiedSourcePreviewUrl = String(similarState.sourceVideoObjectUrl || "").trim();
            similarState.verifiedSourceName = String(similarState.sourceVideoName || sourceFile.name || "video").trim();
        } else {
            _clearSimilarSourcePreview();
            _setSimilarStatus("Baixando o vídeo de referência para verificar a duração...", "running");

            const response = await api("/video/workflow/import-video-url", {
                method: "POST",
                body: JSON.stringify({
                    source_url: sourceUrl,
                    formato: "video_melhor",
                }),
            });

            const uploadId = String(response?.upload_id || "").trim();
            const previewUrl = String(response?.preview_url || "").trim();
            if (!uploadId || !previewUrl) {
                throw new Error("Não foi possível preparar o vídeo para verificação.");
            }

            _renderSimilarResolvedSourcePreview(previewUrl, {
                title: "Vídeo verificado",
                sourceUrl: String(response?.source_url || sourceUrl).trim() || sourceUrl,
                sourceKey: currentSourceKey,
            });

            durationSeconds = await _awaitSimilarSourceDuration();
            if (similarState.sourceVerificationToken !== verificationToken) return;

            similarState.verifiedSourceUploadId = uploadId;
            similarState.verifiedSourcePreviewUrl = previewUrl;
            similarState.verifiedSourceUrl = String(response?.source_url || sourceUrl).trim() || sourceUrl;
            similarState.verifiedSourceName = String(response?.file_name || "video").trim() || "video";
        }

        similarState.verifiedSourceKey = currentSourceKey;
        similarState.sourceVerificationStatus = "ready";
        similarState.sourceVerificationMessage = "";
        _setSimilarStatus("", "running");
    } catch (error) {
        if (similarState.sourceVerificationToken !== verificationToken) return;
        similarState.sourceVerificationStatus = "error";
        similarState.sourceVerificationMessage = error.message || "Não foi possível verificar o vídeo.";
        similarState.verifiedSourceKey = "";
        similarState.verifiedSourceUploadId = "";
        similarState.verifiedSourcePreviewUrl = "";
        similarState.verifiedSourceUrl = "";
        similarState.verifiedSourceName = "";
        _hideSimilarAnalysisEstimateBadges();
        _setSimilarStatus(`Erro ao verificar o vídeo: ${similarState.sourceVerificationMessage}`, "error");
    } finally {
        if (similarState.sourceVerificationToken === verificationToken) {
            _refreshSimilarButtonsDisabled(false);
        }
    }
}

async function similarStartAnalysis(analysisMode = "scene") {
    const sourceEl = document.getElementById("similar-source-url");
    const titleEl = document.getElementById("similar-title");
    const aspectEl = document.getElementById("similar-aspect");
    const normalizedAnalysisMode = String(analysisMode || "scene").trim().toLowerCase() === "general"
        ? "general"
        : "scene";

    const sourceUrl = _normalizeSimilarSourceUrl(sourceEl?.value || "");
    const sourceFile = similarState.sourceVideoFile;
    const verifiedUploadId = String(similarState.verifiedSourceUploadId || "").trim();
    if (!sourceUrl && !sourceFile && !verifiedUploadId) {
        alert("Cole o link do vídeo de referência ou envie um vídeo para analisar.");
        return;
    }
    if (!_isSimilarSourceVerified()) {
        alert("Clique em Verificar vídeo antes de iniciar a análise.");
        return;
    }

    const payload = {
        source_url: verifiedUploadId ? "" : sourceUrl,
        source_upload_id: "",
        source_upload_name: "",
        title: String(titleEl?.value || "").trim(),
        aspect_ratio: aspectEl?.value || "16:9",
        analysis_mode: normalizedAnalysisMode,
    };

    similarState.engineManuallySelected = false;
    similarState.detectedMode = "";
    similarState.detectedReason = "";
    similarState.detectedConfidence = 0;
    _setSimilarEngineSelection("lite2", { markManual: false });
    _clearSimilarUnifiedPrompt();

    _refreshSimilarButtonsDisabled(true);

    try {
        const analysisLabel = normalizedAnalysisMode === "general" ? "análise geral" : "análise por cena";
        const verifiedPreviewUrl = String(similarState.verifiedSourcePreviewUrl || "").trim();

        if (verifiedUploadId) {
            payload.source_upload_id = verifiedUploadId;
            payload.source_upload_name = String(similarState.verifiedSourceName || "video").trim() || "video";
            payload.source_url = "";
            if (verifiedPreviewUrl) {
                _renderSimilarResolvedSourcePreview(verifiedPreviewUrl, {
                    title: sourceFile ? "Prévia do vídeo enviado" : "Vídeo verificado",
                    sourceUrl: String(similarState.verifiedSourceUrl || "").trim(),
                    sourceKey: String(similarState.verifiedSourceKey || verifiedPreviewUrl).trim(),
                });
            }
            _setSimilarStatus(`Iniciando ${analysisLabel} do vídeo verificado...`, "running");
        } else if (sourceFile) {
            _setSimilarStatus(`Enviando vídeo verificado para ${analysisLabel}...`, "running");
            const uploaded = await uploadTempFileWithRetry(sourceFile, "video", "video de referencia");
            const uploadId = String(uploaded?.upload_id || "").trim();
            if (!uploadId) {
                throw new Error("Falha ao enviar o vídeo de referência.");
            }
            payload.source_upload_id = uploadId;
            payload.source_upload_name = String(similarState.sourceVideoName || sourceFile.name || "video").trim();
            _setSimilarStatus(`Iniciando ${analysisLabel} do vídeo enviado...`, "running");
        } else {
            _setSimilarStatus(`Iniciando ${analysisLabel} do vídeo de referência...`, "running");
        }

        _queueSimilarScroll({ preferStatus: true, preferSource: true, preferScenes: true });

        const response = await api("/video/similar/analyze", {
            method: "POST",
            body: JSON.stringify(payload),
        });

        const projectId = Number(response?.project_id || 0);
        if (!projectId) {
            throw new Error("Resposta inválida ao iniciar a análise.");
        }

        similarState.projectId = projectId;
        similarState.lastProjectSnapshot = null;
        similarState.sceneEngineSelectionBySceneId = {};
        similarState.sceneDraftsBySceneId = {};
        similarState.sceneMergeSelectionBySceneId = {};
        _clearAllSimilarScenePendingUploads();
        similarState.pendingImageUploadsBySceneId = {};
        _clearSimilarUnifiedPendingUploads();
        similarState.unifiedUseLastImageAsFinalFrame = false;
        similarState.unifiedLastFrameDirty = false;
        _setSimilarStatus(
            normalizedAnalysisMode === "general"
                ? "Análise geral iniciada. Aguardando o retorno da IA..."
                : "Análise por cena iniciada. Aguardando o retorno da IA...",
            "running",
        );
        _startSimilarPolling();
        await _refreshSimilarProject();
    } catch (error) {
        _setSimilarStatus(`Erro ao iniciar a análise: ${error.message}`, "error");
    } finally {
        _refreshSimilarButtonsDisabled(false);
    }
}

async function similarBuildUnifiedPrompt() {
    const projectId = Number(similarState.projectId || 0);
    const project = similarState.lastProjectSnapshot;
    const scenes = Array.isArray(project?.scenes) ? project.scenes : [];

    if (!projectId || !scenes.length) {
        alert("Analise o video antes de gerar o prompt unico.");
        return;
    }

    _refreshSimilarButtonsDisabled(true);
    _setSimilarStatus("Transformando a analise em um prompt unico...", "running");
    _queueSimilarScroll({ preferUnified: true, preferStatus: true });

    try {
        const response = await api(`/video/projects/${projectId}/similar/unified-prompt`, {
            method: "POST",
        });

        const promptText = String(response?.prompt || "").trim();
        if (!promptText) {
            throw new Error("Resposta invalida ao criar prompt unico");
        }

        const nextTags = _buildSimilarUnifiedPromptTags(project?.tags, response);
        const nextProject = {
            ...(project || {}),
            tags: nextTags,
        };

        similarState.lastProjectSnapshot = nextProject;
        _renderSimilarUnifiedPrompt(nextProject);
        await _refreshSimilarProject({ silent: true, preserveUnifiedTags: nextTags });
        _setSimilarStatus("", "running");
        showToast("Prompt unico criado.", "success");
    } catch (error) {
        _setSimilarStatus(`Erro ao gerar prompt unico: ${error.message}`, "error");
        showToast(`Erro ao gerar prompt unico: ${error.message}`, "error");
    } finally {
        _refreshSimilarButtonsDisabled(false);
    }
}

async function similarCopyUnifiedPrompt() {
    const textEl = document.getElementById("similar-unified-prompt-text");
    const promptText = String(textEl?.value || "").trim();
    if (!promptText) {
        showToast("Gere o prompt unico antes de copiar.", "error");
        return;
    }

    try {
        if (navigator.clipboard?.writeText) {
            await navigator.clipboard.writeText(promptText);
        } else if (textEl) {
            textEl.focus();
            textEl.select();
            textEl.setSelectionRange(0, textEl.value.length);
            const copied = document.execCommand("copy");
            if (!copied) {
                throw new Error("Falha ao copiar");
            }
        } else {
            throw new Error("Campo indisponivel");
        }
        showToast("Prompt unico copiado.", "success");
    } catch (error) {
        showToast(`Erro ao copiar prompt unico: ${error.message || error}`, "error");
    }
}

async function similarGenerateUnifiedScene() {
    const projectId = Number(similarState.projectId || 0);
    const project = similarState.lastProjectSnapshot;
    const promptEl = document.getElementById("similar-unified-prompt-text");
    const promptText = String(promptEl?.value || project?.tags?.similar_unified_prompt || "").trim();

    if (!projectId) {
        alert("Analise o video antes de gerar a cena unica.");
        return;
    }
    if (!promptText) {
        showToast("Gere ou escreva o prompt unico antes de criar a cena.", "error");
        return;
    }

    const tags = _safeSimilarTags(project?.tags);
    const engine = _getSimilarUnifiedSelectedEngine(tags);
    const duration = _getSimilarUnifiedSelectedDuration(tags);
    const uploadIds = [];
    _getSimilarUnifiedPendingUploads().forEach((item) => {
        const uploadId = String(item?.upload_id || "").trim();
        if (uploadId && !uploadIds.includes(uploadId)) {
            uploadIds.push(uploadId);
        }
    });
    const useLastImageAsFinalFrame = _isSeedanceFamilyEngine(engine)
        && !!document.getElementById("similar-unified-seedance-last-frame")?.checked;

    try {
        _setSimilarBusyIntent("generating_unified_scene");
        _updateSimilarBusyOverlay(similarState.lastProjectSnapshot, tags, {
            stage: "generating_unified_scene",
            status: "generating_clips",
            progress: 4,
        });
        _queueSimilarScroll({ preferUnified: true, preferStatus: true });
        _refreshSimilarButtonsDisabled(true);
        if (similarState.lastProjectSnapshot) {
            _renderSimilarUnifiedPrompt(similarState.lastProjectSnapshot);
        }
        await api(`/video/projects/${projectId}/similar/generate-unified-scene`, {
            method: "POST",
            body: JSON.stringify({
                engine,
                duration_seconds: duration,
                prompt_override: promptText,
                aspect_ratio: document.getElementById("similar-aspect")?.value || "16:9",
                image_upload_ids: uploadIds,
                use_last_image_as_final_frame: useLastImageAsFinalFrame,
            }),
        });
        _setSimilarStatus("Geração do vídeo iniciada...", "running");
        _startSimilarPolling();
        await _refreshSimilarProject();
    } catch (error) {
        showToast(`Erro ao gerar a cena unica: ${error.message}`, "error");
        _clearSimilarBusyIntent();
        _hideSimilarBusyOverlay();
        _refreshSimilarButtonsDisabled(false);
    }
}

function similarUploadUnifiedImages() {
    const input = document.getElementById("similar-unified-image-input");
    if (!input) return;
    input.value = "";
    input.click();
}

async function _handleSimilarUnifiedImageInput(event) {
    const projectId = Number(similarState.projectId || 0);
    const files = Array.from(event.target?.files || []);
    event.target.value = "";

    if (!projectId || !files.length) {
        return;
    }

    try {
        const existingUploads = _getSimilarUnifiedPendingUploads();
        const remainingSlots = Math.max(0, 6 - existingUploads.length);
        if (!remainingSlots) {
            showToast("A cena unica ja possui 6 imagens enviadas. Limpe antes de enviar novas.", "error");
            return;
        }

        const selectedFiles = files.slice(0, remainingSlots);
        if (files.length > selectedFiles.length) {
            showToast(`Limite de 6 imagens para a cena unica. So ${selectedFiles.length} nova(s) imagem(ns) foi(ram) adicionada(s).`, "error");
        }

        for (let index = 0; index < selectedFiles.length; index += 1) {
            const file = selectedFiles[index];
            if (!file.type.match(/^image\/(jpeg|png|webp)$/)) {
                throw new Error("Use somente imagens JPG, PNG ou WebP.");
            }
            _setSimilarUnifiedUploadStatus(`Enviando imagem ${index + 1}/${selectedFiles.length} da cena unica...`, "running");
            const uploaded = await uploadTempFileWithRetry(file, "image", "imagem da cena unica", { showProgress: false });
            const uploadId = String(uploaded?.upload_id || "").trim();
            if (!uploadId) {
                throw new Error("Upload da imagem retornou sem identificador. Tente novamente.");
            }

            existingUploads.push({
                upload_id: uploadId,
                file_name: String(file.name || `imagem-${existingUploads.length + 1}`),
                preview_url: URL.createObjectURL(file),
            });
        }

        _setSimilarUnifiedUploadStatus(
            "Imagem(ns) enviada(s). Clique no + novamente se quiser; todas entram na geracao da cena unica.",
            "running",
        );
        _syncSimilarUnifiedUploadUi(similarState.lastProjectSnapshot);
        showToast("Imagem(ns) enviada(s) para a cena unica.", "success");
    } catch (error) {
        _setSimilarUnifiedUploadStatus(`Erro ao enviar imagem: ${error.message}`, "error");
        showToast(`Erro ao enviar imagem: ${error.message}`, "error");
    }
}

function similarClearUnifiedUploads() {
    const pendingUploads = _getSimilarUnifiedPendingUploads();
    if (!pendingUploads.length) return;

    _clearSimilarUnifiedPendingUploads();
    _setSimilarUnifiedUploadStatus("");
    _syncSimilarUnifiedUploadUi(similarState.lastProjectSnapshot);
    _renderSimilarUnifiedPrompt(similarState.lastProjectSnapshot);
    showToast("Imagens da cena unica removidas.", "success");
}

