function _formatScriptImageCreatorCostLabel(credits) {
    const parsed = Number.parseInt(String(credits), 10);
    if (!Number.isFinite(parsed) || parsed <= 0) {
        return "Grátis";
    }
    return `${_formatCreditsInt(parsed)} ${parsed === 1 ? "crédito" : "créditos"}`;
}

function _setScriptImageCreatorEstimate(modelId, credits = null) {
    _scriptImageCreatorState.selectedEstimateModelId = String(modelId || "").trim();
    if (credits === null || credits === undefined || credits === "") {
        _scriptImageCreatorState.selectedEstimateCredits = null;
    } else {
        const parsed = Number.parseInt(String(credits), 10);
        _scriptImageCreatorState.selectedEstimateCredits = Number.isFinite(parsed) ? Math.max(0, parsed) : null;
    }
    _syncScriptImageCreatorModelCardCosts();
}

function _syncScriptImageCreatorModelCardCosts() {
    const selectedId = String(document.getElementById("script-image-generator-model")?.value || DEFAULT_SCRIPT_IMAGE_CREATOR_MODEL_ID).trim();

    document.querySelectorAll(".script-image-model-card").forEach((button) => {
        const costEl = button.querySelector(".script-image-model-card-price");
        if (!costEl) return;

        const modelId = String(button.dataset.model || "").trim();
        const meta = SCRIPT_IMAGE_CREATOR_MODELS.find((item) => item.id === modelId);
        let label = String(meta?.defaultCostLabel || "").trim();

        if (modelId === selectedId && _scriptImageCreatorState.selectedEstimateModelId === modelId) {
            label = _scriptImageCreatorState.selectedEstimateCredits === null
                ? label
                : _formatScriptImageCreatorCostLabel(_scriptImageCreatorState.selectedEstimateCredits);
        }

        costEl.hidden = !label;
        costEl.textContent = label;
        costEl.classList.toggle("is-free", /^gr[aá]tis$/i.test(label));
    });
}

function _getScriptImageCreatorModelMeta() {
    const modelSelect = document.getElementById("script-image-generator-model");
    const selectedId = String(modelSelect?.value || DEFAULT_SCRIPT_IMAGE_CREATOR_MODEL_ID).trim();
    const baseMeta = SCRIPT_IMAGE_CREATOR_MODELS.find((item) => item.id === selectedId)
        || SCRIPT_IMAGE_CREATOR_MODELS.find((item) => item.id === DEFAULT_SCRIPT_IMAGE_CREATOR_MODEL_ID)
        || SCRIPT_IMAGE_CREATOR_MODELS[0];
    if (_scriptImageCreatorState.referenceFiles.length > 0 && baseMeta?.editOverrides) {
        return {
            ...baseMeta,
            ...baseMeta.editOverrides,
        };
    }
    return baseMeta;
}

function _normalizeScriptImageCreatorCount(rawValue) {
    const parsed = Number.parseInt(String(rawValue || "").trim(), 10);
    if (!Number.isFinite(parsed)) {
        return 1;
    }
    return Math.min(SCRIPT_IMAGE_CREATOR_MAX_SEQUENCE_COUNT, Math.max(1, parsed));
}

function _setScriptImageCreatorCountValue(rawValue) {
    const normalized = _normalizeScriptImageCreatorCount(rawValue);
    const countSelect = document.getElementById("script-image-generator-count");
    if (!countSelect) {
        return normalized;
    }

    Array.from(countSelect.options).forEach((option) => {
        if (option.dataset.dynamic === "true" && option.value !== String(normalized)) {
            option.remove();
        }
    });

    let option = Array.from(countSelect.options).find((item) => item.value === String(normalized));
    if (!option) {
        option = document.createElement("option");
        option.value = String(normalized);
        option.textContent = String(normalized);
        option.dataset.dynamic = "true";
        countSelect.appendChild(option);
    }
    countSelect.value = String(normalized);
    return normalized;
}

function _getScriptImageCreatorCount() {
    return _setScriptImageCreatorCountValue(document.getElementById("script-image-generator-count")?.value || "1");
}

function _ensureScriptImageCreatorPromptCapacity(count) {
    const desired = _normalizeScriptImageCreatorCount(count);
    if (!Array.isArray(_scriptImageCreatorState.promptValues) || !_scriptImageCreatorState.promptValues.length) {
        _scriptImageCreatorState.promptValues = [""];
    }
    while (_scriptImageCreatorState.promptValues.length < desired) {
        _scriptImageCreatorState.promptValues.push("");
    }
}

function _setScriptImageCreatorSequenceValue(mode) {
    const normalized = SCRIPT_IMAGE_CREATOR_SEQUENCE_MODES.has(String(mode || "").trim())
        ? String(mode || "").trim()
        : DEFAULT_SCRIPT_IMAGE_CREATOR_SEQUENCE_MODE;
    const sequenceSelect = document.getElementById("script-image-generator-sequence-mode");
    if (sequenceSelect) {
        sequenceSelect.value = normalized;
    }
    return normalized;
}

function _getScriptImageCreatorSequenceMode() {
    return _setScriptImageCreatorSequenceValue(
        document.getElementById("script-image-generator-sequence-mode")?.value || DEFAULT_SCRIPT_IMAGE_CREATOR_SEQUENCE_MODE,
    );
}

function _getScriptImageCreatorPromptInput(index = 0) {
    return document.querySelector(`#script-image-generator-prompt-list textarea[data-prompt-index="${index}"]`);
}

function _getScriptImageCreatorSceneResultIndex(sceneIndex) {
    for (let index = 0; index < _scriptImageCreatorState.generatedImages.length; index += 1) {
        const item = _scriptImageCreatorState.generatedImages[index];
        const currentSceneIndex = Number.parseInt(String(item?.scene_index ?? index), 10);
        if (currentSceneIndex === sceneIndex) {
            return index;
        }
    }
    return -1;
}

function _getScriptImageCreatorSceneResult(sceneIndex) {
    const resultIndex = _getScriptImageCreatorSceneResultIndex(sceneIndex);
    return resultIndex >= 0 ? _scriptImageCreatorState.generatedImages[resultIndex] : null;
}

function _getScriptImageCreatorPromptValues(count = null) {
    const desiredCount = _normalizeScriptImageCreatorCount(count ?? (_isScriptImageCreatorEditMode() ? 1 : _getScriptImageCreatorCount()));
    _ensureScriptImageCreatorPromptCapacity(desiredCount);
    return _scriptImageCreatorState.promptValues.slice(0, desiredCount).map((value) => String(value || ""));
}

function _scriptImageCreatorPromptSuggestsMultipleImages(promptText) {
    const normalized = String(promptText || "").trim().toLowerCase();
    if (!normalized) return false;
    return /(\d{1,2})\s*(imagens?|cenas?|fotos?|frames?)/i.test(normalized)
        || /foto por foto|cena por cena|imagem por imagem/i.test(normalized);
}

function focusScriptImageCreatorPrompt(index = 0) {
    const promptInput = _getScriptImageCreatorPromptInput(index);
    if (!promptInput) {
        return;
    }
    promptInput.focus();
    promptInput.select();
}

async function _planScriptImageCreatorPrompts(options = {}) {
    if (_scriptImageCreatorState.busy || _scriptImageCreatorState.promptPlannerBusy) {
        return null;
    }

    const isEditing = _isScriptImageCreatorEditMode();
    const initialCount = isEditing ? 1 : _getScriptImageCreatorCount();
    const targetIndex = Number.isInteger(options.targetIndex) ? Math.max(0, options.targetIndex) : null;
    const rewriteAll = !!options.rewriteAll;
    const currentPrompts = _getScriptImageCreatorPromptValues(initialCount);
    const trimmedPrompts = currentPrompts.map((value) => String(value || "").trim());
    const masterPrompt = String(trimmedPrompts[0] || "").trim();
    const seedPrompt = targetIndex === null ? masterPrompt : (String(trimmedPrompts[targetIndex] || "").trim() || masterPrompt);
    if (!seedPrompt) {
        alert("Descreva o prompt mestre antes de criar os prompts.");
        return null;
    }

    const targetLabel = targetIndex === null && initialCount > 1
        ? "Criando prompts detalhados para a sequência..."
        : `Criando prompt da cena ${Math.min((targetIndex ?? 0) + 1, Math.max(initialCount, 1))}...`;

    _scriptImageCreatorState.promptPlannerBusy = true;
    _scriptImageCreatorState.promptPlannerTargetIndex = targetIndex === null ? -1 : targetIndex;
    renderScriptImageCreatorPromptEditors();
    setScriptImageCreatorStatus(options.statusMessage || targetLabel, "info");

    try {
        const response = await api("/video/script-image/plan-prompts", {
            method: "POST",
            body: JSON.stringify({
                master_prompt: masterPrompt || seedPrompt,
                scene_count: initialCount,
                aspect_ratio: document.getElementById("script-image-generator-aspect")?.value || "1:1",
                target_scene_index: targetIndex,
                existing_prompts: currentPrompts,
                reference_image_count: _scriptImageCreatorState.referenceFiles.length,
                sequence_mode: isEditing ? "first-generated" : _getScriptImageCreatorSequenceMode(),
                rewrite_all: rewriteAll,
            }),
        });

        let nextCount = _normalizeScriptImageCreatorCount(response?.scene_count || initialCount);
        if (isEditing) {
            nextCount = 1;
        } else {
            _setScriptImageCreatorCountValue(nextCount);
            _scriptImageCreatorState.customCountOpen = nextCount > SCRIPT_IMAGE_CREATOR_PRESET_COUNTS[SCRIPT_IMAGE_CREATOR_PRESET_COUNTS.length - 1];
        }

        _ensureScriptImageCreatorPromptCapacity(nextCount);
        const incomingPrompts = Array.isArray(response?.prompts) ? response.prompts : [];
        const mergedPrompts = _getScriptImageCreatorPromptValues(nextCount);
        for (let index = 0; index < nextCount; index += 1) {
            const incoming = String(incomingPrompts[index] || "").trim();
            if (incoming) {
                mergedPrompts[index] = incoming;
            }
        }
        _scriptImageCreatorState.promptValues = mergedPrompts;
        syncScriptImageCreatorControls();
        return {
            sceneCount: nextCount,
            prompts: mergedPrompts,
        };
    } finally {
        _scriptImageCreatorState.promptPlannerBusy = false;
        _scriptImageCreatorState.promptPlannerTargetIndex = -1;
        syncScriptImageCreatorControls();
    }
}

async function createScriptImageCreatorPrompt(index) {
    const totalCount = _isScriptImageCreatorEditMode() ? 1 : _getScriptImageCreatorCount();
    const planEntireSequence = !_isScriptImageCreatorEditMode() && totalCount > 1 && index === 0;

    try {
        const plan = await _planScriptImageCreatorPrompts({
            targetIndex: planEntireSequence ? null : index,
            rewriteAll: planEntireSequence || totalCount === 1,
        });
        if (!plan) {
            return;
        }
        focusScriptImageCreatorPrompt(Math.min(index, Math.max(plan.sceneCount - 1, 0)));
        setScriptImageCreatorStatus(
            plan.sceneCount > 1 ? `${plan.sceneCount} prompts prontos para a sequência.` : "Prompt pronto para gerar a imagem.",
            "success",
        );
        showToast(
            plan.sceneCount > 1 ? "Prompts da sequência criados com sucesso." : "Prompt criado com sucesso.",
            "success",
        );
    } catch (error) {
        setScriptImageCreatorStatus(`Erro ao criar prompt: ${error.message}`, "error");
    }
}

function _getScriptImageCreatorPromptPlaceholder(index, totalCount) {
    const meta = _getScriptImageCreatorModelMeta();
    if (_isScriptImageCreatorEditMode()) {
        return "Ajuste o prompt";
    }
    if (meta.requiresReference) {
        return index === 0
            ? "Cena inicial"
            : `Cena ${index + 1}`;
    }
    if (totalCount > 1) {
        return index === 0
            ? "Prompt mestre"
            : `Cena ${index + 1}`;
    }
    return "Descreva a imagem";
}

function _getScriptImageCreatorActionIcon(kind) {
    if (kind === "edit") {
        return '<svg class="script-image-generator-prompt-card-action-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M12 20h9"></path><path d="M16.5 3.5a2.12 2.12 0 1 1 3 3L7 19l-4 1 1-4 12.5-12.5z"></path></svg>';
    }
    return '<svg class="script-image-generator-prompt-card-action-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M12 3l1.9 4.6L18.5 9.5 13.9 11.4 12 16l-1.9-4.6L5.5 9.5l4.6-1.9L12 3z"></path><path d="M19 14l.9 2.1L22 17l-2.1.9L19 20l-.9-2.1L16 17l2.1-.9L19 14z"></path></svg>';
}

function handleScriptImageCreatorPromptInput(index, value) {
    _ensureScriptImageCreatorPromptCapacity(index + 1);
    _scriptImageCreatorState.promptValues[index] = String(value || "");
}

function renderScriptImageCreatorPromptEditors() {
    const host = document.getElementById("script-image-generator-prompt-list");
    const summary = document.getElementById("script-image-generator-prompt-summary");
    if (!host) return;

    const totalCount = _isScriptImageCreatorEditMode() ? 1 : _getScriptImageCreatorCount();
    _ensureScriptImageCreatorPromptCapacity(totalCount);
    if (summary) {
        summary.textContent = String(totalCount);
    }

    host.innerHTML = "";
    for (let index = 0; index < totalCount; index += 1) {
        const card = document.createElement("div");
        card.className = "script-image-generator-prompt-card";
        const isMasterCard = !_isScriptImageCreatorEditMode() && totalCount > 1 && index === 0;
        if (isMasterCard) {
            card.classList.add("is-base");
        }

        const head = document.createElement("div");
        head.className = "script-image-generator-prompt-card-head";

        const copy = document.createElement("div");
        copy.className = "script-image-generator-prompt-card-copy";

        const title = document.createElement("strong");
        title.textContent = _isScriptImageCreatorEditMode() ? "Editar" : (isMasterCard ? "Mestre" : `Cena ${index + 1}`);

        copy.appendChild(title);

        const actions = document.createElement("div");
        actions.className = "script-image-generator-prompt-card-actions";

        const createPromptBtn = document.createElement("button");
        createPromptBtn.type = "button";
        createPromptBtn.className = "script-image-generator-prompt-card-action is-primary";
        const createPromptBusy = _scriptImageCreatorState.promptPlannerBusy
            && ((_scriptImageCreatorState.promptPlannerTargetIndex < 0 && index === 0 && totalCount > 1)
                || _scriptImageCreatorState.promptPlannerTargetIndex === index);
        const createPromptLabel = createPromptBusy
            ? "Criando prompt"
            : (isMasterCard ? "Criar prompts" : "Criar prompt");
        createPromptBtn.title = createPromptLabel;
        createPromptBtn.setAttribute("aria-label", createPromptLabel);
        createPromptBtn.innerHTML = `${_getScriptImageCreatorActionIcon("create")}<span>${createPromptBusy ? "Criando" : "Criar"}</span>`;
        createPromptBtn.disabled = _scriptImageCreatorState.busy || _scriptImageCreatorState.promptPlannerBusy;
        createPromptBtn.onclick = () => {
            createScriptImageCreatorPrompt(index);
        };

        const editPromptBtn = document.createElement("button");
        editPromptBtn.type = "button";
        editPromptBtn.className = "script-image-generator-prompt-card-action";
        editPromptBtn.title = "Editar prompt";
        editPromptBtn.setAttribute("aria-label", "Editar prompt");
        editPromptBtn.innerHTML = `${_getScriptImageCreatorActionIcon("edit")}<span>Editar</span>`;
        editPromptBtn.disabled = _scriptImageCreatorState.busy;
        editPromptBtn.onclick = () => {
            focusScriptImageCreatorPrompt(index);
        };

        actions.appendChild(createPromptBtn);
        actions.appendChild(editPromptBtn);

        head.appendChild(copy);
        head.appendChild(actions);

        const scenePreview = document.createElement("button");
        scenePreview.type = "button";
        scenePreview.className = "script-image-generator-prompt-card-preview";
        scenePreview.style.aspectRatio = _scriptImageCreatorAspectToCssValue(
            document.getElementById("script-image-generator-aspect")?.value || "1:1",
        );

        const sceneResult = _getScriptImageCreatorSceneResult(index);
        const sceneResultIndex = _getScriptImageCreatorSceneResultIndex(index);
        const isGeneratingScene = _scriptImageCreatorState.busy && _scriptImageCreatorState.activeSceneIndex === index;
        const shouldShowScenePreview = Boolean(sceneResult?.image_url) || isGeneratingScene;
        if (sceneResult?.image_url && sceneResultIndex >= 0) {
            scenePreview.classList.add("is-ready");
            if (isGeneratingScene) {
                scenePreview.classList.add("is-loading");
            }
            scenePreview.title = `Abrir resultado da cena ${index + 1}`;
            scenePreview.onclick = () => {
                setActiveScriptImageCreatorResult(sceneResultIndex);
            };

            const previewImage = document.createElement("img");
            previewImage.src = sceneResult.image_url;
            previewImage.alt = `Cena ${index + 1}`;
            scenePreview.appendChild(previewImage);

            const previewBadge = document.createElement("span");
            previewBadge.className = "script-image-generator-prompt-card-preview-badge";
            previewBadge.textContent = isGeneratingScene ? "Gerando" : "Pronta";
            scenePreview.appendChild(previewBadge);
        } else {
            scenePreview.disabled = true;
            if (isGeneratingScene) {
                scenePreview.classList.add("is-loading");
            }

            const emptyState = document.createElement("div");
            emptyState.className = "script-image-generator-prompt-card-preview-empty";

            const emptyTitle = document.createElement("strong");
            emptyTitle.textContent = isGeneratingScene ? "Gerando..." : "";

            emptyState.appendChild(emptyTitle);
            scenePreview.appendChild(emptyState);
        }

        const textarea = document.createElement("textarea");
        textarea.className = "wizard-textarea script-image-generator-prompt";
        textarea.rows = totalCount > 1 ? 6 : 9;
        textarea.maxLength = 5000;
        textarea.placeholder = _getScriptImageCreatorPromptPlaceholder(index, totalCount);
        textarea.dataset.promptIndex = String(index);
        textarea.value = String(_scriptImageCreatorState.promptValues[index] || "");
        textarea.addEventListener("input", (event) => {
            handleScriptImageCreatorPromptInput(index, event.target.value);
        });
        textarea.addEventListener("paste", handleScriptImageCreatorPromptPaste);

        card.appendChild(head);
        card.appendChild(textarea);
        host.appendChild(card);
    }
}

function openScriptImageCreatorCustomCount() {
    if (_isScriptImageCreatorEditMode()) {
        return;
    }
    _scriptImageCreatorState.customCountOpen = true;
    syncScriptImageCreatorControls();
    const manualInput = document.getElementById("script-image-generator-count-manual");
    if (manualInput) {
        if (_getScriptImageCreatorCount() <= SCRIPT_IMAGE_CREATOR_PRESET_COUNTS[SCRIPT_IMAGE_CREATOR_PRESET_COUNTS.length - 1]) {
            manualInput.value = "5";
        }
        manualInput.focus();
        manualInput.select();
    }
}

function handleScriptImageCreatorCustomCountInput(rawValue) {
    if (_isScriptImageCreatorEditMode()) {
        return;
    }
    const text = String(rawValue || "").trim();
    if (!text) {
        return;
    }
    const normalized = _setScriptImageCreatorCountValue(text);
    _scriptImageCreatorState.customCountOpen = normalized > SCRIPT_IMAGE_CREATOR_PRESET_COUNTS[SCRIPT_IMAGE_CREATOR_PRESET_COUNTS.length - 1];
    syncScriptImageCreatorControls();
    scheduleScriptImageCreatorEstimate(0);
}

function setScriptImageCreatorSequenceMode(mode) {
    if (_isScriptImageCreatorEditMode()) {
        return;
    }
    _setScriptImageCreatorSequenceValue(mode);
    syncScriptImageCreatorControls();
    scheduleScriptImageCreatorEstimate(0);
}

function _syncScriptImageCreatorChoiceButtons() {
    const meta = _getScriptImageCreatorModelMeta();
    const selectedAspect = String(document.getElementById("script-image-generator-aspect")?.value || "1:1").trim();
    const selectedCount = _getScriptImageCreatorCount();
    const selectedSequenceMode = _getScriptImageCreatorSequenceMode();
    const isEditing = _isScriptImageCreatorEditMode();
    const hasReferences = _scriptImageCreatorState.referenceFiles.length > 0;
    const hasMultiple = !isEditing && selectedCount > 1;

    document.querySelectorAll(".script-image-model-card").forEach((button) => {
        button.classList.toggle("is-active", button.dataset.model === meta.id);
    });

    document.querySelectorAll("#script-image-generator-aspect-options .script-image-generator-segment").forEach((button) => {
        button.classList.toggle("is-active", button.dataset.aspect === selectedAspect);
    });

    document.querySelectorAll("#script-image-generator-count-options .script-image-generator-segment").forEach((button) => {
        const rawCount = String(button.dataset.count || "").trim();
        const isCustom = rawCount === "custom";
        const count = Number.parseInt(rawCount || "1", 10) || 1;
        const disabled = isEditing;
        const active = isCustom
            ? (_scriptImageCreatorState.customCountOpen || selectedCount > SCRIPT_IMAGE_CREATOR_PRESET_COUNTS[SCRIPT_IMAGE_CREATOR_PRESET_COUNTS.length - 1])
            : (!disabled && count === selectedCount);
        button.disabled = disabled;
        button.classList.toggle("is-disabled", disabled);
        button.classList.toggle("is-active", active);
    });

    document.querySelectorAll("#script-image-generator-sequence-options .script-image-generator-segment").forEach((button) => {
        const mode = String(button.dataset.sequence || "").trim();
        const disabled = isEditing
            || !hasMultiple
            || (mode === "reference" && !hasReferences)
            || (mode === "none" && meta.requiresReference && hasMultiple);
        button.disabled = disabled;
        button.classList.toggle("is-disabled", disabled);
        button.classList.toggle("is-active", !disabled && mode === selectedSequenceMode);
    });

    _syncScriptImageCreatorModelCardCosts();
}

function resetScriptImageCreatorModalState() {
    _clearScriptImageCreatorEstimateTimer();
    _scriptImageCreatorLaunchSource = "script";
    _scriptImageCreatorVideoLaunch = {
        active: false,
        sourceUploadId: "",
    };
    _scriptImageCreatorState = {
        referenceFiles: [],
        generatedImages: [],
        activeResultIndex: 0,
        promptValues: [""],
        customCountOpen: false,
        activeSceneIndex: -1,
        promptPlannerBusy: false,
        promptPlannerTargetIndex: -1,
        busy: false,
        estimateTimer: null,
        estimateSeq: _scriptImageCreatorState.estimateSeq || 0,
        editingIndex: -1,
        referenceFilesBackup: [],
        countBackup: "1",
        selectedEstimateModelId: "",
        selectedEstimateCredits: null,
        profileReferenceUploads: {},
    };

    const modelSelect = document.getElementById("script-image-generator-model");
    if (modelSelect) modelSelect.value = DEFAULT_SCRIPT_IMAGE_CREATOR_MODEL_ID;
    const aspectSelect = document.getElementById("script-image-generator-aspect");
    if (aspectSelect) aspectSelect.value = "1:1";
    const sizeSelect = document.getElementById("script-image-generator-size");
    if (sizeSelect) sizeSelect.value = "2K";
    const countSelect = document.getElementById("script-image-generator-count");
    if (countSelect) _setScriptImageCreatorCountValue("1");
    const sequenceSelect = document.getElementById("script-image-generator-sequence-mode");
    if (sequenceSelect) sequenceSelect.value = DEFAULT_SCRIPT_IMAGE_CREATOR_SEQUENCE_MODE;
    const seedInput = document.getElementById("script-image-generator-seed");
    if (seedInput) seedInput.value = "-1";
    const thinkingToggle = document.getElementById("script-image-generator-thinking");
    if (thinkingToggle) thinkingToggle.checked = false;
    const refInput = document.getElementById("script-image-generator-reference-input");
    if (refInput) refInput.value = "";
    setScriptImageCreatorContextCollapsed(true);

    _resetScriptImageCreatorPersonaContexts();

    setScriptImageCreatorStatus("", "info");
    syncScriptImageCreatorControls();
    renderScriptImageCreatorReferencePreview();
    renderScriptImageCreatorResults();
    _refreshScriptImageCreatorReferenceContexts().catch((error) => {
        console.warn("Failed to refresh script image creator persona contexts:", error);
    });
    scheduleScriptImageCreatorEstimate(0);
}

function openScriptImageCreatorModal() {
    _scriptImageCreatorLaunchSource = "script";
    setScriptImageCreatorContextCollapsed(true);
    const scriptPrompt = String(document.getElementById("script-text")?.value || "").trim();
    _ensureScriptImageCreatorPromptCapacity(1);
    if (!String(_scriptImageCreatorState.promptValues[0] || "").trim() && scriptPrompt) {
        _scriptImageCreatorState.promptValues[0] = scriptPrompt;
    }
    syncScriptImageCreatorControls();
    renderScriptImageCreatorReferencePreview();
    renderScriptImageCreatorResults();
    _refreshScriptImageCreatorReferenceContexts().catch((error) => {
        console.warn("Failed to refresh script image creator persona contexts:", error);
    });
    scheduleScriptImageCreatorEstimate(0);
    openModal("modal-script-image-creator");
}

function openScriptImageCreatorFromCreateMode() {
    _scriptImageCreatorLaunchSource = "create-mode";
    setScriptImageCreatorContextCollapsed(true);
    syncScriptImageCreatorControls();
    renderScriptImageCreatorReferencePreview();
    renderScriptImageCreatorResults();
    _refreshScriptImageCreatorReferenceContexts().catch((error) => {
        console.warn("Failed to refresh script image creator persona contexts:", error);
    });
    scheduleScriptImageCreatorEstimate(0);
    openModal("modal-script-image-creator");
}

function closeScriptImageCreatorModal() {
    closeModal("modal-script-image-creator");
}

function selectScriptImageCreatorModel(modelId) {
    const modelSelect = document.getElementById("script-image-generator-model");
    if (!modelSelect) return;
    modelSelect.value = modelId;
    handleScriptImageCreatorModelChange();
}

function setScriptImageCreatorAspect(aspectRatio) {
    const aspectSelect = document.getElementById("script-image-generator-aspect");
    if (!aspectSelect) return;
    aspectSelect.value = aspectRatio;
    _syncScriptImageCreatorPreviewAspect();
    _syncScriptImageCreatorChoiceButtons();
    renderScriptImageCreatorResults();
    scheduleScriptImageCreatorEstimate(0);
}

function setScriptImageCreatorCount(count) {
    if (_isScriptImageCreatorEditMode()) return;
    const normalized = _setScriptImageCreatorCountValue(count);
    _scriptImageCreatorState.customCountOpen = normalized > SCRIPT_IMAGE_CREATOR_PRESET_COUNTS[SCRIPT_IMAGE_CREATOR_PRESET_COUNTS.length - 1];
    syncScriptImageCreatorControls();
    scheduleScriptImageCreatorEstimate(0);
}

function handleScriptImageCreatorMetaChange() {
    syncScriptImageCreatorControls();
    scheduleScriptImageCreatorEstimate(0);
}

function handleScriptImageCreatorModelChange() {
    const meta = _getScriptImageCreatorModelMeta();
    const maxReferences = Math.max(0, meta.maxReferences || 0);
    if (_isScriptImageCreatorEditMode() && maxReferences <= 0) {
        cancelScriptImageCreatorEdit(true);
    }
    if (!_isScriptImageCreatorEditMode() && _scriptImageCreatorState.referenceFiles.length > maxReferences) {
        _scriptImageCreatorState.referenceFiles = _scriptImageCreatorState.referenceFiles.slice(0, maxReferences);
    }
    syncScriptImageCreatorControls();
    renderScriptImageCreatorReferencePreview();
    renderScriptImageCreatorResults();
    scheduleScriptImageCreatorEstimate(0);
}

function syncScriptImageCreatorControls() {
    const meta = _getScriptImageCreatorModelMeta();
    const pasteHint = document.getElementById("script-image-generator-paste-hint");
    const countGroup = document.getElementById("script-image-generator-count-group");
    const countCustom = document.getElementById("script-image-generator-count-custom");
    const countManualInput = document.getElementById("script-image-generator-count-manual");
    const sizeGroup = document.getElementById("script-image-generator-size-group");
    const seedGroup = document.getElementById("script-image-generator-seed-group");
    const sequenceGroup = document.getElementById("script-image-generator-sequence-group");
    const sequenceSelect = document.getElementById("script-image-generator-sequence-mode");
    const thinkingGroup = document.getElementById("script-image-generator-thinking-group");
    const referenceGroup = document.getElementById("script-image-generator-reference-group");
    const contextGroup = document.getElementById("script-image-generator-context-group");
    const sizeSelect = document.getElementById("script-image-generator-size");
    const countSelect = document.getElementById("script-image-generator-count");
    const seedInput = document.getElementById("script-image-generator-seed");
    const thinkingToggle = document.getElementById("script-image-generator-thinking");
    const isEditing = _isScriptImageCreatorEditMode();
    if (pasteHint) {
        pasteHint.hidden = (meta.maxReferences || 0) <= 0;
        pasteHint.textContent = isEditing
            ? "Cole uma captura de tela com Ctrl+V para adicionar direto nas referências desta edição."
            : "Cole uma captura de tela com Ctrl+V para enviar direto para as imagens de referência.";
    }
    let selectedCount = _getScriptImageCreatorCount();
    if (countSelect) {
        if (isEditing) {
            selectedCount = _setScriptImageCreatorCountValue("1");
        } else {
            selectedCount = _setScriptImageCreatorCountValue(countSelect.value || "1");
        }
        countSelect.disabled = isEditing;
    }
    const hasReferences = _scriptImageCreatorState.referenceFiles.length > 0;
    let sequenceMode = _getScriptImageCreatorSequenceMode();
    if (sequenceMode === "reference" && !hasReferences) {
        sequenceMode = DEFAULT_SCRIPT_IMAGE_CREATOR_SEQUENCE_MODE;
    }
    if (!isEditing && selectedCount > 1 && meta.requiresReference && sequenceMode === "none") {
        sequenceMode = hasReferences ? "reference" : DEFAULT_SCRIPT_IMAGE_CREATOR_SEQUENCE_MODE;
    }
    if (sequenceSelect) {
        sequenceSelect.value = sequenceMode;
    }
    if (countGroup) countGroup.classList.toggle("is-disabled", isEditing);
    if (countCustom) {
        countCustom.hidden = isEditing || !(_scriptImageCreatorState.customCountOpen || selectedCount > SCRIPT_IMAGE_CREATOR_PRESET_COUNTS[SCRIPT_IMAGE_CREATOR_PRESET_COUNTS.length - 1]);
    }
    if (countManualInput) {
        countManualInput.disabled = isEditing;
        if (!countCustom?.hidden && document.activeElement !== countManualInput) {
            countManualInput.value = String(selectedCount > SCRIPT_IMAGE_CREATOR_PRESET_COUNTS[SCRIPT_IMAGE_CREATOR_PRESET_COUNTS.length - 1] ? selectedCount : 5);
        }
    }
    if (sequenceGroup) sequenceGroup.hidden = isEditing || selectedCount <= 1;
    if (referenceGroup) referenceGroup.hidden = (meta.maxReferences || 0) <= 0;
    if (contextGroup) contextGroup.hidden = (meta.maxReferences || 0) <= 0;
    if (sizeGroup) sizeGroup.classList.toggle("is-disabled", !meta.supportsSize);
    if (sizeSelect) sizeSelect.disabled = !meta.supportsSize;
    if (seedGroup) seedGroup.classList.toggle("is-disabled", !meta.supportsThinkingMode);
    if (seedInput) seedInput.disabled = !meta.supportsThinkingMode;
    if (thinkingGroup) thinkingGroup.classList.toggle("is-disabled", !meta.supportsThinkingMode);
    if (thinkingToggle) {
        thinkingToggle.disabled = !meta.supportsThinkingMode;
        if (!meta.supportsThinkingMode) thinkingToggle.checked = false;
    }
    _syncScriptImageCreatorPreviewAspect();
    _syncScriptImageCreatorChoiceButtons();
    renderScriptImageCreatorPromptEditors();
    _syncScriptImageCreatorSubmitButton();
}

function _scriptImageCreatorAspectToCssValue(aspectRatio) {
    const [width, height] = String(aspectRatio || "1:1").split(":").map((value) => Number.parseFloat(value) || 1);
    return `${width} / ${height}`;
}

function _syncScriptImageCreatorPreviewAspect() {
    const resultPanel = document.getElementById("script-image-generator-results-panel");
    if (!resultPanel) return;
    const selectedAspect = String(document.getElementById("script-image-generator-aspect")?.value || "1:1").trim();
    resultPanel.dataset.aspect = selectedAspect;
    resultPanel.style.setProperty("--script-image-result-ratio", _scriptImageCreatorAspectToCssValue(selectedAspect));
}

function _shouldShowScriptImageCreatorResults() {
    return !!(_scriptImageCreatorState.busy || _scriptImageCreatorState.generatedImages.length);
}

function setActiveScriptImageCreatorResult(index) {
    const parsed = Number.parseInt(String(index), 10);
    if (!Number.isFinite(parsed)) return;
    if (parsed < 0 || parsed >= _scriptImageCreatorState.generatedImages.length) return;
    if (_isScriptImageCreatorEditMode() && parsed !== _scriptImageCreatorState.editingIndex) {
        cancelScriptImageCreatorEdit(true);
    }
    _scriptImageCreatorState.activeResultIndex = parsed;
    renderScriptImageCreatorResults();
}

function triggerScriptImageCreatorReferenceUpload() {
    document.getElementById("script-image-generator-reference-input")?.click();
}

function handleScriptImageCreatorReferenceSelect(event) {
    const files = Array.from(event?.target?.files || []);
    addScriptImageCreatorReferences(files);
    if (event?.target) event.target.value = "";
}

function setScriptImageCreatorContextCollapsed(collapsed = true) {
    const contextShell = document.getElementById("script-image-generator-context-group");
    if (!contextShell) return;

    const toggleBtn = contextShell.querySelector(".script-image-generator-context-toggle");
    const body = contextShell.querySelector(".collapsible-body");
    if (toggleBtn) {
        toggleBtn.setAttribute("aria-expanded", String(!collapsed));
    }
    if (body) {
        body.hidden = !!collapsed;
    }
}

function _normalizeScriptImageCreatorClipboardImage(file, index = 0) {
    if (!(file instanceof File)) {
        return null;
    }

    const normalizedType = String(file.type || "image/png").toLowerCase();
    const extension = normalizedType.includes("jpeg")
        ? "jpg"
        : normalizedType.includes("webp")
        ? "webp"
        : "png";
    const originalName = String(file.name || "").trim();
    if (originalName && /\.[a-z0-9]+$/i.test(originalName)) {
        return file;
    }

    return new File([file], `captura-colada-${Date.now()}-${index + 1}.${extension}`, {
        type: normalizedType,
        lastModified: Date.now(),
    });
}

function _getScriptImageCreatorClipboardImages(event) {
    const items = Array.from(event?.clipboardData?.items || []);
    return items
        .filter((item) => item.kind === "file" && String(item.type || "").toLowerCase().startsWith("image/"))
        .map((item, index) => _normalizeScriptImageCreatorClipboardImage(item.getAsFile(), index))
        .filter(Boolean);
}

function handleScriptImageCreatorPromptPaste(event) {
    const files = _getScriptImageCreatorClipboardImages(event);
    if (!files.length) {
        return;
    }

    event.preventDefault();

    const meta = _getScriptImageCreatorModelMeta();
    if ((meta.maxReferences || 0) <= 0) {
        showToast("O modelo atual não aceita imagens de referência.", "info");
        return;
    }

    const beforeCount = _scriptImageCreatorState.referenceFiles.length;
    addScriptImageCreatorReferences(files);
    const addedCount = _scriptImageCreatorState.referenceFiles.length - beforeCount;
    if (addedCount <= 0) {
        return;
    }

    const promptIndex = Number.parseInt(String(event?.target?.dataset?.promptIndex || "0"), 10) || 0;
    focusScriptImageCreatorPrompt(promptIndex);
    showToast(
        addedCount === 1
            ? "Captura colada nas referências."
            : `${addedCount} capturas coladas nas referências.`,
        "success",
    );
}

function addScriptImageCreatorReferences(files) {
    const meta = _getScriptImageCreatorModelMeta();
    const maxReferences = meta.maxReferences || 5;

    for (const file of files) {
        if (_scriptImageCreatorState.referenceFiles.length >= maxReferences) {
            alert(`Máximo de ${maxReferences} referências atingido.`);
            break;
        }
        if (!file.type.match(/^image\/(jpeg|png|webp)$/)) {
            alert(`Formato não suportado: ${file.name}. Use JPG, PNG ou WebP.`);
            continue;
        }
        if (file.size > MAX_PHOTO_SIZE) {
            alert(`${file.name} excede 10MB. Reduza o tamanho.`);
            continue;
        }
        _scriptImageCreatorState.referenceFiles.push({
            file,
            upload_id: "",
            preview_url: "",
        });
    }

    syncScriptImageCreatorControls();
    renderScriptImageCreatorReferencePreview();
    scheduleScriptImageCreatorEstimate(0);
}

function removeScriptImageCreatorReference(index) {
    if (_scriptImageCreatorState.referenceFiles[index]?.locked) {
        return;
    }
    _scriptImageCreatorState.referenceFiles.splice(index, 1);
    syncScriptImageCreatorControls();
    renderScriptImageCreatorReferencePreview();
    scheduleScriptImageCreatorEstimate(0);
}

function renderScriptImageCreatorReferencePreview() {
    const preview = document.getElementById("script-image-generator-reference-preview");
    const count = document.getElementById("script-image-generator-reference-count");
    if (!preview || !count) return;

    const meta = _getScriptImageCreatorModelMeta();
    const maxRefs = meta.maxReferences || 5;
    count.textContent = `${Math.min(_scriptImageCreatorState.referenceFiles.length + _getScriptImageCreatorSelectedReferenceCount(), maxRefs)}/${maxRefs}`;
    preview.innerHTML = "";

    _scriptImageCreatorState.referenceFiles.forEach((item, index) => {
        const tile = document.createElement("div");
        tile.className = "photo-preview-item";
        if (item?.locked) {
            tile.classList.add("script-image-generator-reference-item--locked");
            tile.title = "Imagem base da edição";
        }

        const img = document.createElement("img");
        const previewUrl = String(item?.preview_url || "").trim();
        if (previewUrl) {
            img.src = previewUrl;
        } else if (item?.file) {
            img.src = URL.createObjectURL(item.file);
            img.onload = () => URL.revokeObjectURL(img.src);
        }

        tile.appendChild(img);
        if (!item?.locked) {
            const btn = document.createElement("button");
            btn.className = "photo-remove-btn";
            btn.type = "button";
            btn.textContent = "\u00d7";
            btn.onclick = () => removeScriptImageCreatorReference(index);
            tile.appendChild(btn);
        }
        preview.appendChild(tile);
    });
}

function setScriptImageCreatorStatus(message, tone = "info") {
    const status = document.getElementById("script-image-generator-status");
    if (!status) return;
    const text = String(message || "").trim();
    const showStatus = !!text && tone === "error";
    status.hidden = !showStatus;
    status.textContent = text;
    status.classList.remove("is-error", "is-success");
    if (tone === "error") status.classList.add("is-error");
    if (tone === "success") status.classList.add("is-success");
}

function scheduleScriptImageCreatorEstimate(delayMs = 140) {
    _clearScriptImageCreatorEstimateTimer();
    _scriptImageCreatorState.estimateTimer = setTimeout(() => {
        updateScriptImageCreatorEstimate().catch(() => {
            _setScriptImageCreatorEstimate(_getScriptImageCreatorModelMeta().id, null);
        });
    }, Math.max(0, delayMs));
}

async function updateScriptImageCreatorEstimate() {
    const meta = _getScriptImageCreatorModelMeta();
    const imageCount = Number.parseInt(document.getElementById("script-image-generator-count")?.value || "1", 10) || 1;
    const size = String(document.getElementById("script-image-generator-size")?.value || "2K").trim();
    const thinkingMode = !!document.getElementById("script-image-generator-thinking")?.checked;
    const referenceCount = _scriptImageCreatorState.referenceFiles.length + _getScriptImageCreatorSelectedReferenceCount();
    const seq = (_scriptImageCreatorState.estimateSeq || 0) + 1;
    _scriptImageCreatorState.estimateSeq = seq;

    try {
        const estimate = await api("/video/estimate-credits", {
            method: "POST",
            body: JSON.stringify({
                mode: "image-generation",
                image_model: meta.id,
                image_count: imageCount,
                image_size: size,
                reference_image_count: referenceCount,
                image_thinking_mode: thinkingMode,
            }),
        });
        if (_scriptImageCreatorState.estimateSeq !== seq) {
            return;
        }

        const creditsNeeded = _extractEstimateCredits(estimate);
        _setScriptImageCreatorEstimate(meta.id, creditsNeeded);
    } catch (_error) {
        if (_scriptImageCreatorState.estimateSeq === seq) {
            _setScriptImageCreatorEstimate(meta.id, null);
        }
    }
}

function _findScriptImageCreatorResultIndexByUploadId(uploadId) {
    const normalizedUploadId = String(uploadId || "").trim();
    if (!normalizedUploadId) {
        return -1;
    }
    return _scriptImageCreatorState.generatedImages.findIndex((item) => String(item?.upload_id || "").trim() === normalizedUploadId);
}

function _isScriptImageCreatorVideoPendingStatus(status) {
    return ["pending", "generating_scenes", "generating_clips", "rendering"].includes(String(status || "").trim().toLowerCase());
}

function _updateScriptImageCreatorVideoState(sourceUploadId, patch = {}) {
    const index = _findScriptImageCreatorResultIndexByUploadId(sourceUploadId);
    if (index < 0) {
        return null;
    }

    const item = _scriptImageCreatorState.generatedImages[index];
    item.video_state = {
        ...(item.video_state || {}),
        ...patch,
    };
    renderScriptImageCreatorResults();
    return item.video_state;
}

function _buildScriptImageCreatorVideoSlot(item) {
    const videoState = item?.video_state;
    if (!videoState) {
        return "";
    }

    const status = String(videoState.status || "").trim().toLowerCase();
    const progress = Math.max(0, Math.min(100, Number(videoState.progress || 0)));
    const engineLabel = workflowEscapeHtml(String(videoState.engine_label || "IA").trim() || "IA");
    const errorMessage = workflowEscapeHtml(String(videoState.error_message || "").trim());
    const message = workflowEscapeHtml(String(videoState.message || "").trim());
    const videoUrl = String(videoState.video_url || "").trim();
    const thumbnailUrl = String(videoState.thumbnail_url || "").trim();
    const continuationReady = !!String(videoState.last_frame_upload_id || "").trim();

    if (status === "failed") {
        return `
            <div class="script-image-generator-video-slot is-error">
                <div class="script-image-generator-video-copy">
                    <strong>Falha ao criar o vídeo</strong>
                    <small>${errorMessage || message || "Tente gerar novamente com outro prompt ou motor."}</small>
                </div>
            </div>
        `;
    }

    if (_isScriptImageCreatorVideoPendingStatus(status)) {
        return `
            <div class="script-image-generator-video-slot is-pending" aria-live="polite">
                <div class="script-image-generator-video-copy">
                    <strong>${engineLabel} está criando o vídeo</strong>
                    <small>${message || "A cena voltou para a tela de imagens enquanto o vídeo renderiza."}</small>
                </div>
                <div class="script-image-generator-video-progress"><span style="width:${progress}%"></span></div>
            </div>
        `;
    }

    return `
        <div class="script-image-generator-video-slot is-complete">
            ${videoUrl ? `<video class="script-image-generator-video-preview" src="${workflowEscapeHtml(videoUrl)}" ${thumbnailUrl ? `poster="${workflowEscapeHtml(thumbnailUrl)}"` : ""} controls playsinline preload="metadata"></video>` : ""}
            <div class="script-image-generator-video-copy">
                <strong>Vídeo pronto</strong>
                <small>${continuationReady ? "Último frame já foi carregado para a próxima cena." : "Resultado disponível para continuar desta imagem."}</small>
            </div>
        </div>
    `;
}

function removeScriptImageCreatorResult(index) {
    const parsed = Number.parseInt(String(index), 10);
    if (!Number.isFinite(parsed) || parsed < 0 || parsed >= _scriptImageCreatorState.generatedImages.length) {
        return;
    }

    const item = _scriptImageCreatorState.generatedImages[parsed];
    if (_isScriptImageCreatorVideoPendingStatus(item?.video_state?.status)) {
        showToast("Aguarde esse vídeo terminar antes de remover a imagem.", "info");
        return;
    }

    _scriptImageCreatorState.generatedImages.splice(parsed, 1);
    if (_scriptImageCreatorState.generatedImages.length === 0) {
        _scriptImageCreatorState.activeResultIndex = 0;
    } else {
        _scriptImageCreatorState.activeResultIndex = Math.max(0, Math.min(_scriptImageCreatorState.activeResultIndex, _scriptImageCreatorState.generatedImages.length - 1));
    }
    renderScriptImageCreatorResults();
}
window.removeScriptImageCreatorResult = removeScriptImageCreatorResult;

function _upsertScriptImageCreatorContinuationResult(sourceUploadId, payload) {
    const sourceIndex = _findScriptImageCreatorResultIndexByUploadId(sourceUploadId);
    const sourceItem = sourceIndex >= 0 ? _scriptImageCreatorState.generatedImages[sourceIndex] : null;
    const uploadId = String(payload?.upload_id || "").trim();
    const imageUrl = String(payload?.image_url || "").trim();
    if (!uploadId || !imageUrl) {
        return;
    }

    const continuationItem = {
        upload_id: uploadId,
        image_url: imageUrl,
        mime_type: "image/png",
        file_name: `ultimo-frame-${Date.now()}.png`,
        label: sourceItem?.label ? `${sourceItem.label} - último frame` : "Último frame",
        model: String(sourceItem?.model || "video-last-frame").trim(),
        prompt_text: String(sourceItem?.prompt_text || "").trim(),
        scene_index: Number.isInteger(sourceItem?.scene_index) ? sourceItem.scene_index : 0,
        derived_from_upload_id: sourceUploadId,
        derived_from_project_id: Number(payload?.project_id || 0) || 0,
    };

    const existingIndex = _findScriptImageCreatorResultIndexByUploadId(uploadId);
    if (existingIndex >= 0) {
        _scriptImageCreatorState.generatedImages.splice(existingIndex, 1, {
            ..._scriptImageCreatorState.generatedImages[existingIndex],
            ...continuationItem,
        });
        _scriptImageCreatorState.activeResultIndex = existingIndex;
    } else {
        const insertIndex = sourceIndex >= 0 ? sourceIndex + 1 : _scriptImageCreatorState.generatedImages.length;
        _scriptImageCreatorState.generatedImages.splice(insertIndex, 0, continuationItem);
        _scriptImageCreatorState.activeResultIndex = insertIndex;
    }

    renderScriptImageCreatorResults();
}

async function _handleScriptImageCreatorVideoCompleted(sourceUploadId, projectId, detail, engineLabel) {
    const render = _pickLatestAvailableRender(detail?.renders || []);
    _updateScriptImageCreatorVideoState(sourceUploadId, {
        status: "completed",
        progress: 100,
        message: "Vídeo pronto.",
        engine_label: engineLabel,
        video_url: String(render?.video_url || "").trim(),
        thumbnail_url: String(render?.thumbnail_url || "").trim(),
    });

    await loadProjects();

    try {
        const lastFrame = await api(`/video/projects/${projectId}/extract-last-frame`, {
            method: "POST",
        });
        if (lastFrame?.upload_id && lastFrame?.image_url) {
            _updateScriptImageCreatorVideoState(sourceUploadId, {
                last_frame_upload_id: String(lastFrame.upload_id || "").trim(),
                last_frame_image_url: String(lastFrame.image_url || "").trim(),
            });
            _upsertScriptImageCreatorContinuationResult(sourceUploadId, lastFrame);
            showToast("Vídeo pronto. O último frame já está carregado para a próxima cena.", "success");
            return;
        }
    } catch (error) {
        showToast(`Vídeo pronto, mas não foi possível preparar o último frame: ${error.message}`, "error");
        return;
    }

    showToast("Vídeo pronto.", "success");
}

async function _pollScriptImageCreatorVideoProject(sourceUploadId, projectId, engineLabel) {
    const maxWait = 12 * 60 * 1000;
    const pollInterval = 4000;
    const startedAt = Date.now();

    while (Date.now() - startedAt < maxWait) {
        await new Promise((resolve) => setTimeout(resolve, pollInterval));

        try {
            const response = await fetch(`${API}/video/projects/${projectId}`, {
                headers: getHeaders(),
            });
            if (!response.ok) {
                continue;
            }

            const detail = await response.json();
            const progress = Math.max(0, Math.min(100, Number(detail.progress || 0)));
            const status = String(detail.status || "").trim().toLowerCase();
            const message = status === "failed"
                ? String(detail.error_message || "Falha na geração do vídeo.").trim()
                : progress < 15
                    ? "Preparando a cena..."
                    : progress < 80
                        ? `${engineLabel} está criando seu vídeo...`
                        : progress < 95
                            ? "Finalizando vídeo..."
                            : "Preparando continuidade...";

            _updateScriptImageCreatorVideoState(sourceUploadId, {
                project_id: projectId,
                status,
                progress,
                message,
                engine_label: engineLabel,
                error_message: String(detail.error_message || "").trim(),
            });

            if (status === "completed") {
                await _handleScriptImageCreatorVideoCompleted(sourceUploadId, projectId, detail, engineLabel);
                return;
            }

            if (status === "failed") {
                showToast(detail.error_message || "Falha na geração do vídeo.", "error");
                return;
            }
        } catch (error) {
            if (error?.message && !String(error.message).toLowerCase().includes("fetch")) {
                _updateScriptImageCreatorVideoState(sourceUploadId, {
                    status: "failed",
                    error_message: error.message,
                });
                showToast(`Falha ao acompanhar o vídeo: ${error.message}`, "error");
                return;
            }
        }
    }

    _updateScriptImageCreatorVideoState(sourceUploadId, {
        status: "failed",
        error_message: "Tempo limite excedido. Confira o projeto na lista principal.",
    });
    showToast("O vídeo continua na lista de projetos, mas o acompanhamento desta tela expirou.", "info");
}

function _startScriptImageCreatorVideoProjectTracking(sourceUploadId, projectId, engineLabel) {
    if (!sourceUploadId || !projectId) {
        return;
    }
    void _pollScriptImageCreatorVideoProject(sourceUploadId, projectId, engineLabel);
}

function renderScriptImageCreatorResults() {
    const host = document.getElementById("script-image-generator-results");
    if (!host) return;

    const items = _scriptImageCreatorState.generatedImages;
    const panel = document.getElementById("script-image-generator-results-panel");
    if (panel) {
        panel.hidden = !_shouldShowScriptImageCreatorResults();
    }

    if (_scriptImageCreatorState.busy && !items.length) {
        host.innerHTML = `
            <div class="script-image-generator-result-card script-image-generator-result-card--loading">
                <div class="script-image-generator-card-preview">
                    <div class="script-image-generator-card-loading" aria-hidden="true">
                        <span class="script-image-generator-card-loading-shimmer"></span>
                    </div>
                </div>
            </div>
        `;
        return;
    }

    if (!items.length) {
        host.innerHTML = "";
        return;
    }

    const activeIndex = Math.min(_scriptImageCreatorState.activeResultIndex || 0, items.length - 1);
    _scriptImageCreatorState.activeResultIndex = activeIndex;
    const busyAttr = _scriptImageCreatorState.busy ? " disabled" : "";
    const loadingCard = _scriptImageCreatorState.busy
        ? `
            <div class="script-image-generator-result-card script-image-generator-result-card--loading" aria-live="polite">
                <div class="script-image-generator-card-preview">
                    <div class="script-image-generator-card-loading" aria-hidden="true">
                        <span class="script-image-generator-card-loading-shimmer"></span>
                    </div>
                </div>
            </div>
        `
        : "";

    host.innerHTML = `
        ${items.map((item, index) => {
            const isActive = index === activeIndex;
            const isEditingActive = _scriptImageCreatorState.editingIndex === index;
            const isVideoPending = _isScriptImageCreatorVideoPendingStatus(item?.video_state?.status);
            const editButtonTitle = isEditingActive ? "Cancelar edicao" : "Editar imagem";
            const editButtonAction = isEditingActive ? "cancelScriptImageCreatorEdit()" : `startScriptImageCreatorEdit(${index})`;
            const primaryActionLabel = _scriptImageCreatorConsumer ? "Usar no projeto" : "Criar video";
            const actionBusyAttr = (_scriptImageCreatorState.busy || isVideoPending) ? " disabled" : "";
            const videoSlotHtml = _buildScriptImageCreatorVideoSlot(item);
            return `
                <article class="script-image-generator-result-card${isActive ? " is-active" : ""}">
                    <div class="script-image-generator-card-frame">
                        <button
                            type="button"
                            class="script-image-generator-card-preview"
                            onclick="openScriptImageCreatorExpandedResult(${index})"
                            aria-label="Expandir resultado ${index + 1}"
                        >
                            <img src="${workflowEscapeHtml(item.image_url)}" alt="${workflowEscapeHtml(item.label || `Imagem gerada ${index + 1}`)}">
                        </button>
                        <div class="script-image-generator-result-actions">
                            <button class="btn-icon-sm script-image-generator-card-icon${isEditingActive ? " is-active" : ""}" type="button" title="${editButtonTitle}" aria-label="${editButtonTitle}"${actionBusyAttr} onclick="${editButtonAction}">
                                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="m12 20 9-9-3-3-9 9-1 4Z"/><path d="M16 7 19 10"/></svg>
                            </button>
                            <button class="btn-icon-sm script-image-generator-card-icon" type="button" title="Baixar imagem" aria-label="Baixar imagem"${busyAttr} onclick="downloadScriptImageCreatorResult(${index})">
                                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M12 3v12"/><path d="m7 10 5 5 5-5"/><path d="M5 21h14"/></svg>
                            </button>
                            <button class="btn-icon-sm script-image-generator-card-icon" type="button" title="Remover imagem" aria-label="Remover imagem"${actionBusyAttr} onclick="removeScriptImageCreatorResult(${index})">
                                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M3 6h18"/><path d="M8 6V4h8v2"/><path d="M19 6l-1 14H6L5 6"/><path d="M10 11v6"/><path d="M14 11v6"/></svg>
                            </button>
                        </div>
                    </div>
                    ${videoSlotHtml}
                    <button class="btn btn-primary btn-sm script-image-generator-create-btn" type="button"${actionBusyAttr} onclick="createVideoFromScriptImageCreatorResult(${index})">${primaryActionLabel}</button>
                </article>
            `;
        }).join("")}
        ${loadingCard}
    `;
}

function openScriptImageCreatorExpandedResult(index) {
    const parsed = Number.parseInt(index, 10);
    const item = _scriptImageCreatorState.generatedImages[parsed];
    if (!item?.image_url) return;

    _scriptImageCreatorState.activeResultIndex = parsed;
    renderScriptImageCreatorResults();

    const titleEl = document.getElementById("script-image-viewer-title");
    if (titleEl) {
        titleEl.textContent = `Imagem ${parsed + 1}`;
    }

    const imageEl = document.getElementById("script-image-viewer-img");
    if (imageEl) {
        imageEl.src = item.image_url;
        imageEl.alt = item.label || `Imagem gerada ${parsed + 1}`;
    }

    openModal("modal-script-image-viewer");
}

function closeScriptImageCreatorExpandedResult() {
    const imageEl = document.getElementById("script-image-viewer-img");
    if (imageEl) {
        imageEl.removeAttribute("src");
    }
    closeModal("modal-script-image-viewer");
}

function downloadScriptImageCreatorResult(index) {
    const item = _scriptImageCreatorState.generatedImages[index];
    if (!item?.image_url) return;
    const link = document.createElement("a");
    link.href = item.image_url;
    link.download = item.file_name || `imagem-gerada-${index + 1}.png`;
    document.body.appendChild(link);
    link.click();
    link.remove();
}

async function _dataUrlToImageFile(dataUrl, fileName) {
    const response = await fetch(dataUrl);
    const blob = await response.blob();
    return new File([blob], fileName, { type: blob.type || "image/png" });
}

async function _addScriptImageCreatorResultToProject(index) {
    const item = _scriptImageCreatorState.generatedImages[index];
    if (!item?.image_url || !item?.upload_id) {
        throw new Error("Imagem gerada inválida.");
    }
    if (scriptPhotos.length >= MAX_PHOTOS) {
        throw new Error(`Máximo de ${MAX_PHOTOS} fotos atingido.`);
    }

    const generatedFile = await _dataUrlToImageFile(
        item.image_url,
        item.file_name || `imagem-gerada-${Date.now()}.png`,
    );
    generatedFile.upload_id = item.upload_id;
    generatedFile.preview_url = item.image_url;
    generatedFile.generated = true;
    generatedFile.source_label = item.label || "";
    scriptPhotos.push(generatedFile);

    const photoCb = document.getElementById("script-use-photos");
    if (photoCb && !photoCb.checked) {
        photoCb.checked = true;
        togglePhotoUpload();
    }

    renderPhotoPreview();
}

function _prepareScriptImageCreatorVideoDraftState() {
    scriptData.videoType = "realista";
    scriptData.useCustomImages = scriptPhotos.length > 0;
    scriptData.useCustomVideo = false;
    scriptData.useCustomAudio = false;
    scriptData.createNarration = false;
    scriptData.aspect = document.getElementById("script-image-generator-aspect")?.value || scriptData.aspect || "16:9";

    const photoCb = document.getElementById("script-use-photos");
    if (photoCb) {
        photoCb.checked = scriptPhotos.length > 0;
    }

    const photoArea = document.getElementById("script-photo-area");
    if (photoArea) {
        photoArea.hidden = scriptPhotos.length === 0;
    }

    const narChoice = document.getElementById("script-narration-choice");
    if (narChoice) {
        narChoice.hidden = scriptPhotos.length === 0;
    }

    const narCb = document.getElementById("script-create-narration");
    if (narCb) {
        narCb.checked = true;
    }

    toggleScriptNarration();
    _updateScriptRealisticPersonaVisibility();
    scheduleScriptCreditEstimate();
}

async function useScriptImageCreatorResult(index) {
    try {
        await _addScriptImageCreatorResultToProject(index);
        showToast("Imagem adicionada ao sistema.", "success");
    } catch (error) {
        alert(`Não foi possível usar a imagem no sistema: ${error.message}`);
    }
}

async function createVideoFromScriptImageCreatorResult(index) {
    try {
        const parsedIndex = Number.parseInt(String(index), 10) || 0;
        const item = _scriptImageCreatorState.generatedImages[parsedIndex];
        if (!item?.image_url) {
            throw new Error("Imagem nao encontrada para criar o video.");
        }
        if (typeof _scriptImageCreatorConsumer === "function") {
            if (!item?.image_url) {
                throw new Error("Imagem nao encontrada para vincular ao projeto.");
            }
            await _scriptImageCreatorConsumer(item, parsedIndex);
            closeScriptImageCreatorModal();
            showToast("Imagem vinculada ao projeto.", "success");
            return;
        }

        const launchSource = _scriptImageCreatorLaunchSource;
        await _addScriptImageCreatorResultToProject(parsedIndex);
        _scriptImageCreatorVideoLaunch = {
            active: launchSource === "create-mode",
            sourceUploadId: String(item.upload_id || "").trim(),
        };
        closeScriptImageCreatorModal();

        if (launchSource === "create-mode") {
            _prepareScriptImageCreatorVideoDraftState();
            adaptScriptStepForVideoType("realista");

            const scriptTypeGrid = document.getElementById("script-video-type-grid");
            if (scriptTypeGrid) {
                scriptTypeGrid.querySelectorAll(".video-type-card").forEach((card) => {
                    card.classList.toggle("selected", card.dataset.type === "realista");
                });
            }

            scriptStep = 2;
            switchCreateMode("script");
            updateFlowUI("create-panel-script", scriptStep, getScriptFlow(), "script");
            _prepareScriptImageCreatorVideoDraftState();

            const promptField = document.getElementById("script-text");
            if (promptField && !String(promptField.value || "").trim()) {
                promptField.value = String(item.prompt_text || "").trim();
            }

            window.requestAnimationFrame(() => {
                const promptField = document.getElementById("script-text");
                if (promptField) {
                    promptField.disabled = false;
                }
                promptField?.focus();
                promptField?.scrollIntoView({ behavior: "smooth", block: "center" });
            });
            showToast("Imagem adicionada. Agora descreva como você quer o vídeo.", "success");
            return;
        }

        window.requestAnimationFrame(() => {
            document.getElementById("script-photo-area")?.scrollIntoView({ behavior: "smooth", block: "center" });
        });
        showToast("Imagem adicionada. Agora você pode criar o vídeo.", "success");
    } catch (error) {
        _scriptImageCreatorVideoLaunch = {
            active: false,
            sourceUploadId: "",
        };
        alert(`Não foi possível preparar a imagem para o vídeo: ${error.message}`);
    }
}

function startScriptImageCreatorEdit(index) {
    const parsed = Number.parseInt(String(index), 10);
    if (!Number.isFinite(parsed)) return;
    const meta = _getScriptImageCreatorModelMeta();
    if ((meta.maxReferences || 0) <= 0) {
        showToast("Esse modelo ainda não tem um modo de imagem para imagem publicado no Atlas.", "info");
        return;
    }

    const item = _scriptImageCreatorState.generatedImages[parsed];
    if (!item?.upload_id || !item?.image_url) {
        return;
    }

    if (_isScriptImageCreatorEditMode()) {
        if (_scriptImageCreatorState.editingIndex === parsed) {
            _getScriptImageCreatorPromptInput()?.focus();
            return;
        }
        cancelScriptImageCreatorEdit(true);
    }

    _scriptImageCreatorState.referenceFilesBackup = _cloneScriptImageCreatorReferenceFiles(_scriptImageCreatorState.referenceFiles);
    _scriptImageCreatorState.countBackup = String(document.getElementById("script-image-generator-count")?.value || "1").trim() || "1";
    _scriptImageCreatorState.referenceFiles = [{
        file: null,
        upload_id: item.upload_id,
        preview_url: item.image_url,
        locked: true,
    }];
    _scriptImageCreatorState.editingIndex = parsed;
    _scriptImageCreatorState.activeResultIndex = parsed;

    const countSelect = document.getElementById("script-image-generator-count");
    if (countSelect) {
        countSelect.value = "1";
    }

    setScriptImageCreatorStatus("", "info");
    syncScriptImageCreatorControls();
    renderScriptImageCreatorReferencePreview();
    renderScriptImageCreatorResults();
    scheduleScriptImageCreatorEstimate(0);

    const promptInput = _getScriptImageCreatorPromptInput();
    if (promptInput) {
        promptInput.focus();
        promptInput.select();
    }
    showToast("Ajuste o prompt e clique em Aplicar edição.", "info");
}

function cancelScriptImageCreatorEdit(silent = false) {
    if (!_isScriptImageCreatorEditMode()) {
        return;
    }

    _scriptImageCreatorState.referenceFiles = _cloneScriptImageCreatorReferenceFiles(_scriptImageCreatorState.referenceFilesBackup);

    const countSelect = document.getElementById("script-image-generator-count");
    if (countSelect && _scriptImageCreatorState.countBackup) {
        _setScriptImageCreatorCountValue(_scriptImageCreatorState.countBackup);
    }
    _scriptImageCreatorState.customCountOpen = (Number.parseInt(_scriptImageCreatorState.countBackup, 10) || 0) > SCRIPT_IMAGE_CREATOR_PRESET_COUNTS[SCRIPT_IMAGE_CREATOR_PRESET_COUNTS.length - 1];

    _scriptImageCreatorState.editingIndex = -1;
    _scriptImageCreatorState.referenceFilesBackup = [];
    _scriptImageCreatorState.countBackup = "1";

    if (!silent) {
        setScriptImageCreatorStatus("", "info");
    }
    syncScriptImageCreatorControls();
    renderScriptImageCreatorReferencePreview();
    renderScriptImageCreatorResults();
    scheduleScriptImageCreatorEstimate(0);
}

async function _prepareScriptImageCreatorReferenceUploadIds() {
    const uploadIds = [];
    for (let index = 0; index < _scriptImageCreatorState.referenceFiles.length; index += 1) {
        const item = _scriptImageCreatorState.referenceFiles[index];
        const existingUploadId = String(item?.upload_id || "").trim();
        if (existingUploadId) {
            uploadIds.push(existingUploadId);
            continue;
        }

        const uploaded = await uploadTempFileWithRetry(item.file, "image", `referência ${index + 1}`, { showProgress: false });
        const uploadId = String(uploaded?.upload_id || "").trim();
        if (!uploadId) {
            throw new Error(`Falha ao enviar a referência ${index + 1}.`);
        }
        item.upload_id = uploadId;
        uploadIds.push(uploadId);
    }
    return uploadIds;
}

function _createScriptImageCreatorResultItem(item, meta, options = {}) {
    const fallbackLabel = String(options.fallbackLabel || meta.label || "Imagem gerada").trim();
    const fallbackFileName = String(options.fallbackFileName || "imagem-gerada-1.png").trim();
    return {
        upload_id: String(item?.upload_id || "").trim(),
        image_url: String(item?.image_url || "").trim(),
        mime_type: String(item?.mime_type || "image/png").trim(),
        file_name: String(item?.file_name || fallbackFileName).trim(),
        label: String(item?.label || fallbackLabel).trim(),
        model: String(item?.model || meta.id).trim(),
        prompt_text: String(options.promptText || "").trim(),
        scene_index: Number.isInteger(options.sceneIndex) ? options.sceneIndex : 0,
    };
}

function _resolveScriptImageCreatorSceneReferenceUploadIds(options = {}) {
    const sceneIndex = Number.parseInt(String(options.sceneIndex || 0), 10) || 0;
    const totalScenes = Number.parseInt(String(options.totalScenes || 1), 10) || 1;
    const baseReferenceUploadIds = Array.isArray(options.baseReferenceUploadIds) ? options.baseReferenceUploadIds : [];
    const sequenceMode = String(options.sequenceMode || "none").trim();
    const firstGeneratedBaseUploadId = String(options.firstGeneratedBaseUploadId || "").trim();
    const previousGeneratedUploadIds = Array.isArray(options.previousGeneratedUploadIds) ? options.previousGeneratedUploadIds : [];
    const maxReferences = Math.max(1, Number.parseInt(String(options.maxReferences || 5), 10) || 5);
    const isEditing = !!options.isEditing;

    const mergedReferenceIds = [];
    const addUnique = (candidateIds) => {
        for (const rawId of candidateIds) {
            const uploadId = String(rawId || "").trim();
            if (!uploadId || mergedReferenceIds.includes(uploadId)) {
                continue;
            }
            mergedReferenceIds.push(uploadId);
            if (mergedReferenceIds.length >= maxReferences) {
                break;
            }
        }
    };

    if (isEditing || totalScenes <= 1 || sceneIndex === 0) {
        addUnique(baseReferenceUploadIds);
        return mergedReferenceIds;
    }

    if (sequenceMode === "reference") {
        addUnique(baseReferenceUploadIds);
    }
    if (sequenceMode === "first-generated") {
        if (!firstGeneratedBaseUploadId) {
            throw new Error("A primeira imagem precisa ser criada antes de continuar a sequência.");
        }
        addUnique([firstGeneratedBaseUploadId]);
        addUnique(baseReferenceUploadIds);
    }
    if (sequenceMode === "none") {
        return [];
    }

    const recentGeneratedIds = previousGeneratedUploadIds
        .map((value) => String(value || "").trim())
        .filter(Boolean)
        .reverse();
    addUnique(recentGeneratedIds);
    return mergedReferenceIds.slice(0, maxReferences);
}

async function generateScriptImageFromModal() {
    if (_scriptImageCreatorState.busy || _scriptImageCreatorState.promptPlannerBusy) {
        return;
    }

    const meta = _getScriptImageCreatorModelMeta();
    const isEditing = _isScriptImageCreatorEditMode();
    let requestedCount = isEditing ? 1 : _getScriptImageCreatorCount();
    _ensureScriptImageCreatorPromptCapacity(requestedCount);
    let prompts = _getScriptImageCreatorPromptValues(requestedCount).map((value) => String(value || "").trim());
    const masterPrompt = String(prompts[0] || "").trim();
    const missingScenePrompts = !isEditing && requestedCount > 1 && prompts.slice(1).some((value) => !value);
    const masterRequestsSequence = !isEditing && requestedCount === 1 && _scriptImageCreatorPromptSuggestsMultipleImages(masterPrompt);

    if (masterPrompt && (missingScenePrompts || masterRequestsSequence)) {
        try {
            const promptPlan = await _planScriptImageCreatorPrompts({
                targetIndex: null,
                rewriteAll: masterRequestsSequence,
                statusMessage: masterRequestsSequence
                    ? "Expandindo o prompt mestre em uma sequência de cenas..."
                    : "Completando os prompts da sequência automaticamente...",
            });
            if (promptPlan) {
                requestedCount = promptPlan.sceneCount;
                prompts = promptPlan.prompts.map((value) => String(value || "").trim());
            }
        } catch (error) {
            setScriptImageCreatorStatus(`Erro ao criar prompt: ${error.message}`, "error");
            return;
        }
    }

    const emptyPromptIndex = prompts.findIndex((value) => !value);
    if (emptyPromptIndex >= 0) {
        alert(requestedCount > 1
            ? `Descreva a cena ${emptyPromptIndex + 1} antes de gerar.`
            : "Descreva a imagem antes de gerar.");
        return;
    }
    if (meta.requiresReference && !_hasScriptImageCreatorAnyReference()) {
        alert("Envie ao menos uma imagem de referência para esse modelo.");
        return;
    }

    const submitBtn = document.getElementById("script-image-generator-submit");
    _scriptImageCreatorState.busy = true;
    if (submitBtn) {
        submitBtn.disabled = true;
        submitBtn.textContent = isEditing ? "Aplicando..." : "Gerando...";
    }
    setScriptImageCreatorStatus(
        isEditing
            ? `Aplicando edição com ${meta.label}...`
            : (requestedCount > 1 ? `Gerando sequência com ${meta.label}...` : `Gerando imagem com ${meta.label}...`),
        "info",
    );
    renderScriptImageCreatorResults();

    let lastSceneIndex = 0;
    try {
        const manualReferenceUploadIds = _scriptImageCreatorState.referenceFiles.length
            ? await _prepareScriptImageCreatorReferenceUploadIds()
            : [];
        const profileReferenceUploadIds = await _prepareScriptImageCreatorProfileReferenceUploadIds(meta.maxReferences || 5);
        const baseReferenceUploadIds = [...manualReferenceUploadIds, ...profileReferenceUploadIds]
            .filter(Boolean)
            .slice(0, Math.max(0, meta.maxReferences || 5));
        const sequenceMode = isEditing ? "none" : _getScriptImageCreatorSequenceMode();
        const aspectRatio = document.getElementById("script-image-generator-aspect")?.value || "1:1";
        const size = document.getElementById("script-image-generator-size")?.value || "2K";
        const seed = Number.parseInt(document.getElementById("script-image-generator-seed")?.value || "-1", 10) || -1;
        const thinkingMode = !!document.getElementById("script-image-generator-thinking")?.checked;
        const parsedImages = [];
        let firstGeneratedBaseUploadId = "";

        if (!isEditing) {
            _scriptImageCreatorState.generatedImages = [];
            _scriptImageCreatorState.activeResultIndex = 0;
            _scriptImageCreatorState.activeSceneIndex = -1;
            renderScriptImageCreatorPromptEditors();
            renderScriptImageCreatorResults();
        }

        for (let sceneIndex = 0; sceneIndex < prompts.length; sceneIndex += 1) {
            lastSceneIndex = sceneIndex;
            const scenePrompt = prompts[sceneIndex];
            _scriptImageCreatorState.activeSceneIndex = sceneIndex;
            renderScriptImageCreatorPromptEditors();
            const sceneReferenceUploadIds = _resolveScriptImageCreatorSceneReferenceUploadIds({
                sceneIndex,
                totalScenes: prompts.length,
                baseReferenceUploadIds,
                sequenceMode,
                firstGeneratedBaseUploadId,
                previousGeneratedUploadIds: parsedImages.map((item) => item.upload_id),
                maxReferences: meta.maxReferences,
                isEditing,
            });

            setScriptImageCreatorStatus(
                isEditing
                    ? `Aplicando edição com ${meta.label}...`
                    : (prompts.length > 1
                        ? `Gerando cena ${sceneIndex + 1} de ${prompts.length} com ${meta.label}...`
                        : `Gerando imagem com ${meta.label}...`),
                "info",
            );

            const response = await api("/video/script-image/generate", {
                method: "POST",
                body: JSON.stringify({
                    prompt: scenePrompt,
                    model: meta.id,
                    aspect_ratio: aspectRatio,
                    size,
                    n: 1,
                    seed,
                    thinking_mode: thinkingMode,
                    reference_upload_ids: sceneReferenceUploadIds,
                }),
            });

            const images = Array.isArray(response?.images) ? response.images : [];
            if (!images.length) {
                throw new Error("A imagem foi gerada, mas o servidor não retornou arquivos válidos.");
            }

            const sceneLabel = isEditing
                ? String(_scriptImageCreatorState.generatedImages[_scriptImageCreatorState.editingIndex]?.label || meta.label).trim()
                : (prompts.length > 1 ? `Cena ${sceneIndex + 1}` : meta.label);
            const sceneImage = _createScriptImageCreatorResultItem(images[0], meta, {
                fallbackLabel: sceneLabel,
                fallbackFileName: prompts.length > 1 ? `cena-${sceneIndex + 1}.png` : "imagem-gerada-1.png",
                promptText: scenePrompt,
                sceneIndex,
            });
            if (!sceneImage.upload_id || !sceneImage.image_url) {
                throw new Error("A imagem foi gerada, mas o retorno veio vazio.");
            }

            parsedImages.push(sceneImage);
            if (!firstGeneratedBaseUploadId) {
                firstGeneratedBaseUploadId = sceneImage.upload_id;
            }

            if (!isEditing) {
                _scriptImageCreatorState.generatedImages = [...parsedImages];
                _scriptImageCreatorState.activeResultIndex = parsedImages.length - 1;
                renderScriptImageCreatorResults();
            }
        }

        if (isEditing) {
            const editIndex = _scriptImageCreatorState.editingIndex;
            if (editIndex >= 0 && editIndex < _scriptImageCreatorState.generatedImages.length) {
                _scriptImageCreatorState.generatedImages.splice(editIndex, 1, parsedImages[0]);
                _scriptImageCreatorState.activeResultIndex = editIndex;
            } else {
                _scriptImageCreatorState.generatedImages = [parsedImages[0]];
                _scriptImageCreatorState.activeResultIndex = 0;
            }
            cancelScriptImageCreatorEdit(true);
        } else {
            _scriptImageCreatorState.generatedImages = parsedImages;
            _scriptImageCreatorState.activeResultIndex = 0;
        }

        renderScriptImageCreatorResults();
        setScriptImageCreatorStatus("", "info");
        showToast(
            isEditing
                ? "Imagem atualizada com sucesso."
                : (parsedImages.length > 1 ? "Sequência de imagens gerada com sucesso." : "Imagem gerada com sucesso."),
            "success",
        );
    } catch (error) {
        const partialCount = isEditing ? 0 : _scriptImageCreatorState.generatedImages.length;
        const sceneLabel = !isEditing && prompts.length > 1 ? ` na cena ${Math.min(lastSceneIndex + 1, prompts.length)}` : "";
        const partialLabel = partialCount > 0
            ? ` ${partialCount} ${partialCount === 1 ? "imagem pronta permaneceu disponível." : "imagens prontas permaneceram disponíveis."}`
            : "";
        setScriptImageCreatorStatus(`Erro ao gerar imagem${sceneLabel}: ${error.message}${partialLabel}`, "error");
    } finally {
        _scriptImageCreatorState.busy = false;
        _scriptImageCreatorState.activeSceneIndex = -1;
        renderScriptImageCreatorPromptEditors();
        renderScriptImageCreatorResults();
        if (submitBtn) {
            submitBtn.disabled = false;
        }
        syncScriptImageCreatorControls();
        scheduleScriptImageCreatorEstimate(0);
    }
}

function togglePhotoUpload() {
    const checked = document.getElementById("script-use-photos").checked;
    document.getElementById("script-photo-area").hidden = !checked;
    // Photos and video are mutually exclusive
    if (checked) {
        const videoCb = document.getElementById("script-use-video");
        if (videoCb && videoCb.checked) {
            videoCb.checked = false;
            toggleVideoUpload();
        }
    }
    toggleScriptPhotoDependentFields();
    if (!checked) {
        scriptData.createNarration = true;
        const narCb = document.getElementById("script-create-narration");
        if (narCb) narCb.checked = true;
    }
    updateNarrationChoiceVisibility();
    scheduleScriptCreditEstimate();
}

function _setScriptAudioBuilderStatus(message = "", tone = "") {
    const statusEl = document.getElementById("script-audio-builder-status");
    if (!statusEl) return;
    if (!message) {
        statusEl.hidden = true;
        statusEl.textContent = "";
        statusEl.className = "script-audio-builder-status";
        return;
    }
    statusEl.hidden = false;
    statusEl.textContent = message;
    statusEl.className = `script-audio-builder-status${tone ? ` is-${tone}` : ""}`;
}

function _setScriptAudioDictationStatus(message = "", tone = "") {
    const statusEl = document.getElementById("script-audio-dictation-status");
    if (!statusEl) return;
    if (!message) {
        statusEl.hidden = true;
        statusEl.textContent = "";
        statusEl.className = "script-audio-builder-inline-status";
        return;
    }
    statusEl.hidden = false;
    statusEl.textContent = message;
    statusEl.className = `script-audio-builder-inline-status${tone ? ` is-${tone}` : ""}`;
}

function _updateScriptGeneratedAudioSummary() {
    const summaryEl = document.getElementById("script-generated-audio-summary");
    const titleEl = document.getElementById("script-generated-audio-title");
    const nameEl = document.getElementById("script-generated-audio-name");
    const playerEl = document.getElementById("script-generated-audio-player");
    const usingVideo = !!document.getElementById("script-use-video")?.checked;
    const hasGeneratedAudio = !!scriptGeneratedAudioUploadId;

    if (summaryEl) summaryEl.hidden = !hasGeneratedAudio;
    if (titleEl) {
        titleEl.textContent = usingVideo ? "Áudio pronto para este vídeo" : "Áudio pronto para este projeto";
    }
    if (nameEl) {
        if (!hasGeneratedAudio) {
            nameEl.textContent = "";
        } else {
            const durationLabel = scriptGeneratedAudioDurationSeconds > 0
                ? ` • ${Math.max(1, Math.round(scriptGeneratedAudioDurationSeconds))}s`
                : "";
            nameEl.textContent = `${scriptGeneratedAudioFileName || "audio-gerado.mp3"}${durationLabel}`;
        }
    }
    if (playerEl) {
        if (!hasGeneratedAudio || !scriptGeneratedAudioPreviewUrl) {
            playerEl.pause();
            playerEl.removeAttribute("src");
            playerEl.load();
        } else if (playerEl.src !== scriptGeneratedAudioPreviewUrl) {
            playerEl.src = scriptGeneratedAudioPreviewUrl;
            playerEl.load();
        }
    }

    const builderTrigger = document.getElementById("script-video-audio-builder-trigger");
    if (builderTrigger) {
        builderTrigger.classList.toggle("is-ready", hasGeneratedAudio);
    }
    const userAudioBuilderTrigger = document.getElementById("script-user-audio-builder-trigger");
    if (userAudioBuilderTrigger) {
        userAudioBuilderTrigger.classList.toggle("is-ready", hasGeneratedAudio);
    }
}

function updateScriptVideoAreaVisibility() {
    const section = document.getElementById("script-video-upload-section");
    const header = document.getElementById("script-video-tools-header");
    const area = document.getElementById("script-video-area");
    const builder = document.getElementById("script-video-audio-builder");
    const selectionRow = document.getElementById("script-video-selection-row");
    const narrationChoice = document.getElementById("script-video-narration-choice");
    const clearBtn = document.getElementById("script-video-clear-btn");
    const uploadTrigger = document.getElementById("script-video-upload-trigger");
    const builderTrigger = document.getElementById("script-video-audio-builder-trigger");
    const audioSection = document.getElementById("script-user-audio-section");
    const audioArea = document.getElementById("script-user-audio-area");
    const audioSelectionRow = document.getElementById("script-user-audio-selection-row");
    const audioClearBtn = document.getElementById("script-user-audio-clear-btn");
    const audioMusicChoice = document.getElementById("script-audio-music-choice");
    const audioUploadTrigger = document.getElementById("script-user-audio-upload-trigger");
    const audioVideoTrigger = document.getElementById("script-user-audio-video-trigger");
    const builderHeading = document.getElementById("script-audio-builder-heading");
    const builderSubheading = document.getElementById("script-audio-builder-subheading");
    const videoEnabled = !!document.getElementById("script-use-video")?.checked;
    const userAudioEnabled = !!document.getElementById("script-use-user-audio")?.checked;
    const audioFirstMode = _isCreateAudioFirstMode();
    const hasVideo = !!scriptUserVideoFile;
    const hasManualAudio = !!scriptUserAudioFile;
    const builderOpen = !!builder && !builder.hidden;
    const hasGeneratedAudio = !!scriptGeneratedAudioUploadId;
    const shouldShowSection = audioFirstMode
        ? (builderOpen || hasGeneratedAudio)
        : (videoEnabled || builderOpen || hasGeneratedAudio);
    const shouldShow = audioFirstMode
        ? (builderOpen || hasGeneratedAudio)
        : (hasVideo || builderOpen || hasGeneratedAudio);

    if (section) section.hidden = !shouldShowSection;
    if (header) header.hidden = audioFirstMode || !videoEnabled;
    if (area) area.hidden = !shouldShow;
    if (selectionRow) selectionRow.hidden = audioFirstMode || !hasVideo;
    if (clearBtn) clearBtn.hidden = !hasVideo;
    if (narrationChoice) narrationChoice.hidden = audioFirstMode || !hasVideo || hasGeneratedAudio;
    if (uploadTrigger) uploadTrigger.classList.toggle("has-file", hasVideo);
    if (uploadTrigger) uploadTrigger.hidden = audioFirstMode || !videoEnabled;
    if (builderTrigger) builderTrigger.hidden = audioFirstMode || !videoEnabled;
    if (audioSection) audioSection.hidden = audioFirstMode || !userAudioEnabled;
    if (audioArea) audioArea.hidden = audioFirstMode || !userAudioEnabled;
    if (audioSelectionRow) audioSelectionRow.hidden = !hasManualAudio;
    if (audioClearBtn) audioClearBtn.hidden = !hasManualAudio;
    if (audioMusicChoice) audioMusicChoice.hidden = !hasManualAudio;
    if (audioUploadTrigger) audioUploadTrigger.classList.toggle("has-file", hasManualAudio && scriptUserAudioSourceKind !== "video");
    if (audioVideoTrigger) {
        audioVideoTrigger.classList.toggle("has-file", hasManualAudio && scriptUserAudioSourceKind === "video");
        audioVideoTrigger.disabled = scriptUserAudioVideoExtracting;
    }
    const builderCopy = document.getElementById("script-audio-builder-copy");
    if (builderCopy) builderCopy.hidden = audioFirstMode || !hasVideo;
    if (builderHeading && hasVideo) {
        builderHeading.textContent = "Criar áudio para este vídeo";
    }
    if (builderSubheading && hasVideo) {
        builderSubheading.textContent = "Grave para transcrever, cole a letra ou escreva o texto e gere o áudio antes de continuar.";
    }

    _syncScriptAudioFirstSurface();
}

