let personaRecordingTimer = null;
let personaSampleBlobs = {}; // keyed by prefix: 'wizard' or 'script'
const PERSONA_SAMPLE_HINT_TEXT = "Grave, envie áudio ou extraia 10-30s de um vídeo para criar seu perfil de voz";

