function _renderGlobalBalance() {
    const balanceText = `${_formatCreditsInt(_userCredits)} créditos`;
    document.querySelectorAll("[data-credits-count]").forEach((el) => {
        el.textContent = balanceText;
    });
}

async function updateCreditsDisplay() {
    _renderGlobalBalance();
    try {
        const data = await api("/credits");
        _userCredits = data.credits;
        _creditsPerMinute = data.creditsPerMinute || 5;
        _creditPackages = data.packages || [];
        _creditPlans = data.plans || [];
        _creditComparisonSections = data.comparisonSections || [];
        _creditValueBrl = Number(data.creditValueBrl || 0);
        _creditValueUsd = Number(data.creditValueUsd || 0.01) || 0.01;
        _creditPricingVersion = String(data.pricingVersion || "");
        _currentCreditPlan = String(data.currentPlan || "free").trim().toLowerCase() || "free";
        _currentCreditPlanExpiresAt = data.planExpiresAt || "";
        _renderGlobalBalance();
        renderSession();

        scheduleWizardCreditEstimate();
        scheduleScriptCreditEstimate();
        scheduleAutoCreditEstimate();
        scheduleWorkflowCreditEstimate();
    } catch {}
}

function _formatUsd(value, suffix = "") {
    const parsed = Number(value || 0);
    const safe = Number.isFinite(parsed) ? parsed : 0;
    const decimals = safe >= 10 && Math.abs(safe - Math.round(safe)) < 0.0001 ? 0 : 2;
    const suffixText = suffix ? ` ${suffix}` : "";
    return `$${safe.toFixed(decimals)}${suffixText}`;
}

function _formatCompactMoney(value, currency = "usd") {
    return currency === "brl" ? _formatBrl(value) : _formatUsd(value, "USD");
}

function _creditPlansCatalog() {
    return _creditPlans.length ? _creditPlans : _fallbackCreditPlans;
}

function _creditPackagesCatalog() {
    return _creditPackages.length ? _creditPackages : _fallbackCreditPackages;
}

function _paidCreditPlans() {
    return _creditPlansCatalog().filter((plan) => String(plan.code || "").toLowerCase() !== "free");
}

function _getCreditPlanByCode(planCode) {
    const raw = String(planCode || "free").trim().toLowerCase() || "free";
    const normalized = raw === "pro" ? "professional" : raw;
    return _creditPlansCatalog().find((plan) => String(plan.code || "").toLowerCase() === normalized) || _creditPlansCatalog()[0] || null;
}

function _getCurrentPlanLabel() {
    const current = _getCreditPlanByCode(_currentCreditPlan);
    return current ? (current.name || current.shortName || current.code || "Gratuito") : "Gratuito";
}

function _getDisplayPrice(entry) {
    if (_creditDisplayCurrency === "brl") {
        return _formatBrl(entry.price || 0);
    }
    return _formatUsd(entry.priceUsd || 0, "USD");
}

function _normalizeCreditBillingPeriod(period) {
    return String(period || "monthly").trim().toLowerCase() === "annual" ? "annual" : "monthly";
}

function _getPlanBillingDetails(plan, billingPeriod = _creditBillingPeriod) {
    const normalizedPeriod = _normalizeCreditBillingPeriod(billingPeriod);
    const isFreePlan = String(plan?.code || "").trim().toLowerCase() === "free";
    const monthlyCredits = parseInt(plan?.monthlyCredits || 0, 10) || 0;
    const annualDiscountPercent = Math.max(0, parseInt(plan?.annualDiscountPercent || 20, 10) || 20);
    const monthlyPriceUsd = Number(plan?.monthlyPriceUsd ?? plan?.priceUsd ?? 0) || 0;
    const monthlyPriceBrl = Number(plan?.monthlyPrice ?? plan?.price ?? 0) || 0;
    const annualPriceUsd = Number(plan?.annualPriceUsd ?? (monthlyPriceUsd * 12 * (1 - (annualDiscountPercent / 100)))) || 0;
    const annualPriceBrl = Number(plan?.annualPrice ?? (monthlyPriceBrl * 12 * (1 - (annualDiscountPercent / 100)))) || 0;
    const annualCredits = parseInt(plan?.annualCredits || (monthlyCredits * 12), 10) || 0;
    const configuredBilling = plan?.billing?.[normalizedPeriod] || null;

    const details = normalizedPeriod === "annual" && !isFreePlan
        ? {
            period: "annual",
            label: "Anual",
            days: Number(configuredBilling?.days || 365) || 365,
            credits: parseInt(configuredBilling?.credits || annualCredits, 10) || annualCredits,
            priceUsd: Number(configuredBilling?.priceUsd ?? annualPriceUsd) || annualPriceUsd,
            price: Number(configuredBilling?.price ?? annualPriceBrl) || annualPriceBrl,
            billingLabel: configuredBilling?.billingLabel || `Ciclo anual de ${Number(configuredBilling?.days || 365) || 365} dias`,
            pointsLabel: `${_formatCreditsInt(annualCredits)} pontos por ano`,
            comparisonMultiplier: 12,
            priceSuffix: "/ano",
            comparisonMetaLabel: `${_formatCreditsInt(annualCredits)} créditos/ano`,
            summaryLabel: `${_formatCreditsInt(annualCredits)} créditos por ciclo anual de ${Number(configuredBilling?.days || 365) || 365} dias`,
            discountPercent: annualDiscountPercent,
        }
        : {
            period: "monthly",
            label: "Mensal",
            days: Number(configuredBilling?.days || 30) || 30,
            credits: parseInt(configuredBilling?.credits || monthlyCredits, 10) || monthlyCredits,
            priceUsd: Number(configuredBilling?.priceUsd ?? monthlyPriceUsd) || monthlyPriceUsd,
            price: Number(configuredBilling?.price ?? monthlyPriceBrl) || monthlyPriceBrl,
            billingLabel: configuredBilling?.billingLabel || `Ciclo mensal de ${Number(configuredBilling?.days || 30) || 30} dias`,
            pointsLabel: `${_formatCreditsInt(monthlyCredits)} pontos por mês`,
            comparisonMultiplier: 1,
            priceSuffix: "/mês",
            comparisonMetaLabel: `${_formatCreditsInt(monthlyCredits)} créditos`,
            summaryLabel: `${_formatCreditsInt(monthlyCredits)} créditos por ciclo de 30 dias`,
            discountPercent: annualDiscountPercent,
        };

    details.priceLabel = _creditDisplayCurrency === "brl"
        ? _formatBrl(details.price || 0)
        : _formatUsd(details.priceUsd || 0, "USD");
    details.headlinePrice = `${details.priceLabel}${details.priceSuffix}`;
    details.equivalentMonthlyLabel = details.period === "annual"
        ? `${_creditDisplayCurrency === "brl" ? _formatBrl((details.price || 0) / 12) : _formatUsd((details.priceUsd || 0) / 12, "USD")}/mês equivalente`
        : "";
    return details;
}

function _getDisplayUnitPrice(row) {
    const unitSuffix = row.unit === "second" ? "s" : "img";
    if (Number(row.usdPerUnit || 0) <= 0) {
        return `Grátis/${unitSuffix}`;
    }
    if (_creditDisplayCurrency === "brl") {
        return `${_formatBrl(row.brlPerUnit || 0)}/${unitSuffix}`;
    }
    return `${_formatUsd(row.usdPerUnit || 0).replace(" USD", "")}/${unitSuffix}`;
}

function _formatComparisonUnits(row, count) {
    const formatted = _formatCreditsInt(count);
    if (row.unit === "second") {
        return `${formatted} s`;
    }
    return `${formatted} imagens`;
}

function _shouldShowCreditTopupSection() {
    return Math.max(0, parseInt(_userCredits || "0", 10) || 0) <= 0;
}

function _ensureCreditOfferSelection() {
    const packages = _creditPackagesCatalog();
    const paidPlans = _paidCreditPlans();

    if (_selectedCreditOffer.kind === "plan") {
        const selectedPlanCode = String(_selectedCreditOffer.code || "").trim().toLowerCase();
        const hasPlan = paidPlans.some((plan) => String(plan.code || "").trim().toLowerCase() === selectedPlanCode);
        if (hasPlan) {
            _selectedCreditOffer.code = selectedPlanCode;
            return;
        }
    }
    if (_selectedCreditOffer.kind === "package") {
        const idx = Number(_selectedCreditOffer.packageIndex || 0);
        if (_shouldShowCreditTopupSection() && packages[idx]) {
            _selectedCreditOffer.packageIndex = idx;
            return;
        }
    }

    _selectedCreditOffer = { kind: "", code: "", packageIndex: 0 };
}

function _applyPreferredCreditOffer(preferredKind = "") {
    const normalized = String(preferredKind || "").trim().toLowerCase();
    if (normalized === "plan") {
        const paidPlans = _paidCreditPlans();
        if (paidPlans.length) {
            const currentPlan = paidPlans.find((plan) => String(plan.code || "").trim().toLowerCase() === _currentCreditPlan);
            _selectedCreditOffer = {
                kind: "plan",
                code: String((currentPlan || paidPlans[0] || {}).code || "starter"),
                packageIndex: 0,
            };
            return;
        }
    }
    if (["package", "topup", "recarga"].includes(normalized) && _shouldShowCreditTopupSection() && _creditPackagesCatalog().length) {
        _selectedCreditOffer = { kind: "package", code: "", packageIndex: 0 };
        return;
    }
    _selectedCreditOffer = { kind: "", code: "", packageIndex: 0 };
}

function _getSelectedCreditOfferDetails() {
    _ensureCreditOfferSelection();

    if (_selectedCreditOffer.kind === "package") {
        const pkg = _creditPackagesCatalog()[Number(_selectedCreditOffer.packageIndex || 0)] || _creditPackagesCatalog()[0] || null;
        if (!pkg) return null;
        return {
            kind: "package",
            title: pkg.label || `Recarga ${_formatCreditsInt(pkg.credits)}`,
            subtitle: `${_formatCreditsInt(pkg.credits)} créditos extras avulsos`,
            priceLabel: _getDisplayPrice(pkg),
            headlinePrice: _getDisplayPrice(pkg),
            purchaseLabel: "Créditos extras",
        };
    }

    const plan = _getCreditPlanByCode(_selectedCreditOffer.code || "");
    if (!plan) return null;
    const billing = _getPlanBillingDetails(plan);
    return {
        kind: "plan",
        title: `${plan.name || plan.shortName || "Plano"}${billing.period === "annual" ? " anual" : ""}`,
        subtitle: billing.summaryLabel,
        priceLabel: billing.priceLabel,
        headlinePrice: billing.headlinePrice,
        purchaseLabel: billing.period === "annual" ? "Plano anual" : "Plano mensal",
    };
}

function _renderPricingPlanCards() {
    const selectedPlanCode = _selectedCreditOffer.kind === "plan" ? String(_selectedCreditOffer.code || "") : "";
    return _paidCreditPlans().map((plan) => {
        const planCode = String(plan.code || "");
        const isSelected = selectedPlanCode === planCode;
        const billing = _getPlanBillingDetails(plan);
        const isCurrent = _creditBillingPeriod === "monthly" && planCode === _currentCreditPlan;
        const badge = plan.badge ? `<span class="pricing-plan-badge">${plan.badge}</span>` : "";
        const ctaLabel = isCurrent ? "Plano atual" : "Selecionar plano";
        const creditsLabel = billing.pointsLabel;
        const benefits = Array.isArray(plan.benefits) ? plan.benefits : [];
        const detailLine = billing.headlinePrice;
        const cycleLabel = billing.period === "annual"
            ? `Cobrança anual com ${billing.discountPercent}% OFF`
            : (plan.billingLabel || billing.billingLabel || "Ciclo mensal de 30 dias");
        const equivalentMonthly = billing.equivalentMonthlyLabel
            ? `<div class="pricing-plan-subprice">${billing.equivalentMonthlyLabel}</div>`
            : "";
        const actionButton = isCurrent
            ? `<button class="pricing-plan-select is-disabled" type="button" disabled>${ctaLabel}</button>`
            : `<button class="pricing-plan-select" type="button" onclick="event.stopPropagation(); selectCreditPlan('${planCode}', true)">${ctaLabel}</button>`;
        return `
            <article class="pricing-plan-card ${isSelected ? "is-selected" : ""}" data-theme="${plan.accent || planCode}" onclick="selectCreditPlan('${planCode}', false)">
                ${badge}
                <div class="pricing-plan-card-head">
                    <h3>${plan.name || plan.shortName || planCode}</h3>
                    <p>${plan.description || ""}</p>
                </div>
                <div class="pricing-plan-price">${detailLine}</div>
                ${equivalentMonthly}
                <div class="pricing-plan-cycle">${cycleLabel}</div>
                ${actionButton}
                <div class="pricing-plan-points">${creditsLabel}</div>
                <ul class="pricing-plan-benefits">
                    ${benefits.map((item) => `<li>${item}</li>`).join("")}
                </ul>
            </article>
        `;
    }).join("");
}

function _renderPricingPackages() {
    const selectedPackageIndex = _selectedCreditOffer.kind === "package"
        ? Number(_selectedCreditOffer.packageIndex || 0)
        : -1;

    return _creditPackagesCatalog().map((pkg, index) => {
        const badge = pkg.badge ? `<span class="pricing-topup-badge">${pkg.badge}</span>` : "";
        const selected = selectedPackageIndex === index ? "is-selected" : "";
        return `
            <button class="pricing-topup-card ${selected}" type="button" onclick="selectCreditPackage(${index}, true)">
                ${badge}
                <span class="pricing-topup-title">${pkg.label || `Recarga ${_formatCreditsInt(pkg.credits)}`}</span>
                <strong class="pricing-topup-price">${_getDisplayPrice(pkg)}</strong>
                <span class="pricing-topup-meta">${_formatCreditsInt(pkg.credits || 0)} créditos extras</span>
                <span class="pricing-topup-copy">${pkg.description || "Saldo avulso para complementar seu ciclo atual."}</span>
            </button>
        `;
    }).join("");
}

function _renderPricingComparisonSections() {
    const sections = Array.isArray(_creditComparisonSections) ? _creditComparisonSections : [];
    const plans = _creditPlansCatalog();
    if (!sections.length || !plans.length) {
        return '<div class="pricing-table-card"><p class="credits-hint">Carregando comparativo de modelos...</p></div>';
    }

    const comparisonHeader = plans.map((plan) => {
        const code = String(plan.code || "free");
        const billing = _getPlanBillingDetails(plan);
        const isCurrent = _creditBillingPeriod === "monthly" && code === _currentCreditPlan;
        const planBudget = parseInt(plan.comparisonCredits || plan.monthlyCredits || 0, 10) || 0;
        const priceLabel = code === "free"
            ? _formatUsd(0, "USD")
            : billing.priceLabel;
        const metaLine = code === "free"
            ? (plan.billingLabel || `${_formatCreditsInt(planBudget)} créditos iniciais`)
            : billing.comparisonMetaLabel;
        const actionLabel = isCurrent ? "Plano atual" : "Selecionar plano";
        const actionButton = code === "free"
            ? `<button class="pricing-compare-plan-btn is-disabled" type="button" disabled>${isCurrent ? "Plano atual" : "Plano gratuito"}</button>`
            : isCurrent
            ? `<button class="pricing-compare-plan-btn is-disabled" type="button" disabled>${actionLabel}</button>`
            : `<button class="pricing-compare-plan-btn" type="button" onclick="selectCreditPlan('${code}', true)">${actionLabel}</button>`;
        return `
            <th class="pricing-compare-plan ${isCurrent ? "is-current" : ""}" data-theme="${plan.accent || code}">
                <div class="pricing-compare-plan-name">${plan.shortName || plan.name || code}</div>
                <div class="pricing-compare-plan-price">${priceLabel}</div>
                <div class="pricing-compare-plan-meta">${metaLine}</div>
                ${actionButton}
            </th>
        `;
    }).join("");

    return sections.map((section) => {
        const rows = Array.isArray(section.rows) ? section.rows : [];
        const defaultVisibleRows = Number(section.defaultVisibleRows || rows.length) || rows.length;
        const expanded = !!_creditExpandedComparisonSections[section.key];
        const visibleRows = expanded ? rows : rows.slice(0, defaultVisibleRows);
        const canToggle = rows.length > defaultVisibleRows;
        const rowsHtml = visibleRows.map((row) => {
            const firstCell = `
                <td class="pricing-model-cell">
                    <strong>${row.label || row.key}</strong>
                    <span>${row.creditsPerUnit || 0} créditos/${row.unit === "second" ? "s" : "imagem"}</span>
                </td>
            `;
            const planCells = plans.map((plan) => {
                const usage = row.plans?.[plan.code] || {};
                const billing = _getPlanBillingDetails(plan);
                const isUnlimited = !!usage.unlimited;
                const baseCount = parseInt(usage.includedUnits || 0, 10) || 0;
                const count = isUnlimited
                    ? null
                    : String(plan.code || "free") === "free"
                    ? baseCount
                    : baseCount * (billing.comparisonMultiplier || 1);
                return `
                    <td class="pricing-model-value-cell" data-theme="${plan.accent || plan.code || 'free'}">
                        <strong>${isUnlimited ? "Ilimitado" : _formatComparisonUnits(row, count)}</strong>
                        <span>${_getDisplayUnitPrice(row)}</span>
                    </td>
                `;
            }).join("");
            return `<tr>${firstCell}${planCells}</tr>`;
        }).join("");

        return `
            <section class="pricing-table-card">
                <div class="pricing-table-section-head">
                    <h3>${section.title || "Comparativo"}</h3>
                </div>
                <div class="pricing-table-scroll">
                    <table class="pricing-comparison-table">
                        <thead>
                            <tr>
                                <th class="pricing-model-cell pricing-model-cell--head">Modelo</th>
                                ${comparisonHeader}
                            </tr>
                        </thead>
                        <tbody>${rowsHtml}</tbody>
                    </table>
                </div>
                ${canToggle
                    ? `<button class="pricing-table-toggle" type="button" onclick="toggleCreditComparisonSection('${section.key}')">${expanded ? "Ver menos" : "Ver mais"}</button>`
                    : ""}
            </section>
        `;
    }).join("");
}

function _renderCreditFaq() {
    return _creditFaqItems.map((item, index) => {
        const isOpen = _creditFaqOpenIndex === index;
        return `
            <button class="pricing-faq-item ${isOpen ? "is-open" : ""}" type="button" onclick="toggleCreditFaq(${index})">
                <span>${item.question}</span>
                <span class="pricing-faq-icon">${isOpen ? "-" : "+"}</span>
            </button>
            <div class="pricing-faq-answer" ${isOpen ? "" : "hidden"}>${item.answer}</div>
        `;
    }).join("");
}

function _renderCreditCheckoutPanel() {
    const selectedOffer = _getSelectedCreditOfferDetails();
    if (!selectedOffer) return "";

    return `
        <section class="pricing-checkout-panel">
            <div class="pricing-checkout-copy">
                <span>${selectedOffer.purchaseLabel}</span>
                <strong>${selectedOffer.title}</strong>
                <small>${selectedOffer.subtitle} • ${selectedOffer.headlinePrice || selectedOffer.priceLabel}</small>
            </div>
            <div class="pricing-checkout-actions">
                <button class="credits-btn credits-btn-pix" type="button" onclick="purchaseCredits('pix')">Pagar com PIX</button>
                <button class="credits-btn credits-btn-card" type="button" onclick="purchaseCredits('card')">Pagar com Cartão</button>
            </div>
        </section>
    `;
}

function closeCreditCheckoutModal() {
    document.getElementById("credit-checkout-modal-overlay")?.remove();
}

function closeCreditsPurchaseModal() {
    closeCreditCheckoutModal();
    document.getElementById("credits-modal-overlay")?.remove();
}

function _renderCreditCheckoutModalContent() {
    const selectedOffer = _getSelectedCreditOfferDetails();
    if (!selectedOffer) return "";

    const isPlan = selectedOffer.kind === "plan";
    const helperText = isPlan
        ? "Confira o plano selecionado e escolha como deseja finalizar o pagamento."
        : "Confira a recarga escolhida e selecione a forma de pagamento para adicionar créditos ao saldo.";

    return `
        <div class="credit-checkout-modal">
            <button class="credits-modal-close" type="button" onclick="closeCreditCheckoutModal()">&times;</button>
            <span class="credit-checkout-kicker">${selectedOffer.purchaseLabel}</span>
            <h3>${isPlan ? "Finalizar escolha do plano" : "Finalizar compra de créditos"}</h3>
            <p class="credit-checkout-description">${helperText}</p>
            <div class="credit-checkout-balance">
                <strong>Saldo atual:</strong> ${_formatCreditsInt(_userCredits)} créditos
            </div>
            ${_renderCreditCheckoutPanel()}
        </div>
    `;
}

function showCreditCheckoutModal() {
    const selectedOffer = _getSelectedCreditOfferDetails();
    if (!selectedOffer) {
        showToast("Selecione um plano ou uma recarga para continuar.", "error");
        return;
    }

    let overlay = document.getElementById("credit-checkout-modal-overlay");
    if (!overlay) {
        overlay = document.createElement("div");
        overlay.id = "credit-checkout-modal-overlay";
        overlay.className = "credit-checkout-modal-overlay";
        overlay.addEventListener("click", (event) => {
            if (event.target === overlay) {
                closeCreditCheckoutModal();
            }
        });
        document.body.appendChild(overlay);
    }

    overlay.innerHTML = _renderCreditCheckoutModalContent();
}

function _renderCreditsPurchaseModalContent() {
    _ensureCreditOfferSelection();
    const currentPlan = _getCurrentPlanLabel();
    const creditUnitText = _creditDisplayCurrency === "brl"
        ? _formatBrl(_creditValueBrl || 0)
        : _formatUsd(_creditValueUsd || 0.01, "USD");
    const expiresText = _currentCreditPlanExpiresAt
        ? new Date(_currentCreditPlanExpiresAt).toLocaleDateString("pt-BR")
        : "";
    const showTopupSection = _shouldShowCreditTopupSection();
    const pricingIntroText = showTopupSection
        ? "Plano mensal com créditos inclusos. Como seu saldo atual acabou, as recargas extras estão liberadas abaixo."
        : "Plano mensal com créditos inclusos. As recargas extras aparecem quando o saldo do ciclo acabar.";

    return `
        <div class="credits-modal credits-modal--pricing">
            <button class="credits-modal-close" type="button" onclick="closeCreditsPurchaseModal()">&times;</button>
            <div class="pricing-shell">
                <div class="pricing-head">
                    <div>
                        <h2>Mude seu plano</h2>
                        <p>${pricingIntroText}</p>
                    </div>
                    <div class="pricing-toolbar">
                        <div class="pricing-currency-switch">
                            <button type="button" class="${_creditDisplayCurrency === "usd" ? "is-active" : ""}" onclick="setCreditDisplayCurrency('usd')">USD</button>
                            <button type="button" class="${_creditDisplayCurrency === "brl" ? "is-active" : ""}" onclick="setCreditDisplayCurrency('brl')">BRL</button>
                        </div>
                        <div class="pricing-period-switch">
                            <button type="button" class="${_creditBillingPeriod === "monthly" ? "is-active" : ""}" onclick="setCreditBillingPeriod('monthly')">Mensal</button>
                            <button type="button" class="${_creditBillingPeriod === "annual" ? "is-active" : ""}" onclick="setCreditBillingPeriod('annual')">Anual <span>20% OFF</span></button>
                        </div>
                        <button class="pricing-enterprise-btn" type="button" disabled>Empresa</button>
                    </div>
                </div>

                <div class="pricing-status-strip">
                    <div>
                        <strong>Plano atual:</strong> ${currentPlan}${expiresText ? ` até ${expiresText}` : ""}
                    </div>
                    <div>
                        <strong>1 crédito =</strong> ${creditUnitText}${_creditDisplayCurrency === "usd" ? " por centavo do modelo" : " por crédito"} · ${_creditPricingVersion || "v3.0"}
                    </div>
                </div>

                <div class="pricing-plan-grid">${_renderPricingPlanCards()}</div>

                ${showTopupSection
                    ? `
                <section class="pricing-topup-section">
                    <div class="pricing-topup-section-head">
                        <h3>Créditos extras</h3>
                        <p>Seu saldo atual acabou. Escolha uma recarga avulsa para continuar gerando sem trocar de plano.</p>
                    </div>
                    <div class="pricing-topup-grid">${_renderPricingPackages()}</div>
                </section>`
                    : ""}

                <div class="pricing-comparison-stack">${_renderPricingComparisonSections()}</div>

                <section class="pricing-faq-section">
                    <h3>Perguntas frequentes</h3>
                    <div class="pricing-faq-list">${_renderCreditFaq()}</div>
                </section>
            </div>
        </div>
    `;
}

function _rerenderCreditsPurchaseModal() {
    const overlay = document.getElementById("credits-modal-overlay");
    if (!overlay) return;
    const currentShell = overlay.querySelector(".pricing-shell");
    const scrollTop = currentShell ? currentShell.scrollTop : 0;
    overlay.innerHTML = _renderCreditsPurchaseModalContent();
    const nextShell = overlay.querySelector(".pricing-shell");
    if (nextShell) {
        nextShell.scrollTop = scrollTop;
    }
}

function showCreditsPurchaseModal(preferredKind = "") {
    let overlay = document.getElementById("credits-modal-overlay");
    if (!overlay) {
        overlay = document.createElement("div");
        overlay.id = "credits-modal-overlay";
        overlay.className = "credits-modal-overlay";
        overlay.addEventListener("click", (event) => {
            if (event.target === overlay) {
                closeCreditsPurchaseModal();
            }
        });
        document.body.appendChild(overlay);
    }

    closeCreditCheckoutModal();
    _applyPreferredCreditOffer(preferredKind);
    _ensureCreditOfferSelection();
    overlay.innerHTML = _renderCreditsPurchaseModalContent();
}

function selectCreditPlan(planCode, openCheckout = false) {
    const normalizedPlanCode = String(planCode || "starter");
    const isCurrentPlan = _creditBillingPeriod === "monthly"
        && normalizedPlanCode.trim().toLowerCase() === _currentCreditPlan;
    _selectedCreditOffer = { kind: "plan", code: normalizedPlanCode, packageIndex: 0 };
    _rerenderCreditsPurchaseModal();
    if (openCheckout && !isCurrentPlan) {
        showCreditCheckoutModal();
        return;
    }
    closeCreditCheckoutModal();
}

function selectCreditPackage(idx, openCheckout = false) {
    _selectedCreditOffer = { kind: "package", code: "", packageIndex: Math.max(0, parseInt(idx || "0", 10) || 0) };
    _rerenderCreditsPurchaseModal();
    if (openCheckout) {
        showCreditCheckoutModal();
        return;
    }
    closeCreditCheckoutModal();
}

function setCreditDisplayCurrency(currency) {
    const normalized = String(currency || "usd").trim().toLowerCase();
    if (!["usd", "brl"].includes(normalized)) return;
    _creditDisplayCurrency = normalized;
    _rerenderCreditsPurchaseModal();
}

function setCreditBillingPeriod(period) {
    const normalized = _normalizeCreditBillingPeriod(period);
    if (_creditBillingPeriod === normalized) return;
    _creditBillingPeriod = normalized;
    _rerenderCreditsPurchaseModal();
}

function toggleCreditComparisonSection(sectionKey) {
    _creditExpandedComparisonSections[sectionKey] = !_creditExpandedComparisonSections[sectionKey];
    _rerenderCreditsPurchaseModal();
}

function toggleCreditFaq(index) {
    _creditFaqOpenIndex = _creditFaqOpenIndex === index ? -1 : index;
    _rerenderCreditsPurchaseModal();
}

async function purchaseCredits(method) {
    try {
        const selectedOffer = _getSelectedCreditOfferDetails();
        if (!selectedOffer) {
            showToast("Selecione um plano ou uma recarga para continuar.", "error");
            return;
        }

        let endpoint = method === "pix" ? "/credits/purchase/pix" : "/credits/purchase/card";
        let payload = { packageIndex: 0 };
        if (_selectedCreditOffer.kind === "plan") {
            endpoint = method === "pix" ? "/credits/purchase/plan/pix" : "/credits/purchase/plan/card";
            payload = { planCode: _selectedCreditOffer.code, billingPeriod: _creditBillingPeriod };
        } else {
            payload = { packageIndex: Number(_selectedCreditOffer.packageIndex || 0) || 0 };
        }

        const data = await api(endpoint, {
            method: "POST",
            body: JSON.stringify(payload),
        });
        closeCreditsPurchaseModal();

        if (method === "pix" && data.pixCopiaECola) {
            showPixQrModal(data);
            pollCreditStatus(data.reference);
        } else if (data.checkoutUrl) {
            window.open(data.checkoutUrl, "_blank");
            showToast(`${selectedOffer.title}: checkout aberto em nova aba.`, "info");
            pollCreditStatus(data.reference);
        }
    } catch (err) {
        showToast(err.message || "Erro ao processar compra.", "error");
    }
}

function showPixQrModal(data) {
    const existing = document.getElementById("pix-modal-overlay");
    if (existing) existing.remove();

    const billingPeriod = _normalizeCreditBillingPeriod(data.billingPeriod || "monthly");
    const purchaseTitle = String(data.kind || "").toLowerCase() === "plan"
        ? `Ative ${data.planName || "seu plano"}${billingPeriod === "annual" ? " anual" : ""} com PIX`
        : "Pague com PIX";
    const purchaseHint = String(data.kind || "").toLowerCase() === "plan"
        ? `${_formatCreditsInt(data.credits || 0)} créditos entram assim que o pagamento confirmar no ${billingPeriod === "annual" ? "ciclo anual" : "ciclo mensal"}.`
        : `${_formatCreditsInt(data.credits || 0)} créditos extras entram assim que o pagamento confirmar.`;

    const overlay = document.createElement("div");
    overlay.id = "pix-modal-overlay";
    overlay.className = "pix-modal-overlay";
    overlay.addEventListener("click", (e) => { if (e.target === overlay) overlay.remove(); });
    overlay.innerHTML = `
        <div class="pix-modal">
            <h3>${purchaseTitle}</h3>
            ${data.qrBase64 ? `<img class="pix-qr-img" src="data:image/png;base64,${data.qrBase64}" alt="QR Code PIX"/>` : ""}
            <div class="pix-code-box" id="pix-code">${data.pixCopiaECola}</div>
            <button class="pix-copy-btn" onclick="navigator.clipboard.writeText(document.getElementById('pix-code').textContent);this.textContent='Copiado!';">Copiar código PIX</button>
            <p class="pix-waiting">${purchaseHint}</p>
        </div>
    `;
    document.body.appendChild(overlay);
}

async function pollCreditStatus(reference) {
    for (let i = 0; i < 120; i++) {
        await new Promise((r) => setTimeout(r, 5000));
        try {
            const data = await api(`/credits/status/${encodeURIComponent(reference)}`);
            if (data.status === "confirmed") {
                document.getElementById("pix-modal-overlay")?.remove();
                const isPlan = String(data.kind || "").toLowerCase() === "plan";
                const plan = isPlan ? _getCreditPlanByCode(data.planCode || "") : null;
                if (isPlan && plan) {
                    const billingPeriod = _normalizeCreditBillingPeriod(data.billingPeriod || "monthly");
                    const planLabel = `${plan.name || "Plano"}${billingPeriod === "annual" ? " anual" : ""}`;
                    showToast(`${planLabel} ativado com ${_formatCreditsInt(data.credits || 0)} créditos.`, "success");
                } else {
                    showToast(`${_formatCreditsInt(data.credits || 0)} créditos adicionados!`, "success");
                }
                updateCreditsDisplay();
                return;
            }
        } catch {}
    }
}

// Wire up all page credit badges.
document.querySelectorAll("[data-credits-trigger]").forEach((el) => {
    el.addEventListener("click", () => {
        showCreditsPurchaseModal(el.dataset.creditsPreferred || "");
    });
});

window.selectCreditPackage = selectCreditPackage;
window.selectCreditPlan = selectCreditPlan;
window.showCreditCheckoutModal = showCreditCheckoutModal;
window.closeCreditCheckoutModal = closeCreditCheckoutModal;
window.closeCreditsPurchaseModal = closeCreditsPurchaseModal;
window.setCreditDisplayCurrency = setCreditDisplayCurrency;
window.setCreditBillingPeriod = setCreditBillingPeriod;
window.toggleCreditComparisonSection = toggleCreditComparisonSection;
window.toggleCreditFaq = toggleCreditFaq;
window.purchaseCredits = purchaseCredits;

