let _editorMobileBarDragSuppressUntil = 0;

function _editorBindMobileHorizontalBarDrag(container) {
    if (!container || container.dataset.mobileBarDragBound === "1") return;
    container.dataset.mobileBarDragBound = "1";

    const drag = {
        pointerId: null,
        startX: 0,
        startScrollLeft: 0,
        active: false,
        captured: false,
    };

    const finishDrag = (pointerId = drag.pointerId) => {
        if (drag.captured && pointerId != null && typeof container.releasePointerCapture === "function") {
            try {
                container.releasePointerCapture(pointerId);
            } catch (_) {
                // Ignore missing capture release on browsers that do not support it.
            }
        }

        if (drag.active) {
            _editorMobileBarDragSuppressUntil = Date.now() + 180;
        }

        drag.pointerId = null;
        drag.startX = 0;
        drag.startScrollLeft = 0;
        drag.active = false;
        drag.captured = false;
        container.classList.remove("editor-mobile-bar-dragging");
    };

    container.addEventListener("pointerdown", (event) => {
        if (!_editorIsMobileViewport()) return;
        if (event.pointerType === "mouse" && event.button !== 0) return;

        drag.pointerId = event.pointerId;
        drag.startX = event.clientX;
        drag.startScrollLeft = Number(container.scrollLeft || 0);
        drag.active = false;
    });

    container.addEventListener("pointermove", (event) => {
        if (!_editorIsMobileViewport() || drag.pointerId !== event.pointerId) return;

        const deltaX = event.clientX - drag.startX;
        if (!drag.active && Math.abs(deltaX) < 6) {
            return;
        }

        if (!drag.captured && typeof container.setPointerCapture === "function") {
            try {
                container.setPointerCapture(event.pointerId);
                drag.captured = true;
            } catch (_) {
                // Ignore browsers that refuse capture for this target.
            }
        }

        drag.active = true;
        container.classList.add("editor-mobile-bar-dragging");
        container.scrollLeft = Math.max(0, drag.startScrollLeft - deltaX);
        event.preventDefault();
    });

    container.addEventListener("pointerup", (event) => {
        if (drag.pointerId !== event.pointerId) return;
        finishDrag(event.pointerId);
    });

    container.addEventListener("pointercancel", (event) => {
        if (drag.pointerId !== event.pointerId) return;
        finishDrag(event.pointerId);
    });

    container.addEventListener("lostpointercapture", () => {
        if (drag.pointerId == null) return;
        finishDrag();
    });

    container.addEventListener("click", (event) => {
        if (!_editorIsMobileViewport()) return;
        if (Date.now() >= _editorMobileBarDragSuppressUntil) return;
        event.preventDefault();
        event.stopPropagation();
        _editorMobileBarDragSuppressUntil = 0;
    }, true);
}

function _editorAttachPreviewSeekHandlers(videoEl) {
    if (!videoEl || videoEl._editorSeekHandlersAttached) return;

    videoEl._editorSeekHandlersAttached = true;
    videoEl._editorPendingSeekTime = Number.NaN;
    videoEl._editorSeekInFlight = false;
    videoEl._editorLastSeekTs = 0;
    videoEl._editorLastSeekApplied = Number(videoEl.currentTime || 0);

    videoEl.addEventListener("seeked", () => {
        videoEl._editorSeekInFlight = false;
        videoEl._editorLastSeekApplied = Number(videoEl.currentTime || 0);
    });
}

function _editorPreviewSeekTo(videoEl, targetTime, options = {}) {
    if (!videoEl) return;

    _editorAttachPreviewSeekHandlers(videoEl);

    const safeTarget = Math.max(0, Number(targetTime || 0));
    const force = Boolean(options.force);
    const threshold = Math.max(0.02, Number(options.threshold || _EDITOR_PREVIEW_SEEK_THRESHOLD));
    const minIntervalMs = Math.max(16, Number(options.minIntervalMs || _EDITOR_PREVIEW_SEEK_INTERVAL_MS));
    const nowMs = Number(options.nowMs || performance.now());

    videoEl._editorPendingSeekTime = safeTarget;

    if (!force) {
        const currentDiff = Math.abs(Number(videoEl.currentTime || 0) - safeTarget);
        const lastAppliedDiff = Math.abs(Number(videoEl._editorLastSeekApplied || 0) - safeTarget);
        if (currentDiff <= threshold || lastAppliedDiff <= threshold) {
            return;
        }
        if (videoEl._editorSeekInFlight) {
            return;
        }
        if (nowMs - Number(videoEl._editorLastSeekTs || 0) < minIntervalMs) {
            return;
        }
    }

    videoEl._editorSeekInFlight = true;
    videoEl._editorLastSeekTs = nowMs;
    try {
        videoEl.currentTime = safeTarget;
    } catch {
        videoEl._editorSeekInFlight = false;
    }
}

