async function _editorGenerateAIMusic() {
    if (!_editor.projectId) {
        showToast("Projeto não encontrado no editor.", "error");
        return;
    }
    if (_editorAIMusicModal.generating) return;

    _editorAIMusicModal.generating = true;
    _editorAIMusicModal.error = "";
    _editorRenderAIMusicModal();

    try {
        const timelineDuration = Math.max(1, Number(_editorGetTimelineDuration() || _editor.duration || 0));
        const payload = await api("/video/editor/generate-tevoxi-music", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
                project_id: Number(_editor.projectId || 0),
                mood: _editorAIMusicModal.mood,
                characteristics: (_editorAIMusicModal.characteristics || "").trim(),
                duration_seconds: timelineDuration,
            }),
        });

        const serverPath = String(payload?.path || "").trim();
        const mediaUrlRaw = String(payload?.media_url || "").trim();
        const mediaUrl = mediaUrlRaw.startsWith("/")
            ? `${API.replace("/api", "")}${mediaUrlRaw}`
            : mediaUrlRaw;

        if (!serverPath) {
            throw new Error("Falha ao gerar áudio IA no servidor");
        }

        _editorSaveState();
        _editor._musicSource = "ai";
        _editor._musicFile = null;
        _editor._musicServerPath = serverPath;
        _editor.musicUrl = mediaUrl;
        _editorSetMusicPreviewSource(_editor.musicUrl || "");

        if (!_editor.audioSegments.length) {
            _editor.audioSegments = _editorCloneVideoSegmentsForAudio();
        }
        _editor.selectedTracks = ["video", "audio"];
        _editor.selectedClip = { kind: "music", id: "music" };
        _editorRefreshQuickActions();
        _editorRenderProps();
        _editorRenderTimeline();

        _editorAIMusicModal.open = false;
        _editorAIMusicModal.generating = false;
        _editorRenderAIMusicModal();
        showToast("Áudio IA criado com sucesso e adicionado na faixa!", "success");
    } catch (err) {
        _editorAIMusicModal.generating = false;
        _editorAIMusicModal.error = err?.message || "Erro ao gerar áudio IA";
        _editorRenderAIMusicModal();
        showToast("Erro ao gerar áudio IA: " + (_editorAIMusicModal.error || "erro desconhecido"), "error");
    }
}
window._editorGenerateAIMusic = _editorGenerateAIMusic;

function _editorResolveMediaLayerPlacement(layer) {
    const width = Math.max(8, Math.min(100, Number(layer?.width || 100)));
    const rawX = Math.max(0, Math.min(100, Number(layer?.x || 0)));
    const rawY = Math.max(0, Math.min(100, Number(layer?.y || 0)));
    const layoutMode = String(layer?.layoutMode || "").trim();
    if (layoutMode === "track-sequence") {
        return {
            width: 100,
            x: 0,
            y: 0,
            layoutMode: "track-sequence",
        };
    }
    const legacyAutoCenter = !layoutMode && width >= 99.5 && rawX <= 0.01 && rawY <= 0.01;
    const autoCenter = layoutMode === "auto-center" || legacyAutoCenter;
    return {
        width,
        x: autoCenter ? 50 : rawX,
        y: autoCenter ? 50 : rawY,
        layoutMode: autoCenter ? "auto-center" : (layoutMode || "manual"),
    };
}

function _editorNormalizeMediaLayer(layer) {
    const kind = String(layer?.kind || "image").trim().toLowerCase();
    const aspect = Math.max(0.2, Number(layer.aspectRatio || 1));
    const duration = Math.max(0, Number(layer.duration || 0));
    const sourceOffset = _editorGetMediaLayerSourceOffset({
        ...layer,
        kind,
        duration,
    });
    const sourceDuration = _editorGetMediaLayerSourceDuration({
        ...layer,
        kind,
        duration,
        sourceOffset,
    });
    const speed = _editorMediaLayerPlaybackSpeed(layer);
    const startTime = Math.max(0, Number(layer.startTime || 0));
    let endTime = Math.max(startTime, Number(layer.endTime || 0));
    const maxTimelineSpan = _editorGetMediaLayerMaxTimelineSpan({
        ...layer,
        kind,
        duration,
        sourceOffset,
        sourceDuration,
        speed,
    });
    if (endTime <= startTime + 0.02) {
        endTime = startTime + (Number.isFinite(maxTimelineSpan) ? maxTimelineSpan : 0.1);
    }
    endTime = Math.max(startTime + 0.1, endTime);
    if (Number.isFinite(maxTimelineSpan)) {
        endTime = Math.min(endTime, startTime + maxTimelineSpan);
    }
    const trackIndex = _editorGetLayerTrackIndex(layer);
    const placement = _editorResolveMediaLayerPlacement(layer);
    return {
        ...layer,
        width: placement.width,
        x: placement.x,
        y: placement.y,
        startTime,
        endTime,
        duration,
        sourceOffset,
        sourceDuration,
        speed,
        volume: Math.max(0, Math.min(200, Number(layer.volume ?? 100))),
        audioOnly: Boolean(layer.audioOnly),
        hasAudio: _editorMediaLayerHasAudio(layer),
        reversed: Boolean(layer.reversed),
        aspectRatio: aspect,
        trackIndex,
        layoutMode: placement.layoutMode,
    };
}

function _editorGetMediaLayerLayout(layer, hostWidth, hostHeight) {
    const safeLayer = _editorNormalizeMediaLayer(layer);
    if (safeLayer.layoutMode === "track-sequence") {
        return {
            widthPx: hostWidth,
            heightPx: hostHeight,
            leftPx: 0,
            topPx: 0,
            maxLeft: 0,
            maxTop: 0,
        };
    }
    let widthPx = (hostWidth * safeLayer.width) / 100;
    let heightPx = widthPx / safeLayer.aspectRatio;
    if (heightPx > hostHeight) {
        heightPx = hostHeight;
        widthPx = heightPx * safeLayer.aspectRatio;
    }
    const maxLeft = Math.max(0, hostWidth - widthPx);
    const maxTop = Math.max(0, hostHeight - heightPx);
    const leftPx = (safeLayer.x / 100) * maxLeft;
    const topPx = (safeLayer.y / 100) * maxTop;
    return { widthPx, heightPx, leftPx, topPx, maxLeft, maxTop };
}

function _editorSyncMediaLayersWithTime(timeSec) {
    const host = document.getElementById("editor-media-layer-host");
    if (!host) return;
    const currentTime = Math.max(0, Number(timeSec || 0));
    const shouldPlay = Boolean(_editor.playing);

    host.querySelectorAll(".editor-media-layer-item").forEach((item) => {
        const layer = _editorGetMediaLayerById(item.dataset.id || "");
        if (!layer) {
            item.remove();
            return;
        }

        const normalizedLayer = _editorNormalizeMediaLayer(layer);
        const transitionState = _editorGetLayerPreviewTransitionState(normalizedLayer, currentTime);
        const localTime = Math.max(0, currentTime - normalizedLayer.startTime);
        const sourceOffset = Math.max(0, Number(normalizedLayer.sourceOffset || 0));
        const sourceEnd = _editorGetMediaLayerSourceEnd(normalizedLayer);
        const layerSpeed = _editorMediaLayerPlaybackSpeed(normalizedLayer);
        const clipDuration = Math.max(0, Number(normalizedLayer.endTime || 0) - Number(normalizedLayer.startTime || 0));
        let playbackTime = Math.max(0, sourceOffset + (localTime * layerSpeed));
        if (normalizedLayer.kind === "video" && normalizedLayer.reversed && sourceEnd > 0) {
            const layerSourceEnd = Math.min(sourceEnd, sourceOffset + (clipDuration * layerSpeed));
            playbackTime = Math.max(sourceOffset, layerSourceEnd - (localTime * layerSpeed) - 0.03);
        }
        const reachedVideoEnd = normalizedLayer.kind === "video"
            && sourceEnd > 0
            && !normalizedLayer.reversed
            && playbackTime > sourceEnd;
        const inRange = (
            currentTime >= normalizedLayer.startTime
            && currentTime <= normalizedLayer.endTime
            && !reachedVideoEnd
        ) || Boolean(transitionState?.role === "in");

        item.style.transform = "";
        item.style.filter = "";
        item.style.clipPath = "";
        if (item.dataset.baseZ) {
            item.style.zIndex = item.dataset.baseZ;
        }

        if (normalizedLayer.kind === "audio") {
            item.style.display = "none";
            item.style.opacity = "0";
            item.style.pointerEvents = "none";
        } else if (normalizedLayer.kind === "video" && normalizedLayer.audioOnly) {
            item.style.display = inRange ? "block" : "none";
            item.style.opacity = "0";
            item.style.pointerEvents = "none";
        } else {
            item.style.display = inRange ? "block" : "none";
            item.style.opacity = "1";
            item.style.pointerEvents = "";
        }

        if (transitionState && item.style.display !== "none") {
            _editorApplyPreviewTransitionStyles(item, transitionState, normalizedLayer);
        }

        if (normalizedLayer.kind !== "video" && normalizedLayer.kind !== "audio") return;

        const mediaEl = normalizedLayer.kind === "audio"
            ? item.querySelector("audio")
            : item.querySelector("video");
        if (!mediaEl) return;

        const maxTime = sourceEnd > 0 ? Math.max(0, sourceEnd - 0.05) : playbackTime;
        const targetTime = Math.max(0, Math.min(playbackTime, maxTime));
        const useSmoothReverseSeek = Boolean(shouldPlay && normalizedLayer.reversed && normalizedLayer.kind === "video");
        const syncTolerance = normalizedLayer.kind === "audio"
            ? (shouldPlay ? 0.45 : 0.12)
            : ((normalizedLayer.kind === "video" && normalizedLayer.audioOnly && shouldPlay) ? 0.28 : 0.1);
        if (useSmoothReverseSeek) {
            _editorPreviewSeekTo(mediaEl, targetTime, { nowMs: performance.now() });
        } else if (Math.abs((mediaEl.currentTime || 0) - targetTime) > syncTolerance) {
            try {
                mediaEl.currentTime = targetTime;
            } catch {
                // Ignore seek errors while metadata is loading.
            }
        }
        mediaEl.volume = Math.max(0, Math.min(1, normalizedLayer.volume / 100));
        mediaEl.muted = normalizedLayer.volume <= 0;
        mediaEl.playbackRate = Math.max(0.25, Math.min(8, Number(_editor.playbackRate || 1) * layerSpeed));

        if (shouldPlay && inRange && !mediaEl.ended && !normalizedLayer.reversed && !transitionState?.freezeFrame) {
            if (mediaEl.paused) {
                const playPromise = mediaEl.play();
                if (playPromise?.catch) {
                    playPromise.catch(() => {
                        // Ignore autoplay and interruption errors in preview sync.
                    });
                }
            }
        } else if (!mediaEl.paused) {
            mediaEl.pause();
        }
    });
}

function _editorRenderMediaLayers() {
    const host = document.getElementById("editor-media-layer-host");
    if (!host) return;
    const hostRect = host.getBoundingClientRect();
    const hostWidth = Math.max(1, hostRect.width || host.offsetWidth || 1);
    const hostHeight = Math.max(1, hostRect.height || host.offsetHeight || 1);
    const selectedId = String(_editor.selectedClip.id || "");

    const visibleLayers = _editor.mediaLayers
        .map(rawLayer => _editorNormalizeMediaLayer(rawLayer));

    host.innerHTML = visibleLayers.map((layer, idx) => {
        const layout = _editorGetMediaLayerLayout(layer, hostWidth, hostHeight);
        const selectedClass = selectedId === String(layer.id) && _editor.selectedClip.kind === "media-layer" ? " selected" : "";
        const zIndex = (visibleLayers.length - idx) + 1;
        const isSelected = selectedId === String(layer.id) && _editor.selectedClip.kind === "media-layer";
        const mediaHtml = layer.kind === "video"
            ? `<video src="${esc(layer.url)}" playsinline preload="metadata"></video>`
            : layer.kind === "audio"
                ? `<audio src="${esc(layer.url)}" preload="metadata"></audio>`
                : `<img src="${esc(layer.url)}" alt="Camada" loading="lazy">`;
        const layoutStyle = layer.kind === "audio"
            ? `left:0;top:0;width:0;height:0;z-index:${zIndex};pointer-events:none`
            : `left:${layout.leftPx}px;top:${layout.topPx}px;width:${layout.widthPx}px;height:${layout.heightPx}px;z-index:${zIndex}`;
        return `
            <div
                class="editor-media-layer-item${selectedClass}"
                data-id="${layer.id}"
                data-base-z="${zIndex}"
                style="${layoutStyle}"
            >
                ${mediaHtml}
                ${isSelected && layer.kind !== 'audio' ? '<div class="editor-media-layer-handle" data-role="resize"></div>' : ''}
            </div>
        `;
    }).join("");

    const video = document.getElementById("editor-video");
    const previewTime = Number(_editor.timelineTime || video?.currentTime || 0);
    _editorSyncMediaLayersWithTime(previewTime);
}

function _editorSelectMediaLayer(id, renderProps = true) {
    const layer = _editorGetMediaLayerById(id);
    if (!layer) return;
    const trackIndex = _editorGetLayerTrackIndex(layer);
    const layerTrack = _editorBuildMediaLayerTrackId(_editorGetMediaLayerTrackType(layer), trackIndex);
    _editor.selectedClip = { kind: "media-layer", id: String(layer.id), track: layerTrack };
    _editor.selectedInsertTrack = _editorResolveInsertTrackForUi(layerTrack);

    let switchedTool = false;
    if (renderProps && _editor.activeTool !== "layers") {
        _editorSelectTool("layers");
        switchedTool = true;
    }
    if (renderProps && !switchedTool) {
        _editorRenderProps();
    }

    _editorRenderTimeline();
    _editorRenderMediaLayers();
}
window._editorSelectMediaLayer = _editorSelectMediaLayer;

function _editorSetMediaLayerSize(id, val) {
    const layer = _editorGetMediaLayerById(id);
    if (!layer) return;
    layer.width = Math.max(8, Math.min(100, Number(val || layer.width || 100)));
    layer.layoutMode = "manual";
    _editorRenderMediaLayers();
    _editorRenderProps();
}
window._editorSetMediaLayerSize = _editorSetMediaLayerSize;

function _editorSetMediaLayerX(id, val) {
    const layer = _editorGetMediaLayerById(id);
    if (!layer) return;
    layer.x = Math.max(0, Math.min(100, Number(val || layer.x || 0)));
    layer.layoutMode = "manual";
    _editorRenderMediaLayers();
    _editorRenderProps();
}
window._editorSetMediaLayerX = _editorSetMediaLayerX;

function _editorSetMediaLayerY(id, val) {
    const layer = _editorGetMediaLayerById(id);
    if (!layer) return;
    layer.y = Math.max(0, Math.min(100, Number(val || layer.y || 0)));
    layer.layoutMode = "manual";
    _editorRenderMediaLayers();
    _editorRenderProps();
}
window._editorSetMediaLayerY = _editorSetMediaLayerY;

function _editorSetMediaLayerVolume(id, val) {
    const layer = _editorGetMediaLayerById(id);
    if (!layer || (layer.kind !== "video" && layer.kind !== "audio")) return;
    layer.volume = Math.max(0, Math.min(200, Number(val || layer.volume || 100)));

    const label = document.getElementById("editor-layer-vol-label");
    if (label && _editor.selectedClip.kind === "media-layer" && String(_editor.selectedClip.id) === String(id)) {
        label.textContent = `${Math.round(layer.volume)}%`;
    }

    const video = document.getElementById("editor-video");
    _editorSyncMediaLayersWithTime(Number(_editor.timelineTime || video?.currentTime || 0));
}
window._editorSetMediaLayerVolume = _editorSetMediaLayerVolume;

function _editorToggleMediaLayerAudioOnly(id) {
    const layer = _editorGetMediaLayerById(id);
    if (!layer || layer.kind !== "video") return;
    _editorSaveState();
    layer.audioOnly = !layer.audioOnly;
    _editorRenderMediaLayers();
    _editorRenderTimeline();
    _editorRenderProps();
}
window._editorToggleMediaLayerAudioOnly = _editorToggleMediaLayerAudioOnly;

function _editorSetMediaLayerStart(id, val) {
    const layer = _editorGetMediaLayerById(id);
    if (!layer) return;
    const maxTimeline = _editorGetTimelineDuration();
    const maxSpan = _editorGetMediaLayerMaxTimelineSpan(layer);
    const nextStart = Math.max(0, Math.min(maxTimeline, Number(val || 0)));
    layer.startTime = nextStart;
    layer.endTime = Math.max(nextStart + 0.1, Number(layer.endTime || nextStart + 0.1));
    if (Number.isFinite(maxSpan)) {
        layer.endTime = Math.min(layer.endTime, nextStart + maxSpan);
    }
    if (maxTimeline > 0) {
        layer.endTime = Math.min(maxTimeline, layer.endTime);
    }
    _editorFinalizeTrackSequenceMediaLayerEdit(id);
    _editorRenderTimeline();
    _editorSyncMediaLayersWithTime(Number(_editor.timelineTime || document.getElementById("editor-video")?.currentTime || 0));
    _editorRenderProps();
}
window._editorSetMediaLayerStart = _editorSetMediaLayerStart;

function _editorSetMediaLayerEnd(id, val) {
    const layer = _editorGetMediaLayerById(id);
    if (!layer) return;
    const maxTimeline = _editorGetTimelineDuration();
    const maxSpan = _editorGetMediaLayerMaxTimelineSpan(layer);
    const nextEnd = Math.max(0, Math.min(maxTimeline, Number(val || 0)));
    layer.endTime = nextEnd;
    layer.startTime = Math.min(layer.startTime, Math.max(0, nextEnd - 0.1));
    if (Number.isFinite(maxSpan)) {
        layer.endTime = Math.min(layer.endTime, layer.startTime + maxSpan);
    }
    _editorFinalizeTrackSequenceMediaLayerEdit(id);
    _editorRenderTimeline();
    _editorSyncMediaLayersWithTime(Number(_editor.timelineTime || document.getElementById("editor-video")?.currentTime || 0));
    _editorRenderProps();
}
window._editorSetMediaLayerEnd = _editorSetMediaLayerEnd;

function _editorDeleteMediaLayer(id) {
    _editorSaveState();
    _editor.mediaLayers = _editor.mediaLayers.filter(layer => String(layer.id) !== String(id));
    _editorCollapseVisibleTimelineDeadZones();
    if (_editor.selectedClip.kind === "media-layer" && String(_editor.selectedClip.id) === String(id)) {
        _editor.selectedClip = { kind: "", id: "", track: "" };
    }
    _editorRefreshQuickActions();
    _editorRenderTimeline();
    _editorRenderMediaLayers();
    _editorRenderProps();
}
window._editorDeleteMediaLayer = _editorDeleteMediaLayer;

function _editorPushMediaLayer(kind, payload, options = {}) {
    const previewUrl = String(payload?.media_url || "").trim();
    const serverPath = String(payload?.path || "").trim();
    if (!previewUrl || !serverPath) {
        throw new Error("Resposta de upload invalida para camada.");
    }
    const safeKind = String(kind || payload?.kind || "image").trim().toLowerCase() === "audio"
        ? "audio"
        : (String(kind || payload?.kind || "image").trim().toLowerCase() === "video" ? "video" : "image");
    const width = Math.max(1, Number(payload?.width || 0) || 1);
    const height = Math.max(1, Number(payload?.height || 0) || 1);
    const aspectRatio = width / height;
    const baseDuration = Math.max(0.1, Number(_editor.duration || 0.1));
    const layerDuration = safeKind === "image" ? baseDuration : Math.max(0, Number(payload?.duration || 0));
    const appendToTrack = safeKind === "video" && options?.appendToTrack !== false;
    const sequenceInTrack = safeKind === "video" && options?.sequenceInTrack === true;
    const hasCustomStart = Number.isFinite(Number(options?.startTime));
    const hasCustomEnd = Number.isFinite(Number(options?.endTime));
    const startTime = hasCustomStart
        ? Math.max(0, Number(options.startTime || 0))
        : (safeKind === "audio"
            ? Math.max(0, Number(_editor.timelineTime || document.getElementById("editor-video")?.currentTime || 0))
            : (appendToTrack ? _editorGetLayerVideoAppendStart() : 0));
    const initialSpan = safeKind === "image"
        ? baseDuration
        : Math.max(0.1, layerDuration || 5);
    const initialEnd = hasCustomEnd
        ? Math.max(startTime + 0.1, Number(options.endTime || (startTime + initialSpan)))
        : (startTime + initialSpan);
    const resolvedTrackIndex = Number.isFinite(Number(options?.trackIndex))
        ? Math.max(0, Number(options.trackIndex || 0))
        : (safeKind === "audio" ? _editorGetNextMediaLayerTrackIndex("audio") : 0);
    const layer = {
        id: _editorGenId(),
        kind: safeKind,
        name: String(payload?.name || (safeKind === "audio" ? "Camada de audio" : (safeKind === "video" ? "Camada de video" : "Camada de imagem"))),
        url: previewUrl,
        path: serverPath,
        width: 100,
        x: sequenceInTrack ? 0 : 50,
        y: sequenceInTrack ? 0 : 50,
        startTime,
        endTime: Math.max(0.1, initialEnd),
        duration: layerDuration,
        sourceOffset: 0,
        sourceDuration: safeKind === "video" || safeKind === "audio" ? layerDuration : 0,
        speed: 1,
        aspectRatio,
        volume: 100,
        audioOnly: false,
        hasAudio: safeKind === "audio"
            ? true
            : Boolean(payload?.hasAudio ?? payload?.has_audio ?? (safeKind === "video")),
        trackIndex: resolvedTrackIndex,
        layoutMode: sequenceInTrack ? "track-sequence" : "auto-center",
    };
    _editor.mediaLayers.push(layer);
    if (options?.select === false) {
        return layer;
    }
    _editorSelectMediaLayer(layer.id, true);
    return layer;
}

async function _editorUploadLayerVideo(input) {
    const files = Array.from(input?.files || []);
    if (input) input.value = "";
    if (!files.length) return;
    if (!_editor.projectId) {
        showToast("Abra um projeto no editor antes de enviar vídeos em camada.", "error");
        return;
    }

    const selection = _editorClassifyLocalMediaFiles(files);
    if (selection.error) {
        showToast(selection.error, "error");
        return;
    }

    try {
        const orderedEntries = await _editorResolveMediaImportOrder(selection.orderedEntries, "layer");
        if (!orderedEntries?.length) return;
        _editorSaveState();
        showToast(`Enviando ${orderedEntries.length} mídia(s) para a faixa...`);
        const startTime = Math.max(0, Number(_editorGetTimelineDuration() || 0));
        await _editorAppendOrderedMediaEntries(orderedEntries, { startTime });
        _editorRenderTimeline();
        _editorRenderMediaLayers();
        _editorRenderProps();
    } catch (err) {
        showToast("Erro ao enviar mídia da faixa: " + (err?.message || "erro desconhecido"), "error");
    }
}
window._editorUploadLayerVideo = _editorUploadLayerVideo;

async function _editorUploadLayerAudio(input) {
    const files = Array.from(input?.files || []);
    if (input) input.value = "";
    if (!files.length) return;
    if (!_editor.projectId) {
        showToast("Abra um projeto no editor antes de enviar áudios em camada.", "error");
        return;
    }

    const audioFiles = files.filter((file) => String(file?.type || "").startsWith("audio/"));
    if (!audioFiles.length) {
        showToast("Selecione arquivos de áudio válidos para criar novas faixas.", "error");
        return;
    }

    try {
        _editorSaveState();
        showToast(`Enviando ${audioFiles.length} áudio(s) para novas faixas...`);
        const baseTrackIndex = _editorGetNextMediaLayerTrackIndex("audio");
        const startTime = Math.max(0, Number(_editor.timelineTime || document.getElementById("editor-video")?.currentTime || 0));
        let lastLayer = null;

        const orderedAudioFiles = [...audioFiles].sort(_editorCompareMediaFileNames);
        for (let index = 0; index < orderedAudioFiles.length; index += 1) {
            const payload = await _editorUploadSingleLayerAudio(orderedAudioFiles[index]);
            lastLayer = _editorPushMediaLayer("audio", payload, {
                startTime,
                endTime: startTime + Math.max(0.1, Number(payload?.duration || 0.1)),
                trackIndex: baseTrackIndex + index,
                select: index === orderedAudioFiles.length - 1,
            });
        }

        if (lastLayer) {
            _editor.selectedClip = {
                kind: "media-layer",
                id: String(lastLayer.id),
                track: _editorBuildMediaLayerTrackId("audio", _editorGetLayerTrackIndex(lastLayer)),
            };
        }
        _editorRenderTimeline();
        _editorRenderMediaLayers();
        _editorRenderProps();
        showToast(`${orderedAudioFiles.length} faixa(s) de áudio adicionada(s).`, "success");
    } catch (err) {
        showToast("Erro ao enviar áudio da camada: " + (err?.message || "erro desconhecido"), "error");
    }
}
window._editorUploadLayerAudio = _editorUploadLayerAudio;

async function _editorUploadLayerImage(input) {
    const file = input.files?.[0];
    if (!file) return;
    if (!_editor.projectId) {
        input.value = "";
        showToast("Abra um projeto no editor antes de enviar imagens em camada.", "error");
        return;
    }

    try {
        _editorSaveState();
        showToast("Enviando imagem para camada...");
        const formData = new FormData();
        formData.append("file", file);
        const payload = await apiForm("/video/editor/upload-layer-image", formData, { method: "POST" });
        _editorPushMediaLayer("image", payload);
        _editorRenderTimeline();
        _editorRenderMediaLayers();
        showToast("Nova camada de imagem adicionada.", "success");
    } catch (err) {
        showToast("Erro ao enviar imagem da camada: " + err.message, "error");
    } finally {
        input.value = "";
    }
}
window._editorUploadLayerImage = _editorUploadLayerImage;

function _editorOnMediaLayerPointerDown(e) {
    const host = document.getElementById("editor-media-layer-host");
    const item = e.target.closest(".editor-media-layer-item");
    if (!host || !item || !host.contains(item)) return;

    const layerId = item.dataset.id || "";
    const layer = _editorGetMediaLayerById(layerId);
    if (!layer) return;

    _editorSelectMediaLayer(layerId, true);

    const hostRect = host.getBoundingClientRect();
    const hostWidth = Math.max(1, hostRect.width || host.offsetWidth || 1);
    const hostHeight = Math.max(1, hostRect.height || host.offsetHeight || 1);
    const layout = _editorGetMediaLayerLayout(layer, hostWidth, hostHeight);
    const onResizeHandle = Boolean(e.target.closest(".editor-media-layer-handle[data-role='resize']"));

    _editorMediaLayerDrag = {
        id: String(layer.id),
        mode: onResizeHandle ? "resize" : "move",
        startX: e.clientX,
        startY: e.clientY,
        startLeft: layout.leftPx,
        startTop: layout.topPx,
        startWidth: layout.widthPx,
        startHeight: layout.heightPx,
        hostWidth,
        hostHeight,
        aspectRatio: Math.max(0.2, Number(layer.aspectRatio || 1)),
        maxLeft: layout.maxLeft,
        maxTop: layout.maxTop,
        dirty: false,
    };

    item.setPointerCapture?.(e.pointerId);
    e.preventDefault();
    e.stopPropagation();
}

function _editorOnMediaLayerDragMove(e) {
    if (!_editorMediaLayerDrag) return;
    const drag = _editorMediaLayerDrag;
    const layer = _editorGetMediaLayerById(drag.id);
    if (!layer) {
        _editorMediaLayerDrag = null;
        return;
    }

    const dx = e.clientX - drag.startX;
    const dy = e.clientY - drag.startY;

    if (!drag.dirty && (Math.abs(dx) > 1 || Math.abs(dy) > 1)) {
        _editorSaveState();
        drag.dirty = true;
    }

    let nextLeft = drag.startLeft;
    let nextTop = drag.startTop;
    let nextWidth = drag.startWidth;
    let nextHeight = drag.startHeight;

    if (drag.mode === "resize") {
        const minWidth = Math.max(32, drag.hostWidth * 0.08);
        const maxByWidth = Math.max(minWidth, drag.hostWidth - drag.startLeft);
        const maxByHeight = Math.max(minWidth, (drag.hostHeight - drag.startTop) * drag.aspectRatio);
        nextWidth = Math.max(minWidth, Math.min(Math.min(maxByWidth, maxByHeight), drag.startWidth + dx));
        nextHeight = nextWidth / drag.aspectRatio;

        const nextMaxLeft = Math.max(0, drag.hostWidth - nextWidth);
        const nextMaxTop = Math.max(0, drag.hostHeight - nextHeight);
        nextLeft = Math.max(0, Math.min(nextMaxLeft, drag.startLeft));
        nextTop = Math.max(0, Math.min(nextMaxTop, drag.startTop));

        layer.width = Math.max(8, Math.min(100, (nextWidth / drag.hostWidth) * 100));
        layer.x = nextMaxLeft > 0 ? (nextLeft / nextMaxLeft) * 100 : 0;
        layer.y = nextMaxTop > 0 ? (nextTop / nextMaxTop) * 100 : 0;
        layer.layoutMode = "manual";
    } else {
        nextLeft = Math.max(0, Math.min(drag.maxLeft, drag.startLeft + dx));
        nextTop = Math.max(0, Math.min(drag.maxTop, drag.startTop + dy));
        layer.x = drag.maxLeft > 0 ? (nextLeft / drag.maxLeft) * 100 : 0;
        layer.y = drag.maxTop > 0 ? (nextTop / drag.maxTop) * 100 : 0;
        layer.layoutMode = "manual";
    }

    const host = document.getElementById("editor-media-layer-host");
    const safeId = String(layer.id).replace(/"/g, "\\\"");
    const item = host?.querySelector(`.editor-media-layer-item[data-id="${safeId}"]`);
    if (item) {
        item.style.left = `${nextLeft}px`;
        item.style.top = `${nextTop}px`;
        if (drag.mode === "resize") {
            item.style.width = `${nextWidth}px`;
            item.style.height = `${nextHeight}px`;
        }
    }

    _editorRenderProps();
    e.preventDefault();
}

function _editorOnMediaLayerDragEnd() {
    if (!_editorMediaLayerDrag) return;
    _editorMediaLayerDrag = null;
    _editorRenderMediaLayers();
    _editorRenderProps();
    _editorScheduleDraftPersist(150);
}

async function _editorUploadProjectImages(input) {
    const files = Array.from(input.files || []);
    if (!files.length) return;
    if (!_editor.projectId) {
        input.value = "";
        showToast("Abra um projeto no editor antes de enviar imagens.", "error");
        return;
    }

    try {
        const formData = new FormData();
        files.forEach((file) => formData.append("images", file));
        showToast(`Enviando ${files.length} imagem(ns) para o projeto...`);
        const payload = await apiForm(`/video/projects/${_editor.projectId}/images`, formData, { method: "POST" });
        const savedCount = Math.max(0, Number(payload?.saved_count || 0));
        if (savedCount > 0) {
            showToast(`${savedCount} imagem(ns) enviada(s) para este projeto.`, "success");
        } else {
            showToast("Nenhuma imagem valida foi enviada.", "error");
        }
    } catch (err) {
        showToast("Erro ao enviar imagens: " + err.message, "error");
    } finally {
        input.value = "";
    }
}
window._editorUploadProjectImages = _editorUploadProjectImages;

function _editorParseDurationSeconds(value) {
    if (typeof value === "number") {
        return Number.isFinite(value) && value > 0 ? value : 0;
    }

    const raw = String(value || "").trim();
    if (!raw) return 0;

    if (/^\d+(\.\d+)?$/.test(raw)) {
        const numeric = Number(raw);
        return Number.isFinite(numeric) && numeric > 0 ? numeric : 0;
    }

    const normalized = raw.replace(",", ".");
    const pieces = normalized.split(":").map((part) => Number(part));
    if (pieces.some((part) => !Number.isFinite(part) || part < 0)) {
        return 0;
    }

    if (pieces.length === 3) {
        return (pieces[0] * 3600) + (pieces[1] * 60) + pieces[2];
    }
    if (pieces.length === 2) {
        return (pieces[0] * 60) + pieces[1];
    }

    return 0;
}

function _editorResolveProjectDurationSeconds(detail = {}, render = {}, videoDuration = 0) {
    const metadataDuration = _editorParseDurationSeconds(videoDuration);
    const renderDuration = _editorParseDurationSeconds(render?.duration);
    const trackDuration = _editorParseDurationSeconds(detail?.track_duration);
    const sceneEndDuration = Array.isArray(detail?.scenes)
        ? detail.scenes.reduce((maxValue, scene) => Math.max(maxValue, _editorParseDurationSeconds(scene?.end_time)), 0)
        : 0;

    return Math.max(0.1, metadataDuration, renderDuration, trackDuration, sceneEndDuration);
}

// ---------- Open editor for a project ----------
async function openEditor(projectId, options = {}) {
    try {
        const shouldRestoreDraft = options && options.restoreDraft !== false;
        const initialMediaLayers = Array.isArray(options?.initialMediaLayers) ? options.initialMediaLayers : [];
        const initialImageDurationSeconds = Math.max(0.5, Number(options?.initialImageDurationSeconds || _EDITOR_IMAGE_SEQUENCE_CLIP_SECONDS));
        const hideBaseVideoTrack = Boolean(options?.hideBaseVideoTrack);
        const detail = await api(`/video/projects/${projectId}`);
        const render = _pickLatestAvailableRender(detail.renders || []);
        if (!render || !render.video_url) {
            showToast("Este vídeo não tem arquivo disponível.", "error");
            return;
        }
        // Reset editor state
        _editor.projectId = projectId;
        _editor.videoUrl = render.video_url;
        _editor.sourceProjectTitle = String(detail.title || "").trim();
        _editor.editProjectName = "";
        _editorProjectNameEditState.active = false;
        _editorProjectNameEditState.original = "";
        _editorProjectNameEditState.saving = false;
        _editorSetProjectNameEditingState(false);
        _editor.sourceAspectRatio = ["9:16", "16:9", "1:1"].includes(detail.aspect_ratio) ? detail.aspect_ratio : "9:16";
        _editor.outputAspectRatio = "source";
        _editor.playing = false;
        _editor.activeTool = "trim";
        _editor.smartCuts = [];
        _editor.smartCutsLoading = false;
        _editor.smartCutsError = "";
        _editor.smartCutSubtitleStyle = "destaque";
        _editor.smartCutWords = [];
        _editor.subtitleListOpen = false;
        _editor.selectedClip = { kind: "", id: "", track: "" };
        _editor.texts = [];
        _editor.subtitles = [];
        _editor.videoSegments = [];
        _editor.audioSegments = [];
        _editor.hideBaseVideoTrack = hideBaseVideoTrack;
        _editor.selectedTracks = ["video"];
        _editor.selectedInsertTrack = "video";
        _editor.trimStart = 0;
        _editor.trimEnd = 0;
        _editor.musicUrl = "";
        _editor._musicFile = null;
        _editor._musicServerPath = "";
        _editor._musicSource = "audio";
        _editorSetMusicPreviewSource("");
        _editor.musicVolume = 80;
        _editor.originalVolume = 100;
        _editor.filter = "none";
        _editor.stickers = [];
        _editor.transitions = [];
        _editor.mediaLayers = [];
        _editor.quality = "original";
        _editor.undoStack = [];
        _editor.redoStack = [];
        _editor._nextId = 1;
        _editor.timelineTime = 0;
        _editor.timelineZoom = 1;
        _editor.playbackRate = 1;
        _editor.mobileControlMode = "tools";
        _editor._virtualPlaybackActive = false;
        _editorStopPlaybackFollowLoop();
        _editorInlineTextEditId = "";
        _editorInlineTextEditPendingFocus = "";
        _editorMobileTrackVolumeOpen = "";
        _editorStopVirtualTimelinePlayback();
        _editorResetSourceWaveformState();
        _editorCloseAIMusicModal(true);
        _editorResetAIMusicModalState();
        _editorCloseAudioVideoSourceModal(true);
        _editorCloseRecorderModal(true);

        document.getElementById("editor-select-view").hidden = true;
        document.getElementById("editor-workspace").hidden = false;
        document.getElementById("page-editor")?.classList.add("editor-fullscreen");
        _editorSetMobileControlMode("tools");

        const video = document.getElementById("editor-video");
        video.preload = "auto";
        video.playsInline = true;
        video.setAttribute("playsinline", "true");
        video.setAttribute("webkit-playsinline", "true");
        video.src = _editor.videoUrl;
        video.load();
        let editorReady = false;
        let resolveOpen;
        const readyPromise = new Promise((resolve) => {
            resolveOpen = resolve;
        });
        const refreshEditorPreviewFrame = () => {
            if (!editorReady) return;
            requestAnimationFrame(() => {
                const previewTime = Number(_editor.timelineTime || 0);
                _editorApplyAspectRatio();
                _editorRenderMediaLayers();
                _editorApplyTimelineFrame(previewTime, false);
            });
        };
        const finalizeEditorOpen = () => {
            if (editorReady) return;
            editorReady = true;

            _editor.duration = _editorResolveProjectDurationSeconds(detail, render, Number(video.duration || 0));
            _editorInitVideoSegments();
            let restored = false;
            if (shouldRestoreDraft) {
                restored = _editorRestoreDraft(projectId, _editor.videoUrl);
            } else {
                _editorClearDraft(projectId);
            }
            if (!restored) {
                _editor.timelineTime = 0;
            }

            if (!restored && initialMediaLayers.length) {
                _editorApplyImageSequenceLayers(initialMediaLayers, {
                    startTime: 0,
                    clipSeconds: initialImageDurationSeconds,
                });
            }

            _editorCollapseVisibleTimelineDeadZones();

            if (restored) {
                _editorSetProjectName(_editor.editProjectName, _editor.sourceProjectTitle, Number(projectId || 0));
            } else {
                const generatedName = _editorBuildDefaultEditName(_editor.sourceProjectTitle, Number(projectId || 0));
                _editorSetProjectName(generatedName, _editor.sourceProjectTitle, Number(projectId || 0));
            }

            if (!["9:16", "16:9", "1:1"].includes(detail.aspect_ratio)) {
                _editor.sourceAspectRatio = video.videoWidth >= video.videoHeight ? "16:9" : "9:16";
            }
            _editorApplyAspectRatio();
            _editorRenderMediaLayers();
            document.getElementById("editor-time-total").textContent = _fmtTime(_editorGetTimelineDuration());
            _editorApplyPlaybackRate(_editor.playbackRate, { announce: false });
            _editorApplyTimelineFrame(Number(_editor.timelineTime || 0), false);
            _editorRefreshQuickActions();
            _editorRenderTimeline();
            _editorCenterTimelineOnTime(Number(_editor.timelineTime || 0));
            _editorSelectTool(_editorResolveInitialActiveTool(restored ? _editor.activeTool : "trim", _editor.selectedClip));
            if (shouldRestoreDraft && restored) {
                showToast("Edição restaurada de onde você parou.", "success");
            }
            refreshEditorPreviewFrame();
            resolveOpen?.();
        };
        video.onloadedmetadata = finalizeEditorOpen;
        video.onloadeddata = () => {
            if (!editorReady) {
                finalizeEditorOpen();
            }
            refreshEditorPreviewFrame();
        };
        video.oncanplay = refreshEditorPreviewFrame;
        video.onerror = finalizeEditorOpen;
        setTimeout(finalizeEditorOpen, 1500);
        _updateUndoRedoBtns();
        await readyPromise;
    } catch (err) {
        showToast("Erro ao abrir editor: " + err.message, "error");
    }
}
window.openEditor = openEditor;

async function _editorStartFreshEdit() {
    const projectId = Number(_editor.projectId || 0);
    if (!projectId) {
        showToast("Abra um projeto no editor antes de iniciar uma nova edição.", "error");
        return;
    }

    _editorPersistDraftNow();
    _editorClearDraft(projectId);
    await openEditor(projectId, { restoreDraft: false });
    showToast("Nova edição iniciada do zero.", "success");
}
window._editorStartFreshEdit = _editorStartFreshEdit;

// ---------- Close editor ----------
function closeEditor() {
    _editorCloseSubtitleTextModal();
    _editorPersistDraftNow();
    if (_editorDraftPersistTimer) {
        clearTimeout(_editorDraftPersistTimer);
        _editorDraftPersistTimer = 0;
    }
    document.getElementById("editor-select-view").hidden = false;
    document.getElementById("editor-workspace").hidden = true;
    document.getElementById("page-editor")?.classList.remove("editor-fullscreen");
    _editorCloseLayerVideoLibrary();
    _editorCloseAIMusicModal(true);
    _editorResetAIMusicModalState();
    _editorCloseAudioVideoSourceModal(true);
    _editorCloseRecorderModal(true);
    const video = document.getElementById("editor-video");
    _editorStopPlaybackFollowLoop();
    _editorStopVirtualTimelinePlayback();
    _editor._virtualPlaybackActive = false;
    video.pause();
    video.removeAttribute("src");
    _editorSetMusicPreviewSource("");
    const pp = document.getElementById("editor-props-panel");
    if (pp) {
        pp.classList.remove("open");
        pp.style.removeProperty("display");
    }
    const wrapper = document.getElementById("editor-canvas-wrapper");
    if (wrapper) wrapper.style.removeProperty("--editor-aspect-ratio");
    const layerHost = document.getElementById("editor-media-layer-host");
    if (layerHost) layerHost.innerHTML = "";
    _editor.selectedClip = { kind: "", id: "", track: "" };
    _editor.selectedInsertTrack = "video";
    _editorRefreshQuickActions();
    _editorRefreshTrackSelectionUI();
    _editor.playing = false;
    _editor.timelineTime = 0;
    _editor.timelineZoom = 1;
    _editor.playbackRate = 1;
    _editor.mobileControlMode = "tools";
    _editorResetSourceWaveformState();
    _editorApplyMobileControlMode();
}

// ---------- Format time ----------
function _fmtTime(sec) {
    if (!sec || isNaN(sec)) return "00:00";
    const m = Math.floor(sec / 60);
    const s = Math.floor(sec % 60);
    return String(m).padStart(2, "0") + ":" + String(s).padStart(2, "0");
}

function _editorFormatRateLabel(rate = 1) {
    const safeRate = Math.max(_EDITOR_SEGMENT_SPEED_MIN, Math.min(_EDITOR_SEGMENT_SPEED_MAX, Number(rate || 1)));
    return `${safeRate.toFixed(2).replace(/\.00$/, "").replace(/(\.\d)0$/, "$1")}x`;
}

function _editorClampTimelineZoom(value) {
    const parsed = Number(value || 1);
    if (!Number.isFinite(parsed)) return 1;
    return Math.max(_EDITOR_TIMELINE_MIN_ZOOM, Math.min(_EDITOR_TIMELINE_MAX_ZOOM, parsed));
}

function _editorGetTimelineTrackWidth(durationSec = 0) {
    const timelineEl = document.getElementById("editor-timeline");
    const parentWidth = Number(timelineEl?.parentElement?.clientWidth || 0);
    const viewportWidth = parentWidth > 0 ? parentWidth : Number(timelineEl?.clientWidth || 0);
    const viewportTrackWidth = Math.max(560, viewportWidth - (_editorGetTimelineLabelWidth() + _EDITOR_TIMELINE_RIGHT_GUTTER));
    const zoom = _editorClampTimelineZoom(_editor.timelineZoom || 1);
    const baseWidth = Math.max(420, viewportTrackWidth);
    return Math.round(baseWidth * zoom);
}

function _editorGetTimelineFocusTime() {
    const video = document.getElementById("editor-video");
    return Number(_editor.timelineTime || video?.currentTime || 0);
}

function _editorCenterTimelineOnTime(timeSec) {
    const timelineEl = document.getElementById("editor-timeline");
    if (!timelineEl) return;

    requestAnimationFrame(() => {
        const timelineDuration = _editorGetTimelineDuration();
        if (!timelineDuration) return;
        const trackWidth = Math.max(document.getElementById("editor-track-video")?.offsetWidth || 0, _editorGetTimelineTrackWidth(timelineDuration));
        const safeTime = Math.max(0, Math.min(timelineDuration, Number(timeSec || 0)));
        const leadGutter = _editorGetTimelineLeadGutter();
        const x = _editorGetTimelineLabelWidth() + leadGutter + (safeTime / timelineDuration) * trackWidth;
        const viewportTarget = _editorUseFixedMobilePlayhead() ? _editorGetTimelineViewportFocusOffset() : (timelineEl.clientWidth / 2);
        const targetScroll = Math.max(0, Math.min(timelineEl.scrollWidth - timelineEl.clientWidth, x - viewportTarget));
        timelineEl.scrollLeft = targetScroll;
    });
}

function _editorPreserveTimelineFocusViewport(focusTime, previousTrackWidth = 0) {
    const timelineEl = document.getElementById("editor-timeline");
    const timelineDuration = _editorGetTimelineDuration();
    if (!timelineEl || !timelineDuration) return false;

    const safeFocus = Math.max(0, Math.min(timelineDuration, Number(focusTime || 0)));
    const oldTrackWidth = Math.max(1, Number(previousTrackWidth || _editorGetTimelineTrackWidth(timelineDuration)));
    const oldLeadGutter = _editorGetTimelineLeadGutter();
    const labelWidth = _editorGetTimelineLabelWidth();
    const oldFocusX = labelWidth + oldLeadGutter + ((safeFocus / timelineDuration) * oldTrackWidth);
    const viewportOffset = _editorUseFixedMobilePlayhead()
        ? _editorGetTimelineViewportFocusOffset()
        : (oldFocusX - Number(timelineEl.scrollLeft || 0));

    requestAnimationFrame(() => {
        const nextTrackWidth = Math.max(1, _editorGetTimelineTrackWidth(timelineDuration));
        const nextLeadGutter = _editorGetTimelineLeadGutter();
        const nextFocusX = labelWidth + nextLeadGutter + ((safeFocus / timelineDuration) * nextTrackWidth);
        const maxScroll = Math.max(0, timelineEl.scrollWidth - timelineEl.clientWidth);
        const targetScroll = Math.max(0, Math.min(maxScroll, nextFocusX - viewportOffset));
        timelineEl.scrollLeft = targetScroll;
    });

    return true;
}

function _editorSetTimelineZoom(nextZoom, options = {}) {
    const safeZoom = _editorClampTimelineZoom(nextZoom);
    const focusTime = Number(options.focusTime);
    const resolvedFocus = Number.isFinite(focusTime) ? focusTime : _editorGetTimelineFocusTime();
    const announce = Boolean(options.announce);
    const previousTrackWidth = _editorGetTimelineTrackWidth(_editorGetTimelineDuration());

    if (Math.abs(safeZoom - Number(_editor.timelineZoom || 1)) < 0.0001) {
        _editorPreserveTimelineFocusViewport(resolvedFocus, previousTrackWidth);
        return false;
    }

    _editor.timelineZoom = safeZoom;
    _editorRenderTimeline();
    _editorPreserveTimelineFocusViewport(resolvedFocus, previousTrackWidth);
    if (announce) {
        showToast(`Zoom da timeline: ${Math.round(safeZoom * 100)}%`, "info");
    }
    _editorScheduleDraftPersist(120);
    return true;
}

function _editorAdjustTimelineZoom(direction = 1, options = {}) {
    const current = _editorClampTimelineZoom(_editor.timelineZoom || 1);
    if (direction >= 0) {
        const next = _EDITOR_TIMELINE_ZOOM_LEVELS.find((level) => level > current + 0.001) || _EDITOR_TIMELINE_MAX_ZOOM;
        return _editorSetTimelineZoom(next, options);
    }

    const lowerLevels = _EDITOR_TIMELINE_ZOOM_LEVELS.filter((level) => level < current - 0.001);
    const next = lowerLevels.length ? lowerLevels[lowerLevels.length - 1] : _EDITOR_TIMELINE_MIN_ZOOM;
    return _editorSetTimelineZoom(next, options);
}

function _editorFormatRulerTime(sec, totalDuration, stepSec) {
    const safeSec = Math.max(0, Number(sec || 0));
    const safeTotal = Math.max(0, Number(totalDuration || 0));
    const safeStep = Math.max(0.05, Number(stepSec || 1));

    // For long timelines, keep labels minute-oriented by default.
    if (safeTotal >= 600) {
        if (safeStep >= 60) {
            const minutes = safeSec / 60;
            const rounded = Math.round(minutes * 10) / 10;
            if (Math.abs(rounded - Math.round(rounded)) < 0.05) {
                return `${Math.round(rounded)}m`;
            }
            return `${rounded.toFixed(1)}m`;
        }
        return _fmtTime(safeSec);
    }

    if (safeStep <= 1) {
        return `${safeSec.toFixed(safeStep < 0.5 ? 2 : 1).replace(/\.0+$/, "")}s`;
    }

    if (safeStep <= 30) {
        return `${Math.round(safeSec)}s`;
    }

    return _fmtTime(safeSec);
}

function _editorResolveRulerStepSec(durationSec, trackWidthPx) {
    const safeDuration = Math.max(1, Number(durationSec || 1));
    const safeWidth = Math.max(320, Number(trackWidthPx || 0));
    const targetMarkCount = Math.max(4, Math.floor(safeWidth / 88));
    const rawStep = safeDuration / targetMarkCount;
    const minStepForLongVideo = safeDuration >= 600 && Number(_editor.timelineZoom || 1) <= 1.01 ? 60 : 0;
    const candidate = _EDITOR_RULER_STEPS_SEC.find((step) => step >= Math.max(rawStep, minStepForLongVideo));
    if (candidate) return candidate;
    return Math.max(1200, Math.ceil(rawStep / 300) * 300);
}

function _editorApplyPlaybackRate(nextRate, options = {}) {
    const safeRate = Math.max(0.25, Math.min(2, Number(nextRate || 1)));
    _editor.playbackRate = safeRate;

    const video = document.getElementById("editor-video");
    if (video) {
        video.playbackRate = safeRate;
        video.defaultPlaybackRate = safeRate;
    }

    if (_editorMusicPreviewAudio) {
        _editorMusicPreviewAudio.playbackRate = safeRate;
    }

    if (_editorSourcePreviewAudio) {
        _editorSourcePreviewAudio.playbackRate = safeRate;
    }

    const speedBtn = document.getElementById("editor-quick-speed");
    if (speedBtn) {
        const label = _editorFormatRateLabel(safeRate);
        speedBtn.title = `Velocidade de reprodução (${label})`;
        speedBtn.setAttribute("aria-label", `Velocidade de reprodução ${label}`);
        speedBtn.setAttribute("data-rate-label", label);
    }

    if (options.announce) {
        showToast(`Velocidade: ${_editorFormatRateLabel(safeRate)}`, "info");
    }
    _editorScheduleDraftPersist(120);
}

function _editorCyclePlaybackRate() {
    const current = Math.max(0.25, Math.min(2, Number(_editor.playbackRate || 1)));
    const idx = _EDITOR_PLAYBACK_RATES.findIndex((value) => Math.abs(value - current) < 0.001);
    const next = _EDITOR_PLAYBACK_RATES[(idx + 1 + _EDITOR_PLAYBACK_RATES.length) % _EDITOR_PLAYBACK_RATES.length];
    _editorApplyPlaybackRate(next, { announce: true });
}

// ---------- Play/Pause ----------
function _editorTogglePlay() {
    const video = document.getElementById("editor-video");
    if (!video.src) return;
    _editorApplyPlaybackRate(_editor.playbackRate, { announce: false });

    if (_editor.playing) {
        _editor.playing = false;
        _editorStopPlaybackFollowLoop();
        _editorStopVirtualTimelinePlayback();
        video.pause();
        _editorApplyTimelineFrame(_editor.timelineTime || video.currentTime || 0, false);
        _updatePlayIcon();
        return;
    }

    const timelineDuration = _editorGetTimelineDuration();
    let startTime = Number(_editor.timelineTime || video.currentTime || 0);
    if (startTime >= timelineDuration - 0.02) {
        startTime = 0;
    }

    const sorted = [..._editor.videoSegments].sort((a, b) => a.start - b.start);
    if (sorted.length && startTime <= _editorGetVideoPlaybackEndTime() + 0.01) {
        const first = sorted[0];
        if (first && startTime < first.start) {
            startTime = first.start;
        }
        const inSegment = sorted.some(seg => startTime >= seg.start && startTime <= seg.end);
        if (!inSegment) {
            const next = sorted.find(seg => seg.start > startTime);
            startTime = (next || sorted[0]).start;
        }
    }

    _editorSetMusicPreviewSource(_editor.musicUrl || "");
    _editor.playing = true;
    if (!_editorMusicPreviewPrimed) {
        _editorPrimeMusicPreviewPlayback(startTime);
    }
    _editorSyncBaseVideoPreviewVolume(startTime, true);

    const videoPlaybackEnd = _editorGetVideoPlaybackEndTime();
    if (_editorShouldUseVirtualVideoPlayback() || startTime > videoPlaybackEnd + 0.01) {
        _editorStartVirtualTimelinePlayback(startTime);
    } else {
        _editor._virtualPlaybackActive = false;
        _editorStopVirtualTimelinePlayback();
        video.currentTime = _editorTimelineToSourceTime(startTime);
        const playPromise = video.play();
        if (playPromise?.catch) {
            playPromise.catch(() => {
                // Ignore autoplay interruptions in preview.
            });
        }
        _editorApplyTimelineFrame(startTime, true);
        _editorStartPlaybackFollowLoop();
    }

    _updatePlayIcon();
}

function _updatePlayIcon() {
    const icon = document.getElementById("editor-play-icon");
    if (_editor.playing) {
        icon.innerHTML = '<rect x="6" y="4" width="4" height="16" fill="currentColor"/><rect x="14" y="4" width="4" height="16" fill="currentColor"/>';
    } else {
        icon.innerHTML = '<polygon points="6 3 20 12 6 21 6 3"/>';
    }
}

function _editorResetPlaybackToStart() {
    const video = document.getElementById("editor-video");
    if (!video) return;

    _editorStopPlaybackFollowLoop();
    _editorStopVirtualTimelinePlayback();
    _editor._virtualPlaybackActive = false;
    video.pause();
    video.currentTime = 0;
    _editor.playing = false;
    _editorApplyTimelineFrame(0, false);
    _updatePlayIcon();
}

// ---------- Time update ----------
function _editorTimeUpdate() {
    const video = document.getElementById("editor-video");
    if (!video || _editor._virtualPlaybackActive) return;

    const sourceT = Number(video.currentTime || 0);

    if (_editor.videoSegments.length) {
        const sorted = [..._editor.videoSegments].sort((a, b) => a.start - b.start);
        const last = sorted[sorted.length - 1];
        const lastSourceEnd = _editorSegSourceEnd(last);

        if (_editor.playing && last && sourceT >= (lastSourceEnd - 0.02)) {
            const timelineDuration = _editorGetTimelineDuration();
            if (timelineDuration > Number(last.end || 0) + 0.02) {
                _editorStartVirtualTimelinePlayback(Number(last.end || 0));
            } else {
                _editorResetPlaybackToStart();
            }
            return;
        }

        if (_editor.playing) {
            const currentSeg = sorted.find(seg => {
                const ss = _editorSegSourceStart(seg);
                const se = _editorSegSourceEnd(seg);
                return sourceT >= ss - 0.01 && sourceT < se;
            });
            if (!currentSeg) {
                const next = sorted.find(seg => _editorSegSourceStart(seg) > sourceT);
                if (next) {
                    video.currentTime = _editorSegSourceStart(next);
                    _editorApplyTimelineFrame(Number(next.start), true);
                    return;
                }
            }
        }

        const tl = _editorSourceToTimelineTime(sourceT);
        _editorApplyTimelineFrame(tl, _editor.playing);
    } else if (_editor.playing && _editor.trimEnd > 0 && sourceT >= _editor.trimEnd) {
        const timelineDuration = _editorGetTimelineDuration();
        if (timelineDuration > _editor.trimEnd + 0.02) {
            _editorStartVirtualTimelinePlayback(_editor.trimEnd);
        } else {
            _editorResetPlaybackToStart();
        }
        return;
    } else {
        _editorApplyTimelineFrame(sourceT, _editor.playing);
    }
}

function _editorMovePlayhead(t) {
    const playhead = document.getElementById("editor-timeline-playhead");
    const timelineEl = document.getElementById("editor-timeline");
    const timelineDuration = _editorGetTimelineDuration();
    if (!playhead || !timelineEl || !timelineDuration) return;
    const trackWidth = _editorGetTimelineTrackWidth(timelineDuration);
    const safeTime = Math.max(0, Math.min(timelineDuration, t || 0));
    const pct = timelineDuration > 0 ? (safeTime / timelineDuration) : 0;
    const x = Math.max(0, Math.min(trackWidth - 2, pct * trackWidth));
    const leadGutter = _editorGetTimelineLeadGutter();
    const absoluteX = _editorGetTimelineLabelWidth() + leadGutter + x;

    if (_editorUseFixedMobilePlayhead()) {
        const fixedOffset = _editorGetTimelineViewportFocusOffset();
        const maxScroll = Math.max(0, timelineEl.scrollWidth - timelineEl.clientWidth);
        const targetScroll = Math.max(0, Math.min(maxScroll, absoluteX - fixedOffset));
        if (Math.abs(Number(timelineEl.scrollLeft || 0) - targetScroll) > 0.5) {
            timelineEl.scrollLeft = targetScroll;
        }
        playhead.style.left = `${targetScroll + fixedOffset}px`;
        return;
    }

    playhead.style.left = `${absoluteX}px`;
}

function _editorClampToVideoSegments(timeSec) {
    const sorted = [..._editor.videoSegments].sort((a, b) => a.start - b.start);
    let t = Math.max(0, Math.min(_editor.duration || 0, timeSec));
    const inside = sorted.find(seg => t >= seg.start && t <= seg.end);
    if (inside) return t;
    const next = sorted.find(seg => seg.start > t);
    if (next) return next.start;
    return sorted[sorted.length - 1].end;
}

function _editorSeekByClientX(clientX) {
    const trackContent = document.getElementById("editor-track-video");
    const video = document.getElementById("editor-video");
    const timelineDuration = _editorGetTimelineDuration();
    if (!trackContent || !video || !timelineDuration) return;

    const rect = trackContent.getBoundingClientRect();
    const x = Math.max(0, Math.min(clientX - rect.left, rect.width));
    const pct = rect.width > 0 ? (x / rect.width) : 0;
    const rawTime = pct * timelineDuration;
    const videoPlaybackEnd = _editorGetVideoPlaybackEndTime();

    if (rawTime <= videoPlaybackEnd + 0.01) {
        const nextTime = _editorClampToVideoSegments(rawTime);
        _editorStopVirtualTimelinePlayback();
        _editor._virtualPlaybackActive = false;
        video.currentTime = _editorTimelineToSourceTime(nextTime);
        if (_editor.playing && video.paused) {
            const playPromise = video.play();
            if (playPromise?.catch) {
                playPromise.catch(() => {
                    // Ignore autoplay interruptions in preview.
                });
            }
            _editorStartPlaybackFollowLoop();
        }
        _editorApplyTimelineFrame(nextTime, _editor.playing);
        return;
    }

    const nextTime = Math.max(0, Math.min(timelineDuration, rawTime));
    if (_editor.playing) {
        _editorStartVirtualTimelinePlayback(nextTime);
        return;
    }

    _editorStopVirtualTimelinePlayback();
    _editor._virtualPlaybackActive = true;
    video.pause();
    const anchor = _editorGetVideoTailAnchorTime();
    if (Math.abs(Number(video.currentTime || 0) - anchor) > 0.05) {
        try {
            video.currentTime = anchor;
        } catch {
            // Ignore seek errors while metadata is loading.
        }
    }
    _editorApplyTimelineFrame(nextTime, false);
}

function _editorCapturePointer(target, pointerId) {
    if (!target || pointerId === undefined || typeof target.setPointerCapture !== "function") return;
    try {
        target.setPointerCapture(pointerId);
    } catch {
        // Touch browsers may reject capture while a native scroll is active.
    }
}

function _editorReleasePointerCapture(target, pointerId) {
    if (!target || pointerId === undefined || typeof target.releasePointerCapture !== "function") return;
    try {
        target.releasePointerCapture(pointerId);
    } catch {
        // Ignore if the pointer was already released.
    }
}

function _editorStartTimelineScrub(event) {
    if (!_editorGetTimelineDuration()) return false;
    if (event.button !== undefined && event.button !== 0) return false;
    if (event.target.closest(".editor-track-clip")) return false;
    if (event.target.closest(".editor-track-label")) return false;

    const timelineEl = document.getElementById("editor-timeline");
    const pointerType = String(event.pointerType || "mouse");
    const rulerEl = document.getElementById("editor-timeline-ruler");
    const playheadEl = document.getElementById("editor-timeline-playhead");
    const timelineRect = timelineEl?.getBoundingClientRect?.();
    const playheadRect = playheadEl?.getBoundingClientRect?.();
    const localY = timelineRect ? (Number(event.clientY || 0) - timelineRect.top) : 0;
    const rulerHeight = Math.max(24, Number(rulerEl?.offsetHeight || 24));
    const pointerNearRuler = Boolean(rulerEl && (event.target === rulerEl || event.target.closest?.(".editor-timeline-ruler")));
    const pointerNearPlayhead = Boolean(
        playheadRect
        && Math.abs(Number(event.clientX || 0) - (playheadRect.left + (playheadRect.width / 2))) <= 18
        && localY <= (rulerHeight + 18)
    );
    const prefersDirectScrub = pointerType === "touch" && (pointerNearRuler || pointerNearPlayhead || localY <= (rulerHeight + 6));

    if (pointerType === "touch" && !prefersDirectScrub) {
        return false;
    }

    _editorTimelineScrub = {
        active: true,
        pointerId: event.pointerId,
        pointerType,
        pointerTarget: timelineEl,
        startX: Number(event.clientX || 0),
        startY: Number(event.clientY || 0),
        startScrollLeft: Number(timelineEl?.scrollLeft || 0),
        mode: prefersDirectScrub ? "scrub" : pointerType === "touch" ? "pending" : "scrub",
        moved: false,
    };

    if (_editorTimelineScrub.mode === "scrub") {
        _editorSeekByClientX(event.clientX);
    }

    _editorCapturePointer(timelineEl, event.pointerId);
    document.addEventListener("pointermove", _editorOnTimelineScrubMove);
    document.addEventListener("pointerup", _editorOnTimelineScrubEnd);
    document.addEventListener("pointercancel", _editorOnTimelineScrubEnd);
    return true;
}

function _editorOnTimelineScrubMove(event) {
    const scrub = _editorTimelineScrub;
    if (!scrub?.active) return;
    if (scrub.pointerId !== undefined && event.pointerId !== undefined && event.pointerId !== scrub.pointerId) return;

    const dx = Number(event.clientX || 0) - scrub.startX;
    const dy = Number(event.clientY || 0) - scrub.startY;

    if (scrub.mode === "pending") {
        const threshold = scrub.pointerType === "touch" ? 6 : 0;
        if (Math.abs(dx) < threshold && Math.abs(dy) < threshold) {
            return;
        }

        scrub.moved = true;
        scrub.mode = Math.abs(dx) >= Math.abs(dy) ? "pan" : "scrub";
        if (scrub.mode === "scrub") {
            _editorSeekByClientX(event.clientX);
        }
        return;
    }

    if (scrub.mode === "pan") {
        const timelineEl = document.getElementById("editor-timeline");
        if (!timelineEl) return;
        timelineEl.scrollLeft = Math.max(0, scrub.startScrollLeft - dx);
        if (_editorUseFixedMobilePlayhead()) {
            const nextTime = _editorGetTimeAtTimelineViewport(timelineEl.scrollLeft);
            _editorApplyTimelineFrame(nextTime, _editor.playing);
        }
        scrub.moved = true;
        if (event.cancelable) {
            event.preventDefault();
        }
        return;
    }

    scrub.moved = true;
    _editorSeekByClientX(event.clientX);
}

function _editorOnTimelineScrubEnd(event) {
    document.removeEventListener("pointermove", _editorOnTimelineScrubMove);
    document.removeEventListener("pointerup", _editorOnTimelineScrubEnd);
    document.removeEventListener("pointercancel", _editorOnTimelineScrubEnd);

    const scrub = _editorTimelineScrub;
    if (scrub?.active && scrub.pointerType === "touch" && scrub.mode === "pending" && event?.clientX !== undefined) {
        _editorSeekByClientX(event.clientX);
    }
    _editorReleasePointerCapture(scrub?.pointerTarget, scrub?.pointerId);
    _editorTimelineScrub = null;
}

// ---------- Draw canvas overlays (texts, stickers, subtitles) ----------
function _editorDrawOverlays(t) {
    const canvas = document.getElementById("editor-overlay-canvas");
    const wrapper = document.getElementById("editor-canvas-wrapper");
    if (!canvas || !wrapper) return;
    canvas.width = wrapper.offsetWidth;
    canvas.height = wrapper.offsetHeight;
    const ctx = canvas.getContext("2d");
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // Apply filter to video element
    const video = document.getElementById("editor-video");
    video.style.filter = _getCSSFilter(_editor.filter);

    // Draw texts
    const selectedText = _editorGetSelectedTextItem();
    const inlineEditingTextId = String(_editorInlineTextEditId || "");
    let selectedTextBounds = null;
    for (const txt of _editor.texts) {
        if (t >= txt.startTime && t <= txt.endTime) {
            const fs = txt.fontSize * (canvas.height / 720);
            let fontStr = "";
            if (txt.italic) fontStr += "italic ";
            if (txt.bold) fontStr += "bold ";
            fontStr += fs + "px " + (txt.fontFamily || "Manrope, sans-serif");
            ctx.font = fontStr;
            ctx.fillStyle = txt.color || "#ffffff";
            ctx.textAlign = "center";
            ctx.textBaseline = "middle";
            // Shadow for readability
            ctx.shadowColor = "rgba(0,0,0,0.7)";
            ctx.shadowBlur = 4;
            ctx.shadowOffsetX = 1;
            ctx.shadowOffsetY = 1;
            const x = (txt.x / 100) * canvas.width;
            const y = (txt.y / 100) * canvas.height;
            const isInlineEditing = inlineEditingTextId && String(txt.id) === inlineEditingTextId;
            if (!isInlineEditing) {
                ctx.fillText(txt.content, x, y);
            }
            ctx.shadowColor = "transparent";

            if (_editorIsMobileViewport() && _editor.activeTool === "text" && selectedText && String(selectedText.id) === String(txt.id)) {
                selectedTextBounds = _editorGetTextCanvasBounds(txt, canvas, ctx);
            }
        }
    }

    if (selectedTextBounds && _editorIsMobileViewport() && _editor.activeTool === "text") {
        const scale = canvas.height / 720;
        ctx.save();
        ctx.setLineDash([Math.max(4, 6 * scale), Math.max(3, 4 * scale)]);
        ctx.lineWidth = Math.max(1.6, 2 * scale);
        ctx.strokeStyle = "rgba(238, 246, 255, 0.92)";
        ctx.strokeRect(
            selectedTextBounds.left,
            selectedTextBounds.top,
            selectedTextBounds.right - selectedTextBounds.left,
            selectedTextBounds.bottom - selectedTextBounds.top,
        );
        ctx.setLineDash([]);
        ctx.fillStyle = "rgba(255, 92, 112, 0.96)";
        ctx.beginPath();
        ctx.arc(selectedTextBounds.handleX, selectedTextBounds.handleY, selectedTextBounds.handleRadius, 0, Math.PI * 2);
        ctx.fill();
        ctx.lineWidth = Math.max(1.2, 1.6 * scale);
        ctx.strokeStyle = "rgba(4, 14, 24, 0.82)";
        ctx.stroke();
        const trashW = selectedTextBounds.handleRadius * 0.95;
        const trashH = selectedTextBounds.handleRadius * 1.02;
        const trashX = selectedTextBounds.handleX - (trashW / 2);
        const trashY = selectedTextBounds.handleY - (trashH / 2) + 0.5;
        ctx.strokeStyle = "rgba(255,255,255,0.95)";
        ctx.beginPath();
        ctx.moveTo(trashX + trashW * 0.2, trashY + trashH * 0.22);
        ctx.lineTo(trashX + trashW * 0.8, trashY + trashH * 0.22);
        ctx.moveTo(trashX + trashW * 0.35, trashY + trashH * 0.14);
        ctx.lineTo(trashX + trashW * 0.65, trashY + trashH * 0.14);
        ctx.moveTo(trashX + trashW * 0.28, trashY + trashH * 0.26);
        ctx.lineTo(trashX + trashW * 0.34, trashY + trashH * 0.82);
        ctx.lineTo(trashX + trashW * 0.66, trashY + trashH * 0.82);
        ctx.lineTo(trashX + trashW * 0.72, trashY + trashH * 0.26);
        ctx.moveTo(trashX + trashW * 0.44, trashY + trashH * 0.38);
        ctx.lineTo(trashX + trashW * 0.44, trashY + trashH * 0.68);
        ctx.moveTo(trashX + trashW * 0.56, trashY + trashH * 0.38);
        ctx.lineTo(trashX + trashW * 0.56, trashY + trashH * 0.68);
        ctx.stroke();
        ctx.restore();
    }

    _editorRenderInlineTextEditor(selectedText, selectedTextBounds);

    const selectedSubtitle = _editorGetSelectedSubtitleItem();
    let selectedSubtitleBounds = null;

    // Draw subtitles
    for (const sub of _editor.subtitles) {
        if (t >= sub.startTime && t <= sub.endTime) {
            const scale = canvas.height / 720;
            const fs = (sub.fontSize || 28) * scale;
            let fontStr = "";
            if (sub.italic) fontStr += "italic ";
            if (sub.bold) fontStr += "bold ";
            fontStr += fs + "px " + (sub.fontFamily || "Arial, sans-serif");
            ctx.font = fontStr;
            ctx.textAlign = "center";
            ctx.textBaseline = "middle";
            const sx = (sub.x / 100) * canvas.width;
            const sy = (sub.y / 100) * canvas.height;
            const textW = ctx.measureText(sub.text).width;
            // Background box
            if (sub.bgColor) {
                ctx.fillStyle = sub.bgColor;
                const pad = 8 * scale;
                const radius = 6 * scale;
                const bx = sx - textW / 2 - pad;
                const by = sy - fs / 2 - pad * 0.6;
                const bw = textW + pad * 2;
                const bh = fs + pad * 1.2;
                ctx.beginPath();
                ctx.roundRect(bx, by, bw, bh, radius);
                ctx.fill();
            }
            // Outline
            if (sub.outlineColor) {
                ctx.strokeStyle = sub.outlineColor;
                ctx.lineWidth = Math.max(2, fs * 0.08);
                ctx.lineJoin = "round";
                ctx.strokeText(sub.text, sx, sy);
            }
            // Fill text
            ctx.fillStyle = sub.fontColor || "#ffffff";
            ctx.shadowColor = "rgba(0,0,0,0.6)";
            ctx.shadowBlur = 4;
            ctx.shadowOffsetX = 1;
            ctx.shadowOffsetY = 1;
            ctx.fillText(sub.text, sx, sy);
            ctx.shadowColor = "transparent";

            if (_editor.activeTool === "subtitles" && selectedSubtitle && String(selectedSubtitle.id) === String(sub.id)) {
                selectedSubtitleBounds = _editorGetSubtitleCanvasBounds(sub, canvas, ctx);
            }
        }
    }

    if (selectedSubtitleBounds && _editor.activeTool === "subtitles") {
        const scale = canvas.height / 720;
        ctx.save();
        ctx.setLineDash([Math.max(4, 6 * scale), Math.max(3, 4 * scale)]);
        ctx.lineWidth = Math.max(1.6, 2 * scale);
        ctx.strokeStyle = "rgba(238, 246, 255, 0.92)";
        ctx.strokeRect(
            selectedSubtitleBounds.left,
            selectedSubtitleBounds.top,
            selectedSubtitleBounds.right - selectedSubtitleBounds.left,
            selectedSubtitleBounds.bottom - selectedSubtitleBounds.top,
        );
        ctx.setLineDash([]);
        ctx.fillStyle = "rgba(255, 184, 77, 0.96)";
        ctx.beginPath();
        ctx.arc(selectedSubtitleBounds.handleX, selectedSubtitleBounds.handleY, selectedSubtitleBounds.handleRadius, 0, Math.PI * 2);
        ctx.fill();
        ctx.lineWidth = Math.max(1.2, 1.6 * scale);
        ctx.strokeStyle = "rgba(4, 14, 24, 0.82)";
        ctx.stroke();
        ctx.strokeStyle = "rgba(4, 14, 24, 0.92)";
        ctx.beginPath();
        ctx.moveTo(selectedSubtitleBounds.handleX - selectedSubtitleBounds.handleRadius * 0.34, selectedSubtitleBounds.handleY + selectedSubtitleBounds.handleRadius * 0.18);
        ctx.lineTo(selectedSubtitleBounds.handleX + selectedSubtitleBounds.handleRadius * 0.18, selectedSubtitleBounds.handleY - selectedSubtitleBounds.handleRadius * 0.34);
        ctx.lineTo(selectedSubtitleBounds.handleX + selectedSubtitleBounds.handleRadius * 0.18, selectedSubtitleBounds.handleY + selectedSubtitleBounds.handleRadius * 0.18);
        ctx.closePath();
        ctx.stroke();
        ctx.restore();
    }

    // Draw stickers
    for (const st of _editor.stickers) {
        if (t >= st.startTime && t <= st.endTime) {
            const size = (st.size || 48) * (canvas.height / 720);
            const x = (st.x / 100) * canvas.width;
            const y = (st.y / 100) * canvas.height;
            ctx.font = size + "px serif";
            ctx.textAlign = "center";
            ctx.textBaseline = "middle";
            ctx.fillText(st.emoji, x, y);
        }
    }
}

function _editorFindSubtitleAtCanvasPoint(clientX, clientY) {
    const canvas = document.getElementById("editor-overlay-canvas");
    if (!canvas || !_editor.subtitles.length) return null;

    const video = document.getElementById("editor-video");
    if (!video) return null;
    const currentTime = Number(_editor.timelineTime || video.currentTime || 0);

    const rect = canvas.getBoundingClientRect();
    const x = clientX - rect.left;
    const y = clientY - rect.top;
    if (x < 0 || y < 0 || x > rect.width || y > rect.height) return null;

    const ctx = canvas.getContext("2d");
    if (!ctx) return null;

    const activeSubs = _editor.subtitles.filter(sub => currentTime >= sub.startTime && currentTime <= sub.endTime);
    if (!activeSubs.length) return null;

    for (let i = activeSubs.length - 1; i >= 0; i -= 1) {
        const sub = activeSubs[i];
        const bounds = _editorGetSubtitleCanvasBounds(sub, canvas, ctx);

        if (x >= bounds.left && x <= bounds.right && y >= bounds.top && y <= bounds.bottom) {
            return sub;
        }
    }

    return null;
}

function _editorGetSubtitleCanvasBounds(item, canvas, ctx) {
    const scale = canvas.height / 720;
    const fs = Number(item.fontSize || 28) * scale;
    let fontStr = "";
    if (item.italic) fontStr += "italic ";
    if (item.bold) fontStr += "bold ";
    fontStr += `${fs}px ${item.fontFamily || "Arial, sans-serif"}`;
    ctx.font = fontStr;

    const content = String(item.text || "");
    const textW = ctx.measureText(content).width;
    const pad = item.bgColor ? 8 * scale : 4 * scale;
    const tx = (Number(item.x || 50) / 100) * canvas.width;
    const ty = (Number(item.y || 82) / 100) * canvas.height;
    const handleRadius = Math.max(10, fs * 0.24);
    const left = tx - textW / 2 - pad;
    const right = tx + textW / 2 + pad;
    const top = ty - fs / 2 - pad * 0.7;
    const bottom = ty + fs / 2 + pad * 0.7;
    const handleX = Math.min(canvas.width - handleRadius - 4, right + handleRadius * 0.45);
    const handleY = Math.min(canvas.height - handleRadius - 4, bottom + handleRadius * 0.15);

    return {
        left,
        right,
        top,
        bottom,
        handleX,
        handleY,
        handleRadius,
        widthPct: ((right - left) / Math.max(1, canvas.width)) * 100,
        heightPct: ((bottom - top) / Math.max(1, canvas.height)) * 100,
    };
}

function _editorFindTextAtCanvasPoint(clientX, clientY) {
    const canvas = document.getElementById("editor-overlay-canvas");
    if (!canvas || !_editor.texts.length) return null;

    const video = document.getElementById("editor-video");
    if (!video) return null;
    const currentTime = Number(_editor.timelineTime || video.currentTime || 0);

    const rect = canvas.getBoundingClientRect();
    const x = clientX - rect.left;
    const y = clientY - rect.top;
    if (x < 0 || y < 0 || x > rect.width || y > rect.height) return null;

    const ctx = canvas.getContext("2d");
    if (!ctx) return null;

    const activeTexts = _editor.texts.filter((item) => currentTime >= item.startTime && currentTime <= item.endTime);
    if (!activeTexts.length) return null;

    for (let i = activeTexts.length - 1; i >= 0; i -= 1) {
        const item = activeTexts[i];
        const bounds = _editorGetTextCanvasBounds(item, canvas, ctx);
        if (x >= bounds.left && x <= bounds.right && y >= bounds.top && y <= bounds.bottom) {
            return item;
        }
    }

    return null;
}

function _editorGetTextCanvasBounds(item, canvas, ctx) {
    const scale = canvas.height / 720;
    const fs = Number(item.fontSize || 36) * scale;
    let fontStr = "";
    if (item.italic) fontStr += "italic ";
    if (item.bold) fontStr += "bold ";
    fontStr += `${fs}px ${item.fontFamily || "Manrope, sans-serif"}`;
    ctx.font = fontStr;

    const content = String(item.content || "");
    const textW = ctx.measureText(content).width;
    const pad = Math.max(6 * scale, fs * 0.18);
    const tx = (Number(item.x || 50) / 100) * canvas.width;
    const ty = (Number(item.y || 50) / 100) * canvas.height;
    const handleRadius = Math.max(9, fs * 0.24);
    const left = tx - textW / 2 - pad;
    const right = tx + textW / 2 + pad;
    const top = ty - fs / 2 - pad;
    const bottom = ty + fs / 2 + pad;
    const handleX = Math.min(canvas.width - handleRadius - 4, right + handleRadius * 0.7);
    const handleY = ty;

    return {
        left,
        right,
        top,
        bottom,
        handleX,
        handleY,
        handleRadius,
        widthPct: ((right - left) / Math.max(1, canvas.width)) * 100,
        heightPct: ((bottom - top) / Math.max(1, canvas.height)) * 100,
    };
}

function _editorShouldShowInlineTextEditor(item = null) {
    const selectedText = item || _editorGetSelectedTextItem();
    return Boolean(
        selectedText
        && _editorIsMobileViewport()
        && _editor.activeTool === "text"
        && String(_editorInlineTextEditId || "") === String(selectedText.id || "")
    );
}

function _editorFocusInlineTextEditor(selectAll = false) {
    const input = document.querySelector("#editor-inline-text-host .editor-inline-text-editor");
    if (!input) return;
    try {
        input.focus({ preventScroll: true });
    } catch {
        input.focus();
    }
    if (selectAll && typeof input.select === "function") {
        input.select();
        return;
    }
    if (typeof input.setSelectionRange === "function") {
        const len = String(input.value || "").length;
        input.setSelectionRange(len, len);
    }
}

function _editorRenderInlineTextEditor(item = null, bounds = null) {
    const host = document.getElementById("editor-inline-text-host");
    const canvas = document.getElementById("editor-overlay-canvas");
    if (!host || !canvas) return;

    const selectedText = item || _editorGetSelectedTextItem();
    if (!_editorShouldShowInlineTextEditor(selectedText)) {
        if (host.innerHTML) {
            host.innerHTML = "";
        }
        host.hidden = true;
        return;
    }

    const ctx = canvas.getContext("2d");
    if (!ctx || !selectedText) {
        host.innerHTML = "";
        host.hidden = true;
        return;
    }

    const resolvedBounds = bounds || _editorGetTextCanvasBounds(selectedText, canvas, ctx);
    const scale = canvas.height / 720;
    const width = Math.max(72, resolvedBounds.right - resolvedBounds.left);
    const height = Math.max(32, resolvedBounds.bottom - resolvedBounds.top);
    const left = Math.max(4, Math.min(canvas.width - width - 4, resolvedBounds.left));
    const top = Math.max(4, Math.min(canvas.height - height - 4, resolvedBounds.top));

    let input = host.querySelector(".editor-inline-text-editor");
    const currentId = String(selectedText.id || "");
    if (!input || String(input.dataset.textId || "") !== currentId) {
        host.innerHTML = '<input class="editor-inline-text-editor" type="text" spellcheck="false" autocomplete="off" autocapitalize="sentences">';
        input = host.querySelector(".editor-inline-text-editor");
        input.addEventListener("pointerdown", (event) => {
            event.stopPropagation();
        });
        input.addEventListener("click", (event) => {
            event.stopPropagation();
        });
        input.addEventListener("focus", () => {
            _editorInlineTextEditId = String(input.dataset.textId || "");
        });
        input.addEventListener("blur", () => {
            if (String(_editorInlineTextEditId || "") !== String(input.dataset.textId || "")) return;
            if (!String(input.value || "").trim().length) {
                _editorDeleteText(input._editorTextId);
                return;
            }
            _editorInlineTextEditId = "";
            _editorInlineTextEditPendingFocus = "";
            const video = document.getElementById("editor-video");
            _editorDrawOverlays(Number(_editor.timelineTime || video?.currentTime || 0));
        });
        input.addEventListener("keydown", (event) => {
            event.stopPropagation();
            if (event.key === "Enter") {
                event.preventDefault();
                input.blur();
                return;
            }
            if ((event.key === "Backspace" || event.key === "Delete") && !String(input.value || "").length) {
                event.preventDefault();
                _editorDeleteText(input._editorTextId);
                return;
            }
            if (event.key === "Escape") {
                event.preventDefault();
                _editorInlineTextEditId = "";
                _editorInlineTextEditPendingFocus = "";
                input.blur();
            }
        });
        input.addEventListener("input", () => {
            _editorUpdateTextProp(input._editorTextId, "content", input.value);
        });
    }

    input._editorTextId = selectedText.id;
    input.dataset.textId = currentId;
    input.placeholder = "Digite aqui";
    input.style.left = `${left}px`;
    input.style.top = `${top}px`;
    input.style.width = `${width}px`;
    input.style.height = `${height}px`;
    input.style.lineHeight = `${height}px`;
    input.style.fontSize = `${Math.max(16, Number(selectedText.fontSize || 36) * scale)}px`;
    input.style.fontFamily = String(selectedText.fontFamily || "Manrope, sans-serif");
    input.style.fontWeight = selectedText.bold ? "700" : "500";
    input.style.fontStyle = selectedText.italic ? "italic" : "normal";
    input.style.color = String(selectedText.color || "#ffffff");
    host.hidden = false;

    if (document.activeElement !== input && input.value !== String(selectedText.content || "")) {
        input.value = String(selectedText.content || "");
    }

    if (_editorInlineTextEditPendingFocus && _editorInlineTextEditPendingFocus === currentId) {
        _editorInlineTextEditPendingFocus = "";
        requestAnimationFrame(() => _editorFocusInlineTextEditor(true));
    }
}

function _editorResolveTextOverlayInteraction(clientX, clientY) {
    const canvas = document.getElementById("editor-overlay-canvas");
    if (!canvas || !_editor.texts.length) return null;

    const video = document.getElementById("editor-video");
    if (!video) return null;
    const currentTime = Number(_editor.timelineTime || video.currentTime || 0);

    const rect = canvas.getBoundingClientRect();
    const x = clientX - rect.left;
    const y = clientY - rect.top;
    if (x < 0 || y < 0 || x > rect.width || y > rect.height) return null;

    const ctx = canvas.getContext("2d");
    if (!ctx) return null;

    const activeTexts = _editor.texts.filter((item) => currentTime >= item.startTime && currentTime <= item.endTime);
    if (!activeTexts.length) return null;

    const selectedText = _editorGetSelectedTextItem();
    if (selectedText && activeTexts.some((item) => String(item.id) === String(selectedText.id))) {
        const bounds = _editorGetTextCanvasBounds(selectedText, canvas, ctx);
        const handleDx = x - bounds.handleX;
        const handleDy = y - bounds.handleY;
        if ((handleDx * handleDx) + (handleDy * handleDy) <= (bounds.handleRadius * bounds.handleRadius)) {
            return { item: selectedText, bounds, mode: "delete" };
        }
    }

    for (let i = activeTexts.length - 1; i >= 0; i -= 1) {
        const item = activeTexts[i];
        const bounds = _editorGetTextCanvasBounds(item, canvas, ctx);
        if (x >= bounds.left && x <= bounds.right && y >= bounds.top && y <= bounds.bottom) {
            return { item, bounds, mode: "move" };
        }
    }

    return null;
}

function _editorResolveSubtitleOverlayInteraction(clientX, clientY) {
    if (_editor.activeTool !== "subtitles") return null;

    const canvas = document.getElementById("editor-overlay-canvas");
    if (!canvas || !_editor.subtitles.length) return null;

    const video = document.getElementById("editor-video");
    if (!video) return null;
    const currentTime = Number(_editor.timelineTime || video.currentTime || 0);

    const rect = canvas.getBoundingClientRect();
    const x = clientX - rect.left;
    const y = clientY - rect.top;
    if (x < 0 || y < 0 || x > rect.width || y > rect.height) return null;

    const ctx = canvas.getContext("2d");
    if (!ctx) return null;

    const activeSubs = _editor.subtitles.filter((item) => currentTime >= item.startTime && currentTime <= item.endTime);
    if (!activeSubs.length) return null;

    const selectedSubtitle = _editorGetSelectedSubtitleItem();
    if (selectedSubtitle && activeSubs.some((item) => String(item.id) === String(selectedSubtitle.id))) {
        const bounds = _editorGetSubtitleCanvasBounds(selectedSubtitle, canvas, ctx);
        const handleDx = x - bounds.handleX;
        const handleDy = y - bounds.handleY;
        if ((handleDx * handleDx) + (handleDy * handleDy) <= (bounds.handleRadius * bounds.handleRadius)) {
            return { item: selectedSubtitle, bounds, mode: "resize" };
        }
    }

    for (let i = activeSubs.length - 1; i >= 0; i -= 1) {
        const item = activeSubs[i];
        const bounds = _editorGetSubtitleCanvasBounds(item, canvas, ctx);
        if (x >= bounds.left && x <= bounds.right && y >= bounds.top && y <= bounds.bottom) {
            return { item, bounds, mode: "move" };
        }
    }

    return null;
}

function _editorStartSubtitleOverlayDrag(event) {
    const interaction = _editorResolveSubtitleOverlayInteraction(event.clientX, event.clientY);
    if (!interaction?.item) return false;

    if (!_editorIsMobileViewport() && String(_editor.selectedClip.id || "") !== String(interaction.item.id)) {
        return false;
    }

    _editorSelectSubtitle(interaction.item.id, false);
    const canvas = document.getElementById("editor-overlay-canvas");
    if (!canvas) return false;

    _editorSubtitleOverlayDrag = {
        id: String(interaction.item.id),
        mode: interaction.mode,
        startClientX: event.clientX,
        startClientY: event.clientY,
        startX: Number(interaction.item.x || 50),
        startY: Number(interaction.item.y || 82),
        startFontSize: Number(interaction.item.fontSize || 28),
        widthPct: Number(interaction.bounds.widthPct || 0),
        heightPct: Number(interaction.bounds.heightPct || 0),
        pointerId: event.pointerId,
        pointerTarget: canvas,
        saved: false,
        moved: false,
    };

    _editorCapturePointer(canvas, event.pointerId);
    document.addEventListener("pointermove", _editorOnSubtitleOverlayDragMove);
    document.addEventListener("pointerup", _editorOnSubtitleOverlayDragEnd);
    document.addEventListener("pointercancel", _editorOnSubtitleOverlayDragEnd);
    event.preventDefault();
    event.stopPropagation();
    return true;
}

function _editorOnSubtitleOverlayDragMove(event) {
    if (!_editorSubtitleOverlayDrag) return;
    if (_editorSubtitleOverlayDrag.pointerId !== undefined && event.pointerId !== undefined && event.pointerId !== _editorSubtitleOverlayDrag.pointerId) return;

    const drag = _editorSubtitleOverlayDrag;
    const item = _editor.subtitles.find((entry) => String(entry.id) === String(drag.id));
    if (!item) return;

    const canvas = document.getElementById("editor-overlay-canvas");
    if (!canvas) return;

    const dx = event.clientX - drag.startClientX;
    const dy = event.clientY - drag.startClientY;
    if (Math.abs(dx) > 2 || Math.abs(dy) > 2) {
        drag.moved = true;
    }
    if (drag.moved && !drag.saved) {
        _editorSaveState();
        drag.saved = true;
    }

    if (drag.mode === "resize") {
        const delta = (dx / Math.max(1, canvas.width)) * 180;
        item.fontSize = Math.max(14, Math.min(120, Math.round(drag.startFontSize + delta)));
    } else {
        const halfWidthPct = drag.widthPct / 2;
        const halfHeightPct = drag.heightPct / 2;
        item.x = Math.max(halfWidthPct + 2, Math.min(98 - halfWidthPct, drag.startX + ((dx / Math.max(1, canvas.width)) * 100)));
        item.y = Math.max(halfHeightPct + 2, Math.min(98 - halfHeightPct, drag.startY + ((dy / Math.max(1, canvas.height)) * 100)));
    }

    const video = document.getElementById("editor-video");
    _editorDrawOverlays(Number(_editor.timelineTime || video?.currentTime || 0));
    if (event.cancelable) {
        event.preventDefault();
    }
}

function _editorOnSubtitleOverlayDragEnd() {
    document.removeEventListener("pointermove", _editorOnSubtitleOverlayDragMove);
    document.removeEventListener("pointerup", _editorOnSubtitleOverlayDragEnd);
    document.removeEventListener("pointercancel", _editorOnSubtitleOverlayDragEnd);
    if (!_editorSubtitleOverlayDrag) return;

    _editorReleasePointerCapture(_editorSubtitleOverlayDrag.pointerTarget, _editorSubtitleOverlayDrag.pointerId);
    const moved = Boolean(_editorSubtitleOverlayDrag.moved);
    _editorSubtitleOverlayDrag = null;
    if (!moved) return;

    _editorSubtitleOverlayIgnoreClick = true;
    _editorRenderProps();
    _editorRenderTimeline();
    _editorScheduleDraftPersist(120);
}

function _editorStartTextOverlayDrag(event) {
    if (!_editorIsMobileViewport()) return false;
    const interaction = _editorResolveTextOverlayInteraction(event.clientX, event.clientY);
    if (!interaction?.item) return false;

    if (interaction.mode === "delete") {
        _editorTextOverlayIgnoreClick = true;
        _editorDeleteText(interaction.item.id);
        event.preventDefault();
        event.stopPropagation();
        return true;
    }

    _editorInlineTextEditId = "";
    _editorInlineTextEditPendingFocus = "";
    _editorSelectText(interaction.item.id);
    const canvas = document.getElementById("editor-overlay-canvas");
    if (!canvas) return false;

    _editorTextOverlayDrag = {
        id: String(interaction.item.id),
        mode: interaction.mode,
        startClientX: event.clientX,
        startClientY: event.clientY,
        startX: Number(interaction.item.x || 50),
        startY: Number(interaction.item.y || 50),
        startFontSize: Number(interaction.item.fontSize || 36),
        widthPct: Number(interaction.bounds.widthPct || 0),
        heightPct: Number(interaction.bounds.heightPct || 0),
        pointerId: event.pointerId,
        pointerTarget: canvas,
        saved: false,
        moved: false,
    };

    _editorCapturePointer(canvas, event.pointerId);
    document.addEventListener("pointermove", _editorOnTextOverlayDragMove);
    document.addEventListener("pointerup", _editorOnTextOverlayDragEnd);
    document.addEventListener("pointercancel", _editorOnTextOverlayDragEnd);
    event.preventDefault();
    event.stopPropagation();
    return true;
}

function _editorOnTextOverlayDragMove(event) {
    if (!_editorTextOverlayDrag) return;
    if (_editorTextOverlayDrag.pointerId !== undefined && event.pointerId !== undefined && event.pointerId !== _editorTextOverlayDrag.pointerId) return;

    const drag = _editorTextOverlayDrag;
    const item = _editor.texts.find((entry) => String(entry.id) === String(drag.id));
    if (!item) return;

    const canvas = document.getElementById("editor-overlay-canvas");
    if (!canvas) return;

    const dx = event.clientX - drag.startClientX;
    const dy = event.clientY - drag.startClientY;
    if (Math.abs(dx) > 2 || Math.abs(dy) > 2) {
        drag.moved = true;
    }
    if (drag.moved && !drag.saved) {
        _editorSaveState();
        drag.saved = true;
    }

    if (drag.mode === "resize") {
        const delta = (dx / Math.max(1, canvas.width)) * 180;
        item.fontSize = Math.max(14, Math.min(120, Math.round(drag.startFontSize + delta)));
    } else {
        const halfWidthPct = drag.widthPct / 2;
        const halfHeightPct = drag.heightPct / 2;
        item.x = Math.max(halfWidthPct + 2, Math.min(98 - halfWidthPct, drag.startX + ((dx / Math.max(1, canvas.width)) * 100)));
        item.y = Math.max(halfHeightPct + 2, Math.min(98 - halfHeightPct, drag.startY + ((dy / Math.max(1, canvas.height)) * 100)));
    }

    const video = document.getElementById("editor-video");
    _editorDrawOverlays(Number(_editor.timelineTime || video?.currentTime || 0));
    _editorRenderMobileStagePanel();
    if (event.cancelable) {
        event.preventDefault();
    }
}

function _editorOnTextOverlayDragEnd() {
    document.removeEventListener("pointermove", _editorOnTextOverlayDragMove);
    document.removeEventListener("pointerup", _editorOnTextOverlayDragEnd);
    document.removeEventListener("pointercancel", _editorOnTextOverlayDragEnd);
    if (!_editorTextOverlayDrag) return;

    _editorReleasePointerCapture(_editorTextOverlayDrag.pointerTarget, _editorTextOverlayDrag.pointerId);
    const moved = Boolean(_editorTextOverlayDrag.moved);
    _editorTextOverlayDrag = null;
    if (!moved) return;

    _editorTextOverlayIgnoreClick = true;
    _editorRenderMobileStagePanel();
    _editorRenderProps();
    _editorScheduleDraftPersist(120);
}

function _editorHandleOverlayClick(event) {
    if (_editorTextOverlayIgnoreClick || _editorSubtitleOverlayIgnoreClick) {
        _editorTextOverlayIgnoreClick = false;
        _editorSubtitleOverlayIgnoreClick = false;
        return;
    }

    const hitText = _editorFindTextAtCanvasPoint(event.clientX, event.clientY);
    if (hitText) {
        event.preventDefault();
        event.stopPropagation();
        const alreadySelected = String(_editor.selectedClip.id || "") === String(hitText.id);
        _editorSelectText(hitText.id);
        if (_editorIsMobileViewport() && alreadySelected) {
            _editorInlineTextEditId = String(hitText.id);
            _editorInlineTextEditPendingFocus = String(hitText.id);
            const video = document.getElementById("editor-video");
            _editorDrawOverlays(Number(_editor.timelineTime || video?.currentTime || 0));
        }
        return;
    }

    if (_editorInlineTextEditId) {
        _editorInlineTextEditId = "";
        _editorInlineTextEditPendingFocus = "";
        const video = document.getElementById("editor-video");
        _editorDrawOverlays(Number(_editor.timelineTime || video?.currentTime || 0));
    }

    const hitSubtitle = _editorFindSubtitleAtCanvasPoint(event.clientX, event.clientY);
    if (!hitSubtitle) return;

    event.preventDefault();
    event.stopPropagation();
    const alreadySelected = String(_editor.selectedClip.id || "") === String(hitSubtitle.id);
    if (_editor.activeTool !== "subtitles") {
        _editorSelectSubtitle(hitSubtitle.id, true);
        return;
    }

    _editorSelectSubtitle(hitSubtitle.id, false);

    if (_editorIsMobileViewport()) {
        if (!_editor.mobileSubtitleModalOpen) {
            _editor.mobileSubtitleModalOpen = true;
            _editorRenderMobileSubtitleSheet();
            return;
        }
        if (alreadySelected) {
            _editorOpenSubtitleTextModal(hitSubtitle.id);
        }
        return;
    }

    if (alreadySelected) {
        _editorOpenSubtitleTextModal(hitSubtitle.id);
    }
}

function _getCSSFilter(name) {
    const filters = {
        none: "none",
        grayscale: "grayscale(1)",
        sepia: "sepia(0.8)",
        warm: "saturate(1.3) brightness(1.05) hue-rotate(-10deg)",
        cool: "saturate(0.9) brightness(1.05) hue-rotate(15deg)",
        vintage: "sepia(0.4) contrast(1.1) brightness(0.95)",
        vivid: "saturate(1.6) contrast(1.1)",
        dramatic: "contrast(1.4) brightness(0.9) saturate(0.8)",
        fade: "brightness(1.1) saturate(0.7) contrast(0.9)",
        noir: "grayscale(1) contrast(1.3) brightness(0.85)",
        cinematic: "contrast(1.15) saturate(1.1) brightness(0.95) sepia(0.1)",
        retro: "sepia(0.5) hue-rotate(-15deg) saturate(1.2)",
    };
    return filters[name] || "none";
}

function _editorGetTransitionOption(type) {
    return _EDITOR_TRANSITION_OPTIONS.find((option) => option.value === String(type || "").trim()) || _EDITOR_TRANSITION_OPTIONS[0];
}

function _editorTransitionTrackLabel(trackIndex) {
    return Number(trackIndex || 0) <= 0 ? "Faixa principal" : `Camada ${Number(trackIndex) + 1}`;
}

function _editorTransitionClipLabel(layer) {
    const safeLayer = _editorNormalizeMediaLayer(layer || {});
    const fallback = safeLayer.kind === "audio" ? "Áudio" : (safeLayer.kind === "video" ? "Vídeo" : "Imagem");
    const raw = String(safeLayer.name || fallback).trim();
    return raw || fallback;
}

function _editorGetTransitionSlots() {
    const groups = new Map();
    (_editor.mediaLayers || []).forEach((layer, index) => {
        const safeLayer = _editorNormalizeMediaLayer(layer);
        if (!safeLayer || safeLayer.audioOnly || safeLayer.kind === "audio") return;
        if (Number(safeLayer.endTime || 0) <= Number(safeLayer.startTime || 0) + 0.05) return;
        const trackIndex = _editorGetLayerTrackIndex(safeLayer);
        if (!groups.has(trackIndex)) groups.set(trackIndex, []);
        groups.get(trackIndex).push({ ...safeLayer, _order: index });
    });

    const slots = [];
    [...groups.entries()]
        .sort((a, b) => a[0] - b[0])
        .forEach(([trackIndex, layers]) => {
            layers.sort((a, b) => (a.startTime - b.startTime) || (a.endTime - b.endTime) || (a._order - b._order));
            for (let index = 0; index < layers.length - 1; index += 1) {
                const fromLayer = layers[index];
                const toLayer = layers[index + 1];
                const gap = Number(toLayer.startTime || 0) - Number(fromLayer.endTime || 0);
                if (gap > 0.35) continue;
                const track = `layer-video-${trackIndex}`;
                slots.push({
                    key: `${track}:${fromLayer.id}:${toLayer.id}`,
                    track,
                    trackIndex,
                    fromId: String(fromLayer.id),
                    toId: String(toLayer.id),
                    fromLayer,
                    toLayer,
                    boundaryTime: Math.max(0, Number(toLayer.startTime || fromLayer.endTime || 0)),
                });
            }
        });
    return slots;
}

function _editorGetTransitionByKey(key) {
    return (_editor.transitions || []).find((transition) => String(transition?.key || "") === String(key || "")) || null;
}

function _editorGetConfiguredTransitionSlots() {
    return _editorGetTransitionSlots()
        .map((slot) => {
            const transition = _editorGetTransitionByKey(slot.key);
            return transition?.type ? { ...slot, transition } : null;
        })
        .filter(Boolean);
}

function _editorResolveTransitionTrack(track) {
    const resolvedTrack = _editorResolveInsertTrackForUi(track || _editor.selectedInsertTrack || "");
    if (resolvedTrack === "video") return "layer-video-0";
    const match = /^video-(\d+)$/i.exec(resolvedTrack);
    return match ? `layer-video-${match[1]}` : resolvedTrack;
}

function _editorFindPreferredTransitionSlot() {
    const slots = _editorGetTransitionSlots();
    if (!slots.length) return null;

    const selectedKey = _editor.selectedClip.kind === "transition" ? String(_editor.selectedClip.id || "") : "";
    if (selectedKey) {
        const selectedSlot = slots.find((slot) => slot.key === selectedKey);
        if (selectedSlot) return selectedSlot;
    }

    const currentTrack = _editorResolveTransitionTrack(_editor.selectedClip.track || _editor.selectedInsertTrack || "");
    const currentId = String(_editor.selectedClip.id || "");
    const currentTime = Math.max(0, Number(_editor.timelineTime || document.getElementById("editor-video")?.currentTime || 0));

    const trackSlots = currentTrack
        ? slots.filter((slot) => String(slot.track || "") === currentTrack)
        : [];
    let candidates = trackSlots.length ? trackSlots : slots;

    if (_editor.selectedClip.kind === "media-layer" && currentId) {
        const touchingSlots = candidates.filter((slot) => String(slot.fromId) === currentId || String(slot.toId) === currentId);
        if (touchingSlots.length) {
            candidates = touchingSlots;
        }
    }

    const unconfiguredCandidates = candidates.filter((slot) => !_editorGetTransitionByKey(slot.key));
    const prioritized = unconfiguredCandidates.length ? unconfiguredCandidates : candidates;

    return [...prioritized].sort((left, right) => {
        const leftDistance = Math.abs(Number(left.boundaryTime || 0) - currentTime);
        const rightDistance = Math.abs(Number(right.boundaryTime || 0) - currentTime);
        if (leftDistance !== rightDistance) return leftDistance - rightDistance;
        return Number(left.boundaryTime || 0) - Number(right.boundaryTime || 0);
    })[0] || null;
}

function _editorAutoSelectTransitionSlot() {
    const slot = _editorFindPreferredTransitionSlot();
    if (!slot) return null;

    _editor.selectedClip = { kind: "transition", id: slot.key, track: slot.track };
    _editor.selectedInsertTrack = _editorResolveInsertTrackForUi(slot.track);
    return slot;
}

function _editorGetTransitionPreviewDuration(slot) {
    const fromDuration = Math.max(0.1, Number(slot?.fromLayer?.endTime || 0) - Number(slot?.fromLayer?.startTime || 0));
    return Math.max(0.12, Math.min(_EDITOR_TRANSITION_PREVIEW_SEC, fromDuration * 0.45));
}

function _editorGetLayerPreviewTransitionState(layer, currentTime) {
    const safeLayer = _editorNormalizeMediaLayer(layer || {});
    const safeTime = Math.max(0, Number(currentTime || 0));

    for (const slot of _editorGetConfiguredTransitionSlots()) {
        const duration = _editorGetTransitionPreviewDuration(slot);
        const boundary = Math.max(0, Number(slot.boundaryTime || slot.toLayer?.startTime || 0));
        const windowStart = Math.max(0, boundary - duration);

        if (String(slot.fromId) === String(safeLayer.id) && safeTime >= windowStart && safeTime <= boundary) {
            return {
                role: "out",
                type: String(slot.transition.type || "dissolve"),
                progress: duration > 0 ? (safeTime - windowStart) / duration : 1,
            };
        }

        if (
            String(slot.toId) === String(safeLayer.id)
            && String(slot.transition.type || "") !== "fade-black"
            && safeTime >= windowStart
            && safeTime <= boundary
        ) {
            return {
                role: "in",
                type: String(slot.transition.type || "dissolve"),
                progress: duration > 0 ? (safeTime - windowStart) / duration : 1,
                freezeFrame: true,
            };
        }
    }

    return null;
}

function _editorApplyPreviewTransitionStyles(item, transitionState, layer) {
    const safeLayer = _editorNormalizeMediaLayer(layer || {});
    const baseZ = Number(item.dataset.baseZ || item.style.zIndex || 1) || 1;
    const progress = Math.max(0, Math.min(1, Number(transitionState?.progress || 0)));
    const eased = progress < 0.5
        ? 2 * progress * progress
        : 1 - Math.pow(-2 * progress + 2, 2) / 2;
    const isIncoming = transitionState?.role === "in";

    item.style.transformOrigin = "center center";
    item.style.transform = "";
    item.style.filter = "";
    item.style.clipPath = "";
    item.style.zIndex = String(baseZ);
    item.style.opacity = safeLayer.kind === "video" && safeLayer.audioOnly ? "0" : "1";

    switch (String(transitionState?.type || "dissolve")) {
        case "fade-black":
            item.style.filter = `brightness(${Math.max(0, 1 - eased)})`;
            break;
        case "slide-left":
            item.style.transform = isIncoming
                ? `translateX(${(1 - eased) * 36}%)`
                : `translateX(${-eased * 36}%)`;
            if (isIncoming) item.style.zIndex = String(baseZ + 2000);
            break;
        case "slide-right":
            item.style.transform = isIncoming
                ? `translateX(${-((1 - eased) * 36)}%)`
                : `translateX(${eased * 36}%)`;
            if (isIncoming) item.style.zIndex = String(baseZ + 2000);
            break;
        case "slide-up":
            item.style.transform = isIncoming
                ? `translateY(${(1 - eased) * 32}%)`
                : `translateY(${-eased * 32}%)`;
            if (isIncoming) item.style.zIndex = String(baseZ + 2000);
            break;
        case "slide-down":
            item.style.transform = isIncoming
                ? `translateY(${-((1 - eased) * 32)}%)`
                : `translateY(${eased * 32}%)`;
            if (isIncoming) item.style.zIndex = String(baseZ + 2000);
            break;
        case "zoom-in":
            item.style.opacity = isIncoming ? String(0.3 + eased * 0.7) : String(Math.max(0.3, 1 - eased * 0.3));
            item.style.transform = isIncoming
                ? `scale(${1.18 - eased * 0.18})`
                : `scale(${1 + eased * 0.08})`;
            if (isIncoming) item.style.zIndex = String(baseZ + 2000);
            break;
        case "flash-white":
            if (isIncoming) {
                item.style.opacity = String(Math.max(0, (eased - 0.55) / 0.45));
                item.style.filter = `brightness(${1.1 + (1 - eased) * 0.4})`;
                item.style.zIndex = String(baseZ + 2000);
            } else {
                item.style.opacity = String(Math.max(0.35, 1 - eased * 0.2));
                item.style.filter = `brightness(${1 + Math.sin(progress * Math.PI) * 1.4})`;
            }
            break;
        case "dissolve":
        default:
            item.style.opacity = isIncoming ? String(eased) : String(1 - eased);
            if (isIncoming) item.style.zIndex = String(baseZ + 2000);
            break;
    }
}

function _editorTransitionSlotLabel(slot) {
    if (!slot) return "";
    return `${_editorTransitionClipLabel(slot.fromLayer)} → ${_editorTransitionClipLabel(slot.toLayer)}`;
}

function _editorGetVideoTransitionSlots() {
    return _editorGetTransitionSlots().filter((slot) => {
        const fromKind = String(slot?.fromLayer?.kind || "").trim().toLowerCase();
        const toKind = String(slot?.toLayer?.kind || "").trim().toLowerCase();
        return fromKind === "video" && toKind === "video";
    });
}

function _editorSetTransitionType(slotKey, type) {
    const safeKey = String(slotKey || "").trim();
    if (!safeKey) {
        showToast("Selecione um marcador de transição na timeline.", "error");
        return;
    }
    const slot = _editorGetTransitionSlots().find((item) => item.key === safeKey);
    if (!slot) {
        showToast("Selecione uma junção válida na faixa para aplicar a transição.", "error");
        return;
    }

    _editorSaveState();
    _editor.transitions = (_editor.transitions || []).filter((transition) => String(transition?.key || "") !== safeKey);

    const safeType = String(type || "").trim();
    if (safeType) {
        _editor.transitions.push({
            key: safeKey,
            track: slot.track,
            fromId: slot.fromId,
            toId: slot.toId,
            type: safeType,
        });
    }

    _editor.selectedClip = { kind: "transition", id: safeKey, track: slot.track };
    _editorRenderProps();
    _editorRenderTimeline();
    _editorRenderMediaLayers();

    if (safeType) {
        showToast(`Transição ${_editorGetTransitionOption(safeType).label.toLowerCase()} aplicada.`, "success");
    } else {
        showToast("Transição removida da junção.", "success");
    }
}
window._editorSetTransitionType = _editorSetTransitionType;

function _editorApplyTransitionTypeToAllVideoSlots(slotKey, type) {
    const safeType = String(type || "").trim();
    if (!safeType) {
        showToast("Selecione um tipo de transição antes de aplicar em todas.", "error");
        return;
    }

    const videoSlots = _editorGetVideoTransitionSlots();
    if (!videoSlots.length) {
        showToast("Não há emendas de vídeo disponíveis para aplicar a transição.", "error");
        return;
    }

    _editorSaveState();

    const videoSlotKeys = new Set(videoSlots.map((slot) => String(slot.key || "")));
    _editor.transitions = (_editor.transitions || []).filter((transition) => !videoSlotKeys.has(String(transition?.key || "")));
    videoSlots.forEach((slot) => {
        _editor.transitions.push({
            key: slot.key,
            track: slot.track,
            fromId: slot.fromId,
            toId: slot.toId,
            type: safeType,
        });
    });

    const selectedSlot = videoSlots.find((slot) => String(slot.key || "") === String(slotKey || "")) || videoSlots[0];
    if (selectedSlot) {
        _editor.selectedClip = { kind: "transition", id: selectedSlot.key, track: selectedSlot.track };
        _editor.selectedInsertTrack = _editorResolveInsertTrackForUi(selectedSlot.track);
    }

    _editorRenderProps();
    _editorRenderTimeline();
    _editorRenderMediaLayers();

    const appliedCount = videoSlots.length;
    const countLabel = appliedCount === 1 ? "1 emenda de vídeo" : `${appliedCount} emendas de vídeo`;
    showToast(`Transição ${_editorGetTransitionOption(safeType).label.toLowerCase()} aplicada em ${countLabel}.`, "success");
}
window._editorApplyTransitionTypeToAllVideoSlots = _editorApplyTransitionTypeToAllVideoSlots;

// ---------- Tool selection ----------
function _editorSelectTool(toolName) {
    if (toolName !== "text") {
        _editorInlineTextEditId = "";
        _editorInlineTextEditPendingFocus = "";
    }
    if (toolName !== "trim") {
        _editorMobileTrackVolumeOpen = "";
    }
    if (toolName === "subtitles" && _editorIsMobileViewport()) {
        _editor.mobileSubtitleModalOpen = true;
    } else if (toolName !== "subtitles") {
        _editor.mobileSubtitleModalOpen = false;
    }
    _editor.activeTool = toolName;
    document.querySelectorAll(".editor-tool-btn").forEach(btn => {
        btn.classList.toggle("active", btn.dataset.tool === toolName);
    });

    const overlayCanvas = document.getElementById("editor-overlay-canvas");
    if (overlayCanvas) {
        overlayCanvas.style.pointerEvents = toolName === "layers" ? "none" : "auto";
    }

    let autoSelectedTransition = null;
    if (toolName === "transitions" && _editor.selectedClip.kind !== "transition") {
        autoSelectedTransition = _editorAutoSelectTransitionSlot();
    }

    if (toolName === "layers") {
        _editorRenderMediaLayers();
    } else if (toolName === "transitions") {
        _editorRenderTimeline();
        if (autoSelectedTransition) {
            _editorRenderMediaLayers();
        }
    }

    _editorRenderProps();
    const pp = document.getElementById("editor-props-panel");
    if (pp && _editorIsMobileViewport()) {
        pp.classList.remove("open");
        pp.style.removeProperty("display");
    } else if (pp) {
        pp.style.removeProperty("display");
    }

    _editorApplyMobileControlMode();

    const video = document.getElementById("editor-video");
    _editorDrawOverlays(Number(_editor.timelineTime || video?.currentTime || 0));
}

function _editorGetApprovedSmartCuts() {
    return (_editor.smartCuts || []).filter((cut) => cut && cut.approved !== false && Number(cut.end || 0) > Number(cut.start || 0));
}

function _editorBuildSmartCutSubtitleCfg() {
    const cfg = _buildAutoSubtitleCfg(_editor.smartCutSubtitleStyle || "destaque");
    return {
        ...cfg,
        enabled: true,
        y: 75,
    };
}

function _editorSetSmartCutSubtitleStyle(styleName) {
    const style = _getSubStyle(styleName || "destaque");
    _editor.smartCutSubtitleStyle = style.name;
    _editorScheduleDraftPersist(120);
    if (_editor.activeTool === "smartcuts") {
        _editorRenderProps();
    }
}
window._editorSetSmartCutSubtitleStyle = _editorSetSmartCutSubtitleStyle;

async function _editorAnalyzeSmartCuts() {
    if (!_editor.projectId || _editor.smartCutsLoading) return;
    _editor.smartCutsLoading = true;
    _editor.smartCutsError = "";
    _editorRenderProps();
    try {
        const payload = await api("/video/editor/smart-cuts", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ project_id: _editor.projectId }),
        });
        const cuts = Array.isArray(payload?.cuts) ? payload.cuts : [];
        _editor.smartCutWords = Array.isArray(payload?.words) ? payload.words : [];
        _editor.smartCuts = cuts.map((cut, idx) => ({
            id: String(cut.id || `smart-${idx + 1}`),
            start: Math.max(0, Number(cut.start || 0)),
            end: Math.max(0, Number(cut.end || 0)),
            title: String(cut.title || `Short ${idx + 1}`),
            reason: String(cut.reason || "Trecho indicado pela IA."),
            score: Math.max(0, Math.min(100, Number(cut.score || 0))),
            approved: cut.approved !== false,
        })).filter((cut) => cut.end - cut.start >= 1);
        if (!_editor.smartCuts.length) {
            _editor.smartCutsError = "A IA não encontrou cortes bons neste vídeo.";
        }
        _editorScheduleDraftPersist(120);
    } catch (err) {
        _editor.smartCutWords = [];
        _editor.smartCutsError = err?.message || "Erro ao criar cortes inteligentes.";
        showToast("Erro ao criar cortes inteligentes: " + _editor.smartCutsError, "error");
    } finally {
        _editor.smartCutsLoading = false;
        _editorRenderProps();
        _editorScrollSmartCutResultsIntoView();
    }
}

function _editorScrollSmartCutResultsIntoView() {
    if (_editor.activeTool !== "smartcuts") return;

    requestAnimationFrame(() => {
        const target = document.getElementById("editor-smartcuts-results-anchor")
            || document.querySelector(".editor-smartcut-item")
            || document.querySelector(".editor-smartcuts-error");
        if (!target) return;

        target.scrollIntoView({ behavior: "smooth", block: "start", inline: "nearest" });
    });
}

function _editorSeekToSmartCut(cutId) {
    const cut = (_editor.smartCuts || []).find((item) => String(item.id) === String(cutId));
    if (!cut) return;

    _editorStopVirtualTimelinePlayback();
    _editor.playing = false;
    const video = document.getElementById("editor-video");
    const target = Math.max(0, Number(cut.start || 0));
    if (video) {
        video.pause();
        video.currentTime = target;
    }
    _editorApplyTimelineFrame(target, false);
    _updatePlayIcon();
}

function _editorToggleSmartCut(cutId, checked) {
    const cut = (_editor.smartCuts || []).find((item) => String(item.id) === String(cutId));
    if (!cut) return;
    cut.approved = Boolean(checked);
    _editorScheduleDraftPersist(120);
    _editorRenderProps();
}

function _editorClearSmartCuts() {
    _editor.smartCuts = [];
    _editor.smartCutWords = [];
    _editor.smartCutsError = "";
    _editorScheduleDraftPersist(120);
    _editorRenderProps();
}

window._editorAnalyzeSmartCuts = _editorAnalyzeSmartCuts;
window._editorSeekToSmartCut = _editorSeekToSmartCut;
window._editorToggleSmartCut = _editorToggleSmartCut;
window._editorClearSmartCuts = _editorClearSmartCuts;

function _editorBuildSubtitlesPanelMarkup() {
    const isGenerating = _editor._subtitleGenerating;
    const hasSubs = _editor.subtitles.length > 0;
    const bulkApplyMarkup = hasSubs ? _editorBuildSubtitleBulkApplyMarkup() : "";

    return `
        <div class="editor-sub-toolbar editor-sub-actions-row">
            <button
                class="editor-sub-icon-btn editor-sub-action-btn editor-sub-action-btn-labeled"
                type="button"
                onclick="_editorAutoSubtitles()"
                ${isGenerating ? "disabled" : ""}
                title="Gerar legendas automáticas"
                aria-label="Gerar legendas automáticas"
            >
                ${isGenerating
                    ? '<div class="spinner-small" style="width:14px;height:14px"></div>'
                    : '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01z"/></svg>'}
                <span class="editor-sub-action-btn-label">Criar automático</span>
            </button>
            <button
                class="editor-sub-icon-btn editor-sub-action-btn editor-sub-action-btn-labeled"
                type="button"
                onclick="_editorAddSubtitle()"
                title="Adicionar legenda manual"
                aria-label="Adicionar legenda manual"
            >
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                    <path d="M12 5v14"/>
                    <path d="M5 12h14"/>
                </svg>
                <span class="editor-sub-action-btn-label">Criar manual</span>
            </button>
            ${hasSubs ? `
                <button
                    class="editor-sub-icon-btn editor-sub-action-btn${_editor.subtitleListOpen ? " active" : ""}"
                    type="button"
                    onclick="_editorToggleSubtitleList()"
                    title="Editar trechos"
                    aria-label="Editar trechos"
                >
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                        <path d="M12 20h9"/>
                        <path d="M16.5 3.5a2.12 2.12 0 1 1 3 3L7 19l-4 1 1-4 12.5-12.5z"/>
                    </svg>
                </button>
                <button
                    class="editor-sub-icon-btn editor-sub-action-btn editor-sub-icon-btn-danger"
                    type="button"
                    onclick="_editorClearSubtitles()"
                    title="Limpar todas"
                    aria-label="Limpar todas"
                >
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                        <polyline points="3 6 5 6 21 6"/>
                        <path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"/>
                        <path d="M10 11v6"/>
                        <path d="M14 11v6"/>
                        <path d="M9 6V4a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v2"/>
                    </svg>
                </button>
            ` : ""}
        </div>
        ${hasSubs && _editor.subtitleListOpen ? `
            <div class="editor-props-group" style="margin-top:8px;max-height:200px;overflow-y:auto">
                ${_editor.subtitles.map(s => `
                    <div class="editor-subtitle-item${s._selected ? ' active' : ''}" onclick="_editorSelectSubtitle(${s.id})">
                        <span class="sub-time">${_fmtTime(s.startTime)}-${_fmtTime(s.endTime)}</span>
                        <span class="sub-text">${esc(s.text)}</span>
                        <button class="sub-delete" onclick="event.stopPropagation();_editorDeleteSubtitle(${s.id})">✕</button>
                    </div>
                `).join("")}
            </div>
        ` : ""}
        ${hasSubs ? `
            <div class="editor-props-title" style="margin-top:12px">Estilos</div>
            <div class="editor-subtitle-styles-grid">
                ${SUBTITLE_STYLES.map(st => `
                    <div class="editor-sub-style-card${(_editor.subtitles.find(s => s._selected) || {}).styleName === st.name ? ' active' : ''}" onclick="_editorApplySubStyle('${st.name}')">
                        <div class="editor-sub-style-preview" style="font-family:${st.fontFamily};color:${st.fontColor};font-size:11px;font-weight:${st.bold ? 'bold' : 'normal'};font-style:${st.italic ? 'italic' : 'normal'};${st.bgColor ? 'background:' + st.bgColor + ';padding:2px 4px;border-radius:3px;' : ''}${st.outlineColor ? 'text-shadow:-1px -1px 0 ' + st.outlineColor + ',1px -1px 0 ' + st.outlineColor + ',-1px 1px 0 ' + st.outlineColor + ',1px 1px 0 ' + st.outlineColor + ';' : ''}">Abc</div>
                        <span>${st.label}</span>
                    </div>
                `).join("")}
            </div>
        ` : ""}
        ${bulkApplyMarkup}
        ${_editor.subtitleListOpen ? _editorSubtitleEditForm() : ""}
    `;
}

function _editorBuildSubtitleBulkApplyMarkup() {
    const selectedSubtitle = _editorGetSelectedSubtitleItem();
    const otherCount = Math.max(0, _editor.subtitles.length - 1);
    if (!selectedSubtitle || otherCount < 1) return "";

    return `
        <div class="editor-sub-bulk-actions">
            <div class="editor-sub-bulk-copy">
                <strong>Aplicar para todas</strong>
                <span>Replicar a posição ou o tamanho desta legenda nas outras ${otherCount}.</span>
            </div>
            <div class="editor-sub-bulk-buttons">
                <button class="editor-sub-bulk-btn" type="button" onclick="_editorApplySelectedSubtitleToAll('position')">Aplicar posição</button>
                <button class="editor-sub-bulk-btn" type="button" onclick="_editorApplySelectedSubtitleToAll('size')">Aplicar tamanho</button>
            </div>
        </div>
    `;
}

function _editorRenderMobileSubtitleSheet() {
    const sheet = document.getElementById("editor-mobile-subtitles-sheet");
    if (!sheet) return;

    const shouldOpen = _editorIsMobileViewport()
        && _editor.activeTool === "subtitles"
        && _editor.mobileSubtitleModalOpen;

    if (!shouldOpen) {
        sheet.hidden = true;
        sheet.classList.remove("open");
        sheet.innerHTML = "";
        return;
    }

    sheet.hidden = false;
    sheet.classList.add("open");
    sheet.innerHTML = `
        <div class="editor-mobile-subtitles-sheet-header">
            <div class="editor-mobile-subtitles-sheet-title">Legendas</div>
            <button
                class="editor-mobile-subtitles-sheet-close"
                type="button"
                onclick="_editorCloseMobileSubtitleSheet()"
                aria-label="Fechar painel de legendas"
            >
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                    <path d="M18 6 6 18"/>
                    <path d="m6 6 12 12"/>
                </svg>
            </button>
        </div>
        <div class="editor-mobile-subtitles-sheet-body">
            ${_editorBuildSubtitlesPanelMarkup()}
        </div>
    `;
}

function _editorCloseMobileSubtitleSheet() {
    _editor.mobileSubtitleModalOpen = false;
    _editorRenderMobileSubtitleSheet();
}
window._editorCloseMobileSubtitleSheet = _editorCloseMobileSubtitleSheet;

// ---------- Render properties panel based on tool ----------
function _editorRenderProps() {
    const container = document.getElementById("editor-props-content");
    if (!container) return;
    const tool = _editor.activeTool;

    if (tool === "text") {
        container.innerHTML = `
            <div class="editor-props-title">Textos</div>
            <button class="editor-add-btn" onclick="_editorAddText()">+ Criar texto manual</button>
            <div class="editor-props-title" style="margin-top:12px">Modelos prontos</div>
            <p class="editor-text-presets-intro">Toque em um modelo para inserir no video e depois editar o texto como quiser.</p>
            <div class="editor-text-presets-grid">
                ${EDITOR_TEXT_PRESETS.map((preset) => {
                    const previewStyle = [
                        `font-family:${preset.fontFamily}`,
                        `color:${preset.color}`,
                        `font-size:${Math.max(16, Math.min(22, Math.round(Number(preset.fontSize || 28) * 0.55)))}px`,
                        `font-weight:${preset.bold ? "700" : "500"}`,
                        `font-style:${preset.italic ? "italic" : "normal"}`,
                    ].join(";");
                    return `
                        <button class="editor-text-preset-card" type="button" onclick="_editorAddTextPreset('${preset.key}')">
                            <span class="editor-text-preset-badge">${esc(preset.label)}</span>
                            <span class="editor-text-preset-preview" style="${previewStyle}">${esc(preset.preview)}</span>
                            <span class="editor-text-preset-meta">Adicionar e editar</span>
                        </button>
                    `;
                }).join("")}
            </div>
            <div class="editor-props-title" style="margin-top:12px">Textos adicionados</div>
            <div id="editor-text-list" class="editor-props-group">
                ${_editor.texts.map(t => `
                    <div class="editor-subtitle-item${t._selected ? ' active' : ''}" onclick="_editorSelectText(${t.id})">
                        <span class="sub-time">${_fmtTime(t.startTime)}-${_fmtTime(t.endTime)}</span>
                        <span class="sub-text">${esc(t.content)}</span>
                        <button class="sub-delete" onclick="event.stopPropagation();_editorDeleteText(${t.id})">✕</button>
                    </div>
                `).join("")}
            </div>
            ${_editorTextEditForm()}
        `;
    } else if (tool === "smartcuts") {
        const isLoading = Boolean(_editor.smartCutsLoading);
        const cuts = Array.isArray(_editor.smartCuts) ? _editor.smartCuts : [];
        const approvedCount = _editorGetApprovedSmartCuts().length;
        const errorHtml = _editor.smartCutsError ? `<p class="editor-smartcuts-error">${esc(_editor.smartCutsError)}</p>` : "";
        const smartCutSubtitleCfg = _editorBuildSmartCutSubtitleCfg();
        const smartCutStyleLabel = _getSubStyle(_editor.smartCutSubtitleStyle || "destaque").label;

        container.innerHTML = `
            <div class="editor-props-title">Cortes IA</div>
            <div class="editor-smartcuts-summary">${_editor.sourceAspectRatio === "16:9"
                ? "Vídeos 16:9 viram shorts 9:16 com fundo desfocado e o quadro completo centralizado."
                : "Os cortes aprovados serão exportados como shorts prontos para download."}</div>
            <div class="editor-props-group" style="margin-top:10px">
                <label style="display:block;margin-bottom:6px">Legenda direta nos shorts</label>
                <p style="margin:0 0 8px;font-size:11px;color:var(--text-muted)">Escolha o estilo antes de criar ou exportar os cortes. A legenda sai no rodapé inferior do short.</p>
                <div class="editor-smartcuts-summary" style="margin-bottom:8px">Estilo atual: ${esc(smartCutStyleLabel)} · Legenda ${Math.round(smartCutSubtitleCfg.y || 75)}%</div>
                <div class="editor-subtitle-styles-grid">
                    ${SUBTITLE_STYLES.map(st => {
                        const active = (_editor.smartCutSubtitleStyle || "destaque") === st.name;
                        const previewStyle = [
                            `font-family:${st.fontFamily}`,
                            `color:${st.fontColor}`,
                            "font-size:11px",
                            `font-weight:${st.bold ? "bold" : "normal"}`,
                            `font-style:${st.italic ? "italic" : "normal"}`,
                            st.bgColor ? `background:${st.bgColor};padding:2px 4px;border-radius:3px;` : "",
                            st.outlineColor
                                ? `text-shadow:-1px -1px 0 ${st.outlineColor},1px -1px 0 ${st.outlineColor},-1px 1px 0 ${st.outlineColor},1px 1px 0 ${st.outlineColor};`
                                : "",
                        ].join(";");
                        return `
                            <div class="editor-sub-style-card${active ? " active" : ""}" onclick="_editorSetSmartCutSubtitleStyle('${st.name}')">
                                <div class="editor-sub-style-preview" style="${previewStyle}">Abc</div>
                                <span>${esc(st.label)}</span>
                            </div>
                        `;
                    }).join("")}
                </div>
            </div>
            <button class="editor-add-btn" onclick="_editorAnalyzeSmartCuts()" ${isLoading ? "disabled" : ""}>
                ${isLoading
                    ? '<div class="spinner-small" style="width:14px;height:14px"></div> Analisando vídeo...'
                    : '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M14.5 4.5 16 3l1.5 1.5L19 6l-1.5 1.5L16 9l-1.5-1.5L13 6z"/><path d="M5 4v16"/><path d="M19 12v8"/><path d="M8 7h3"/><path d="M8 12h8"/><path d="M8 17h8"/></svg> Criar vários cortes inteligentes'}
            </button>
            ${cuts.length ? `<div id="editor-smartcuts-results-anchor" class="editor-smartcuts-summary">${approvedCount} de ${cuts.length} short(s) aprovados para exportar</div>` : ""}
            ${errorHtml}
            <div class="editor-smartcuts-list">
                ${cuts.map((cut) => `
                    <div class="editor-smartcut-item${cut.approved !== false ? " approved" : ""}" onclick="_editorSeekToSmartCut('${esc(String(cut.id))}')">
                        <div class="editor-smartcut-head">
                            <strong>${esc(cut.title || "Short")}</strong>
                            <label class="editor-smartcut-check" onclick="event.stopPropagation()">
                                <input type="checkbox" ${cut.approved !== false ? "checked" : ""} onchange="_editorToggleSmartCut('${esc(String(cut.id))}', this.checked)">
                                <span>Aprovar</span>
                            </label>
                        </div>
                        <div class="editor-smartcut-time">${_fmtTime(cut.start)} até ${_fmtTime(cut.end)} · ${Math.round(Math.max(0, cut.end - cut.start))}s</div>
                        <p>${esc(cut.reason || "Trecho forte indicado pela IA.")}</p>
                    </div>
                `).join("")}
            </div>
            ${cuts.length ? '<button class="editor-add-btn editor-smartcuts-clear" onclick="_editorClearSmartCuts()">Limpar cortes</button>' : ""}
        `;
    } else if (tool === "subtitles") {
        container.innerHTML = `
            <div class="editor-props-title">Legendas</div>
            ${_editorBuildSubtitlesPanelMarkup()}
        `;
    } else if (tool === "trim") {
        const hasExternalAudio = _editorShouldShowAudioTrack();
        const selectedSeg = _editor.selectedClip.kind === "segment"
            ? _editorFindSegment(_editor.selectedClip.track || "video", _editor.selectedClip.id)
            : null;
        const selectedTrackTargets = _editor.selectedClip.kind === "track"
            ? _editorGetSelectedSegmentTracks().filter((track) => _editorGetSegments(track).length)
            : [];
        const selectedSegTrack = String(_editor.selectedClip.track || "video");
        const selectedSegSpeed = selectedSeg ? _editorSegmentPlaybackSpeed(selectedSeg) : 1;
        const selectedSegSourceDuration = selectedSeg ? _editorSegSourceDuration(selectedSeg) : 0;
        const selectedSegVolume = selectedSeg ? _editorSegmentVolumePercent(selectedSeg) : 100;
        const selectedTrackSpeedState = _editorGetTrackSpeedState(selectedTrackTargets);
        const selectedTrackLabel = selectedTrackTargets
            .map((track) => track === "audio" ? "Faixa de audio" : "Faixa de video")
            .join(" + ");
        const selectedTrackInfo = selectedTrackTargets.length
            ? `${selectedTrackLabel} (${selectedTrackSpeedState.count} trecho(s))`
            : "";
        const segInfo = selectedSeg
            ? `${_fmtTime(selectedSeg.start)} - ${_fmtTime(selectedSeg.end)} (${_fmtTime(selectedSeg.end - selectedSeg.start)})`
            : selectedTrackInfo || "Nenhum trecho selecionado";
        const selectedTracksLabel = _editorGetSelectedSegmentTracks()
            .map(track => track === "video" ? "Video" : "Audio")
            .join(" + ");
        const tracksSummary = hasExternalAudio
            ? `Trechos: Video ${_editor.videoSegments.length} | Audio ${_editor.audioSegments.length}`
            : `Trechos: Video ${_editor.videoSegments.length}`;
        const trimHint = hasExternalAudio
            ? "Marque as faixas Video/Audio na timeline. O corte e ajuste serao aplicados somente nas faixas marcadas."
            : "Sem audio externo, o audio original acompanha os cortes do video automaticamente.";
        const selectedVolumeTracks = _editorGetSelectedSegmentTracks().filter(track => track === "video" || (track === "audio" && hasExternalAudio));
        const volumeControlsHtml = selectedVolumeTracks.map((track) => {
            const isVideo = track === "video";
            const volumePct = isVideo
                ? Math.max(0, Math.min(100, Number(_editor.originalVolume || 0)))
                : Math.max(0, Math.min(100, Number(_editor.musicVolume || 0)));
            const trackLabel = isVideo ? "Video original" : "Audio externo";
            return `
                <div class="editor-track-props-volume-item">
                    <div class="editor-track-props-volume-head">
                        <span class="editor-track-props-volume-name-wrap">
                            <span class="editor-track-props-volume-icon">${_editorTimelineVolumeIcon(track)}</span>
                            <span class="editor-track-props-volume-name">${trackLabel}</span>
                        </span>
                        <span class="editor-track-props-volume-value" id="editor-track-vol-label-${track}">${volumePct}%</span>
                    </div>
                    <input
                        id="editor-track-vol-input-${track}"
                        class="editor-track-props-volume-slider"
                        type="range"
                        min="0"
                        max="100"
                        value="${volumePct}"
                        oninput="_editorSetTrackVolumeFromTrim('${track}', this.value)"
                    >
                </div>
            `;
        }).join("");
        container.innerHTML = `
            <div class="editor-props-title">Cortar video</div>
            <p style="font-size:11px;color:var(--text-muted);margin-bottom:8px">${trimHint}</p>
            <div class="editor-trim-range" style="display:grid;gap:8px">
                <button class="editor-add-btn" type="button" onclick="_editorSplitAtCurrentTime()">Cortar no ponto atual</button>
                <button class="editor-add-btn" type="button" onclick="_editorResetVideoSegments()" style="background:rgba(255,255,255,0.04)">Restaurar video inteiro</button>
                <div class="editor-trim-values">
                    <span>${tracksSummary}</span>
                    <span style="margin-left:10px">Selecionado: ${segInfo}</span>
                </div>
                <div class="editor-trim-values">
                    <span>Faixas marcadas: ${selectedTracksLabel}</span>
                </div>
                ${selectedVolumeTracks.length ? `
                    <div class="editor-props-group editor-track-props-volume-group">
                        <label>Volume das faixas selecionadas</label>
                        <div class="editor-track-props-volume-list">${volumeControlsHtml}</div>
                    </div>
                ` : ""}
                ${selectedSeg ? `
                    <div class="editor-props-group editor-track-props-volume-group">
                        <label>Volume do trecho selecionado</label>
                        <div class="editor-track-props-volume-item">
                            <div class="editor-track-props-volume-head">
                                <span class="editor-track-props-volume-name-wrap">
                                    <span class="editor-track-props-volume-icon">${_editorTimelineVolumeIcon(selectedSegTrack === "audio" ? "audio" : "video")}</span>
                                    <span class="editor-track-props-volume-name">${selectedSegTrack === "audio" ? "Trecho do audio externo" : "Trecho do video"}</span>
                                </span>
                                <span class="editor-track-props-volume-value" id="editor-seg-vol-label">${selectedSegVolume}%</span>
                            </div>
                            <input
                                class="editor-track-props-volume-slider"
                                type="range"
                                min="0"
                                max="100"
                                value="${selectedSegVolume}"
                                oninput="_editorSetSelectedSegmentVolume(this.value)"
                            >
                        </div>
                    </div>
                ` : ""}
                ${(selectedSeg || selectedTrackTargets.length) ? `
                    <div class="editor-props-group editor-track-props-volume-group">
                        <label>${selectedSeg ? "Velocidade do trecho selecionado" : "Velocidade das faixas selecionadas"}</label>
                        <div class="editor-track-props-volume-item">
                            <div class="editor-track-props-volume-head">
                                <span class="editor-track-props-volume-name-wrap">
                                    <span class="editor-track-props-volume-name">${selectedSeg ? (selectedSegTrack === "audio" ? "Trecho do audio externo" : "Trecho do video") : selectedTrackLabel}</span>
                                </span>
                                <span class="editor-track-props-volume-value">${_editorFormatRateLabel(selectedSeg ? selectedSegSpeed : selectedTrackSpeedState.value)}</span>
                            </div>
                            <input
                                class="editor-track-props-volume-slider"
                                type="range"
                                min="${_EDITOR_SEGMENT_SPEED_MIN}"
                                max="${_EDITOR_SEGMENT_SPEED_MAX}"
                                step="0.05"
                                value="${selectedSeg ? selectedSegSpeed : selectedTrackSpeedState.value}"
                                onchange="_editorSetSelectedSegmentSpeed(this.value)"
                            >
                            <div class="editor-trim-values">
                                ${selectedSeg ? `
                                    <span>Origem: ${_fmtTime(selectedSegSourceDuration)}</span>
                                    <span>Duração na timeline: ${_fmtTime(selectedSeg.end - selectedSeg.start)}</span>
                                ` : `
                                    <span>Trechos afetados: ${selectedTrackSpeedState.count}</span>
                                    <span>${selectedTrackSpeedState.mixed ? "Velocidade atual: mista" : `Velocidade atual: ${_editorFormatRateLabel(selectedTrackSpeedState.value)}`}</span>
                                `}
                            </div>
                            <div style="display:flex;flex-wrap:wrap;gap:6px;margin-top:6px">
                                ${_EDITOR_SEGMENT_SPEED_PRESETS.map((rate) => `
                                    <button
                                        class="editor-add-btn${Math.abs(rate - (selectedSeg ? selectedSegSpeed : selectedTrackSpeedState.value)) < 0.001 && !(selectedTrackTargets.length && selectedTrackSpeedState.mixed) ? " active" : ""}"
                                        type="button"
                                        style="margin-top:0;padding:6px 10px;min-width:0"
                                        onclick="_editorSetSelectedSegmentSpeed(${rate})"
                                    >${_editorFormatRateLabel(rate)}</button>
                                `).join("")}
                            </div>
                        </div>
                    </div>
                ` : ""}
            </div>
        `;
    } else if (tool === "music") {
        container.innerHTML = `
            <div class="editor-props-title">Audio</div>
            <div class="editor-props-group" style="margin-top:12px">
                <button class="editor-add-btn" onclick="_editorOpenAIMusicModal()">
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M12 3l2.4 4.9L20 9l-4 3.9L16.9 19 12 16.3 7.1 19 8 12.9 4 9l5.6-1.1L12 3z"/></svg>
                    Criar áudio IA
                </button>
                <button class="editor-add-btn" style="margin-top:8px" onclick="document.getElementById('editor-music-upload').click()">
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" y1="3" x2="12" y2="15"/></svg>
                    Enviar arquivo de audio
                </button>
                <input type="file" id="editor-music-upload" accept="audio/*" hidden onchange="_editorUploadMusic(this)">
                <button class="editor-add-btn" style="margin-top:8px" onclick="_editorOpenAudioVideoSourceModal()">
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="2" y="5" width="15" height="14" rx="2"/><polygon points="22 7 16 12 22 17 22 7"/></svg>
                    Extrair audio de video
                </button>
                ${_editor.musicUrl ? `
                    <div class="editor-music-current">
                        <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="var(--accent)" stroke-width="2"><path d="M9 18V5l12-2v13"/><circle cx="6" cy="18" r="3"/><circle cx="18" cy="16" r="3"/></svg>
                        <div class="editor-music-info">Audio adicionado<small>${_editor._musicSource === "video" ? "Extraido de video" : _editor._musicSource === "ai" ? "Gerado por IA (Tevoxi)" : "Arquivo de audio carregado"}</small></div>
                        <button class="sub-delete" onclick="_editorRemoveMusic()">✕</button>
                    </div>
                    <label>Volume do audio</label>
                    <div class="editor-volume-row">
                        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M9 18V5l12-2v13"/><circle cx="6" cy="18" r="3"/><circle cx="18" cy="16" r="3"/></svg>
                        <input type="range" min="0" max="100" value="${_editor.musicVolume}" oninput="_editorSetMusicVolume(this.value)">
                        <span id="editor-music-vol-label">${_editor.musicVolume}%</span>
                    </div>
                ` : ""}
            </div>
        `;
    } else if (tool === "layers") {
        const selectedLayer = _editor.selectedClip.kind === "media-layer"
            ? _editorGetMediaLayerById(_editor.selectedClip.id)
            : null;
        const orderedLayers = [..._editor.mediaLayers].reverse();

        container.innerHTML = `
            <div class="editor-props-title">Camadas</div>
            <div class="editor-props-group" style="margin-top:12px">
                ${orderedLayers.length ? `
                    <div class="editor-layer-list">
                        ${orderedLayers.map((layer, idx) => `
                            <div class="editor-layer-list-item${selectedLayer && String(selectedLayer.id) === String(layer.id) ? ' active' : ''}" onclick="_editorSelectMediaLayer('${layer.id}')">
                                <span>${esc(layer.kind === 'audio' ? 'Audio' : (layer.kind === 'video' ? 'Video' : 'Imagem'))} ${orderedLayers.length - idx}</span>
                                <button class="sub-delete" onclick="event.stopPropagation();_editorDeleteMediaLayer('${layer.id}')">✕</button>
                            </div>
                        `).join("")}
                    </div>
                ` : '<p style="margin-top:4px;font-size:11px;color:var(--text-muted)">Use os botões da barra lateral para adicionar audio, vídeo, biblioteca e imagem.</p>'}
            </div>

            ${selectedLayer ? `
                <div class="editor-props-title" style="margin-top:12px">Editar camada</div>
                <div class="editor-props-group">
                    ${selectedLayer.kind === 'video' || selectedLayer.kind === 'audio' ? `
                        <label>Volume (<span id="editor-layer-vol-label">${Math.round(selectedLayer.volume ?? 100)}%</span>)</label>
                        <input type="range" min="0" max="200" value="${Math.round(selectedLayer.volume ?? 100)}" oninput="_editorSetMediaLayerVolume('${selectedLayer.id}', this.value)">
                        ${selectedLayer.kind === 'video' ? `
                            <button class="editor-add-btn" type="button" style="margin-top:8px" onclick="_editorToggleMediaLayerAudioOnly('${selectedLayer.id}')">
                                ${selectedLayer.audioOnly ? 'Mostrar video + audio' : 'Usar somente audio da camada'}
                            </button>
                        ` : '<p style="font-size:11px;color:var(--text-muted);margin-top:8px">Faixa de audio permanece invisível na prévia e toca apenas na timeline.</p>'}
                    ` : '<p style="font-size:11px;color:var(--text-muted)">Camada de imagem não possui ajuste de volume.</p>'}

                    <button class="editor-add-btn" type="button" style="margin-top:10px;border-color:rgba(239,68,68,.35);color:#ef4444" onclick="_editorDeleteMediaLayer('${selectedLayer.id}')">
                        Remover camada
                    </button>
                </div>
            ` : ''}
        `;
    } else if (tool === "transitions") {
        const slots = _editorGetTransitionSlots();
        const videoSlots = _editorGetVideoTransitionSlots();
        const selectedKey = _editor.selectedClip.kind === "transition" ? String(_editor.selectedClip.id || "") : "";
        const selectedSlot = slots.find((slot) => slot.key === selectedKey) || null;
        const selectedTransition = selectedSlot ? _editorGetTransitionByKey(selectedSlot.key) : null;
        const selectedTransitionType = String(selectedTransition?.type || "").trim();
        const showApplyAllButton = Boolean(selectedTransitionType) && videoSlots.length > 1;

        container.innerHTML = `
            <div class="editor-props-title">Transições</div>
            ${slots.length ? `
                <div class="editor-transition-grid">
                    ${_EDITOR_TRANSITION_OPTIONS.map((option) => {
                        const active = selectedTransition && selectedTransition.type === option.value;
                        return `
                            <button class="editor-transition-card${active ? " active" : ""}" type="button" onclick="_editorSetTransitionType('${selectedSlot?.key || ""}', '${option.value}')">
                                <div class="editor-transition-preview editor-transition-preview-${option.preview}">
                                    <span class="editor-transition-preview-pane before"></span>
                                    <span class="editor-transition-preview-pane after"></span>
                                    <span class="editor-transition-preview-flash"></span>
                                </div>
                                <strong>${esc(option.label)}</strong>
                            </button>
                        `;
                    }).join("")}
                </div>
                ${selectedSlot ? `<button class="editor-add-btn" type="button" onclick="_editorSetTransitionType('${selectedSlot.key}', '')" style="margin-top:6px">Remover transição</button>` : ""}
                ${showApplyAllButton ? `<button class="editor-add-btn" type="button" onclick="_editorApplyTransitionTypeToAllVideoSlots('${selectedSlot?.key || ""}', '${selectedTransitionType}')" style="margin-top:10px">Aplicar esta transição em todas as emendas de vídeo (${videoSlots.length})</button>` : ""}
            ` : '<div class="editor-transition-empty">Adicione pelo menos dois clipes em sequência na mesma faixa.</div>'}
        `;
    } else if (tool === "filters") {
        const filterNames = ["none","grayscale","sepia","warm","cool","vintage","vivid","dramatic","fade","noir","cinematic","retro"];
        const filterLabels = {"none":"Original","grayscale":"P&B","sepia":"Sepia","warm":"Quente","cool":"Frio","vintage":"Vintage","vivid":"Vivido","dramatic":"Dramatico","fade":"Desbotado","noir":"Noir","cinematic":"Cinema","retro":"Retro"};
        container.innerHTML = `
            <div class="editor-props-title">Filtros</div>
            <div class="editor-filter-grid">
                ${filterNames.map(f => `
                    <div class="editor-filter-card${_editor.filter === f ? ' active' : ''}" onclick="_editorSetFilter('${f}')">
                        <div class="editor-filter-preview" style="filter:${_getCSSFilter(f)}"></div>
                        <span>${filterLabels[f]}</span>
                    </div>
                `).join("")}
            </div>
        `;
    } else if (tool === "stickers") {
        const emojis = ["😀","😂","🥰","😎","🔥","⭐","❤️","👍","🎉","🎵","💯","👏","🤩","💪","✨","🌟","😍","🥳","💥","🎬","📸","🎶","💡","🚀","👑","🏆","💎","🌈","🎯","🙏","😱","🤯","💰","📢","🎭","🎨","🎸","🎤","🎧","👀","💬","🔔","⚡","🌺","🦋","🐾","🍕","☕","🎮","🎁"];
        container.innerHTML = `
            <div class="editor-props-title">Stickers & Emojis</div>
            <div class="editor-sticker-grid">
                ${emojis.map(e => `<div class="editor-sticker-item" onclick="_editorAddSticker('${e}')">${e}</div>`).join("")}
            </div>
            ${_editor.stickers.length ? `
                <div class="editor-props-title" style="margin-top:12px">Adicionados</div>
                <div class="editor-props-group">
                    ${_editor.stickers.map(s => `
                        <div class="editor-subtitle-item">
                            <span style="font-size:20px">${s.emoji}</span>
                            <span class="sub-time">${_fmtTime(s.startTime)}-${_fmtTime(s.endTime)}</span>
                            <button class="sub-delete" onclick="_editorDeleteSticker(${s.id})">✕</button>
                        </div>
                    `).join("")}
                </div>
            ` : ""}
        `;
    } else if (tool === "quality") {
        const qualities = [
            {val: "original", label: "Original", desc: "Manter qualidade atual do video"},
            {val: "enhance", label: "Melhorar", desc: "IA aprimora nitidez e cores"},
            {val: "hd", label: "HD 720p", desc: "Reescalar para 720p"},
            {val: "fullhd", label: "Full HD 1080p", desc: "Reescalar para 1080p"},
        ];
        container.innerHTML = `
            <div class="editor-props-title">Qualidade</div>
            <div class="editor-props-group">
                ${qualities.map(q => `
                    <div class="editor-quality-option${_editor.quality === q.val ? ' active' : ''}" onclick="_editorSetQuality('${q.val}')">
                        <div>
                            <div class="editor-quality-label">${q.label}</div>
                            <div class="editor-quality-desc">${q.desc}</div>
                        </div>
                    </div>
                `).join("")}
            </div>
        `;
    }

    _editorRenderMobileStagePanel();
    _editorRenderMobileSubtitleSheet();
}

// Text edit form
function _editorTextEditForm() {
    const sel = _editor.texts.find(t => t._selected);
    if (!sel) return "";
    return `
        <div class="editor-props-group" style="margin-top:8px;padding-top:8px;border-top:1px solid var(--border)">
            <label>Conteudo</label>
            <textarea rows="2" style="resize:vertical" oninput="_editorUpdateTextProp(${sel.id},'content',this.value)">${esc(sel.content)}</textarea>
            <label>Cor</label>
            <div class="editor-color-row">
                <input type="color" value="${sel.color}" oninput="_editorUpdateTextProp(${sel.id},'color',this.value)">
                <span style="font-size:11px;color:var(--text-muted)">${sel.color}</span>
            </div>
            <label>Tamanho da fonte</label>
            <div class="editor-font-size-row">
                <input type="range" min="12" max="120" value="${sel.fontSize}" oninput="_editorUpdateTextProp(${sel.id},'fontSize',parseInt(this.value))">
                <span>${sel.fontSize}px</span>
            </div>
            <label>Posicao vertical (%)</label>
            <div class="editor-font-size-row">
                <input type="range" min="5" max="95" value="${sel.y}" oninput="_editorUpdateTextProp(${sel.id},'y',parseInt(this.value))">
                <span>${sel.y}%</span>
            </div>
            <label>Tempo</label>
            <div class="editor-trim-values">
                <span>Inicio: ${_fmtTime(sel.startTime)}</span>
                <span>Fim: ${_fmtTime(sel.endTime)}</span>
            </div>
            <div class="editor-font-size-row">
                <input type="range" min="0" max="${_editor.duration}" step="0.1" value="${sel.startTime}" oninput="_editorUpdateTextProp(${sel.id},'startTime',parseFloat(this.value))">
            </div>
            <div class="editor-font-size-row">
                <input type="range" min="0" max="${_editor.duration}" step="0.1" value="${sel.endTime}" oninput="_editorUpdateTextProp(${sel.id},'endTime',parseFloat(this.value))">
            </div>
            <div style="display:flex;gap:8px">
                <label style="display:flex;align-items:center;gap:4px"><input type="checkbox" ${sel.bold ? "checked" : ""} onchange="_editorUpdateTextProp(${sel.id},'bold',this.checked)"> Negrito</label>
                <label style="display:flex;align-items:center;gap:4px"><input type="checkbox" ${sel.italic ? "checked" : ""} onchange="_editorUpdateTextProp(${sel.id},'italic',this.checked)"> Italico</label>
            </div>
        </div>
    `;
}

// Subtitle edit form
function _editorSubtitleEditForm() {
    const sel = _editor.subtitles.find(s => s._selected);
    if (!sel) return "";
    return `
        <div class="editor-props-group" style="margin-top:8px;padding-top:8px;border-top:1px solid var(--border)">
            <label>Texto da legenda</label>
            <textarea rows="2" style="resize:vertical" oninput="_editorUpdateSubProp(${sel.id},'text',this.value)">${esc(sel.text)}</textarea>
            <label>Cor do texto</label>
            <div class="editor-color-row">
                <input type="color" value="${sel.fontColor || '#ffffff'}" oninput="_editorUpdateSubProp(${sel.id},'fontColor',this.value)">
                <span style="font-size:11px;color:var(--text-muted)">${sel.fontColor || '#ffffff'}</span>
            </div>
            <label>Cor de fundo</label>
            <div class="editor-color-row">
                <input type="color" value="${(sel.bgColor||'').startsWith('rgba') ? '#000000' : (sel.bgColor || '#000000')}" oninput="_editorUpdateSubProp(${sel.id},'bgColor',this.value)">
                <label style="display:flex;align-items:center;gap:4px;font-size:11px;margin:0"><input type="checkbox" ${sel.bgColor ? 'checked' : ''} onchange="_editorUpdateSubProp(${sel.id},'bgColor',this.checked?'rgba(0,0,0,0.6)':'')"> Ativado</label>
            </div>
            <label>Contorno</label>
            <div class="editor-color-row">
                <input type="color" value="${sel.outlineColor || '#000000'}" oninput="_editorUpdateSubProp(${sel.id},'outlineColor',this.value)">
                <label style="display:flex;align-items:center;gap:4px;font-size:11px;margin:0"><input type="checkbox" ${sel.outlineColor ? 'checked' : ''} onchange="_editorUpdateSubProp(${sel.id},'outlineColor',this.checked?'#000000':'')"> Ativado</label>
            </div>
            <label>Tamanho da fonte</label>
            <div class="editor-font-size-row">
                <input type="range" min="14" max="72" value="${sel.fontSize || 28}" oninput="_editorUpdateSubProp(${sel.id},'fontSize',parseInt(this.value))">
                <span>${sel.fontSize || 28}px</span>
            </div>
            <label>Posicao vertical</label>
            <div class="editor-font-size-row">
                <input type="range" min="5" max="95" value="${sel.y || 85}" oninput="_editorUpdateSubProp(${sel.id},'y',parseInt(this.value))">
                <span>${sel.y || 85}%</span>
            </div>
            <label>Posicao horizontal</label>
            <div class="editor-font-size-row">
                <input type="range" min="10" max="90" value="${sel.x || 50}" oninput="_editorUpdateSubProp(${sel.id},'x',parseInt(this.value))">
                <span>${sel.x || 50}%</span>
            </div>
            <label>Fonte</label>
            <select onchange="_editorUpdateSubProp(${sel.id},'fontFamily',this.value)" style="background:rgba(255,255,255,0.06);border:1px solid var(--border);border-radius:6px;color:var(--text);padding:6px 8px;font-size:12px">
                <option value="Arial, sans-serif" ${sel.fontFamily==="Arial, sans-serif"?"selected":""}>Arial</option>
                <option value="Arial Black, sans-serif" ${sel.fontFamily==="Arial Black, sans-serif"?"selected":""}>Arial Black</option>
                <option value="Manrope, sans-serif" ${sel.fontFamily==="Manrope, sans-serif"?"selected":""}>Manrope</option>
                <option value="Outfit, sans-serif" ${sel.fontFamily==="Outfit, sans-serif"?"selected":""}>Outfit</option>
                <option value="Georgia, serif" ${sel.fontFamily==="Georgia, serif"?"selected":""}>Georgia</option>
                <option value="Courier New, monospace" ${sel.fontFamily==="Courier New, monospace"?"selected":""}>Courier New</option>
                <option value="Times New Roman, serif" ${sel.fontFamily==="Times New Roman, serif"?"selected":""}>Times New Roman</option>
            </select>
            <div style="display:flex;gap:8px">
                <label style="display:flex;align-items:center;gap:4px"><input type="checkbox" ${sel.bold ? "checked" : ""} onchange="_editorUpdateSubProp(${sel.id},'bold',this.checked)"> Negrito</label>
                <label style="display:flex;align-items:center;gap:4px"><input type="checkbox" ${sel.italic ? "checked" : ""} onchange="_editorUpdateSubProp(${sel.id},'italic',this.checked)"> Italico</label>
            </div>
            <label>Tempo</label>
            <div class="editor-trim-values">
                <span>Inicio: ${_fmtTime(sel.startTime)}</span>
                <span>Fim: ${_fmtTime(sel.endTime)}</span>
            </div>
            <div class="editor-font-size-row">
                <input type="range" min="0" max="${_editor.duration}" step="0.1" value="${sel.startTime}" oninput="_editorUpdateSubProp(${sel.id},'startTime',parseFloat(this.value))">
            </div>
            <div class="editor-font-size-row">
                <input type="range" min="0" max="${_editor.duration}" step="0.1" value="${sel.endTime}" oninput="_editorUpdateSubProp(${sel.id},'endTime',parseFloat(this.value))">
            </div>
        </div>
    `;
}

// ---------- Text actions ----------
function _editorBuildTrackLabelMarkup(row) {
    const trackId = String(row.track || "").trim();
    const usesAudioMasterVolume = trackId === "audio" || /^layer-audio-\d+$/i.test(trackId);
    const controlTrack = usesAudioMasterVolume ? "audio" : trackId;
    const iconHtml = `<span class="editor-track-label-main">${_editorTimelineTrackIcon(row.kind)}</span>`;
    const showMobileVolume = _editorIsMobileViewport() && (trackId === "video" || usesAudioMasterVolume);
    if (!showMobileVolume) {
        return iconHtml;
    }

    const volumePct = Math.max(0, Math.min(100, Math.round(_editorGetTrackMasterVolumePercent(controlTrack))));
    const volumeTitle = `Volume da faixa ${String(row.label || trackId || "").toLowerCase()}`;
    const mutedClass = volumePct <= 0 ? " muted" : "";
    const openClass = _editorMobileTrackVolumeOpen === trackId ? " open" : "";

    return `
        <span class="editor-track-label-controls" onpointerdown="event.stopPropagation()" onclick="event.stopPropagation()">
            ${iconHtml}
            <span class="editor-track-label-volume-wrap${openClass}${mutedClass}" onpointerdown="event.stopPropagation()" onclick="event.stopPropagation()">
            <button
                class="editor-track-label-volume${mutedClass}"
                type="button"
                title="${esc(volumeTitle)}"
                aria-label="${esc(volumeTitle)}"
                aria-expanded="${_editorMobileTrackVolumeOpen === trackId ? "true" : "false"}"
                onclick="event.stopPropagation();_editorToggleMobileTrackVolume('${trackId}')"
            >
                ${_editorTimelineVolumeIcon(controlTrack)}
            </button>
            <span class="editor-track-label-volume-popover${openClass}" onpointerdown="event.stopPropagation()" onclick="event.stopPropagation()">
                <input
                    class="editor-track-label-slider${mutedClass}"
                    type="range"
                    min="0"
                    max="100"
                    value="${volumePct}"
                    title="${esc(volumeTitle)}"
                    aria-label="${esc(volumeTitle)}"
                    onpointerdown="event.stopPropagation()"
                    onclick="event.stopPropagation()"
                    oninput="_editorSetTrackVolumeFromTrim('${controlTrack}', this.value); this.closest('.editor-track-label-volume-wrap')?.classList.toggle('muted', (parseInt(this.value, 10) || 0) <= 0); this.closest('.editor-track-label-volume-wrap')?.querySelector('.editor-track-label-volume')?.classList.toggle('muted', (parseInt(this.value, 10) || 0) <= 0);"
                >
            </span>
            </span>
        </span>
    `;
}

function _editorBuildTrackInlineVolumeMarkup(row) {
    return "";
}

function _editorToggleMobileTrackVolume(track) {
    const nextTrack = String(track || "");
    _editorMobileTrackVolumeOpen = _editorMobileTrackVolumeOpen === nextTrack ? "" : nextTrack;
    _editorRenderTimeline();
}
