// ---------- Trim actions ----------
function _editorSplitAtCurrentTime() {
    const video = document.getElementById("editor-video");
    if (!video || !_editor.videoSegments.length) return;

    const currentTimeline = Number(_editor.timelineTime || video.currentTime || 0);
    const t = Math.max(0, Math.min(currentTimeline, _editorGetTimelineDuration()));
    const canSplitRange = (start, end) => {
        return t > Number(start || 0) + 0.08 && t < Number(end || 0) - 0.08;
    };

    let changed = false;
    let segmentChanged = false;
    let layerChanged = false;
    let overlayChanged = false;
    const ensureSaved = () => {
        if (!changed) {
            _editorSaveState();
            changed = true;
        }
    };

    const splitSegmentInTrack = (track, preferredId = "") => {
        const targetTrack = _editorIsAudioTrack(track)
            ? "audio"
            : (_editorIsVideoTrack(track) ? String(track || "video") : "video");
        const segments = _editorGetSegments(targetTrack);
        let seg = preferredId
            ? segments.find(item => String(item.id) === String(preferredId))
            : null;
        if (!seg || !canSplitRange(seg.start, seg.end)) {
            seg = segments.find(item => canSplitRange(item.start, item.end));
        }
        if (!seg) return null;

        ensureSaved();
        const origSrc = _editorSegSourceStart(seg);
        const origSourceDuration = _editorSegSourceDuration(seg);
        const origSourceEnd = origSrc + origSourceDuration;
        const reversedFlag = _editorSegmentIsReversed(seg);
        const speed = _editorSegmentPlaybackSpeed(seg);
        const splitRatio = Math.max(0, Math.min(1, (t - Number(seg.start || 0)) / Math.max(0.0001, _editorSegTimelineDuration(seg))));
        const firstSourceDuration = Math.max(0.05, origSourceDuration * splitRatio);
        const secondSourceDuration = Math.max(0.05, origSourceDuration - firstSourceDuration);
        const firstSourceStart = reversedFlag
            ? Math.max(origSrc, origSourceEnd - firstSourceDuration)
            : origSrc;
        const secondSourceStart = reversedFlag
            ? origSrc
            : origSrc + firstSourceDuration;
        const segmentVolume = _editorSegmentVolumePercent(seg);
        const first = { id: _editorGenId(), start: seg.start, end: t, sourceStart: firstSourceStart, sourceDuration: firstSourceDuration, speed, reversed: reversedFlag, volume: segmentVolume };
        const second = { id: _editorGenId(), start: t, end: seg.end, sourceStart: secondSourceStart, sourceDuration: secondSourceDuration, speed, reversed: reversedFlag, volume: segmentVolume };
        const nextSegments = segments
            .filter(item => item !== seg)
            .concat([first, second]);
        _editorSetSegments(targetTrack, nextSegments);
        _editorSortSegments(targetTrack);
        segmentChanged = true;
        return { kind: "segment", id: String(second.id), track: targetTrack };
    };

    const splitMediaLayer = (layer) => {
        if (!layer || (layer.kind !== "video" && layer.kind !== "audio")) return null;
        const normalizedLayer = _editorNormalizeMediaLayer(layer);
        if (!canSplitRange(normalizedLayer.startTime, normalizedLayer.endTime)) return null;

        ensureSaved();
        const firstEnd = t;
        const secondStart = t;
        const firstClipDuration = Math.max(0.1, firstEnd - normalizedLayer.startTime);
        const originalSourceOffset = Math.max(0, Number(normalizedLayer.sourceOffset || 0));
        const originalSourceDuration = Math.max(0.1, Number(normalizedLayer.sourceDuration || 0));
        const playbackSpeed = _editorMediaLayerPlaybackSpeed(normalizedLayer);
        const firstConsumedDuration = Math.max(
            0.05,
            Math.min(originalSourceDuration - 0.05, firstClipDuration * playbackSpeed),
        );
        const secondConsumedDuration = Math.max(0.05, originalSourceDuration - firstConsumedDuration);
        const secondSourceOffset = Boolean(normalizedLayer.reversed)
            ? originalSourceOffset
            : Math.max(0, originalSourceOffset + firstConsumedDuration);
        const firstSourceOffset = Boolean(normalizedLayer.reversed)
            ? Math.max(0, originalSourceOffset + secondConsumedDuration)
            : originalSourceOffset;

        const secondLayer = {
            ...layer,
            id: _editorGenId(),
            startTime: secondStart,
            endTime: normalizedLayer.endTime,
            sourceOffset: secondSourceOffset,
            sourceDuration: secondConsumedDuration,
            reversed: Boolean(normalizedLayer.reversed),
        };

        layer.sourceOffset = firstSourceOffset;
        layer.sourceDuration = firstConsumedDuration;
        layer.endTime = firstEnd;

        if (Number(secondLayer.duration || 0) > 0 && Number.isFinite(_editorGetMediaLayerMaxTimelineSpan(secondLayer))) {
            const remainingDuration = _editorGetMediaLayerMaxTimelineSpan(secondLayer);
            secondLayer.endTime = Math.min(secondLayer.endTime, secondLayer.startTime + remainingDuration);
        }
        secondLayer.endTime = Math.max(secondLayer.startTime + 0.1, secondLayer.endTime);

        _editor.mediaLayers.push(secondLayer);
        layerChanged = true;
        const trackIndex = _editorGetLayerTrackIndex(secondLayer);
        return {
            kind: "media-layer",
            id: String(secondLayer.id),
            track: _editorBuildMediaLayerTrackId(_editorGetMediaLayerTrackType(secondLayer), trackIndex),
        };
    };

    const splitTimedOverlayById = (kind, list, itemId, trackBuilder) => {
        if (!Array.isArray(list) || !list.length) return null;
        const idx = list.findIndex(item => String(item.id) === String(itemId));
        if (idx < 0) return null;
        const source = list[idx];
        if (!canSplitRange(source.startTime, source.endTime)) return null;

        ensureSaved();
        const second = {
            ...source,
            id: _editorGenId(),
            startTime: t,
            endTime: Number(source.endTime || t),
        };
        source.endTime = t;
        list.splice(idx + 1, 0, second);
        overlayChanged = true;
        return {
            kind,
            id: String(second.id),
            track: typeof trackBuilder === "function" ? trackBuilder(second) : "",
        };
    };

    const splitTimedOverlayAtTime = (kind, list, trackBuilder) => {
        if (!Array.isArray(list) || !list.length) return null;
        const idx = list.findIndex(item => canSplitRange(item.startTime, item.endTime));
        if (idx < 0) return null;
        const source = list[idx];

        ensureSaved();
        const second = {
            ...source,
            id: _editorGenId(),
            startTime: t,
            endTime: Number(source.endTime || t),
        };
        source.endTime = t;
        list.splice(idx + 1, 0, second);
        overlayChanged = true;
        return {
            kind,
            id: String(second.id),
            track: typeof trackBuilder === "function" ? trackBuilder(second) : "",
        };
    };

    const finalizeSplit = (selection) => {
        if (!changed) return false;
        if (segmentChanged) {
            _editorRecomputeTrimBounds();
            _editorSyncAudioSegmentsWithVideoIfNoExternalAudio();
        }
        _editor.selectedClip = selection || { kind: "", id: "", track: "" };
        if (selection?.track) {
            _editor.selectedInsertTrack = _editorResolveInsertTrackForUi(selection.track);
        }
        _editorRenderTimeline();
        if (layerChanged) {
            _editorRenderMediaLayers();
        }
        _editorRenderProps();
        if (overlayChanged) {
            const currentTime = Number(_editor.timelineTime || video.currentTime || 0);
            _editorDrawOverlays(currentTime);
        }
        return true;
    };

    const selectedKind = String(_editor.selectedClip.kind || "");
    const selectedId = String(_editor.selectedClip.id || "");
    const selectedTrack = String(_editor.selectedClip.track || "");

    if (selectedKind === "segment") {
        const splitSelection = splitSegmentInTrack(selectedTrack || "video", selectedId);
        if (splitSelection && finalizeSplit(splitSelection)) {
            return;
        }
    }

    if (selectedKind === "media-layer") {
        const selectedLayer = _editorGetMediaLayerById(selectedId);
        const splitSelection = splitMediaLayer(selectedLayer);
        if (splitSelection && finalizeSplit(splitSelection)) {
            return;
        }
    }

    if (selectedKind === "text") {
        const splitSelection = splitTimedOverlayById("text", _editor.texts, selectedId, (item) => `text-${item.id}`);
        if (splitSelection && finalizeSplit(splitSelection)) {
            return;
        }
    }

    if (selectedKind === "subtitle") {
        const splitSelection = splitTimedOverlayById("subtitle", _editor.subtitles, selectedId, () => "subtitle");
        if (splitSelection && finalizeSplit(splitSelection)) {
            return;
        }
    }

    if (selectedKind === "sticker") {
        const splitSelection = splitTimedOverlayById("sticker", _editor.stickers, selectedId, (item) => `sticker-${item.id}`);
        if (splitSelection && finalizeSplit(splitSelection)) {
            return;
        }
    }

    if (selectedKind === "music") {
        const splitSelection = splitSegmentInTrack("audio", "");
        if (splitSelection && finalizeSplit(splitSelection)) {
            return;
        }
    }

    const insertTrack = String(_editor.selectedInsertTrack || "").trim();
    if (/^layer-(video|audio)-\d+$/i.test(insertTrack)) {
        const { trackType, trackIndex: targetTrackIndex } = _editorParseMediaLayerTrack(insertTrack, "video", 0);
        const layerOnTrack = _editor.mediaLayers
            .filter(layer => _editorGetMediaLayerTrackType(layer) === trackType && _editorGetLayerTrackIndex(layer) === targetTrackIndex)
            .find(layer => {
                const normalizedLayer = _editorNormalizeMediaLayer(layer);
                return canSplitRange(normalizedLayer.startTime, normalizedLayer.endTime);
            });

        const splitSelection = splitMediaLayer(layerOnTrack);
        if (splitSelection && finalizeSplit(splitSelection)) {
            return;
        }

        showToast("Posicione o playhead dentro de um trecho para cortar.", "error");
        return;
    }

    if (insertTrack.startsWith("text-")) {
        const itemId = insertTrack.slice("text-".length);
        const splitSelection = splitTimedOverlayById("text", _editor.texts, itemId, (item) => `text-${item.id}`);
        if (splitSelection && finalizeSplit(splitSelection)) {
            return;
        }
        showToast("Posicione o playhead dentro de um trecho para cortar.", "error");
        return;
    }

    if (insertTrack === "subtitle") {
        const splitSelection = splitTimedOverlayAtTime("subtitle", _editor.subtitles, () => "subtitle");
        if (splitSelection && finalizeSplit(splitSelection)) {
            return;
        }
        showToast("Posicione o playhead dentro de um trecho para cortar.", "error");
        return;
    }

    if (insertTrack.startsWith("sticker-")) {
        const itemId = insertTrack.slice("sticker-".length);
        const splitSelection = splitTimedOverlayById("sticker", _editor.stickers, itemId, (item) => `sticker-${item.id}`);
        if (splitSelection && finalizeSplit(splitSelection)) {
            return;
        }
        showToast("Posicione o playhead dentro de um trecho para cortar.", "error");
        return;
    }

    if (_editorIsAudioTrack(insertTrack) || _editorIsVideoTrack(insertTrack)) {
        const splitSelection = splitSegmentInTrack(insertTrack, "");
        if (splitSelection && finalizeSplit(splitSelection)) {
            return;
        }
    }

    const selectedTracks = _editorGetSelectedSegmentTracks();
    const splitTargets = selectedTracks.map(track => {
        const seg = _editorGetSegments(track).find(item => canSplitRange(item.start, item.end));
        return { track, seg };
    }).filter(item => item.seg);

    if (!splitTargets.length) {
        showToast("Posicione o playhead dentro de um trecho para cortar.", "error");
        return;
    }

    let selectedSplit = null;
    splitTargets.forEach(({ track, seg }) => {
        const splitSelection = splitSegmentInTrack(track, seg.id);
        if (splitSelection) {
            selectedSplit = splitSelection;
        }
    });

    if (!finalizeSplit(selectedSplit)) {
        showToast("Posicione o playhead dentro de um trecho para cortar.", "error");
    }
}
window._editorSplitAtCurrentTime = _editorSplitAtCurrentTime;

function _editorResetVideoSegments() {
    if (!_editor.duration) return;
    _editorSaveState();
    _editorInitVideoSegments();
    _editor.selectedClip = { kind: "", id: "", track: "" };
    _editorRenderTimeline();
    _editorRenderProps();
    showToast("Cortes removidos. Vídeo restaurado.", "success");
}
window._editorResetVideoSegments = _editorResetVideoSegments;

function _editorSetTrimStart(val) {
    const parsed = parseFloat(val);
    if (isNaN(parsed) || !_editor.videoSegments.length) return;
    _editorSortVideoSegments();
    const first = _editor.videoSegments[0];
    const nextStart = Math.max(0, Math.min(first.end - 0.1, parsed));
    _editorApplySegmentTimelineBounds(first, nextStart, Number(first.end || nextStart + 0.1));
    _editorRecomputeTrimBounds();
    _editorSyncAudioSegmentsWithVideoIfNoExternalAudio();
    const label = document.getElementById("trim-start-label");
    if (label) label.textContent = _fmtTime(_editor.trimStart);
    _editorRenderTimeline();
}
window._editorSetTrimStart = _editorSetTrimStart;

function _editorSetTrimEnd(val) {
    const parsed = parseFloat(val);
    if (isNaN(parsed) || !_editor.videoSegments.length) return;
    _editorSortVideoSegments();
    const last = _editor.videoSegments[_editor.videoSegments.length - 1];
    const nextEnd = Math.max(last.start + 0.1, Math.min(_editor.duration || parsed, parsed));
    _editorApplySegmentTimelineBounds(last, Number(last.start || 0), nextEnd);
    _editorRecomputeTrimBounds();
    _editorSyncAudioSegmentsWithVideoIfNoExternalAudio();
    const label = document.getElementById("trim-end-label");
    if (label) label.textContent = _fmtTime(_editor.trimEnd);
    _editorRenderTimeline();
}
window._editorSetTrimEnd = _editorSetTrimEnd;

// ---------- Music actions ----------
function _editorUploadMusic(input) {
    const file = input.files?.[0];
    if (!file) return;
    _editorApplyImportedAudioTrack({
        musicUrl: URL.createObjectURL(file),
        musicFile: file,
        serverPath: "",
        source: "audio",
    }).catch((err) => {
        showToast("Erro ao carregar áudio: " + (err?.message || "erro desconhecido"), "error");
    }).finally(() => {
        if (input) input.value = "";
    });
}
window._editorUploadMusic = _editorUploadMusic;

function _editorResolveMediaUrl(rawValue = "") {
    const raw = String(rawValue || "").trim();
    if (!raw) return "";
    return raw.startsWith("/") ? `${API.replace("/api", "")}${raw}` : raw;
}

async function _editorApplyVideoAudioSource(payload) {
    const serverPath = String(payload?.path || "").trim();
    const mediaUrl = _editorResolveMediaUrl(payload?.media_url);
    if (!serverPath || !mediaUrl) {
        throw new Error("Falha ao extrair audio do video");
    }

    await _editorApplyImportedAudioTrack({
        musicUrl: mediaUrl,
        musicFile: null,
        serverPath,
        source: "video",
    });
}

function _editorResetAudioVideoSourceModalState() {
    _editorAudioVideoSourceModal.open = false;
    _editorAudioVideoSourceModal.mode = "local";
    _editorAudioVideoSourceModal.loading = false;
    _editorAudioVideoSourceModal.status = "";
    _editorAudioVideoSourceModal.error = "";
    _editorAudioVideoSourceModal.remoteResult = null;

    const input = document.getElementById("editor-audio-video-url-input");
    if (input) input.value = "";
    const localInput = document.getElementById("editor-audio-source-local-input");
    if (localInput) localInput.value = "";
}

function _editorRenderAudioVideoSourceModal() {
    const localBtn = document.getElementById("editor-audio-source-mode-local");
    const internetBtn = document.getElementById("editor-audio-source-mode-internet");
    const localPanel = document.getElementById("editor-audio-source-local-panel");
    const internetPanel = document.getElementById("editor-audio-source-internet-panel");
    const submit = document.getElementById("editor-audio-video-modal-submit");
    const input = document.getElementById("editor-audio-video-url-input");
    const previewHost = document.getElementById("editor-audio-video-preview-host");
    const status = document.getElementById("editor-audio-video-modal-status");
    const localInput = document.getElementById("editor-audio-source-local-input");
    if (!localBtn || !internetBtn || !localPanel || !internetPanel || !submit || !previewHost || !status) return;

    const mode = _editorAudioVideoSourceModal.mode === "internet" ? "internet" : "local";
    localBtn.classList.toggle("active", mode === "local");
    internetBtn.classList.toggle("active", mode === "internet");
    localPanel.hidden = mode !== "local";
    internetPanel.hidden = mode !== "internet";

    if (input) input.disabled = Boolean(_editorAudioVideoSourceModal.loading);
    if (localInput) localInput.disabled = Boolean(_editorAudioVideoSourceModal.loading);

    let submitLabel = "Selecionar vídeo";
    let submitDisabled = Boolean(_editorAudioVideoSourceModal.loading);
    if (mode === "internet") {
        submitLabel = _editorAudioVideoSourceModal.remoteResult ? "Usar áudio" : "Carregar";
        submitDisabled = submitDisabled || (!_editorAudioVideoSourceModal.remoteResult && !String(input?.value || "").trim());
    }
    if (_editorAudioVideoSourceModal.loading) {
        submitLabel = mode === "local" ? "Extraindo..." : "Carregando...";
    }
    submit.textContent = submitLabel;
    submit.disabled = submitDisabled;

    if (mode === "internet") {
        const result = _editorAudioVideoSourceModal.remoteResult;
        if (result?.preview_url) {
            const previewUrl = esc(_editorResolveMediaUrl(result.preview_url));
            const fileName = esc(String(result.file_name || "video"));
            const sourceUrl = String(result.normalized_url || result.source_url || "").trim();
            const sourceLink = sourceUrl
                ? `<a class="workflow-media-item-link" href="${esc(sourceUrl)}" target="_blank" rel="noopener noreferrer">Abrir original</a>`
                : "";
            previewHost.innerHTML = `
                <div class="workflow-media-item editor-audio-video-preview-card">
                    <div class="workflow-media-item-main">
                        <video class="workflow-media-preview" src="${previewUrl}" controls playsinline preload="metadata"></video>
                        <span class="workflow-media-item-label">${fileName}</span>
                        ${sourceLink}
                    </div>
                </div>
            `;
        } else {
            previewHost.innerHTML = `
                <div class="editor-audio-video-preview-empty">
                    <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.7"><path d="M10 13a5 5 0 0 0 7.07 0l1.41-1.41a5 5 0 0 0-7.07-7.07L10 5"/><path d="M14 11a5 5 0 0 0-7.07 0L5.52 12.41a5 5 0 1 0 7.07 7.07L14 19"/></svg>
                    <span>Cole um link</span>
                </div>
            `;
        }
    } else {
        previewHost.innerHTML = "";
    }

    const statusMessage = String(_editorAudioVideoSourceModal.error || _editorAudioVideoSourceModal.status || "").trim();
    status.hidden = !statusMessage;
    status.textContent = statusMessage;
    status.classList.toggle("error", Boolean(_editorAudioVideoSourceModal.error));
}

function _editorOpenAudioVideoSourceModal() {
    _editorResetAudioVideoSourceModalState();
    _editorAudioVideoSourceModal.open = true;
    openModal("modal-editor-audio-video-source");
    _editorRenderAudioVideoSourceModal();
}
window._editorOpenAudioVideoSourceModal = _editorOpenAudioVideoSourceModal;

function _editorCloseAudioVideoSourceModal(forceClose = false) {
    if (_editorAudioVideoSourceModal.loading && !forceClose) return;
    _editorResetAudioVideoSourceModalState();
    closeModal("modal-editor-audio-video-source");
}
window._editorCloseAudioVideoSourceModal = _editorCloseAudioVideoSourceModal;

function _editorSetAudioVideoSourceMode(mode) {
    if (_editorAudioVideoSourceModal.loading) return;
    const nextMode = mode === "internet" ? "internet" : "local";
    const reopenLocalPicker = nextMode === "local" && _editorAudioVideoSourceModal.mode === "local";
    _editorAudioVideoSourceModal.mode = nextMode;
    _editorAudioVideoSourceModal.status = "";
    _editorAudioVideoSourceModal.error = "";
    _editorRenderAudioVideoSourceModal();
    if (_editorAudioVideoSourceModal.mode === "internet") {
        requestAnimationFrame(() => document.getElementById("editor-audio-video-url-input")?.focus());
        return;
    }
    if (reopenLocalPicker) {
        _editorChooseLocalVideoForAudio();
    }
}
window._editorSetAudioVideoSourceMode = _editorSetAudioVideoSourceMode;

function _editorChooseLocalVideoForAudio() {
    if (_editorAudioVideoSourceModal.loading) return;
    const input = document.getElementById("editor-audio-source-local-input");
    if (!input) return;
    if (typeof input.showPicker === "function") {
        try {
            input.showPicker();
            return;
        } catch (err) {
            console.debug("[CriaVideo] showPicker fallback", err);
        }
    }
    input.click();
}
window._editorChooseLocalVideoForAudio = _editorChooseLocalVideoForAudio;

function _editorHandleAudioVideoUrlInput(value) {
    const nextValue = String(value || "").trim();
    const currentResult = _editorAudioVideoSourceModal.remoteResult;
    const currentUrl = String(currentResult?.normalized_url || currentResult?.source_url || "").trim();
    if (currentResult && nextValue && nextValue !== currentUrl) {
        _editorAudioVideoSourceModal.remoteResult = null;
    }
    _editorAudioVideoSourceModal.status = "";
    _editorAudioVideoSourceModal.error = "";
    _editorRenderAudioVideoSourceModal();
}
window._editorHandleAudioVideoUrlInput = _editorHandleAudioVideoUrlInput;

function _editorHandleAudioVideoUrlKeydown(event) {
    if (event.key !== "Enter") return;
    event.preventDefault();
    _editorSubmitAudioVideoSourceModal();
}
window._editorHandleAudioVideoUrlKeydown = _editorHandleAudioVideoUrlKeydown;

async function _editorLoadVideoFromUrlForAudio() {
    if (_editorAudioVideoSourceModal.loading) return;
    const input = document.getElementById("editor-audio-video-url-input");
    const rawUrl = String(input?.value || "").trim();
    if (!rawUrl) {
        _editorAudioVideoSourceModal.error = "Cole um link de vídeo.";
        _editorRenderAudioVideoSourceModal();
        input?.focus();
        return;
    }
    if (!rawUrl.startsWith("http://") && !rawUrl.startsWith("https://")) {
        _editorAudioVideoSourceModal.error = "Informe um link válido.";
        _editorRenderAudioVideoSourceModal();
        input?.focus();
        return;
    }

    _editorAudioVideoSourceModal.loading = true;
    _editorAudioVideoSourceModal.status = "Carregando vídeo...";
    _editorAudioVideoSourceModal.error = "";
    _editorAudioVideoSourceModal.remoteResult = null;
    _editorRenderAudioVideoSourceModal();

    try {
        const payload = await api("/video/editor/upload-video-audio-url", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ source_url: rawUrl }),
        });
        if (!payload?.path || !payload?.media_url || !payload?.preview_url) {
            throw new Error("Falha ao carregar a prévia do vídeo");
        }
        if (input && payload?.normalized_url) {
            input.value = String(payload.normalized_url || "").trim();
        }
        _editorAudioVideoSourceModal.remoteResult = {
            ...payload,
            media_url: _editorResolveMediaUrl(payload.media_url),
            preview_url: _editorResolveMediaUrl(payload.preview_url),
        };
        _editorAudioVideoSourceModal.status = "";
        _editorAudioVideoSourceModal.error = "";
    } catch (err) {
        _editorAudioVideoSourceModal.remoteResult = null;
        _editorAudioVideoSourceModal.error = err?.message || "Erro ao carregar vídeo";
    } finally {
        _editorAudioVideoSourceModal.loading = false;
        _editorRenderAudioVideoSourceModal();
    }
}
window._editorLoadVideoFromUrlForAudio = _editorLoadVideoFromUrlForAudio;

async function _editorSubmitAudioVideoSourceModal() {
    if (_editorAudioVideoSourceModal.loading) return;
    if (_editorAudioVideoSourceModal.mode === "local") {
        _editorChooseLocalVideoForAudio();
        return;
    }
    if (_editorAudioVideoSourceModal.remoteResult) {
        try {
            await _editorApplyVideoAudioSource(_editorAudioVideoSourceModal.remoteResult);
            _editorCloseAudioVideoSourceModal(true);
            showToast("Áudio extraído do vídeo com sucesso!", "success");
        } catch (err) {
            _editorAudioVideoSourceModal.error = err?.message || "Erro ao aplicar áudio";
            _editorRenderAudioVideoSourceModal();
        }
        return;
    }
    await _editorLoadVideoFromUrlForAudio();
}
window._editorSubmitAudioVideoSourceModal = _editorSubmitAudioVideoSourceModal;

async function _editorUploadVideoForMusic(input) {
    const file = input.files?.[0];
    if (!file) return;
    const isModalFlow = Boolean(_editorAudioVideoSourceModal.open);
    try {
        if (isModalFlow) {
            _editorAudioVideoSourceModal.loading = true;
            _editorAudioVideoSourceModal.status = "Extraindo áudio...";
            _editorAudioVideoSourceModal.error = "";
            _editorRenderAudioVideoSourceModal();
        } else {
            showToast("Extraindo áudio do vídeo...");
        }

        const formData = new FormData();
        formData.append("file", file);
        const payload = await apiForm("/video/editor/upload-video-audio", formData, { method: "POST" });
        await _editorApplyVideoAudioSource(payload);
        if (isModalFlow) {
            _editorCloseAudioVideoSourceModal(true);
        }
        showToast("Áudio extraído do vídeo com sucesso!", "success");
    } catch (err) {
        if (isModalFlow) {
            _editorAudioVideoSourceModal.error = err?.message || "erro desconhecido";
            _editorAudioVideoSourceModal.status = "";
            _editorAudioVideoSourceModal.loading = false;
            _editorRenderAudioVideoSourceModal();
        }
        showToast("Erro ao extrair áudio do vídeo: " + (err?.message || "erro desconhecido"), "error");
    } finally {
        if (input) input.value = "";
        if (isModalFlow && _editorAudioVideoSourceModal.open) {
            _editorAudioVideoSourceModal.loading = false;
            _editorRenderAudioVideoSourceModal();
        }
    }
}
window._editorUploadVideoForMusic = _editorUploadVideoForMusic;

