window._editorOpenTrackVolumeControls = _editorOpenTrackVolumeControls;

function _editorSetSegmentVolume(track, id, val) {
    const targetTrack = _editorIsAudioTrack(track)
        ? "audio"
        : (_editorIsVideoTrack(track) ? String(track || "video") : "video");
    const segment = _editorFindSegment(targetTrack, id);
    if (!segment) return;

    segment.volume = _editorClampSegmentVolume(val, _editorSegmentVolumePercent(segment));
    if (_editorIsVideoTrack(targetTrack) && !_editorShouldShowAudioTrack()) {
        _editorSyncAudioSegmentsWithVideoIfNoExternalAudio();
    }

    const segmentLabel = document.getElementById("editor-seg-vol-label");
    if (segmentLabel && _editor.selectedClip.kind === "segment" && String(_editor.selectedClip.id) === String(id)) {
        segmentLabel.textContent = `${Math.round(segment.volume)}%`;
    }

    const video = document.getElementById("editor-video");
    const previewTime = Number(_editor.timelineTime || video?.currentTime || 0);
    _editorApplyTimelineFrame(previewTime, Boolean(_editor.playing));
}
window._editorSetSegmentVolume = _editorSetSegmentVolume;

function _editorSetSelectedSegmentVolume(val) {
    if (_editor.selectedClip.kind !== "segment") return;
    _editorSetSegmentVolume(_editor.selectedClip.track || "video", _editor.selectedClip.id, val);
}
window._editorSetSelectedSegmentVolume = _editorSetSelectedSegmentVolume;

function _editorGetTrackSpeedState(tracks = []) {
    const speeds = [];
    tracks.forEach((track) => {
        _editorGetSegments(track).forEach((segment) => {
            speeds.push(_editorSegmentPlaybackSpeed(segment));
        });
    });

    if (!speeds.length) {
        return { value: 1, mixed: false, count: 0 };
    }

    const first = speeds[0];
    const mixed = speeds.some((speed) => Math.abs(speed - first) > 0.001);
    return {
        value: mixed ? 1 : first,
        mixed,
        count: speeds.length,
    };
}

function _editorApplyTrackSpeedChange(track = "video", nextSpeed = 1) {
    const segments = _editorGetSegments(track);
    if (!segments.length) return false;

    const snapshot = _editorCaptureTrackLayoutSnapshot(track);

    let changed = false;
    segments.forEach((segment) => {
        const currentSpeed = _editorSegmentPlaybackSpeed(segment);
        if (Math.abs(nextSpeed - currentSpeed) < 0.001) return;
        const sourceDuration = _editorEnsureSegmentSourceDuration(segment);
        segment.speed = nextSpeed;
        segment.sourceDuration = sourceDuration;
        segment.end = Number(segment.start || 0) + (sourceDuration / nextSpeed);
        changed = true;
    });

    if (!changed) return false;

    _editorSortSegments(track);
    _editorRippleTrackFromSnapshot(track, snapshot, snapshot[0]?.id || "");
    _editorSortSegments(track);

    if (_editorIsVideoTrack(track)) {
        _editorRecomputeTrimBounds();
        _editorSyncAudioSegmentsWithVideoIfNoExternalAudio();
    }

    return true;
}

function _editorSetSelectedSegmentSpeed(value) {
    const nextSpeed = _editorClampSegmentSpeed(value);

    if (_editor.selectedClip.kind === "track") {
        const targetTracks = _editorGetSelectedSegmentTracks().filter((track) => _editorGetSegments(track).length);
        if (!targetTracks.length) return;

        const needsUpdate = targetTracks.some((track) => _editorGetSegments(track).some((segment) => Math.abs(_editorSegmentPlaybackSpeed(segment) - nextSpeed) > 0.001));
        if (!needsUpdate) return;

        _editorSaveState();
        targetTracks.forEach((track) => {
            _editorApplyTrackSpeedChange(track, nextSpeed);
        });

        if (_editor.playing) {
            _editor.playing = false;
            _editorStopVirtualTimelinePlayback();
            document.getElementById("editor-video")?.pause();
            _editorGetMusicPreviewAudio()?.pause?.();
            _updatePlayIcon();
        }

        const previewTime = Number(_editor.timelineTime || document.getElementById("editor-video")?.currentTime || 0);
        _editorRenderTimeline();
        _editorRenderProps();
        _editorApplyTimelineFrame(previewTime, false);
        _editorRefreshQuickActions();
        _editorScheduleDraftPersist(120);
        return;
    }

    if (_editor.selectedClip.kind !== "segment") return;

    const track = String(_editor.selectedClip.track || "video");
    const segment = _editorFindSegment(track, _editor.selectedClip.id);
    if (!segment) return;

    const currentSpeed = _editorSegmentPlaybackSpeed(segment);
    if (Math.abs(nextSpeed - currentSpeed) < 0.001) return;

    _editorSaveState();
    const snapshot = _editorCaptureTrackLayoutSnapshot(track);
    const sourceDuration = _editorEnsureSegmentSourceDuration(segment);
    segment.speed = nextSpeed;
    segment.sourceDuration = sourceDuration;
    segment.end = Number(segment.start || 0) + (sourceDuration / nextSpeed);

    _editorSortSegments(track);
    _editorRippleTrackFromSnapshot(track, snapshot, segment.id);
    _editorSortSegments(track);

    if (_editorIsVideoTrack(track)) {
        _editorRecomputeTrimBounds();
        _editorSyncAudioSegmentsWithVideoIfNoExternalAudio();
    }

    if (_editor.playing) {
        _editor.playing = false;
        _editorStopVirtualTimelinePlayback();
        document.getElementById("editor-video")?.pause();
        _editorGetMusicPreviewAudio()?.pause?.();
        _updatePlayIcon();
    }

    const previewTime = Number(_editor.timelineTime || document.getElementById("editor-video")?.currentTime || 0);
    _editorRenderTimeline();
    _editorRenderProps();
    _editorApplyTimelineFrame(previewTime, false);
    _editorRefreshQuickActions();
    _editorScheduleDraftPersist(120);
}
window._editorSetSelectedSegmentSpeed = _editorSetSelectedSegmentSpeed;

// ---------- Filter ----------
function _editorSetFilter(name) {
    _editorSaveState();
    _editor.filter = name;
    const video = document.getElementById("editor-video");
    if (video) video.style.filter = _getCSSFilter(name);
    _editorRenderProps();
}
window._editorSetFilter = _editorSetFilter;

// ---------- Sticker actions ----------
function _editorAddSticker(emoji) {
    _editorSaveState();
    const video = document.getElementById("editor-video");
    const t = Number(_editor.timelineTime || video?.currentTime || 0);
    const newSticker = {
        id: _editorGenId(), emoji, x: 50, y: 30, startTime: t, endTime: Math.min(t + 4, _editor.duration), size: 48,
    };
    _editor.stickers.push(newSticker);
    _editor.selectedClip = { kind: "sticker", id: String(newSticker.id) };
    _editorRefreshQuickActions();
    _editorRenderProps();
    _editorRenderTimeline();
}
window._editorAddSticker = _editorAddSticker;

function _editorDeleteSticker(id) {
    _editorSaveState();
    _editor.stickers = _editor.stickers.filter(s => s.id !== id);
    _editorCollapseVisibleTimelineDeadZones();
    if (_editor.selectedClip.kind === "sticker" && _editor.selectedClip.id === String(id)) {
        _editor.selectedClip = { kind: "", id: "" };
    }
    _editorRefreshQuickActions();
    _editorRenderProps();
    _editorRenderTimeline();
}
window._editorDeleteSticker = _editorDeleteSticker;

// ---------- Quality ----------
function _editorSetQuality(val) {
    _editorSaveState();
    _editor.quality = val;
    _editorRenderProps();
}
window._editorSetQuality = _editorSetQuality;

// ---------- Timeline rendering ----------
function _editorTimelineTrackIcon(kind) {
    if (kind === "video") {
        return '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polygon points="23 7 16 12 23 17 23 7"/><rect x="1" y="5" width="15" height="14" rx="2"/></svg>';
    }
    if (kind === "audio") {
        return '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M9 18V5l12-2v13"/><circle cx="6" cy="18" r="3"/><circle cx="18" cy="16" r="3"/></svg>';
    }
    if (kind === "text") {
        return '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M4 7V4h16v3"/><line x1="12" y1="4" x2="12" y2="20"/></svg>';
    }
    if (kind === "subtitle") {
        return '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="2" y="4" width="20" height="16" rx="2"/><path d="M7 12h4"/><path d="M13 12h4"/><path d="M7 16h10"/></svg>';
    }
    if (kind === "media-layer") {
        return '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="3" y="3" width="18" height="18" rx="2"/><path d="M3 9h18"/><path d="M9 21V9"/></svg>';
    }
    return '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><path d="M8 14s1.5 2 4 2 4-2 4-2"/></svg>';
}

function _editorTimelineVolumeIcon(track) {
    const muted = track === "video"
        ? Number(_editor.originalVolume || 0) <= 0
        : Number(_editor.musicVolume || 0) <= 0;

    if (muted) {
        return '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"/><line x1="23" y1="9" x2="17" y2="15"/><line x1="17" y1="9" x2="23" y2="15"/></svg>';
    }
    return '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"/><path d="M15.54 8.46a5 5 0 0 1 0 7.07"/><path d="M19.07 4.93a10 10 0 0 1 0 14.14"/></svg>';
}

function _editorRenderTimeline() {
    const dur = _editorGetTimelineDuration();
    const ruler = document.getElementById("editor-timeline-ruler");
    const tracksWrap = document.getElementById("editor-timeline-tracks");
    const timelineEl = document.getElementById("editor-timeline");
    if (!ruler || !tracksWrap) return;

    const selectedKind = _editor.selectedClip.kind;
    const selectedId = String(_editor.selectedClip.id || "");
    const selectedTrack = _editor.selectedClip.track || "";
    const trackRowSelection = selectedKind === "track" ? _editorGetSelectedSegmentTracks() : [];
    const rows = [];
    const trackW = _editorGetTimelineTrackWidth(dur);
    const leadGutter = _editorGetTimelineLeadGutter();
    const trailingGutter = _editorGetTimelineTrailingGutter();
    const labelWidth = _editorGetTimelineLabelWidth();
    const timelineInnerWidth = Math.max(120, Math.round(labelWidth + leadGutter + trackW + trailingGutter));
    const transitionMarkersByTrack = new Map();

    if (timelineEl) {
        timelineEl.style.setProperty("--editor-timeline-label-width", `${labelWidth}px`);
    }

    if (dur > 0.05) {
        _editorGetTransitionSlots().forEach((slot) => {
            const left = (Math.max(0, Math.min(Number(slot.boundaryTime || 0), dur)) / dur) * 100;
            const applied = _editorGetTransitionByKey(slot.key);
            const transitionLabel = applied ? _editorGetTransitionOption(applied.type).label : "Adicionar transição";
            const selectedClass = selectedKind === "transition" && selectedId === slot.key ? " selected" : "";
            const configuredClass = applied ? " configured" : "";
            const markerHtml = `
                <button
                    class="editor-transition-marker${selectedClass}${configuredClass}"
                    type="button"
                    data-transition-key="${slot.key}"
                    data-track="${slot.track}"
                    style="left:${left}%"
                    title="${esc(`${transitionLabel}: ${_editorTransitionSlotLabel(slot)}`)}"
                    aria-label="${esc(`${transitionLabel}: ${_editorTransitionSlotLabel(slot)}`)}"
                ></button>
            `;
            if (!transitionMarkersByTrack.has(slot.track)) {
                transitionMarkersByTrack.set(slot.track, []);
            }
            transitionMarkersByTrack.get(slot.track).push(markerHtml);
        });
    }

    _editorEnsureSourceWaveform();
    const sourceVideoWaveStyle = _editorGetSourceWaveformInlineStyle("video", dur);
    const sourceAudioWaveStyle = _editorGetSourceWaveformInlineStyle("audio", dur);
    const sourceWaveLoadingClass = _editorSourceWaveformState.loading ? " loading" : "";

    _editorSortSegments("video");
    const baseVideoClipsByTrack = new Map();
    if (!_editor.hideBaseVideoTrack) {
        _editor.videoSegments.forEach((seg, idx) => {
            const segStart = Math.max(0, Math.min(Number(seg.start || 0), dur));
            const segEnd = Math.max(segStart + 0.05, Math.min(Number(seg.end || 0), dur));
            const startPct = (segStart / dur) * 100;
            const widthPct = Math.max(0.5, ((segEnd - segStart) / dur) * 100);
            const trackIndex = _editorGetSegmentTrackIndex(seg);
            const clipTrack = _editorTrackIdForSegmentIndex(trackIndex);
            const trackSelected = trackRowSelection.includes(clipTrack);
            const selectedClass = (selectedKind === "segment" && selectedTrack === clipTrack && selectedId === String(seg.id))
                || trackSelected
                ? " selected"
                : "";
            const reversedClass = _editorSegmentIsReversed(seg) ? " clip-reversed" : "";
            const hasWaveOverlay = Boolean(sourceVideoWaveStyle || _editorSourceWaveformState.loading);
            const waveClass = hasWaveOverlay ? ` with-waveform${sourceWaveLoadingClass}` : "";
            const styleParts = [`left:${startPct}%`, `width:${widthPct}%`];
            if (sourceVideoWaveStyle) {
                styleParts.push(sourceVideoWaveStyle);
            }

            if (!baseVideoClipsByTrack.has(trackIndex)) {
                baseVideoClipsByTrack.set(trackIndex, []);
            }

            baseVideoClipsByTrack.get(trackIndex).push(
                `<div class="editor-track-clip clip-video clip-resizable${waveClass}${selectedClass}${reversedClass}" data-kind="segment" data-track="${clipTrack}" data-id="${seg.id}" style="${styleParts.join(";")}">${_editorBuildTimelineClipContent(`Video ${idx + 1}`, { resizable: true })}</div>`
            );
        });
    }

    const videoLayerClipsByTrack = new Map();
    const audioLayerClipsByTrack = new Map();
    _editor.mediaLayers.forEach((layer, idx) => {
        const normalizedLayer = _editorNormalizeMediaLayer(layer);
        const start = Math.max(0, Math.min(Number(normalizedLayer.startTime || 0), dur));
        const end = Math.max(start + 0.05, Math.min(dur, Number(normalizedLayer.endTime || dur)));
        const left = (start / dur) * 100;
        const width = Math.max(0.5, ((end - start) / dur) * 100);
        const trackIndex = _editorGetLayerTrackIndex(normalizedLayer);
        const layerTrackType = _editorGetMediaLayerTrackType(normalizedLayer);
        const rowTrack = layerTrackType === "audio"
            ? _editorBuildMediaLayerTrackId("audio", trackIndex)
            : _editorTrackIdForSegmentIndex(trackIndex);
        const selectedClass = (selectedKind === "media-layer" && selectedId === String(normalizedLayer.id))
            || (layerTrackType === "video" && trackRowSelection.includes(rowTrack))
            ? " selected"
            : "";
        const reversedClass = normalizedLayer.kind === "video" && normalizedLayer.reversed ? " clip-reversed" : "";
        const labelPrefix = normalizedLayer.kind === "audio"
            ? "Audio"
            : (normalizedLayer.kind === "video" ? "Video" : "Imagem");
        const label = `${labelPrefix} ${idx + 1}`;
        const layerTrack = _editorBuildMediaLayerTrackId(layerTrackType, trackIndex);
        const clipToneClass = normalizedLayer.kind === "audio" ? " clip-audio" : " clip-media";
        const showResizeHandle = normalizedLayer.kind === "video";
        let waveformClass = "";
        const styleParts = [`left:${left}%`, `width:${width}%`];
        if (_editorMediaLayerHasAudio(normalizedLayer)) {
            const waveformState = _editorEnsureMediaLayerWaveform(normalizedLayer) || _editorGetMediaLayerWaveformState(normalizedLayer);
            const waveformStyle = _editorGetMediaLayerWaveformInlineStyle(normalizedLayer);
            if (waveformStyle) {
                styleParts.push(waveformStyle);
            }
            if (waveformStyle || waveformState?.loading) {
                waveformClass = ` with-waveform${waveformState?.loading ? " loading" : ""}`;
            }
        }
        const clipHtml = `<div class="editor-track-clip${clipToneClass}${showResizeHandle ? " clip-resizable" : ""}${waveformClass}${selectedClass}${reversedClass}" data-kind="media-layer" data-track="${layerTrack}" data-id="${normalizedLayer.id}" style="${styleParts.join(";")}">${_editorBuildTimelineClipContent(label, { resizable: showResizeHandle })}</div>`;

        const clipsByTrack = layerTrackType === "audio" ? audioLayerClipsByTrack : videoLayerClipsByTrack;
        if (!clipsByTrack.has(trackIndex)) {
            clipsByTrack.set(trackIndex, []);
        }
        clipsByTrack.get(trackIndex).push(clipHtml);
    });

    const videoTrackIndexes = new Set([0]);
    baseVideoClipsByTrack.forEach((_, trackIndex) => {
        videoTrackIndexes.add(Number(trackIndex) || 0);
    });
    videoLayerClipsByTrack.forEach((_, trackIndex) => {
        videoTrackIndexes.add(Number(trackIndex) || 0);
    });

    [...videoTrackIndexes]
        .sort((a, b) => a - b)
        .forEach((trackIndex) => {
        const rowTrack = _editorTrackIdForSegmentIndex(trackIndex);
        const clipsHtml = `${(baseVideoClipsByTrack.get(trackIndex) || []).join("")}${(videoLayerClipsByTrack.get(trackIndex) || []).join("")}${(transitionMarkersByTrack.get(`layer-video-${trackIndex}`) || []).join("")}`;
        rows.push({
            track: rowTrack,
            kind: "video",
            label: trackIndex === 0 ? "Video" : `Video ${Number(trackIndex) + 1}`,
            contentId: trackIndex === 0 ? "editor-track-video" : undefined,
            clipsHtml,
        });
    });

    const shouldRenderBaseAudioTrack = _editorShouldShowAudioTrack();
    const shouldRenderAnyAudioRows = shouldRenderBaseAudioTrack || audioLayerClipsByTrack.size > 0;
    if (shouldRenderAnyAudioRows) {
        if (shouldRenderBaseAudioTrack) {
            _editorEnsureMusicWaveform();
            _editorSortSegments("audio");
            let audioClips = _editor.audioSegments.map((seg, idx) => {
                const segStart = Math.max(0, Math.min(Number(seg.start || 0), dur));
                const segEnd = Math.max(segStart + 0.05, Math.min(Number(seg.end || 0), dur));
                const startPct = (segStart / dur) * 100;
                const widthPct = Math.max(0.5, ((segEnd - segStart) / dur) * 100);
                const selectedClass = (selectedKind === "segment" && selectedTrack === "audio" && selectedId === String(seg.id))
                    || trackRowSelection.includes("audio")
                    ? " selected"
                    : "";
                const hasWaveOverlay = Boolean(sourceAudioWaveStyle || _editorSourceWaveformState.loading);
                const waveClass = hasWaveOverlay ? ` with-waveform${sourceWaveLoadingClass}` : "";
                const styleParts = [`left:${startPct}%`, `width:${widthPct}%`];
                if (sourceAudioWaveStyle) {
                    styleParts.push(sourceAudioWaveStyle);
                }
                return `<div class="editor-track-clip clip-audio${waveClass}${selectedClass}" data-kind="segment" data-track="audio" data-id="${seg.id}" style="${styleParts.join(";")}">${_editorBuildTimelineClipContent(`Audio ${idx + 1}`)}</div>`;
            }).join("");

            if (_editorShouldRenderAudioMasterClip()) {
                const musicSelected = selectedKind === "music" || trackRowSelection.includes("audio") ? " selected" : "";
                const waveformStyle = _editorGetMusicWaveformInlineStyle(dur);
                const masterClasses = `${musicSelected}${_editorMusicWaveformState.loading ? " loading" : ""}`;
                const audioExtent = Math.max(0.1, Number(_editorGetAudioTrackEndTime() || 0.1));
                const masterWidthPct = Math.max(0.5, Math.min(100, (audioExtent / dur) * 100));
                const masterStyleParts = ["left:0", `width:${masterWidthPct}%`];
                if (waveformStyle) {
                    masterStyleParts.push(waveformStyle);
                }
                audioClips += `<div class="editor-track-clip clip-audio clip-audio-master${masterClasses}" data-kind="music" data-track="audio" data-id="music" style="${masterStyleParts.join(";")}">${_editorBuildTimelineClipContent("Audio")}</div>`;
            }

            rows.push({
                track: "audio",
                kind: "audio",
                contentId: "editor-track-audio",
                label: "Audio",
                clipsHtml: audioClips,
            });
        }

        const audioLayerTrackIndexes = new Set();
        audioLayerClipsByTrack.forEach((_, trackIndex) => {
            audioLayerTrackIndexes.add(Number(trackIndex) || 0);
        });

        [...audioLayerTrackIndexes]
            .sort((a, b) => a - b)
            .forEach((trackIndex) => {
                const rowTrack = _editorBuildMediaLayerTrackId("audio", trackIndex);
                const labelIndex = trackIndex + (shouldRenderBaseAudioTrack ? 2 : 1);
                rows.push({
                    track: rowTrack,
                    kind: "audio",
                    label: !shouldRenderBaseAudioTrack && trackIndex === 0 ? "Audio" : `Audio ${labelIndex}`,
                    clipsHtml: (audioLayerClipsByTrack.get(trackIndex) || []).join(""),
                });
            });
    }

    _editor.texts.forEach((item, idx) => {
        const start = Math.max(0, Math.min(Number(item.startTime || 0), dur));
        const end = Math.max(start + 0.05, Math.min(Number(item.endTime || 0), dur));
        const left = (start / dur) * 100;
        const width = Math.max(0.5, ((end - start) / dur) * 100);
        const selectedClass = selectedKind === "text" && selectedId === String(item.id) ? " selected" : "";
        const clipLabel = esc(String(item.content || "Texto").trim().substring(0, 20));
        rows.push({
            track: `text-${item.id}`,
            kind: "text",
            label: `Texto ${idx + 1}`,
            clipsHtml: `<div class="editor-track-clip clip-text${selectedClass}" data-kind="text" data-track="text-${item.id}" data-id="${item.id}" style="left:${left}%;width:${width}%">${_editorBuildTimelineClipContent(clipLabel)}</div>`,
        });
    });

    if (_editor.subtitles.length) {
        const subtitleClips = _editor.subtitles.map((item) => {
            const start = Math.max(0, Math.min(Number(item.startTime || 0), dur));
            const end = Math.max(start + 0.05, Math.min(Number(item.endTime || 0), dur));
            const left = (start / dur) * 100;
            const width = Math.max(0.5, ((end - start) / dur) * 100);
            const selectedClass = selectedKind === "subtitle" && selectedId === String(item.id) ? " selected" : "";
            const clipLabel = esc(String(item.text || "Legenda").trim().substring(0, 20));
            return `<div class="editor-track-clip clip-text${selectedClass}" data-kind="subtitle" data-track="subtitle" data-id="${item.id}" style="left:${left}%;width:${width}%">${_editorBuildTimelineClipContent(clipLabel)}</div>`;
        }).join("");

        rows.push({
            track: "subtitle",
            kind: "subtitle",
            label: "Legendas",
            clipsHtml: subtitleClips,
        });
    }

    _editor.stickers.forEach((item, idx) => {
        const start = Math.max(0, Math.min(Number(item.startTime || 0), dur));
        const end = Math.max(start + 0.05, Math.min(Number(item.endTime || 0), dur));
        const left = (start / dur) * 100;
        const width = Math.max(0.5, ((end - start) / dur) * 100);
        const selectedClass = selectedKind === "sticker" && selectedId === String(item.id) ? " selected" : "";
        rows.push({
            track: `sticker-${item.id}`,
            kind: "sticker",
            label: `Sticker ${idx + 1}`,
            clipsHtml: `<div class="editor-track-clip clip-sticker${selectedClass}" data-kind="sticker" data-track="sticker-${item.id}" data-id="${item.id}" style="left:${left}%;width:${width}%">${_editorBuildTimelineClipContent(esc(String(item.emoji || "Sticker")))}</div>`,
        });
    });

    tracksWrap.innerHTML = rows.map((row) => {
        return `
            <div class="editor-track" data-track="${row.track}">
                <div class="editor-track-label">
                    ${_editorBuildTrackLabelMarkup(row)}
                </div>
                <div class="editor-track-content"${row.contentId ? ` id="${row.contentId}"` : ""} style="width:${trackW}px;min-width:${trackW}px;${leadGutter ? `margin-left:${leadGutter}px;` : ""}">${row.clipsHtml || ""}</div>
            </div>
        `;
    }).join("");

    _editorRefreshTrackSelectionUI();

    const isMobile = window.innerWidth <= 768;
    const rowHeight = 44;
    const trackCount = Math.max(rows.length, 1);
    const idealHeight = 24 + (trackCount * rowHeight) + 8;
    const minHeight = isMobile ? 116 : 160;
    const maxHeight = isMobile ? 300 : 380;
    const finalHeight = Math.max(minHeight, Math.min(maxHeight, idealHeight));
    if (timelineEl) {
        timelineEl.style.height = `${finalHeight}px`;
        timelineEl.style.overflowY = idealHeight > maxHeight ? "auto" : "hidden";
    }

    ruler.style.minWidth = `${timelineInnerWidth}px`;
    ruler.style.width = `${timelineInnerWidth}px`;
    tracksWrap.style.minWidth = `${timelineInnerWidth}px`;
    tracksWrap.style.width = `${timelineInnerWidth}px`;

    // Ruler marks
    const step = _editorResolveRulerStepSec(dur, trackW);
    const marks = [];
    for (let t = 0; t <= dur + 0.001; t += step) {
        marks.push(Math.min(dur, Number(t.toFixed(3))));
        if (marks.length >= 1200) break;
    }
    if (!marks.length || Math.abs(marks[marks.length - 1] - dur) > 0.08) {
        marks.push(dur);
    }

    let rulerHtml = "";
    const showAllLabels = marks.length <= 16;
    marks.forEach((t, idx) => {
        const pct = (t / dur) * trackW;
        const isLast = idx === marks.length - 1;
        const showLabel = showAllLabels || idx % 2 === 0 || isLast;
        const tickClass = showLabel ? " major" : "";
        if (showLabel) {
            const minuteClass = dur >= 600 && step >= 60 ? " minute" : "";
            rulerHtml += `<span class="editor-ruler-mark${minuteClass}" style="left:${labelWidth + leadGutter + pct}px">${_editorFormatRulerTime(t, dur, step)}</span>`;
        }
        rulerHtml += `<span class="editor-ruler-tick${tickClass}" style="left:${labelWidth + leadGutter + pct}px"></span>`;
    });
    ruler.innerHTML = rulerHtml;

    const totalTimeEl = document.getElementById("editor-time-total");
    if (totalTimeEl) totalTimeEl.textContent = _fmtTime(dur);

    _editorRefreshQuickActions();
    _editorScheduleDraftPersist();
}

function _editorSelectionCanDelete() {
    return ["segment", "text", "subtitle", "sticker", "music", "audio", "media-layer", "transition"].includes(_editor.selectedClip.kind);
}

function _editorCanSwitchLastVideoToAudioOnly() {
    if (Number(_editor.originalVolume || 0) > 0) return true;
    if (_editorShouldShowAudioTrack()) return true;

    return (_editor.mediaLayers || []).some((layer) => {
        const normalizedLayer = _editorNormalizeMediaLayer(layer);
        if (normalizedLayer.kind === "audio") return true;
        return normalizedLayer.kind === "video" && Boolean(normalizedLayer.audioOnly || normalizedLayer.hasAudio);
    });
}

function _editorSelectionCanDuplicate() {
    return ["text", "subtitle", "sticker"].includes(_editor.selectedClip.kind);
}

function _editorSelectionCanCopy() {
    return ["segment", "text", "subtitle", "sticker", "music", "media-layer", "track"].includes(_editor.selectedClip.kind);
}

function _editorSelectionCanCut() {
    if (_editor.selectedClip.kind === "track") {
        return String(_editor.selectedClip.track || "") === "audio";
    }
    return ["segment", "text", "subtitle", "sticker", "music", "media-layer"].includes(_editor.selectedClip.kind);
}

function _editorClipboardHasItems() {
    return Array.isArray(_editorClipboard.items) && _editorClipboard.items.length > 0;
}

function _editorGetClipboardAudioMeta() {
    if (!_editorShouldShowAudioTrack() || !_editor.musicUrl) return null;
    return {
        musicUrl: String(_editor.musicUrl || ""),
        musicFile: _editor._musicFile || null,
        musicServerPath: String(_editor._musicServerPath || ""),
        musicSource: String(_editor._musicSource || "audio"),
    };
}

function _editorGetPrimaryAudioSegment() {
    if (!Array.isArray(_editor.audioSegments) || !_editor.audioSegments.length) return null;
    return [..._editor.audioSegments]
        .sort((left, right) => Number(left?.start || 0) - Number(right?.start || 0))[0] || null;
}

function _editorShouldRenderAudioMasterClip() {
    if (!_editorShouldShowAudioTrack() || !_editor.musicUrl) return false;

    const segments = Array.isArray(_editor.audioSegments) ? _editor.audioSegments : [];
    if (segments.length !== 1) return false;

    const segment = segments[0];
    if (!segment) return false;
    if (_editorSegmentIsReversed(segment)) return false;
    if (Math.abs(_editorSegmentPlaybackSpeed(segment) - 1) > 0.001) return false;
    if (Math.abs(Number(segment.start || 0)) > 0.05) return false;
    if (Math.abs(_editorSegSourceStart(segment)) > 0.05) return false;

    const knownSourceDuration = Math.max(
        0,
        Number(_editorMusicWaveformState.duration || 0),
        Number(_editorGetMusicPreviewAudio()?.duration || 0),
    );
    if (knownSourceDuration > 0.05 && _editorSegSourceDuration(segment) < knownSourceDuration - 0.05) {
        return false;
    }

    return true;
}

function _editorSplitSegmentAtTime(track = "video", timelineTime = 0, preferredId = "") {
    const targetTrack = _editorIsAudioTrack(track)
        ? "audio"
        : (_editorIsVideoTrack(track) ? String(track || "video") : "video");
    const segments = _editorGetSegments(targetTrack);
    const safeTime = Math.max(0, Number(timelineTime || 0));
    const canSplitRange = (start, end) => safeTime > Number(start || 0) + 0.08 && safeTime < Number(end || 0) - 0.08;

    let seg = preferredId
        ? segments.find((item) => String(item.id) === String(preferredId))
        : null;
    if (!seg || !canSplitRange(seg.start, seg.end)) {
        seg = segments.find((item) => canSplitRange(item.start, item.end));
    }
    if (!seg) return null;

    const origSrc = _editorSegSourceStart(seg);
    const origSourceDuration = _editorSegSourceDuration(seg);
    const origSourceEnd = origSrc + origSourceDuration;
    const reversedFlag = _editorSegmentIsReversed(seg);
    const speed = _editorSegmentPlaybackSpeed(seg);
    const splitRatio = Math.max(0, Math.min(1, (safeTime - Number(seg.start || 0)) / Math.max(0.0001, _editorSegTimelineDuration(seg))));
    const firstSourceDuration = Math.max(0.05, origSourceDuration * splitRatio);
    const secondSourceDuration = Math.max(0.05, origSourceDuration - firstSourceDuration);
    const firstSourceStart = reversedFlag
        ? Math.max(origSrc, origSourceEnd - firstSourceDuration)
        : origSrc;
    const secondSourceStart = reversedFlag
        ? origSrc
        : origSrc + firstSourceDuration;
    const segmentVolume = _editorSegmentVolumePercent(seg);
    const first = { id: _editorGenId(), start: seg.start, end: safeTime, sourceStart: firstSourceStart, sourceDuration: firstSourceDuration, speed, reversed: reversedFlag, volume: segmentVolume };
    const second = { id: _editorGenId(), start: safeTime, end: seg.end, sourceStart: secondSourceStart, sourceDuration: secondSourceDuration, speed, reversed: reversedFlag, volume: segmentVolume };
    const nextSegments = segments
        .filter((item) => item !== seg)
        .concat([first, second]);
    _editorSetSegments(targetTrack, nextSegments);
    _editorSortSegments(targetTrack);
    return { first, second };
}

function _editorShiftTrackSegmentsFrom(track = "video", threshold = 0, delta = 0) {
    const safeDelta = Number(delta || 0);
    if (Math.abs(safeDelta) <= 0.0001) return;

    _editorGetSegments(track).forEach((segment) => {
        const start = Number(segment?.start || 0);
        if (start < Number(threshold || 0) - 0.0001) return;
        segment.start = start + safeDelta;
        segment.end = Number(segment.end || 0) + safeDelta;
    });
}

function _editorResolveClipboardPasteTrack() {
    const selectedTrack = String(_editor.selectedClip.track || "");
    const sourceTrack = String(_editorClipboard.sourceTrack || "video");
    if (_editorIsAudioTrack(selectedTrack) && _editorIsAudioTrack(sourceTrack)) {
        return "audio";
    }
    if (_editorIsVideoTrack(selectedTrack) && _editorIsVideoTrack(sourceTrack)) {
        return selectedTrack || sourceTrack || "video";
    }
    return sourceTrack;
}

function _editorRestoreClipboardAudioSource() {
    const meta = _editorClipboard.audioMeta;
    if (!meta?.musicUrl) return false;

    _editor.musicUrl = String(meta.musicUrl || "");
    _editor._musicFile = meta.musicFile || null;
    _editor._musicServerPath = String(meta.musicServerPath || "");
    _editor._musicSource = String(meta.musicSource || "audio");
    _editorSetMusicPreviewSource(_editor.musicUrl || "");
    return true;
}

function _editorBuildClipboardItemsFromSelection() {
    const selection = _editor.selectedClip || {};
    const selectionKind = String(selection.kind || "");
    const selectionTrack = String(selection.track || "video");

    if (selectionKind === "segment") {
        const segment = _editorFindSegment(selectionTrack, selection.id);
        if (!segment) return [];
        return [{
            kind: "segment",
            track: selectionTrack,
            relativeStart: 0,
            timelineDuration: _editorSegTimelineDuration(segment),
            sourceStart: _editorSegSourceStart(segment),
            sourceDuration: _editorSegSourceDuration(segment),
            speed: _editorSegmentPlaybackSpeed(segment),
            reversed: _editorSegmentIsReversed(segment),
            volume: _editorSegmentVolumePercent(segment),
        }];
    }

    if (selectionKind === "music" || selectionKind === "track") {
        const track = selectionKind === "music" ? "audio" : selectionTrack;
        const segments = [..._editorGetSegments(track)].sort((left, right) => Number(left.start || 0) - Number(right.start || 0));
        if (!segments.length) return [];
        const baseStart = Number(segments[0].start || 0);
        return segments.map((segment) => ({
            kind: "segment",
            track,
            relativeStart: Math.max(0, Number(segment.start || 0) - baseStart),
            timelineDuration: _editorSegTimelineDuration(segment),
            sourceStart: _editorSegSourceStart(segment),
            sourceDuration: _editorSegSourceDuration(segment),
            speed: _editorSegmentPlaybackSpeed(segment),
            reversed: _editorSegmentIsReversed(segment),
            volume: _editorSegmentVolumePercent(segment),
        }));
    }

    const cloneTimedItem = (kind, item) => {
        if (!item) return [];
        return [{
            kind,
            relativeStart: 0,
            timelineDuration: Math.max(0.1, Number(item.endTime || 0) - Number(item.startTime || 0)),
            payload: { ...item },
        }];
    };

    if (selectionKind === "text") {
        return cloneTimedItem("text", _editor.texts.find((item) => String(item.id) === String(selection.id)));
    }
    if (selectionKind === "subtitle") {
        return cloneTimedItem("subtitle", _editor.subtitles.find((item) => String(item.id) === String(selection.id)));
    }
    if (selectionKind === "sticker") {
        return cloneTimedItem("sticker", _editor.stickers.find((item) => String(item.id) === String(selection.id)));
    }
    if (selectionKind === "media-layer") {
        const layer = _editorGetMediaLayerById(selection.id);
        if (!layer) return [];
        return [{
            kind: "media-layer",
            relativeStart: 0,
            timelineDuration: Math.max(0.1, Number(layer.endTime || 0) - Number(layer.startTime || 0)),
            payload: { ...layer },
        }];
    }

    return [];
}

function _editorGetReversibleSelection() {
    const selected = _editor.selectedClip || {};
    if (selected.kind === "segment" && _editorIsVideoTrack(selected.track || "video")) {
        return { type: "segment", target: _editorFindVideoSegment(selected.id) };
    }
    if (selected.kind === "media-layer") {
        const layer = _editorGetMediaLayerById(selected.id);
        if (layer && layer.kind === "video") {
            return { type: "media-layer", target: layer };
        }
    }
    return null;
}

function _editorToggleReverseSelection() {
    const selection = _editorGetReversibleSelection();
    if (!selection?.target) return;

    _editorSaveState();
    if (selection.type === "segment") {
        selection.target.reversed = !_editorSegmentIsReversed(selection.target);
        _editorSyncAudioSegmentsWithVideoIfNoExternalAudio();
    } else {
        selection.target.reversed = !Boolean(selection.target.reversed);
    }

    if (_editor.playing) {
        _editor.playing = false;
        _editorStopVirtualTimelinePlayback();
        document.getElementById("editor-video")?.pause();
        _updatePlayIcon();
    }

    const previewTime = Number(_editor.timelineTime || 0);
    _editorApplyTimelineFrame(previewTime, false);
    _editorRefreshQuickActions();
    _editorRenderTimeline();
}
window._editorToggleReverseSelection = _editorToggleReverseSelection;

function _editorGetLayerOrderCount() {
    if (Array.isArray(_editor.mediaLayers) && _editor.mediaLayers.length) {
        return _editor.mediaLayers.length;
    }
    const host = document.getElementById("editor-media-layer-host");
    if (!host) return 0;
    const layeredEls = host.querySelectorAll("[data-layer-id], .editor-media-layer-item, .editor-media-layer");
    if (layeredEls.length) return layeredEls.length;
    return host.children.length;
}

function _editorCycleMediaLayerOrder() {
    const host = document.getElementById("editor-media-layer-host");
    const stateLayers = Array.isArray(_editor.mediaLayers) ? _editor.mediaLayers : [];
    const domLayers = host
        ? Array.from(host.querySelectorAll("[data-layer-id], .editor-media-layer-item, .editor-media-layer"))
        : [];
    const domCount = domLayers.length || (host ? host.children.length : 0);
    const hasStateLayers = stateLayers.length >= 2;
    const hasDomLayers = domCount >= 2;

    if (!hasStateLayers && !hasDomLayers) {
        showToast("Adicione pelo menos 2 camadas para alternar a ordem.", "info");
        _editorRefreshQuickActions();
        return;
    }

    _editorSaveState();

    if (hasStateLayers) {
        const first = stateLayers.shift();
        stateLayers.push(first);
    }

    if (hasDomLayers && host) {
        const firstDom = domLayers.length ? domLayers[0] : host.children[0];
        if (firstDom) host.appendChild(firstDom);
    }

    if (typeof _editorRenderMediaLayers === "function") {
        _editorRenderMediaLayers();
    }
    if (typeof _editorDrawOverlays === "function") {
        const video = document.getElementById("editor-video");
        _editorDrawOverlays(video ? Number(video.currentTime || 0) : 0);
    }

    _editorRenderTimeline();
    _editorRefreshQuickActions();
    showToast("Ordem das camadas alternada.", "success");
}
window._editorCycleMediaLayerOrder = _editorCycleMediaLayerOrder;

function _editorRefreshQuickActions() {
    const delBtn = document.getElementById("editor-quick-delete");
    const copyBtn = document.getElementById("editor-quick-duplicate");
    const pasteBtn = document.getElementById("editor-quick-paste");
    const cutBtn = document.getElementById("editor-quick-cut");
    const reverseBtn = document.getElementById("editor-quick-reverse");
    const layerOrderBtn = document.getElementById("editor-quick-layer-order");
    const zoomOutBtn = document.getElementById("editor-quick-zoom-out");
    const zoomInBtn = document.getElementById("editor-quick-zoom-in");
    const speedBtn = document.getElementById("editor-quick-speed");
    if (delBtn) delBtn.disabled = !_editorSelectionCanDelete();
    if (copyBtn) copyBtn.disabled = !_editorSelectionCanCopy();
    if (pasteBtn) pasteBtn.disabled = !_editorClipboardHasItems();
    if (cutBtn) cutBtn.disabled = !_editor.duration || !_editorGetSelectedSegmentTracks().length;
    if (reverseBtn) {
        const selection = _editorGetReversibleSelection();
        const isActive = Boolean(selection?.target && (selection.type === "segment"
            ? _editorSegmentIsReversed(selection.target)
            : selection.target.reversed));
        reverseBtn.disabled = !selection?.target;
        reverseBtn.classList.toggle("active", isActive);
        reverseBtn.setAttribute("aria-pressed", isActive ? "true" : "false");
        reverseBtn.title = isActive ? "Desinverter vídeo selecionado" : "Inverter vídeo selecionado";
    }
    if (layerOrderBtn) layerOrderBtn.disabled = _editorGetLayerOrderCount() < 2;
    if (zoomOutBtn) zoomOutBtn.disabled = Number(_editor.timelineZoom || 1) <= _EDITOR_TIMELINE_MIN_ZOOM + 0.0001;
    if (zoomInBtn) zoomInBtn.disabled = Number(_editor.timelineZoom || 1) >= _EDITOR_TIMELINE_MAX_ZOOM - 0.0001;
    if (speedBtn) {
        const rateLabel = _editorFormatRateLabel(_editor.playbackRate || 1);
        speedBtn.title = `Velocidade de reprodução (${rateLabel})`;
        speedBtn.setAttribute("aria-label", `Velocidade de reprodução ${rateLabel}`);
        speedBtn.setAttribute("data-rate-label", rateLabel);
    }

    _editorApplyMobileControlMode();
}

function _editorSelectTimelineClip(kind, id, renderProps = true, track = "") {
    const normalizedId = String(id ?? "");
    const normalizedTrack = String(track || "");
    let shouldOpenSubtitleModal = false;
    _editor.selectedClip = { kind: kind || "", id: normalizedId, track: normalizedTrack };
    if (kind === "media-layer") {
        const layer = _editorGetMediaLayerById(normalizedId);
        const layerTrack = normalizedTrack || _editorBuildMediaLayerTrackId(
            _editorGetMediaLayerTrackType(layer),
            _editorGetLayerTrackIndex(layer),
        );
        _editor.selectedClip.track = layerTrack;
        _editor.selectedInsertTrack = _editorResolveInsertTrackForUi(layerTrack);
    } else if (kind === "music") {
        _editor.selectedTracks = ["audio"];
        _editor.selectedClip.track = "audio";
        _editor.selectedInsertTrack = "audio";
    } else if (kind === "segment") {
        _editor.selectedTracks = [normalizedTrack || "video"];
        _editor.selectedInsertTrack = _editorResolveInsertTrackForUi(normalizedTrack || "video");
    } else if (normalizedTrack) {
        _editor.selectedInsertTrack = normalizedTrack;
    }

    let switchedTool = false;
    if (kind === "segment") {
        if (renderProps && _editor.activeTool !== "trim") {
            _editorSelectTool("trim");
            switchedTool = true;
        }
    } else if (kind === "text") {
        _editor.texts.forEach(t => t._selected = String(t.id) === normalizedId);
        _editor.subtitles.forEach(s => s._selected = false);
        if (renderProps && _editor.activeTool !== "text") {
            _editorSelectTool("text");
            switchedTool = true;
        }
    } else if (kind === "subtitle") {
        _editor.subtitles.forEach(s => s._selected = String(s.id) === normalizedId);
        _editor.texts.forEach(t => t._selected = false);
        shouldOpenSubtitleModal = Boolean(renderProps);
        if (renderProps && _editor.activeTool !== "subtitles") {
            _editorSelectTool("subtitles");
            switchedTool = true;
        }
    } else if (kind === "media-layer") {
        if (renderProps && _editor.activeTool !== "layers") {
            _editorSelectTool("layers");
            switchedTool = true;
        }
        _editorRenderMediaLayers();
    } else if (kind === "transition") {
        if (renderProps && _editor.activeTool !== "transitions") {
            _editorSelectTool("transitions");
            switchedTool = true;
        }
    } else if (kind === "sticker" && renderProps && _editor.activeTool !== "stickers") {
        _editorSelectTool("stickers");
        switchedTool = true;
    }

    if (renderProps && !switchedTool) {
        _editorRenderProps();
    }

    _editorRenderTimeline();

    if (shouldOpenSubtitleModal) {
        _editorOpenSubtitleTextModal(normalizedId);
    }
}

function _editorDeleteSelectedClip() {
    if (!_editor.selectedClip.kind) return;
    if (!_editorSelectionCanDelete()) {
        showToast("Selecione um trecho, texto, legenda, sticker, transição ou áudio/música para excluir.", "error");
        return;
    }

    const selKind = _editor.selectedClip.kind;
    const selId = _editor.selectedClip.id;
    const selTrack = _editor.selectedClip.track || "video";
    const removedTimelineWindows = [];
    const pushRemovedTimelineWindow = (start, end) => {
        const safeStart = Math.max(0, Number(start || 0));
        const safeEnd = Math.max(safeStart, Number(end || 0));
        if (safeEnd - safeStart >= 0.02) {
            removedTimelineWindows.push([safeStart, safeEnd]);
        }
    };
    if (selKind === "segment") {
        const trackSegments = _editorGetSegments(selTrack);
        const segmentCount = _editorIsAudioTrack(selTrack) ? trackSegments.length : _editor.videoSegments.length;
        if (segmentCount <= 1) {
            if (_editorIsAudioTrack(selTrack) && _editorShouldShowAudioTrack()) {
                _editorSaveState();
                _editorClearExternalAudioTrack();
                if (_editor.hideBaseVideoTrack) {
                    _editorCollapseHiddenBaseTimelineGaps();
                }
                _editor.selectedClip = { kind: "", id: "", track: "" };
                _editorRenderProps();
                _editorRenderTimeline();
                _editorRenderMediaLayers();
                const currentVideo = document.getElementById("editor-video");
                _editorApplyTimelineFrame(Number(_editor.timelineTime || currentVideo?.currentTime || 0), false);
                showToast("Áudio removido.", "success");
                return;
            }
            if (_editorIsVideoTrack(selTrack) && _editorCanSwitchLastVideoToAudioOnly()) {
                _editorSaveState();
                _editor.hideBaseVideoTrack = true;
                _editorCollapseHiddenBaseTimelineGaps();
                _editor.selectedClip = { kind: "", id: "", track: "" };
                _editorRenderProps();
                _editorRenderTimeline();
                _editorRenderMediaLayers();
                const currentVideo = document.getElementById("editor-video");
                _editorApplyTimelineFrame(Number(_editor.timelineTime || currentVideo?.currentTime || 0), false);
                showToast("Vídeo removido. O editor vai manter apenas o áudio com fundo preto.", "success");
                return;
            }
            const trackLabel = selTrack === "audio" ? "audio" : "video";
            showToast(`Não é possível remover o último trecho do ${trackLabel}.`, "error");
            return;
        }
    }

    _editorSaveState();

    if (selKind === "segment") {
        const removedSegment = _editorFindSegment(selTrack, selId);
        if (removedSegment && _editorIsVideoTrack(selTrack)) {
            pushRemovedTimelineWindow(removedSegment.start, removedSegment.end);
        }
        const next = _editorGetSegments(selTrack).filter(seg => String(seg.id) !== selId);
        _editorSetSegments(selTrack, next);
        _editorSortSegments(selTrack);
        _editorRippleCloseGaps(selTrack);
        if (_editorIsVideoTrack(selTrack)) {
            _editorRippleCloseGaps("audio");
            _editorRecomputeTrimBounds();
            _editorSyncAudioSegmentsWithVideoIfNoExternalAudio();
        }
    } else if (selKind === "text") {
        _editor.texts = _editor.texts.filter(t => String(t.id) !== selId);
    } else if (selKind === "subtitle") {
        _editor.subtitles = _editor.subtitles.filter(s => String(s.id) !== selId);
    } else if (selKind === "sticker") {
        _editor.stickers = _editor.stickers.filter(s => String(s.id) !== selId);
    } else if (selKind === "media-layer") {
        const removedLayer = _editorGetMediaLayerById(selId);
        const normalizedRemovedLayer = removedLayer ? _editorNormalizeMediaLayer(removedLayer) : null;
        if (normalizedRemovedLayer && String(normalizedRemovedLayer.layoutMode || "") === "track-sequence") {
            pushRemovedTimelineWindow(normalizedRemovedLayer.startTime, normalizedRemovedLayer.endTime);
        }
        _editor.mediaLayers = _editor.mediaLayers.filter(layer => String(layer.id) !== selId);
        _editor.transitions = (_editor.transitions || []).filter((transition) => String(transition?.fromId || "") !== selId && String(transition?.toId || "") !== selId);
    } else if (selKind === "transition") {
        _editor.transitions = (_editor.transitions || []).filter((transition) => String(transition?.key || "") !== selId);
    } else if (selKind === "music") {
        _editorClearExternalAudioTrack();
    } else if (selKind === "audio") {
        _editorSetOriginalVolume(0);
        showToast("Áudio original silenciado.", "success");
    }

    if (_editor.hideBaseVideoTrack) {
        _editorCollapseHiddenBaseTimelineGaps();
    } else if (removedTimelineWindows.length) {
        _editorCollapseTimelineItemsByGaps(removedTimelineWindows);
    }

    _editorCollapseVisibleTimelineDeadZones();

    _editor.timelineTime = Math.max(0, Math.min(Number(_editor.timelineTime || 0), _editorGetTimelineDuration()));

    _editor.selectedClip = { kind: "", id: "", track: "" };
    _editorRenderProps();
    _editorRenderTimeline();
    _editorRenderMediaLayers();
    const video = document.getElementById("editor-video");
    _editorApplyTimelineFrame(Number(_editor.timelineTime || video?.currentTime || 0), false);
}
window._editorDeleteSelectedClip = _editorDeleteSelectedClip;

function _editorCopySelectedClip(options = {}) {
    if (!_editorSelectionCanCopy()) return false;

    const items = _editorBuildClipboardItemsFromSelection();
    if (!items.length) {
        if (!options.silent) {
            showToast("Selecione um trecho ou item da timeline para copiar.", "error");
        }
        return false;
    }

    const sourceTrack = String(items[0]?.track || _editor.selectedClip.track || "");
    _editorClipboard = {
        items,
        sourceTrack,
        audioMeta: sourceTrack === "audio" ? _editorGetClipboardAudioMeta() : null,
    };
    _editorRefreshQuickActions();

    if (!options.silent) {
        const itemCount = items.length;
        showToast(itemCount > 1 ? `${itemCount} trechos copiados.` : "Trecho copiado.", "success");
    }
    return true;
}
window._editorCopySelectedClip = _editorCopySelectedClip;

function _editorPasteClipboard() {
    if (!_editorClipboardHasItems()) return false;

    const video = document.getElementById("editor-video");
    const pasteTime = Math.max(0, Number(_editor.timelineTime || video?.currentTime || 0));
    const items = [..._editorClipboard.items];
    if (!items.length) return false;

    _editorSaveState();

    let changed = false;
    let pastedSelection = { kind: "", id: "", track: "" };
    let shouldRenderLayers = false;

    if (items.every((item) => item.kind === "segment")) {
        const track = _editorResolveClipboardPasteTrack();
        if (_editorIsAudioTrack(track)) {
            _editorRestoreClipboardAudioSource();
        }

        const sortedItems = items
            .map((item) => ({ ...item, relativeStart: Math.max(0, Number(item.relativeStart || 0)) }))
            .sort((left, right) => left.relativeStart - right.relativeStart);
        const totalSpan = sortedItems.reduce((maxSpan, item) => {
            return Math.max(maxSpan, Number(item.relativeStart || 0) + Math.max(0.1, Number(item.timelineDuration || 0.1)));
        }, 0);

        _editorSplitSegmentAtTime(track, pasteTime);
        _editorShiftTrackSegmentsFrom(track, pasteTime, totalSpan);

        const insertedSegments = sortedItems.map((item) => {
            const start = pasteTime + Number(item.relativeStart || 0);
            const timelineDuration = Math.max(0.1, Number(item.timelineDuration || 0.1));
            return {
                id: _editorGenId(),
                start,
                end: start + timelineDuration,
                sourceStart: Number(item.sourceStart || 0),
                sourceDuration: Math.max(0.05, Number(item.sourceDuration || timelineDuration)),
                speed: _editorClampSegmentSpeed(item.speed),
                reversed: Boolean(item.reversed),
                volume: _editorClampSegmentVolume(item.volume, 100),
            };
        });

        _editorSetSegments(track, _editorGetSegments(track).concat(insertedSegments));
        _editorSortSegments(track);
        if (_editorIsVideoTrack(track)) {
            _editorRecomputeTrimBounds();
            _editorSyncAudioSegmentsWithVideoIfNoExternalAudio();
        }

        changed = insertedSegments.length > 0;
        _editor.selectedTracks = [track];
        _editor.selectedInsertTrack = track;
        pastedSelection = insertedSegments.length === 1
            ? { kind: "segment", id: String(insertedSegments[0].id), track }
            : { kind: "track", id: track, track };
    } else {
        const appendTimedItem = (kind, collection) => {
            const pasted = [];
            items.filter((item) => item.kind === kind).forEach((item) => {
                const payload = { ...(item.payload || {}) };
                const startTime = pasteTime + Math.max(0, Number(item.relativeStart || 0));
                const span = Math.max(0.1, Number(item.timelineDuration || 0.1));
                payload.id = _editorGenId();
                payload.startTime = startTime;
                payload.endTime = startTime + span;
                if (kind === "text" || kind === "subtitle") {
                    payload._selected = true;
                }
                collection.push(payload);
                pasted.push(payload);
            });
            return pasted;
        };

        const pastedTexts = appendTimedItem("text", _editor.texts);
        const pastedSubtitles = appendTimedItem("subtitle", _editor.subtitles);
        const pastedStickers = appendTimedItem("sticker", _editor.stickers);
        const pastedLayers = appendTimedItem("media-layer", _editor.mediaLayers);

        _editor.texts.forEach((item) => {
            if (!pastedTexts.some((pasted) => String(pasted.id) === String(item.id))) item._selected = false;
        });
        _editor.subtitles.forEach((item) => {
            if (!pastedSubtitles.some((pasted) => String(pasted.id) === String(item.id))) item._selected = false;
        });

        shouldRenderLayers = pastedLayers.length > 0;
        const pastedFirst = pastedTexts[0] || pastedSubtitles[0] || pastedStickers[0] || pastedLayers[0] || null;
        if (pastedFirst) {
            changed = true;
            pastedSelection = pastedFirst.startTime != null
                ? {
                    kind: pastedLayers.includes(pastedFirst)
                        ? "media-layer"
                        : pastedStickers.includes(pastedFirst)
                            ? "sticker"
                            : pastedSubtitles.includes(pastedFirst)
                                ? "subtitle"
                                : "text",
                    id: String(pastedFirst.id),
                    track: pastedLayers.includes(pastedFirst)
                        ? _editorBuildMediaLayerTrackId(_editorGetMediaLayerTrackType(pastedFirst), _editorGetLayerTrackIndex(pastedFirst))
                        : "",
                }
                : pastedSelection;
        }
    }

    if (!changed) {
        return false;
    }

    _editor.selectedClip = pastedSelection;
    _editorRenderTimeline();
    if (shouldRenderLayers) {
        _editorRenderMediaLayers();
    }
    _editorRenderProps();
    _editorApplyTimelineFrame(Number(_editor.timelineTime || video?.currentTime || 0), false);
    _editorRefreshQuickActions();
    _editorScheduleDraftPersist(100);
    showToast("Conteúdo colado na timeline.", "success");
    return true;
}
window._editorPasteClipboard = _editorPasteClipboard;

function _editorCutSelectedClip() {
    if (!_editorSelectionCanCut()) return false;
    if (!_editorCopySelectedClip({ silent: true })) return false;

    if (_editor.selectedClip.kind === "track" && String(_editor.selectedClip.track || "") === "audio") {
        _editorSaveState();
        _editorClearExternalAudioTrack();
        _editor.selectedClip = { kind: "", id: "", track: "" };
        _editor.selectedTracks = ["video"];
        _editor.selectedInsertTrack = "video";
        _editorRenderProps();
        _editorRenderTimeline();
        _editorRefreshQuickActions();
        showToast("Faixa de áudio recortada.", "success");
        return true;
    }

    _editorDeleteSelectedClip();
    return true;
}
window._editorCutSelectedClip = _editorCutSelectedClip;

function _editorDuplicateSelectedClip() {
    if (!_editorSelectionCanDuplicate()) return;

    const selKind = _editor.selectedClip.kind;
    const selId = _editor.selectedClip.id;
    const shift = 0.35;
    _editorSaveState();

    const cloneTimed = (item) => {
        const span = Math.max(0.1, (item.endTime || 0) - (item.startTime || 0));
        const maxStart = Math.max(0, (_editor.duration || span) - span);
        const startTime = Math.max(0, Math.min(maxStart, (item.startTime || 0) + shift));
        return { ...item, id: _editorGenId(), startTime, endTime: startTime + span };
    };

    if (selKind === "text") {
        const source = _editor.texts.find(t => String(t.id) === selId);
        if (!source) return;
        _editor.texts.forEach(t => t._selected = false);
        const copy = cloneTimed(source);
        copy._selected = true;
        _editor.texts.push(copy);
        _editor.selectedClip = { kind: "text", id: String(copy.id) };
    } else if (selKind === "subtitle") {
        const source = _editor.subtitles.find(s => String(s.id) === selId);
        if (!source) return;
        _editor.subtitles.forEach(s => s._selected = false);
        const copy = cloneTimed(source);
        copy._selected = true;
        _editor.subtitles.push(copy);
        _editor.selectedClip = { kind: "subtitle", id: String(copy.id) };
    } else if (selKind === "sticker") {
        const source = _editor.stickers.find(s => String(s.id) === selId);
        if (!source) return;
        const copy = cloneTimed(source);
        _editor.stickers.push(copy);
        _editor.selectedClip = { kind: "sticker", id: String(copy.id) };
    }

    _editorRenderProps();
    _editorRenderTimeline();
}
window._editorDuplicateSelectedClip = _editorDuplicateSelectedClip;

function _editorTimelineCanDrag(kind) {
    return ["segment", "music", "text", "subtitle", "sticker", "media-layer"].includes(kind);
}

function _editorTimelineCanResize(kind, track = "") {
    if (kind === "music") {
        return true;
    }
    if (kind === "segment") {
        return _editorIsVideoTrack(track) || _editorIsAudioTrack(track);
    }
    return ["text", "subtitle", "media-layer"].includes(kind);
}

function _editorBuildTimelineClipContent(label, options = {}) {
    const safeLabel = String(label || "");
    if (!options?.resizable) {
        return `<span class="editor-track-clip-label">${safeLabel}</span>`;
    }

    return `
        <span class="editor-track-clip-handle start" data-resize-edge="start" aria-hidden="true"></span>
        <span class="editor-track-clip-label">${safeLabel}</span>
        <span class="editor-track-clip-handle end" data-resize-edge="end" aria-hidden="true"></span>
    `;
}

function _editorGetTimelineRange(kind, id, track = "") {
    if (kind === "segment") {
        const item = _editorFindSegment(track || "video", id);
        return item ? { start: item.start, end: item.end } : null;
    }
    if (kind === "music") {
        const item = _editorGetPrimaryAudioSegment();
        return item ? { start: item.start, end: item.end } : null;
    }
    if (kind === "text") {
        const item = _editor.texts.find(t => String(t.id) === String(id));
        return item ? { start: item.startTime, end: item.endTime } : null;
    }
    if (kind === "subtitle") {
        const item = _editor.subtitles.find(s => String(s.id) === String(id));
        return item ? { start: item.startTime, end: item.endTime } : null;
    }
    if (kind === "sticker") {
        const item = _editor.stickers.find(s => String(s.id) === String(id));
        return item ? { start: item.startTime, end: item.endTime } : null;
    }
    if (kind === "media-layer") {
        const item = _editorGetMediaLayerById(id);
        return item ? { start: item.startTime, end: item.endTime } : null;
    }
    return null;
}

function _editorApplyDraggedRange(kind, id, start, end, track = "", options = {}) {
    if (kind === "segment" || kind === "music") {
        const targetTrack = kind === "music"
            ? "audio"
            : (_editorIsAudioTrack(track)
                ? "audio"
                : (_editorIsVideoTrack(track) ? String(track || "video") : "video"));
        const item = kind === "music"
            ? _editorGetPrimaryAudioSegment()
            : _editorFindSegment(targetTrack, id);
        if (!item) return;
        _editorEnsureSegmentSourceStart(item);
        _editorEnsureSegmentSourceDuration(item);

        if (_editorIsVideoTrack(targetTrack)) {
            item.trackIndex = _editorParseSegmentTrackId(targetTrack, _editorGetSegmentTrackIndex(item));
        }

        const dragMode = String(options.mode || "move");
        if (_editorIsVideoTrack(targetTrack) && (dragMode === "resize-start" || dragMode === "resize-end")) {
            const [clampedStart, clampedEnd] = _editorClampSegmentResizeBounds(targetTrack, id, start, end, dragMode);
            _editorApplySegmentSpeedResize(item, clampedStart, clampedEnd, dragMode);
        } else {
            const span = Math.max(0.1, end - start);
            const [clampedStart, clampedEnd] = _editorClampSegmentRange(targetTrack, item.id, start, span);
            _editorApplySegmentTimelineBounds(item, clampedStart, clampedEnd);
        }

        if (kind === "music") {
            _editor.selectedClip = { kind: "segment", id: String(item.id), track: "audio" };
            _editor.selectedTracks = ["audio"];
            _editor.selectedInsertTrack = "audio";
        }

        if (_editorIsVideoTrack(targetTrack)) {
            _editorRecomputeTrimBounds();
            _editorSyncAudioSegmentsWithVideoIfNoExternalAudio();
        }
        return;
    }

    const duration = kind === "media-layer"
        ? Math.max(_editorGetTimelineDuration(), Number(end || 0), Number(start || 0) + 0.1)
        : Math.max(_editor.duration || 0.1, 0.1);
    const safeStart = Math.max(0, Math.min(duration - 0.1, start));
    const safeEnd = Math.max(safeStart + 0.1, Math.min(duration, end));

    if (kind === "text") {
        const item = _editor.texts.find(t => String(t.id) === String(id));
        if (item) {
            item.startTime = safeStart;
            item.endTime = safeEnd;
        }
        return;
    }
    if (kind === "subtitle") {
        const item = _editor.subtitles.find(s => String(s.id) === String(id));
        if (item) {
            item.startTime = safeStart;
            item.endTime = safeEnd;
        }
        return;
    }
    if (kind === "sticker") {
        const item = _editor.stickers.find(s => String(s.id) === String(id));
        if (item) {
            item.startTime = safeStart;
            item.endTime = safeEnd;
        }
        return;
    }
    if (kind === "media-layer") {
        const item = _editorGetMediaLayerById(id);
        if (item) {
            const dragMode = String(options.mode || "move");
            if (item.kind === "video" && (dragMode === "resize-start" || dragMode === "resize-end") && _editorGetMediaLayerSourceSpan(item) > 0.05) {
                const [clampedStart, clampedEnd] = _editorClampMediaLayerResizeBounds(id, safeStart, safeEnd, dragMode);
                _editorApplyMediaLayerSpeedResize(item, clampedStart, clampedEnd, dragMode);
                return;
            }

            const maxSpan = _editorGetMediaLayerMaxTimelineSpan(item);
            item.startTime = safeStart;
            item.endTime = Math.max(
                safeStart + 0.1,
                Number.isFinite(maxSpan)
                    ? Math.min(safeEnd, safeStart + maxSpan)
                    : safeEnd,
            );
        }
    }
}

function _editorStartTimelineDrag(kind, id, track, event, trackEl, clipEl) {
    const frozenTrackWidth = Math.max(trackEl?.getBoundingClientRect?.().width || 0, 1);
    const fallbackTrackWidth = Math.max(
        document.getElementById("editor-track-video")?.getBoundingClientRect?.().width || 0,
        document.getElementById("editor-timeline")?.getBoundingClientRect?.().width || 0,
        1
    );
    const stableTrackWidth = Math.max(frozenTrackWidth, fallbackTrackWidth);
    const frozenClipRect = clipEl?.getBoundingClientRect?.() || null;

    _editorSelectTimelineClip(kind, id, false, track);
    if (!_editorTimelineCanDrag(kind) || !trackEl) return false;
    if (kind !== "media-layer" && !_editor.duration) return false;
    const range = _editorGetTimelineRange(kind, id, track);
    if (!range) return false;

    const baseSpan = Math.max(0.1, range.end - range.start);
    const timelineDuration = _editorGetTimelineDuration();
    const extendedTrackDuration = Math.max(
        timelineDuration,
        range.end,
        timelineDuration + baseSpan + 30
    );

    let mode = "move";
    if (_editorTimelineCanResize(kind, track) && frozenClipRect) {
        const handleEdge = event.target?.closest?.(".editor-track-clip-handle")?.dataset?.resizeEdge || "";
        if (handleEdge === "start") {
            mode = "resize-start";
        } else if (handleEdge === "end") {
            mode = "resize-end";
        } else if (event.pointerType !== "touch") {
            const localX = event.clientX - frozenClipRect.left;
            const edgeSize = Math.max(10, Math.min(20, frozenClipRect.width * 0.24));
            if (localX <= edgeSize) {
                mode = "resize-start";
            } else if (localX >= frozenClipRect.width - edgeSize) {
                mode = "resize-end";
            }
        }
    }

    const layerTrackInfo = kind === "media-layer"
        ? _editorParseMediaLayerTrack(
            track,
            _editorGetMediaLayerTrackType(_editorGetMediaLayerById(id)),
            _editorGetLayerTrackIndex(_editorGetMediaLayerById(id)),
        )
        : null;
    const baseTrackIndex = kind === "media-layer"
        ? layerTrackInfo.trackIndex
        : kind === "segment"
            ? _editorParseSegmentTrackId(track, _editorGetSegmentTrackIndex(_editorFindSegment(track, id)))
        : 0;

    _editorTimelineDrag = {
        kind,
        id,
        track: kind === "media-layer"
            ? _editorBuildMediaLayerTrackId(layerTrackInfo?.trackType || "video", baseTrackIndex)
            : kind === "segment" && _editorIsVideoTrack(track)
                ? _editorTrackIdForSegmentIndex(baseTrackIndex)
                : track,
        mode,
        startX: event.clientX,
        startY: event.clientY,
        baseTrackIndex,
        trackWidth: stableTrackWidth,
        pixelDuration: Math.max(timelineDuration, 0.1),
        duration: (kind === "media-layer" || (kind === "segment" && _editorIsVideoTrack(track)))
            ? extendedTrackDuration
            : Math.max(_editor.duration, 0.1),
        baseStart: range.start,
        baseEnd: range.end,
        minDuration: kind === "sticker" ? 0.5 : 0.2,
        moved: false,
        saved: false,
        pointerId: event.pointerId,
        pointerTarget: clipEl,
        pointerType: String(event.pointerType || "mouse"),
    };

    _editorCapturePointer(clipEl, event.pointerId);
    document.addEventListener("pointermove", _editorOnTimelineDragMove);
    document.addEventListener("pointerup", _editorOnTimelineDragEnd);
    document.addEventListener("pointercancel", _editorOnTimelineDragEnd);
    return true;
}

function _editorSnapMediaLayerMove(layerId, start, end, timelineDuration) {
    const span = Math.max(0.1, Number(end || 0) - Number(start || 0));
    const safeDuration = Math.max(span, Number(timelineDuration || span));
    const edges = [0];

    _editor.videoSegments.forEach((seg) => {
        edges.push(Number(seg.start || 0));
        edges.push(Number(seg.end || 0));
    });

    _editor.mediaLayers.forEach((layer) => {
        if (String(layer.id) === String(layerId)) return;
        edges.push(Number(layer.startTime || 0));
        edges.push(Number(layer.endTime || 0));
    });

    const snapWindow = Math.max(0.08, Math.min(0.35, span * 0.12));
    let bestOffset = null;

    edges.forEach((edge) => {
        if (!Number.isFinite(edge)) return;
        const offsetStart = edge - start;
        if (Math.abs(offsetStart) <= snapWindow) {
            if (bestOffset === null || Math.abs(offsetStart) < Math.abs(bestOffset)) {
                bestOffset = offsetStart;
            }
        }

        const offsetEnd = edge - end;
        if (Math.abs(offsetEnd) <= snapWindow) {
            if (bestOffset === null || Math.abs(offsetEnd) < Math.abs(bestOffset)) {
                bestOffset = offsetEnd;
            }
        }
    });

    let snappedStart = start;
    if (bestOffset !== null) {
        snappedStart = start + bestOffset;
    }

    const clampedStart = Math.max(0, Math.min(Math.max(0, safeDuration - span), snappedStart));
    return {
        start: clampedStart,
        end: clampedStart + span,
    };
}

function _editorOnTimelineDragMove(event) {
    if (!_editorTimelineDrag) return;

    const drag = _editorTimelineDrag;
    if (drag.pointerId !== undefined && event.pointerId !== undefined && event.pointerId !== drag.pointerId) return;
    const dx = event.clientX - drag.startX;
    const dy = event.clientY - drag.startY;
    const deltaSec = (dx / drag.trackWidth) * Math.max(0.1, Number(drag.pixelDuration || drag.duration || 0.1));
    const baseSpan = Math.max(0.1, drag.baseEnd - drag.baseStart);
    let nextStart = drag.baseStart;
    let nextEnd = drag.baseEnd;

    if (drag.mode === "resize-start") {
        const maxStart = drag.baseEnd - drag.minDuration;
        nextStart = Math.max(0, Math.min(maxStart, drag.baseStart + deltaSec));
    } else if (drag.mode === "resize-end") {
        const minEnd = drag.baseStart + drag.minDuration;
        nextEnd = Math.max(minEnd, Math.min(drag.duration, drag.baseEnd + deltaSec));
    } else {
        const maxStart = Math.max(0, drag.duration - baseSpan);
        nextStart = Math.max(0, Math.min(maxStart, drag.baseStart + deltaSec));
        nextEnd = nextStart + baseSpan;

        if (drag.kind === "media-layer") {
            const snapped = _editorSnapMediaLayerMove(drag.id, nextStart, nextEnd, drag.duration);
            nextStart = snapped.start;
            nextEnd = snapped.end;

            if (drag.mode === "move") {
                const layer = _editorGetMediaLayerById(drag.id);
                if (layer) {
                    const rowStepPx = 44;
                    const rowDelta = Math.round(dy / rowStepPx);
                    const layerTrackType = _editorGetMediaLayerTrackType(layer);
                    const maxTrackIndex = _editorGetMaxMediaLayerTrackIndex(layerTrackType, drag.id) + 1;
                    const nextTrackIndex = Math.max(0, Math.min(maxTrackIndex, drag.baseTrackIndex + rowDelta));
                    if (_editorGetLayerTrackIndex(layer) !== nextTrackIndex) {
                        layer.trackIndex = nextTrackIndex;
                        drag.track = _editorBuildMediaLayerTrackId(layerTrackType, nextTrackIndex);
                        if (_editor.selectedClip.kind === "media-layer" && String(_editor.selectedClip.id) === String(drag.id)) {
                            _editor.selectedClip.track = drag.track;
                            _editor.selectedInsertTrack = _editorResolveInsertTrackForUi(drag.track);
                        }
                    }
                }
            }
        } else if (drag.kind === "segment" && _editorIsVideoTrack(drag.track)) {
            const segment = _editorFindSegment(drag.track, drag.id);
            if (segment) {
                const rowStepPx = 44;
                const rowDelta = Math.round(dy / rowStepPx);
                const maxTrackIndex = _editorGetMaxVideoSegmentTrackIndex(drag.id) + 1;
                const nextTrackIndex = Math.max(0, Math.min(maxTrackIndex, drag.baseTrackIndex + rowDelta));
                const nextTrack = _editorTrackIdForSegmentIndex(nextTrackIndex);
                if (_editorGetSegmentTrackIndex(segment) !== nextTrackIndex) {
                    segment.trackIndex = nextTrackIndex;
                    drag.track = nextTrack;
                    if (_editor.selectedClip.kind === "segment" && String(_editor.selectedClip.id) === String(drag.id)) {
                        _editor.selectedClip.track = nextTrack;
                        _editor.selectedTracks = [nextTrack];
                        _editor.selectedInsertTrack = _editorResolveInsertTrackForUi(nextTrack);
                    }
                }
            }
        }
    }

    const moveThreshold = drag.pointerType === "touch" ? 4 : 1;
    if (Math.abs(dx) > moveThreshold || Math.abs(dy) > moveThreshold) {
        drag.moved = true;
    }
    if (drag.moved && !drag.saved) {
        _editorSaveState();
        drag.saved = true;
    }

    _editorApplyDraggedRange(drag.kind, drag.id, nextStart, nextEnd, drag.track, { mode: drag.mode });
    _editorRenderTimeline();
    const video = document.getElementById("editor-video");
    const previewTime = Number(_editor.timelineTime || video?.currentTime || 0);
    if (video) {
        _editorDrawOverlays(previewTime);
        if (drag.kind === "media-layer") {
            _editorSyncMediaLayersWithTime(previewTime);
        }
    }
}

function _editorOnTimelineDragEnd() {
    document.removeEventListener("pointermove", _editorOnTimelineDragMove);
    document.removeEventListener("pointerup", _editorOnTimelineDragEnd);
    document.removeEventListener("pointercancel", _editorOnTimelineDragEnd);
    if (!_editorTimelineDrag) return;

    _editorReleasePointerCapture(_editorTimelineDrag.pointerTarget, _editorTimelineDrag.pointerId);
    const moved = _editorTimelineDrag.moved;
    const kind = _editorTimelineDrag.kind;
    const id = _editorTimelineDrag.id;
    const track = _editorTimelineDrag.track;
    _editorTimelineDrag = null;

    if (moved) {
        if (kind === "media-layer") {
            _editorFinalizeTrackSequenceMediaLayerEdit(id);
        }
        _editorRenderTimeline();
        if (kind === "media-layer") {
            _editorRenderMediaLayers();
        }
        _editorRenderProps();
    } else {
        _editorSelectTimelineClip(kind, id, true, track);
    }
}

function _editorHandleDeleteKey(event) {
    const workspace = document.getElementById("editor-workspace");
    if (!workspace || workspace.hidden) return;

    const active = document.activeElement;
    const tag = (active?.tagName || "").toUpperCase();
    const editingText = Boolean(active?.isContentEditable || ["INPUT", "TEXTAREA", "SELECT"].includes(tag));

    const key = String(event.key || "");
    const wantsZoomIn = key === "+" || key === "=" || key === "NumpadAdd";
    const wantsZoomOut = key === "-" || key === "_" || key === "NumpadSubtract";
    const wantsZoomReset = (event.ctrlKey || event.metaKey) && (key === "0" || key === "Numpad0");

    if (!editingText && (wantsZoomIn || wantsZoomOut || wantsZoomReset)) {
        event.preventDefault();
        const focusTime = _editorGetTimelineFocusTime();
        if (wantsZoomReset) {
            _editorSetTimelineZoom(1, { focusTime, announce: true });
        } else if (wantsZoomIn) {
            _editorAdjustTimelineZoom(1, { focusTime, announce: true });
        } else {
            _editorAdjustTimelineZoom(-1, { focusTime, announce: true });
        }
        return;
    }

    if (editingText) {
        return;
    }

    if ((event.ctrlKey || event.metaKey) && !event.altKey) {
        const lowerKey = key.toLowerCase();
        if (lowerKey === "z") {
            event.preventDefault();
            if (event.shiftKey) {
                _editorRedo();
            } else {
                _editorUndo();
            }
            return;
        }
        if (lowerKey === "y") {
            event.preventDefault();
            _editorRedo();
            return;
        }
        if (lowerKey === "c") {
            if (_editorSelectionCanCopy()) {
                event.preventDefault();
                _editorCopySelectedClip();
            }
            return;
        }
        if (lowerKey === "v") {
            if (_editorClipboardHasItems()) {
                event.preventDefault();
                _editorPasteClipboard();
            }
            return;
        }
        if (lowerKey === "x") {
            if (_editorSelectionCanCut()) {
                event.preventDefault();
                _editorCutSelectedClip();
            }
            return;
        }
    }

    if (key !== "Delete" && key !== "Backspace") {
        return;
    }
    if (!_editor.selectedClip.kind) return;

    event.preventDefault();
    _editorDeleteSelectedClip();
}

function _editorHandleTimelineWheel(event) {
    if (event.defaultPrevented) return;
    const workspace = document.getElementById("editor-workspace");
    if (!workspace || workspace.hidden) return;
    if (!(event.ctrlKey || event.metaKey)) return;
    if (!(event.target instanceof Element) || !event.target.closest("#editor-workspace")) return;

    event.preventDefault();
    const direction = Number(event.deltaY || 0) < 0 ? 1 : -1;
    _editorAdjustTimelineZoom(direction, {
        focusTime: _editorGetTimelineFocusTime(),
        announce: false,
    });
}

// ---------- Export ----------
async function _editorExport() {
    if (!_editor.projectId || !_editor.videoUrl) return;

    const normalizedTimeline = _editorCollapseVisibleTimelineDeadZones();
    if (normalizedTimeline) {
        _editorRenderTimeline();
        _editorRenderMediaLayers();
        _editorRenderProps();
        _editorApplyTimelineFrame(Number(_editor.timelineTime || 0), false);
    }

    // Build edit specification
    const edits = {
        project_id: _editor.projectId,
        aspect_ratio: _resolveAspectRatio(),
        trim_start: _editor.trimStart,
        trim_end: _editor.trimEnd,
        hide_base_video_track: Boolean(_editor.hideBaseVideoTrack),
        trim_video_segments: _editor.videoSegments
            .map(seg => ({
                start: _editorSegSourceStart(seg),
                end: _editorSegSourceEnd(seg),
                reversed: _editorSegmentIsReversed(seg),
                speed: _editorSegmentPlaybackSpeed(seg),
                volume: _editorSegmentVolumePercent(seg),
                timeline_start: Number(seg.start || 0),
            }))
            .sort((a, b) => (a.timeline_start - b.timeline_start) || (a.start - b.start))
            .filter(seg => seg.end > seg.start + 0.05),
        trim_audio_segments: _editor.audioSegments
            .map(seg => ({
                start: _editorSegSourceStart(seg),
                end: _editorSegSourceEnd(seg),
                reversed: _editorSegmentIsReversed(seg),
                speed: _editorSegmentPlaybackSpeed(seg),
                volume: _editorSegmentVolumePercent(seg),
                timeline_start: Number(seg.start || 0),
            }))
            .sort((a, b) => (a.timeline_start - b.timeline_start) || (a.start - b.start))
            .filter(seg => seg.end > seg.start + 0.05),
        trim_segments: _editor.videoSegments
            .map(seg => ({
                start: _editorSegSourceStart(seg),
                end: _editorSegSourceEnd(seg),
                reversed: _editorSegmentIsReversed(seg),
                speed: _editorSegmentPlaybackSpeed(seg),
                volume: _editorSegmentVolumePercent(seg),
                timeline_start: Number(seg.start || 0),
            }))
            .sort((a, b) => (a.timeline_start - b.timeline_start) || (a.start - b.start))
            .filter(seg => seg.end > seg.start + 0.05),
        filter: _editor.filter,
        quality: _editor.quality,
        original_volume: _editor.originalVolume,
        music_volume: _editor.musicVolume,
        texts: _editor.texts.map(t => ({
            content: t.content, start_time: t.startTime, end_time: t.endTime,
            x: t.x, y: t.y, font_size: t.fontSize, color: t.color,
            bold: t.bold, italic: t.italic,
        })),
        subtitles: _editor.subtitles.map(s => ({
            text: s.text, start_time: s.startTime, end_time: s.endTime,
            x: s.x, y: s.y, font_size: s.fontSize, font_color: s.fontColor,
            bg_color: s.bgColor, outline_color: s.outlineColor,
            font_family: s.fontFamily, bold: s.bold, italic: s.italic,
        })),
        stickers: _editor.stickers.map(s => ({
            emoji: s.emoji, x: s.x, y: s.y, start_time: s.startTime, end_time: s.endTime, size: s.size,
        })),
        media_layers: _editor.mediaLayers.map((layer) => {
            const normalizedLayer = _editorNormalizeMediaLayer(layer);
            return {
                path: normalizedLayer.path,
                kind: normalizedLayer.kind,
                media_type: normalizedLayer.kind,
                track_index: Number(normalizedLayer.trackIndex || 0),
                layout_mode: String(normalizedLayer.layoutMode || ""),
                x: Number(normalizedLayer.x || 0),
                y: Number(normalizedLayer.y || 0),
                width: Number(normalizedLayer.width || 100),
                start_time: Number(normalizedLayer.startTime || 0),
                end_time: Number(normalizedLayer.endTime || 0),
                duration: Number(normalizedLayer.duration || 0),
                source_offset: Number(normalizedLayer.sourceOffset || 0),
                source_duration: Number(normalizedLayer.sourceDuration || 0),
                speed: Number(normalizedLayer.speed || 1),
                volume: Number(normalizedLayer.volume ?? 100),
                audio_only: Boolean(normalizedLayer.audioOnly),
                reversed: Boolean(normalizedLayer.reversed),
            };
        }),
        smart_cuts: _editorGetApprovedSmartCuts().map((cut) => ({
            start: Number(cut.start || 0),
            end: Number(cut.end || 0),
            title: String(cut.title || ""),
            reason: String(cut.reason || ""),
            score: Math.round(Number(cut.score || 0)),
        })),
        smart_cut_words: (_editor.smartCutWords || []).map((word) => ({
            word: String(word?.word || ""),
            start: Number(word?.start || 0),
            end: Number(word?.end || word?.start || 0),
        })),
        smart_cut_subtitle_style: _editorGetApprovedSmartCuts().length ? _editorBuildSmartCutSubtitleCfg() : null,
    };

    // Show export overlay
    const overlay = document.createElement("div");
    overlay.className = "editor-export-overlay";
    overlay.innerHTML = `
        <div class="editor-export-card">
            <h3>${edits.smart_cuts.length ? "Exportando shorts" : "Exportando video"}</h3>
            <div class="editor-export-progress"><div class="editor-export-progress-fill" id="editor-export-fill"></div></div>
            <p class="editor-export-status" id="editor-export-status">Enviando edicoes ao servidor...</p>
        </div>
    `;
    document.body.appendChild(overlay);

    const fill = document.getElementById("editor-export-fill");
    const status = document.getElementById("editor-export-status");

    try {
        // Upload music file if any
        let musicPath = String(_editor._musicServerPath || "").trim();
        if (!musicPath && _editor._musicFile) {
            const formData = new FormData();
            formData.append("file", _editor._musicFile);
            const musicUploadEndpoint = _editor._musicSource === "video"
                ? "/api/video/editor/upload-video-audio"
                : "/api/video/editor/upload-music";
            if (status) {
                status.textContent = _editor._musicSource === "video"
                    ? "Extraindo audio do video enviado..."
                    : "Enviando audio para o servidor...";
            }
            const uploadRes = await fetch(API.replace("/api", "") + musicUploadEndpoint, {
                method: "POST",
                headers: { Authorization: "Bearer " + token },
                body: formData,
            });
            if (!uploadRes.ok) {
                const errPayload = await uploadRes.json().catch(() => ({}));
                throw new Error(errPayload.detail || "Falha ao enviar audio");
            }
            const uploadData = await uploadRes.json();
            musicPath = String(uploadData?.path || "").trim();
            _editor._musicServerPath = musicPath;
            if (!_editor.musicUrl && uploadData?.media_url) {
                const mediaUrlRaw = String(uploadData.media_url);
                _editor.musicUrl = mediaUrlRaw.startsWith("/")
                    ? `${API.replace("/api", "")}${mediaUrlRaw}`
                    : mediaUrlRaw;
                _editorSetMusicPreviewSource(_editor.musicUrl);
            }
        }
        edits.music_path = musicPath;

        // Submit export job
        const res = await api("/video/editor/export", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify(edits),
        });
        const jobId = res.job_id;

        // Poll progress
        let done = false;
        while (!done) {
            await new Promise(r => setTimeout(r, 2000));
            try {
                const poll = await api(`/video/editor/export/${jobId}/status`);
                if (fill) fill.style.width = (poll.progress || 0) + "%";
                if (status) status.textContent = poll.message || "Processando...";
                if (poll.status === "completed") {
                    done = true;
                    const exportedShorts = Array.isArray(poll.output_urls) ? poll.output_urls : [];
                    if (status) status.textContent = exportedShorts.length ? "Shorts exportados com sucesso!" : "Vídeo exportado com sucesso!";
                    if (fill) fill.style.width = "100%";
                    await new Promise(r => setTimeout(r, 1500));
                    overlay.remove();
                    showToast(exportedShorts.length ? `${exportedShorts.length} shorts exportados com sucesso!` : "Vídeo editado exportado com sucesso!", "success");

                    if (exportedShorts.length) {
                        for (let idx = 0; idx < exportedShorts.length; idx += 1) {
                            const item = exportedShorts[idx];
                            if (!item?.url) continue;
                            const link = document.createElement("a");
                            link.href = item.url;
                            link.download = item.filename || `short-${String(idx + 1).padStart(2, "0")}.mp4`;
                            link.style.display = "none";
                            document.body.appendChild(link);
                            link.click();
                            document.body.removeChild(link);
                            await new Promise(r => setTimeout(r, 900));
                        }
                    } else if (poll.output_url) {
                        const link = document.createElement("a");
                        link.href = poll.output_url;
                        link.download = `${String(_editor.editProjectName || _editor.sourceProjectTitle || "video-editado").trim() || "video-editado"}.mp4`;
                        link.style.display = "none";
                        document.body.appendChild(link);
                        link.click();
                        document.body.removeChild(link);
                    }

                    loadEditorVideosList();
                    loadProjects();
                } else if (poll.status === "failed") {
                    done = true;
                    overlay.remove();
                    showToast("Erro ao exportar: " + (poll.error || "erro desconhecido"), "error");
                }
            } catch (e) {
                done = true;
                overlay.remove();
                showToast("Erro ao verificar status: " + e.message, "error");
            }
        }
    } catch (err) {
        overlay.remove();
        showToast("Erro ao exportar: " + err.message, "error");
    }
}

// ---------- Bind editor events ----------
function _bindEditorEvents() {
    const video = document.getElementById("editor-video");
    if (video) {
        video.addEventListener("timeupdate", _editorTimeUpdate);
        video.addEventListener("ended", () => {
            if (!_editor.playing) return;
            const videoPlaybackEnd = _editorGetVideoPlaybackEndTime();
            if (_editorGetTimelineDuration() > videoPlaybackEnd + 0.02) {
                _editorStartVirtualTimelinePlayback(videoPlaybackEnd);
                return;
            }
            _editorResetPlaybackToStart();
        });
    }
    document.getElementById("editor-overlay-canvas")?.addEventListener("pointerdown", (event) => {
        if (_editorStartTextOverlayDrag(event)) return;
        _editorStartSubtitleOverlayDrag(event);
    });
    document.getElementById("editor-overlay-canvas")?.addEventListener("click", _editorHandleOverlayClick);
    document.getElementById("editor-play-btn")?.addEventListener("click", _editorTogglePlay);
    document.getElementById("editor-aspect-btn")?.addEventListener("click", _editorCycleAspectRatio);
    document.getElementById("editor-back-btn")?.addEventListener("click", closeEditor);
    document.getElementById("editor-new-btn")?.addEventListener("click", _editorOpenStartModal);
    document.getElementById("editor-undo-btn")?.addEventListener("click", _editorUndo);
    document.getElementById("editor-redo-btn")?.addEventListener("click", _editorRedo);
    document.getElementById("editor-export-btn")?.addEventListener("click", _editorExport);
    document.getElementById("editor-upload-btn")?.addEventListener("click", _editorOpenStartModal);
    document.getElementById("editor-side-upload-video-btn")?.addEventListener("click", () => {
        const layerVideoInput = document.getElementById("editor-layer-video-upload-input");
        if (!layerVideoInput) return;
        if (!_editor.projectId) {
            showToast("Abra um projeto no editor antes de enviar vídeos em camada.", "error");
            return;
        }
        layerVideoInput.click();
    });
    document.getElementById("editor-side-upload-audio-btn")?.addEventListener("click", () => {
        const layerAudioInput = document.getElementById("editor-layer-audio-upload-input");
        if (!layerAudioInput) return;
        if (!_editor.projectId) {
            showToast("Abra um projeto no editor antes de enviar áudios em camada.", "error");
            return;
        }
        _editorSelectTool("layers");
        layerAudioInput.click();
    });
    document.getElementById("editor-side-library-btn")?.addEventListener("click", () => {
        if (!_editor.projectId) {
            showToast("Abra um projeto no editor antes de usar a biblioteca.", "error");
            return;
        }
        _editorSelectTool("layers");
        _editorOpenLayerVideoLibrary();
    });
    document.getElementById("editor-side-upload-images-btn")?.addEventListener("click", () => {
        const imageInput = document.getElementById("editor-layer-image-upload-input");
        if (!imageInput) return;
        if (!_editor.projectId) {
            showToast("Abra um projeto no editor antes de enviar imagens em camada.", "error");
            return;
        }
        imageInput.click();
    });

    document.getElementById("editor-media-layer-host")?.addEventListener("pointerdown", _editorOnMediaLayerPointerDown);
    document.addEventListener("pointermove", _editorOnMediaLayerDragMove);
    document.addEventListener("pointerup", _editorOnMediaLayerDragEnd);
    window.addEventListener("resize", _editorRenderMediaLayers);
    window.addEventListener("resize", _editorRenderTimeline);
    window.addEventListener("resize", _editorRenderMobileStagePanel);
    document.getElementById("editor-quick-add-text")?.addEventListener("click", _editorAddText);
    document.getElementById("editor-quick-add-subtitle")?.addEventListener("click", _editorAddSubtitle);
    document.getElementById("editor-quick-cut")?.addEventListener("click", _editorSplitAtCurrentTime);
    document.getElementById("editor-quick-reverse")?.addEventListener("click", _editorToggleReverseSelection);
    document.getElementById("editor-quick-layer-order")?.addEventListener("click", _editorCycleMediaLayerOrder);
    document.getElementById("editor-quick-zoom-out")?.addEventListener("click", () => {
        _editorAdjustTimelineZoom(-1, { focusTime: _editorGetTimelineFocusTime(), announce: true });
    });
    document.getElementById("editor-quick-zoom-in")?.addEventListener("click", () => {
        _editorAdjustTimelineZoom(1, { focusTime: _editorGetTimelineFocusTime(), announce: true });
    });
    document.getElementById("editor-quick-speed")?.addEventListener("click", _editorCyclePlaybackRate);
    document.getElementById("editor-quick-delete")?.addEventListener("click", _editorDeleteSelectedClip);
    document.getElementById("editor-quick-duplicate")?.addEventListener("click", _editorCopySelectedClip);
    document.getElementById("editor-quick-paste")?.addEventListener("click", _editorPasteClipboard);
    document.getElementById("editor-mobile-actions-toggle")?.addEventListener("click", () => {
        _editorToggleMobileControlMode();
    });
    document.getElementById("editor-mobile-tools-toggle")?.addEventListener("click", () => {
        _editorSetMobileControlMode("tools");
    });
    document.getElementById("editor-project-name")?.addEventListener("click", (event) => {
        event.stopPropagation();
        _editorStartProjectNameEdit();
    });
    document.getElementById("editor-project-name")?.addEventListener("blur", () => {
        _editorCommitProjectNameEdit();
    });
    document.getElementById("editor-project-name")?.addEventListener("keydown", (event) => {
        if (event.key === "Enter") {
            event.preventDefault();
            _editorCommitProjectNameEdit();
            return;
        }
        if (event.key === "Escape") {
            event.preventDefault();
            _editorCancelProjectNameEdit();
        }
    });
    document.getElementById("editor-aspect-select")?.addEventListener("change", (e) => {
        _editorSaveState();
        _editorSetOutputAspectRatio(e.target.value);
    });
    document.getElementById("editor-subtitle-modal-input")?.addEventListener("keydown", (event) => {
        if ((event.ctrlKey || event.metaKey) && event.key === "Enter") {
            event.preventDefault();
            _editorSaveSubtitleTextModal();
            return;
        }
        if (event.key === "Escape") {
            event.preventDefault();
            _editorCloseSubtitleTextModal();
        }
    });

    // Tool buttons
    document.querySelectorAll(".editor-tool-btn").forEach(btn => {
        const tool = btn.dataset.tool;
        if (!tool) return;
        btn.addEventListener("click", () => _editorSelectTool(tool));
    });

    document.addEventListener("click", (event) => {
        if (!_editorMobileTrackVolumeOpen) return;
        if (event.target.closest(".editor-track-label-volume-wrap")) return;
        _editorMobileTrackVolumeOpen = "";
        _editorRenderTimeline();
    });

    document.getElementById("editor-timeline-tracks")?.addEventListener("pointerdown", (e) => {
        const clip = e.target.closest(".editor-track-clip");
        if (!clip) return;
        const kind = clip.dataset.kind || "";
        const id = clip.dataset.id || "";
        const track = clip.dataset.track || "";
        const trackEl = clip.parentElement;
        const dragStarted = _editorStartTimelineDrag(kind, id, track, e, trackEl, clip);
        if (dragStarted) {
            e.stopPropagation();
            e.preventDefault();
        }
    });

    document.getElementById("editor-timeline-tracks")?.addEventListener("click", (e) => {
        const label = e.target.closest(".editor-track-label");
        if (label) {
            const track = label.closest(".editor-track")?.dataset.track || "";
            _editor.selectedInsertTrack = track || _editor.selectedInsertTrack;
            if (_editorIsTrackSelectable(track)) {
                _editorToggleTrackSelection(track, {
                    toggle: Boolean(e.ctrlKey || e.metaKey || e.shiftKey),
                });
            } else {
                _editorRefreshTrackSelectionUI();
            }
            e.stopPropagation();
            return;
        }

        const trackContent = e.target.closest(".editor-track-content");
        if (trackContent && !e.target.closest(".editor-track-clip") && !e.target.closest(".editor-transition-marker")) {
            const track = trackContent.closest(".editor-track")?.dataset.track || "";
            _editor.selectedInsertTrack = track || _editor.selectedInsertTrack;
            if (_editorIsTrackSelectable(track)) {
                _editorToggleTrackSelection(track, {
                    toggle: Boolean(e.ctrlKey || e.metaKey || e.shiftKey),
                });
            } else {
                _editorRefreshTrackSelectionUI();
            }
            e.stopPropagation();
            return;
        }

        const transitionMarker = e.target.closest(".editor-transition-marker");
        if (transitionMarker) {
            _editorSelectTimelineClip(
                "transition",
                transitionMarker.dataset.transitionKey || "",
                true,
                transitionMarker.dataset.track || ""
            );
            e.stopPropagation();
            return;
        }

        const clip = e.target.closest(".editor-track-clip");
        if (!clip) return;
        _editorSelectTimelineClip(
            clip.dataset.kind || "",
            clip.dataset.id || "",
            true,
            clip.dataset.track || ""
        );
        e.stopPropagation();
    });

    document.addEventListener("keydown", _editorHandleDeleteKey);

    // Timeline click-and-hold scrub
    document.getElementById("editor-timeline")?.addEventListener("pointerdown", (e) => {
        const started = _editorStartTimelineScrub(e);
        if (started && e.pointerType !== "touch") {
            e.preventDefault();
        }
    });
    document.getElementById("editor-timeline")?.addEventListener("wheel", _editorHandleTimelineWheel, { passive: false });
    document.addEventListener("wheel", _editorHandleTimelineWheel, { passive: false });
    window.addEventListener("resize", _editorApplyMobileControlMode);

    document.addEventListener("visibilitychange", () => {
        if (document.visibilityState === "hidden") {
            _editorPersistDraftNow();
        }
    });
    window.addEventListener("beforeunload", () => {
        _editorPersistDraftNow();
    });

    _editorRefreshQuickActions();
    _editorRefreshTrackSelectionUI();
    _editorApplyMobileControlMode();
}

// Init editor bindings when DOM ready
if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", _bindEditorEvents);
} else {
    _bindEditorEvents();
}

bootstrap();



